insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('ce533b7b-3fb6-5739-acc2-79fda6e209f3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-22', null, null, '通常 / 親子大会作品作り', '前回、ゲームの大枠を決めましたが、その詳細作りに苦戦してました。ともに考えていきましたが、あまり納得したものが得られず、手が進まない状態でした。今回はあまり進められてないので、次回は話を聴きながら進めたあげたほうがいいです。', 'この期間はなつめちゃんと並ばすと、互いを無駄に意識してしまい、うまく進んでいないように見えたので、離した方がいいと思う', '時間帯: その他
タイピング: よくできていました'),
  ('e35ee600-e3ae-57a8-ad46-5c27c9f86560', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-22', null, null, '通常 / 教室に慣れる、スキルの確認', '自分のScratchのアカウントは持っていて、スクアニ（Scratchアニメ）の6期生だか7期生だと言っていました。 さねゆきくんのアカウントを作る間、基本操作コースのカードを見せてブロックが思い浮かぶかどうか確認してもらいましたが、06あたりまでは大丈夫とのこと、07の、パドルでボールが跳ね返るところが少し不安とのことで、ピンポンゲームから始めました。 跳ね返るときの乱数の意味は、ボールの1か所にマーキングして動きを実際に見せたところ、納得していました。跳ね返るコードに「待つ」が必要な意味も、きちんと説明できていました。 ピンポンゲーム完成後、今後の希望について話しました。コンテストなどに出すことは、どちらかといえば苦手だそうで、自分のペースでスキルを学び、好きな作品を作れるようになりたい、とのことでした。スキルを学ぶ上での検定受検や、Monacaには、それなりに興味を示していました。 ゲームはあまり得意ではなく、Scratchユーザーのaoringosanを尊敬していて、閉ざされた都市 新ED（エンディング）（https://scratch.mit.edu/projects/953158422/）のシリーズや、魔法国シリーズが好きだそうです。 メッセージやクローンについては知識もあり、自分でもよく使っているとのことですが、その一方でジャンプの種類などについては疎く、垂直ジャンプ、放物線ジャンプ、等速ジャンプ、加速するジャンプなど、口頭で説明しただけでもびっくりして感心していました。 ジャンプの動きなど、ゲームで使うスキルでアニメでも活用できるものがたくさんあるとの説明に納得してくれたようで、今後の学習にも意欲を示していました。 残り時間で残像の作り方をやりましたが、元の動きを見て、ほぼ自分で作成できていました。', null, '時間帯: その他
盛り上がり: Scratchがある程度わかる相手に話を聞いてもらうのが、とにかく嬉しくてたまらない、といった感じでした。 お勧めの作品を紹介してくれたときも、こちらの反応をワクワクしながら見ていました。 知っているコードであっても、素直に説明を聞いて、楽しみながら取り組んでいました。'),
  ('02df2f14-58b3-59c2-bca0-3de4bb377c59', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-24', '17:30:00', null, '通常 / 検定問題2級①', '実力はあるものの初見に弱く、すぐに諦めてしまう部分がありもったいなかったです。自分の実力maxで取り組めていない気がしたので、合格から遠ざかることを伝え、分からないところが具体的にどこなのか、どこまでなら分かっているのかを念頭にプログラムしてもらいました。 「正解したとき」の考え方が難しかったそうです。ヒントのブロックから組み立てて考えることと演算のブロックの使い方を強調して説明しました。 最後に制御の組み合わせ方を間違えてうまく動かなかったのですが、その原因を私よりも早く見つけられて嬉しそうでした。。', null, null),
  ('dfe01b0e-0ac0-5bdd-ba6d-ff84bb92d272', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-24', '16:30:00', null, '通常 / 基本操作コース 04_追跡ゲーム または 08_さあ踊ろう どちらか 前回、オリジナル作品の花子さんゲームを作成しようとして、なかなか思うような動きができなかったため、多少は自覚を持ってくれてるかも？基本操作コースの表が一通り埋まるくらいになれば、もっと好きなものが作れるから説明し、スタンプ埋めに戻らせてスキルを増やしたい。', 'かなり声をかけて進めるように言うと取り組めました。「ファイルを取りに行く」というのが注意の向き先が変わる良いタイミングになるようなので、授業始まってから取りに行くのが良いかもしれません。 コスチュームを変えるブロックを使ったあと、早着替えになっていることを説明したらすぐに「〇秒待つ！」と考えがでてきたので素晴らしかったです。繰り返しもスムーズにできました。明るさを変えるときもマイナスやプラスを変えると白黒が変わることが頭の中で結びついていたので良かったです。ただプログラムの全体を想像するのは少し難しそうです。部分的には理解できそうです。 スタンプで埋められて嬉しそうでした！', null, 'タイピング: 集中力を欠くためスキップ'),
  ('f0c1de2c-4882-5b68-b670-3faa0f00c7c8', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-24', '16:30:00', null, '通常 / 基本操作コース 04_追跡ゲーム または 08_さあ踊ろう どちらか 前回、オリジナル作品の花子さんゲームを作成しようとして、なかなか思うような動きができなかったため、多少は自覚を持ってくれてるかも？基本操作コースの表が一通り埋まるくらいになれば、もっと好きなものが作れるから説明し、スタンプ埋めに戻らせてスキルを増やしたい。', 'かなり声をかけて進めるように言うと取り組めました。「ファイルを取りに行く」というのが注意の向き先が変わる良いタイミングになるようなので、授業始まってから取りに行くのが良いかもしれません。 コスチュームを変えるプログラム、時間の使い方、明るさや色の効果をやりました。コスチュームや明るさのブロックはよく理解できていましたが、制御のブロックは難しい様子です。1回しか動かないプログラムに制御のブロックを使って発展させていく考えが薄い気がしたので、今回は繰り返しのブロックを積極的に使いました。', null, 'タイピング: 集中力を欠くためスキップ'),
  ('928454ca-8f44-5bdf-9435-6209cb4a9d98', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-24', '16:30:00', null, '通常 / 親子大会オリジナル作品 機織りの繰り返しの部分を作成', '今日は、タイピングに正解すると機織りの布ができていくところを繰り返しで作る、ということで、黙々と作業していました。 一通り動くようになった、というのでコードを見せてもらったところ、タイピングの問題を毎回「○○と聞いて待つ」に打ち込んでいて、正解判定のところにも同様に「答え=○○なら」と打ち込んでいたため、打ち間違いなどのリスクが高くなることと、次の問題に移るときに毎回メッセージを使っていて、同様のコードがいくつも並んでしまっていることを指摘し、問題をリストで管理する提案をしました。リストは初めてということだったので、【小技】クイズ＿リストを使う 問題の多いクイズ屋さんを見せ、タイピングの問題のみのリストを作り、問題番号の変数を使って管理するコードを真似しながら作ってみました。 最初の問題がリストの通りに出てくるのを確認し、感動していました。 機織り機の動きが問題番号によって微妙に変えたいらしいので、ここは変数で管理できるようにしたいこと、タイピングの問題をテキストデータで持ってきてもらっても対応可能なことを伝えました。', '問題番号が進んだ時の機織り機の動きのコードをうまくまとめる', '盛り上がり: 入賞を狙うためにも、コードをなるべくわかりやすく整理しようと持ち掛けると、熱心にリストにチャレンジしていました。うまく動いたときは嬉しそうでした。'),
  ('fbd26a0b-ebad-56cb-924e-c27eb81fb72c', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-22', '16:30:00', null, '通常 / 親子大会の作成', 'いろいろな元素がばらばらに降ってくるようにしたいとのことで、元素のクローンを降らせていました。基本操作コースのキャッチゲームを思い出して無事に作れました。同じような動きをするスプライトがたくさんありますが、ちょっと作るとすぐにコードを複製していったので、一つのスプライトが全部出来てから複製したほうが無駄がないよと伝えました。その後テストプレイをして、元素をクリックしてもつかめないことに気づきました。「ドラッグできるようにする」ブロックと、一度つかんだら落ちる動きを止めればいいことを伝えましたが、それをやっても落ち続けてしまいました。このバグは家で直してくるそうです。', '今思い描いている内容を全て実現するにはリストやクローンを使わないといけなそうなので、相談して妥協点を見つける', '盛り上がり: 今日は前回と違ってやすのりくんの隣の席にしましたが、お互いのゲームが気になって少し気が散った場面がありました。やはり違う席の方が集中できそうです。'),
  ('a0ba13c8-f707-58e4-99e2-a8fb2069e662', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-22', null, null, '通常 / U16大会の製作', '先日扱った「タイムアタック25」で出てきたクローン番号の使い方を応用して、「ボールが大量に降ってきて、それがマウスに触れたらその後はマウスについていく」という動きを作りました。しかしそれをどういう作品に使えばいいのかと案に詰まっていたので、まずは過去の入賞作品を参考にしてもらいました。しかし自分の作品とうまく共通点を見いだせず、次はブレストカードを使いました。制約があるほうがアイデアは出やすいということで、出てきた3枚のカードのうちどれかを絶対使うことにすると、ようやくピンときたようで作成を再開できました。', null, '時間帯: その他
盛り上がり: 方向性が決まった時は少し安心したようでした。'),
  ('3ef8f17c-6d4d-5acd-991e-6ff085d9e6ae', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-22', null, null, '通常 / 手順通りに作成を進める', 'インベーダーゲームの続きを進めることをすぐに思い出せました。座標の数値を大量に入力しないといけないところをやりましたが、キーボードでもタッチパネルでもたびたび操作ミスしてやりづらそうにしていました。しかしあきらめずにその部分を突破し、それ以降の部分も少しできました。今回も「30分は頑張ろう」ということをリマインドしましたが、だんだんその姿勢が定着してきているようです。', null, '時間帯: その他'),
  ('f7263ce8-d333-5845-8cb5-6b9d1dff78a4', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-22', null, null, '通常 / 親子大会の製作', '隔週ということもあり親子大会の製作が初めてだったので軽く説明しました。製作時間も他の子の半分しかないことを不安に思ったそうなので、アルスタジオにある作品を参考にしたりして短い時間でも完成できるものを作ることを勧めました。アルスタジオの「キューブの戦い」に興味を持ち、これをアレンジする方向に決めました。注意点としてキャラクターの見た目は変えた方がいいかもと伝えましたが、まずは動きを作っていくことにしたそうです。相手の方に爆弾を投げるというアイデアを思いつきましたが、作り方がわからないと相談してくれたので、放物ジャンプを応用したらできるとヒントを出しました。アルスタジオにある放物ジャンプのコードを見ながら、とりあえず爆弾が斜めにジャンプするようにできました。', null, '時間帯: その他
盛り上がり: 親子大会の1回目でしたが方向性は決まってきたようです。'),
  ('830c72b6-fd01-592c-82d6-6e7bcf398285', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-22', null, null, '通常 / 親子大会の製作', 'アレンジの内容を考えてきてくれました。紫の風船よりももっとレアな黄色風船を用意して、それを割ると大量加点するようにしたいとのことでした。手順書にも出てきた乱数を応用すればできるのですが、写しただけで内容の理解はあまりできていなかったので、サイコロを例に挙げて説明しました。すると、黄色の風船を出す用の乱数をもう一個用意すればいいことに気づくことができました。乱数の範囲を広くして確率を下げることもできました。 残りの時間は、背景や数字の見た目も変えたいといって色々試していました。', null, '時間帯: その他
タイピング: 苦戦したようで体力回復アイテムを使っていました
盛り上がり: 難しい内容も理解しようと考えてみる姿勢があってよかったです。'),
  ('75970326-9f1e-51b8-83c0-97a0dc2a8dd7', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-21', '18:40:00', null, '通常 / 乱数の復習、親子大会ビギナーズ部門「ふうせんをわろう」の作成続き', '今日は「ふうせんをわろう」の続きを作る！と、ワクワクした様子で来室しました。 前回、ふうせんのコスチュームがランダムにキャシーに変わるようにしていたことを確認して、自分でウケていました。 キャシーがどのくらいの割合で出てくるか、というところで乱数の復習をしました。学年的に、割合というとあまりよくわからないようでしたが、乱数の数値を変えることによってキャシーがたくさん出てきたり、なかなか出てこなかったりするのは納得できたようで、数値をいくつか試して面白がっていました。 もともとのふうせんのコスチュームが3つあったことから、2種類のふうせんの色の使い分けだけではなく、ボスキャラを作りたい、と言い出し、やりたいことをものすごい勢いで語っていました。ひとしきり話を聞いてから、それを一度にやるのは難しいため、わかりやすい部分から少しずつ取り組むことを納得させました。 点数が50になったらボスキャラを出す、というのを、「点数が50になるまで繰り返す」を使って作成しました。 ボスキャラの必殺技の名前を五条悟？からとったそうで、どれだけすごいボスキャラなのかを語りまくっていました。コンテストの締め切りまでにそこを全部作り込むのは無理なので、やりたいことの優先度を少しでもしぼれるよう、お母さんと本人に話しました。 （本人は興奮していて、あまり気にしていないかもしれませんが…）', null, '盛り上がり: 語りまくっていた「やりたいこと」が少しずつ形になるのが、とにかく嬉しそうでした。
備考: 来月からのクラス変更届（隔週→レギュラー）を受け取りました'),
  ('43b9a102-41a3-5ede-81e2-dcd6dadbf0fd', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-21', '17:30:00', null, '通常 / 目標の設定をする', 'U16大会に参加する意思はあるそうで、家でネタ帳を作成しているとのこと、今日まで期末試験でネタ帳を完成させられなかったので、次回それを持ってきて作成に入りたいとのことでした。 今日は、大会に出す予定の作品で使用する可能性のあるスキルを確認しよう、ということで、ジャンプと背景のスクロールを復習することにしました。 久しぶりと言いながらも、スムーズに作成を進めていました。 柚月くんにコスチュームの図形の編集の小技を教えたり、壮介くんに炎のエフェクトを説明したりと、上級生らしく面倒を見てくれたりもしていました。', null, '盛り上がり: 周りの子たちに声掛けをしながら自分の得意な作成を進めたりと、「部長」らしく楽しそうに参加していました。
備考: ガサガサ探検隊に参加したいとのことです。'),
  ('1ee542a3-988b-53ea-8630-cda9cf32c5bc', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-21', '17:30:00', null, '通常 / 作成に集中する', '今日は約束をよく覚えていて、時間前に教室に来てからすぐに「ふうせんをわろう」の手順書を開いていました。 途中何度か、おしゃべりがしたくて中断はしたものの、話の内容が一区切りつくたびに作成を続けようと促すと、約束を思い出して授業に戻ることができました！ 乱数は、以前に習ったのは覚えていないと言っていて、説明しても「難しい」という顔をしていましたが、乱数によって出てくるコスチュームの頻度が変わることはなんとなくイメージできたようで、数値にこだわって作成しようとしていました。 ふうせんと弾丸の2つのスプライトを、それぞれコスチュームによって点数を変えるところまで設定ができました。 お迎えにきたお母さんにも、得意そうに見せていました。', 'ゲームクリアの作成', '盛り上がり: それぞれのコスチュームの頻度や得点にこだわって、自分で数値を決めて設定できたのが嬉しかったようでした。達成感を得られたのか、満足げに帰っていきました。'),
  ('cb34a243-71bc-59ec-b19e-1e1088a7434a', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-21', '16:30:00', null, '通常 / 親子大会ビギナーズ部門「ふうせんをわろう」の完成とアレンジ', '家で色々なゲームを作ってきたと言って、来室早々に作品をいくつか見せてくれました。 公開した作品に「いいね」を付けてくれた人（プログラミングキッズの子？）がいたと喜んでいました。 「りょうまくんの作品51」で、クローンを作成しているにも関わらず、本体の方にコードを書いて、クローンされたときの動きを作成していなかったので、クローンと本体の違いを和先生が説明してくれました。 クローンの作成が速すぎて、クローンが動いているのではなく増殖してしまっているように見えていたところは、自分でクローン作成のタイミングに「〇秒待つ」を入れて解決することができていました。 授業後半は、使用していた音声合成の拡張機能の説明から、他の拡張機能に興味を持ったため、「ビデオモーションセンサー」のカードを使って一通り作成をしました。', null, '盛り上がり: ビデオモーションでアルゴンが太鼓をたたく様子を可愛く作ることができて、けいとくんに嬉しそうに見せていました。'),
  ('424569e7-364c-5907-b2d2-8cdbbe2fd417', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-20', '17:30:00', null, '通常 / 教室について説明、基本操作コースのはじめから', '来室時は少し緊張が見られ、口数もかなり少なかったですが、16時半の男子メンバーの歓迎ぶりに、少しずつしゃべるようになっていきました。 こちらの問いかけや雑談のふりにも、はじめのうちは単語でぽつぽつと返してくる程度でしえたが、授業の終わりの方にはだいぶしゃべってくれるようになりました。 タイピングもプログラミングもほとんどわからない、ということだったので、ファイルの表を見せ、少しずつ色々なスキルを勉強していこうと促しました。 基本操作コース02は、完成形を見せてから言葉で細分化する感じで進めていきました。一つ一つのブロックが新鮮だったようで、特に画像効果（ここは面白がったので、色だけではなく他の効果も試しました）や座標で動かすのが楽しかったようでした。 キーで動かす学習の際、ピストルとライフルに対し、それぞれ別のキーを押したら発射音が鳴るようにして、その後メッセージを使って弾が動くように作成したのを、とても面白がっていて、今後色々なゲームが作れるようになることを実感できたようでした。', null, 'タイピング: 苦手と言っていたので、覚えるのはゆっくりで構わないから、打つ指を意識していこうと促して、ホームポジションとFとJを覚えてもらい、AIUEOまでを学習しました。 指を置く位置が決まっていることに感心していました。
盛り上がり: はじめのうちは、1つ1つのスキルをさせられている感が強めでしたが、最後に弾丸を発射しているような動きを作成できたことで、学習してきた複数の要素がつながり、感動したようでした。（目がキラキラしていました！） お母さんにも、楽しかったと報告していました。
備考: 他の習い事ではサッカーをしているそうです。ゲームはマイクラなどのクリエイティブ系が好きだそうです。'),
  ('f64fe7e3-6b0a-5501-985a-f259e8e4af2d', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-20', '16:30:00', null, '通常 / 親子大会オリジナル作品 野球のバッティングトレーニングゲームの続き', '前回作成していた内容だと、マウンドからキャッチャーとバッターが見えている状態なのに、ピッチャーのスプライトがこちらに向けて投げてくると言って悩んでいました。 メインがバッターとのことなので、ピッチャーは敢えて表示しないで、カウントダウン後にボールが飛んでいくように提案したところ、気に入ったようだったので、ビギナーズ部門のカウントダウン部分をそのまま流用しました。 ボールが飛んでいく場所が一定だとつまらないとのことだったので、ランダムな場所に飛ばすということは、一定の範囲の中のどこかにいくということを説明し、座標を乱数で指定するやり方を教えました。乱数はなんとなく覚えていたようですが、こういう使い方をするんだ、と、興奮して聞いていました。ボールのスピードの速さも乱数でランダムにできると教えたところ、喜んで細かい数値の調整をしていました。 バットにボールが当たったという判定も、スプライトそのものではなく色で判定させることを思い出し、楽しそうに作成していました。', 'ボールがバットにあたったら、の後の作成', '盛り上がり: 自分の作品も楽しそうに作成しつつ、BGMについてりょうやくん、そうたろうくん、るいくんと盛り上がったり、新入会の楓大くんにおすすめゲームを教えたりと、授業後まで楽しそうにして帰っていきました。'),
  ('eefafd99-d933-5bb3-95ef-5d241d334f1a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-20', '16:30:00', null, '通常 / 親子大会作成', '前回はフリーサイトでの自動音声を試していましたが、作成・修正の簡単さを考えてアルスタジオの拡張機能での自動音声を勧めました。納得して採用してくれました。 そのあとは、アイテムを箱に片づける動きを作っていきました。最初は自分で作りましたがバグが出てきたので一緒に確認しました。スプライトの名前が一見してわかりづらかったので、それも間違いの原因になりうるということで簡潔な名前に変えてもらいました。コード自体は、一度アイテムを隠しても別のスクリプトでまた表示されてしまっているせいでバグっていることを伝えると修正できました。', null, '盛り上がり: アレンジ大賞から引き継いだアイデアが、キャラクター以外にもいくつかありました。'),
  ('d74696a8-17e4-5cd6-a953-ad5d3b5d1fd4', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-20', '16:30:00', null, '通常 / 親子大会オリジナル作品 なぞなぞステージ以外の全体像の計画をたてて、作成にとりかかる', '家で構成を考えてきた、と、入室するなり得意そうに発言していました。 なぞなぞ、○×クイズ、図工クイズなど、ジャンルとそれぞれのクイズを考えてきたそうで、丁寧に説明をしてくれました。 今日は、科学クイズ、○×クイズを持参した本の中から決めて紙に書きだした後、オープニング画面として、それぞれのクイズのマップを作成していました。 大会のサイトから素材をダウンロードして、アルスタジオでアップロードする方法を学習しました。', null, '盛り上がり: 問題を考えること、ステージを作ることなど、今はすべてが楽しいようで、意気揚々と説明しながら作成していました。'),
  ('89c77d46-74ad-5e29-88d6-3012f4a97826', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-20', '16:30:00', null, '通常 / ビギナーズ作品を進める', '前回はやや順調だったようですが、今回は手順書通りに一緒に進めようとしてもやりたくないと言うので、作りかけていたアレンジを完成させることを目標に進めました。(手順書の残りを飛ばしても、一応ゲームとして成立はするところまではできています。)風船と別に小さいサイコロを用意して、それを押せたら高得点が入るようにしました。風船の得点を入れるコードを見て思い出し、サイコロでも同様に作ることができました。', null, '盛り上がり: iPadで聞く音楽を色々選ぼうとしたり、スクラッチのゲームをやったりと気が散ることが多かったです。ただ最後の方はなんとか頑張りました。'),
  ('c4086bc9-9e66-5bf1-a635-d901de1e4e05', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-20', '16:30:00', null, '通常 / 親子大会作成', 'フリーBGMを初めて使ってみたかったそうなので、サイトでダウンロードする方法を伝えました。またアレンジ大賞で作った謎解きを参考にして、ドアをクリックしたら部屋を移動する仕組みを作りました。レッスン終盤で家の部屋を全部作り終わりました。しかしその後、ゲーム自体のアイデアが浮かんでいないことに気づきました。「家だけじゃなくて外の背景もいろいろ作ればいけそうだけど...」とえみちゃんが言ったので、それをしていると7月末の締め切りに間に合わないかもしれないという話をして、ペース配分を意識してもらいました。ただアイデアは思いつかないといけないので、ブレストカードを活用してもよさそうです。', null, '盛り上がり: ペースは気にしないといけないですがモチベーション自体はあり、脱線せず作成しています。'),
  ('7de29daf-21ab-5fc5-b1ad-761666ac1490', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-15', null, null, '通常 / 親子大会準備', '自分で家で作ってきたおいかけっこのプログラムを見せてもらいました。またそこに背景を変更したり、スプライトを追加したりしていろいろと試そうとしていましたが、どれもしっくりこなかったようです。大会に出すにあたり、ストーリーの重要性を説明しましたが、ピンとこなかったようなので、実際に去年の受賞作品を見てもらいました。 ゲームの核の部分は出来ているので、ストーリーをまとめていきたいです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('b5073c43-1143-576a-aef7-5ef1e94642f3', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-15', null, null, '通常 / 親子大会準備', 'スプライトの追加をしました。またクイズで出題する問題を一緒に話しながら考えました。作品の中でテーマを統一するため、食に関するクイズを出題するそうです。パッションフルーツの話になり、クイズに取り入れることになりました！！ 最後にうまくスプライトがでてこないバグが起きましたが、リストと制御の部分を見直して解決しました。次回以降、質問を増やしていく予定です！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('39fd6a11-98be-58ee-9322-d007d902c3d5', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-18', null, null, '通常 / 親子大会準備', 'ひよこのジャンプのプログラムはできていたのですが、全体のストーリーや今後の展開に悩んでいるようだったので、アイデアカードを一緒に引いて今後の方針を立てつつ、プログラムをしました。アイデアがでるまでかなり時間がかかりましたが、プログラムをしたり考えたりして前に進んでいる様子でした。クリックするとその部分が表示されるような仕組みを使ってストーリーを作っていくそうです。', null, '時間帯: その他'),
  ('1978b2a1-b76b-5f57-b4a1-a7b8c20f7914', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-15', null, null, '通常 / RPG系のゲームの自主制作', '「スキルが上がって前できなかったことが出来るようになった」という言葉が効いたみたいで、Unityではなくゲームを作ることになりました。 RPG風のコマンドゲームをイメージしていたようです。キャラクターのスプライトにもこだわり、うまく武器を持てていました。主人公が草に当たり、スライムに出会う場面まで作れていました。次回は戦闘部分のプログラムに入るのかな？と思います。楽しそうでした！', null, '時間帯: その他'),
  ('3b9dbbbd-2dae-52b7-a2cd-fc3b8f9b7201', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-15', null, null, '通常 / 親子大会準備（アレンジ部門）', '手順書を見て流れを確認しながらプログラムをひとつずつ進めました。進めつつも、少しずつアレンジを加えました。最初のカウントダウンの部分にエラーがありますが、本人が後で直すとのことだったのであえてそのままにしてあります。手順書にある部分は全てプログラムしました。 ＜アレンジしたポイント＞ ①スイカが移動中にサイズが変わるようになっています（条件分岐の考え方は伝えましたが、3種類に増やしてもしっかり理解できていました） ②スイカのコスチュームの番号によって入る点数が違います。コスチュームは3種類あります（見本は2種だったと思うのですが増やしました） また、やりたいことがたくさんあり、紙に書いてきてくれた＆一生懸命説明してくれたので、聞き取りした内容を次回の予定にメモしておきます！今後の参考にしてください。とても楽しく取り組めていたと思います。', '＜やりたいこと＞ ①スイカの代わりに、神話柄と八王子柄のクッキーにする。八王子のクッキー（全3種を予定）だと加点。神話柄は原点。 ②「はち王子」（スプライトは自分で書く）がスイカを割る人として画面左側に登場（上下キーで動いて針を飛ばす）。クリア（条件不明）したときに大きくなって光る。一度に飛ばす針の数が点数によって変わるかも。', '時間帯: その他
盛り上がり: めちゃめちゃ賞金狙ってました。'),
  ('9c4a1bf0-c590-590a-8df4-f918d2289e18', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-18', '17:30:00', null, '通常 / カエルゲーム続き（演算と制御を整理）→タコのゲーム 文章を少しずつ読めるうようになるといいな', '前回のプログラムをパワーアップさせ、虫を食べるときにスコアが変化するようにしました。文章を自分で読んでプログラムするのはまだできず、こちらが誘導すると手を動かせるようでした。基本的な考え方は分かってプログラムしている様子でした。点数が入るタイミングを限定するときに「かつ」を使い、演算と制御の考え方を共有しました。 後半はタコのゲームを作りました。前回プレイしたときに変数の使い方に気づけられていたので、まず大きな作品の流れと変数の使われ方を追って説明しました。7割くらい理解できている様子でした。ただ、自分でアレンジをしたかったみたいで、作ることを伝えると少し嫌そう？おっくうそう？でした。ボタンを押すプログラムまで完成しました！', null, 'タイピング: 取り組めました。'),
  ('0a195508-85a6-5ea5-b418-c6b081abcaa5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-18', '16:30:00', null, '通常 / 親子大会準備スタート', 'コンセプトやゲーム内容が決まっていなかったので、ブレストカードを使って一緒に考えました。考えられるか心配でしたが、たいまつと壁から想像を膨らませられました。部屋が暗くなっていろいろなものが出てくるホラーゲームになりました。暗くなった直後のギミック、いくつかのホラー要素は出来ましたが、まだまだ内容を増やしたいので考えてくるようにお願いしました。最後は夢だった夢オチエンディングです。', null, null),
  ('61cec945-0713-53b2-9cc3-aab59b49e396', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-18', '16:30:00', null, '通常 / 親子大会準備 締め切り意識をもつ', '本人的にも時間が厳しいことが把握できていました。目を開けるプログラムがほぼ終わったので、幽霊とおいかけっこをするステージを作成しました。他のScratchの作品を例にだして、自分が作りたいものを説明してくれました。今日はスプライトの動きのプログラムの前に、ステージを作成しました。切り替えをコスチュームでやることを提案し、ステージをデザインしていきました。三角形の出っ張りの作り方を共有しました。 無限にステージを作るわけにはいかないので、そろそろスプライトを動かし始めたいです。', null, null),
  ('89d4df96-538f-599b-a5d8-9d3609392667', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-17', '17:30:00', null, '通常 / 親子大会づくり', '脱出ゲームで残っていたバグを直していきました。岩から避けるゲームで1度当たっても石が動き続けるバグがあり、それは自力で治したが、こんどは、コンティニューした際に、医師のクローンの2倍になって出現することです。似たようなバグとして、去年かおととしくらいのはるちゃんの親子大会の作品で、ウミガメの二酸化炭素が繰り返すたびに増殖していくバグと同等なものでした。当時は解決できずに、終わった気がします。子のバグを解析しましたが、「メッセージ」と「クローム削除」と「このほかのスプリクトを止める」コードが相性が悪くことくらいしかわかりませんでした。1度止めたとしても、メッセージが重複して送られているがそこが治せません。このバグは保留となりました。', null, '盛り上がり: 本人的には一層違うものを入れ替えることも考えてらしい'),
  ('fc8a16b3-1866-543e-81b9-98b19c5898b1', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-17', '17:30:00', null, '通常 / 検定2級の問題にチャレンジする', '検定は相変わらずやる気で、授業開始後すぐに取りかかりました。 途中で「もうわからない」とぼやきだしたので様子を見たところ、これまで習っていない文字列の連結だったため、ここだけは今回初めてということで、使用するブロックを教えました。 その後は自力で進めることができ、10分前にアレンジを除いて終了していました。 「大きさが〇ずつ減る」「幽霊効果が10ずつ減る」というのを、いずれも「10ずつ変える」にしていました。問題に直接「-10ずつ変える」と書いてあるとは限らないため、文章の語尾までしっかりと読んで、自分で＋－を判断して作成するよう注意することを伝え、本人も納得していました。', null, '盛り上がり: 本を読むのが好きだそうで、問題文を読むのもつらくない、と得意げに語ってくれました。 ミスはあったものの、全体的には理解して解けたそうで、検定に対するやる気や自信が見えていました。'),
  ('72ba6871-4365-50dc-9593-67e4a069d7ff', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-17', '16:30:00', null, '通常 / オリジナル', 'ゆうさくくんと同様に花子さんゲームを作っていきました。がくくんは、ある程度自分でコードを持ってくることはできますが、手札が少ないので、少し思い通りにいってないです。そして、複数のイラストを１つのスプライト内に描く癖があるので、あとからコードを組む際に、非常にやりづらいです。イラストも少し雑です。岳君も基本操作コースでコードの手札を増やしてあげた方がいいです。 コンテスト作品として、ビギナーズ部門のものも作るのもいいが、あれは以外にも作るのが長いので集中力の観点からも少し微妙です。', null, 'タイピング: キーが勇作君よりかはちゃんと打てています。日本語としても打ててます
盛り上がり: ゆうさくくんの作った作品に素直に楽しんでいました。 性格的には、やりたいことは多いが能力が追い付いてなく少し止まるタイプ'),
  ('bb1a9cb7-2c70-5cb7-b960-b69785c35c61', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-17', '17:30:00', null, '通常 / Scratchの上級スキルを使った作成をする～引数のある定義', '今日もScratchをやりたいとのことだったので、びんごおじさんの最近の作品から、引数のある定義を活用した作品を作ることを勧めました。ひいろくんの好きな鉄道のゲームだったせいか、一生懸命取り組んでいました。鉄道の走る音を自分で取り込んできて採用するなど、こだわりのアレンジもしているようでした。 定義のところはあまり迷わずに理解できたようでしたが、操作盤上のボタンのクローン作成が、緑の旗を押してもうまくいきませんでした。コード上でスクリプトをクリックすると動くのが謎でした。 コード上に、変数を「１にする」「1ずつ変える」の間違いがあったのと、y座標の正負が間違っているところがあったため、そこは修正しましたが、ゲーム上のバグは残ったままでした。', null, '盛り上がり: 鉄道に関する課題だったせいか、熱心に取り組む姿勢が見られました。'),
  ('e276365a-4bf2-5a96-9a1d-c46a6b9fa55f', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-17', '16:30:00', null, '通常 / 花子さんゲーム', '前回作りたかった花子さんゲームを作りました。前回、扉を多く用意してくれたので、歴は短いので、難しいコードを使わずに作っていきました。具体的には、等式の条件に乱数をいれ、＝で成り立つようにして、確率的に出てくるようにしました。算数の計算で＝は出てくるので、なじみの理解は良かったです。 ただ、イラストをぐちゃぐちゃに書いて、訳が分からない所まで来て、満足するので、見栄えとしては低いです。それよりかは基本操作コースでコードを作る魅力を気づかせてあげる方がいいかもしれもません', null, 'タイピング: アルファベットを確認せずに、ガチャガチャたたくので、今の段階では教養はさせなくてもいいかも
盛り上がり: 人前でトイレに行くことがまだ苦手かもしれません、がくくんとまみさんが一緒についっていてあげて、もれそうな状態から行けたので。 性格的にはわからなくてもとりあえず進んじゃうタイプ飽きも出る'),
  ('6f4ab3e2-3583-555c-affc-5cb52b877245', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-17', '16:30:00', null, '通常 / 親子大会のオリジナル作品を作成する', '家で画像をうまく取り込めなかったとのことなので、教室で背景を透過した絵を用意し、自分でアップロードさせました。 元の絵に自分で色を塗りたいとのことだったので、iPadの写真アプリの編集で、蛍光ペンを使って色塗りをしてもらいました。細かいところは画面を拡大して塗ったり、はみ出たところを消しゴムで消したりと、デジタルツールならではの色塗りが楽しかったようで、こんなやり方ができるのかー、と、感心しながら作業していました。 色塗りだけに没頭しすぎず、キリの良いところで完成とし、しっかりとコード作成に戻れたのは、さすがヒロト君という感じでした。 自分のやりたい機織りの動きが一通りできたようで、次回からはこの動作の繰り返しを作成していく、と、計画通りに進められているようでした。', null, '盛り上がり: 機織りの絵に自分で色付けをしたことで、作品により愛着がわいたようでした。 1時間しっかりと集中して作成できていました。'),
  ('dad58559-f065-5f7d-974d-e848493e2a22', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-13', '16:30:00', null, '通常 / 親子大会作品の作成 リストを使いこなす、ゲームのオリジナル性や面白さを追求する', '家でなぞなぞをぎっしり紙に書いてきていて、やる気モードが復活したようでした。 リストの学習が一通り済んだので、実際の作品の作成に入りました。 問題と答えの他、どうしてそうなるのか解説を入れることを思いつき、盛り上がって作成していました。 なぞなぞステージがだいぶできてきたので、他のステージをどうするか、オープニングなど全体の流れをどうするか考えておく、と嬉しそうに帰っていきました。', null, '盛り上がり: なぞなぞゲームのスケールが大きくなってきたせいか、やりがいを感じているようで、終始生き生きと作成していました。'),
  ('912582a7-c404-58de-baba-1f70caf23138', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-10', '17:30:00', null, '通常 / 検定問題3級応用課題2 初めてみるタイプのゲーム作成がスムーズにできるかどうかを確認', '検定問題は楽しいようで、積極的に取り組んでいます。 完成した後、動きがおかしいということで一緒に答え合わせをしたところ、x座標が135より大きくなるまで繰り返すを「x座標=135<x座標」と書いていました。 演算式の書き方を説明したところ、納得していました。', '次回2級の応用課題1', '盛り上がり: 初めてみるタイプの問題でも、大体解けたのが自信になったようでした。 2級にチャレンジしたいと前向きになっていました。'),
  ('63329de9-b21c-5379-ab97-37fb42db26c2', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-16', null, null, '通常 / 親子大会の製作', '原子を組み合わせて分子を作るパズルを考えているそうで、ゲームに入れたい分子の一覧を紙に書いてきてくれました。「使う原子の数ごとにレベルを分ける」「しばらく経って解けなければだんだんヒントを出す」などアイデアを話してくれ、細分化は頭の中である程度できていそうでした。まずはスプライトとして、原子とそれを入れていく枠を作りました。種類が多いので時間がかかりましたが、スプライトはほぼできたので次回からコード作成に入れそうです。', null, '時間帯: その他
タイピング: 腕試しを頑張っていました。
盛り上がり: 兄弟ともに入賞を狙ってモチベーションが高いです。'),
  ('985f5cef-16d7-5b6d-a986-914d440e558d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-15', null, null, '通常 / Excel練習', 'ほぼ順調に進めていました。基本的な関数もでてきましたが、理解に困ったわけではないようでした。説明の意味を間違えて解釈してしまったところが一か所ありましたが、先生に質問して、教材を一緒に見て解決しました。', null, '時間帯: その他'),
  ('2aadc6b4-6184-50ef-87ef-27d42a6778ca', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-15', null, null, '通常 / ゲームの完成を目指す', '最初に改めて今日の流れを確認すると、すぐにインベーダーゲームの作成に気持ちが入り、てきぱきと作っていきました。写経で作りましたが、コードの読み落としやスプライトの取り違えがたまにあったので「この後の部分はなんて書いてある？」などと問いかけると気づきました。途中でクローンが出てきましたが、自分と同じものを複製していることを知っていました。全体的に、自分のできる限り手順書をよく見て作ることができました。', null, '時間帯: その他
盛り上がり: 水を飲みに行ったときに一瞬脱線しかけましたが、30分頑張ろうという目標をもう一度強調すると戻ってくることができました。'),
  ('ad4434b9-c50a-5284-8353-d5e0881fa765', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-15', null, null, '通常 / 検定練習', '「今までの検定練習はだいたいできていたから、今日は問題設定が特殊で難しいのをやってみるから頑張ってね」と声をかけてから解いてもらいました。実際に苦戦したようで、一通り作るのは終わったものの、テストプレイでバグが見つかり、修正に難航していました。バグの場所がわかるから答え合わせをしようという提案もしましたが、もう少し粘りたいそうでレッスンの最後までやっていました。最終的には、答え合わせはできませんでしたがテストプレイは正常に動いたそうです。しかし今までが順調だっただけに落差にショックを受けたのか、ゆき先生に不安な気持ちを話していました。', '答え合わせから(満点を取れなくても合格はできるという精神的なフォローや、バグったときの確かめ方など技術的なフォローを合わせて)', '時間帯: その他
盛り上がり: 授業開始前、U16の作品を作りこんでいてハイレベルでした。'),
  ('37ab5126-d298-51ee-ac35-98307e2b3426', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-15', null, null, '通常 / 親子大会の製作', 'ストーリーの流れは前回でイメージできたようなので今回は動き部分の製作を進めました。以前使ったクローンを思い出し、自力でビーム発射が作れていました。プレイヤーや敵のそのほかの動きは基本的なものだったのでそれも問題なくできました。', null, '時間帯: その他
盛り上がり: あおしくんの横にいるとき先生のパソコンであおしくんの作品を見てみたり、大会ポスターを再び見せてみたりと時々絡んであげました。そのおかげもあったのか、あまり脱線せずに製作を続けられました。'),
  ('7edb361f-53ec-5ba7-9d05-26fd624b6f60', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-06-14', '18:40:00', null, '通常 / 大会オリジナル作品の作成', '作ろうとしているものは、あるようだが。あまり説明してくれず(T_T) 作品のテーマなども特にないようで、ただ作っている感じが気になります。 最近、モチベーションが下がっているので、何か目標ができるといいのですが。少し模索しましょう。 実は、アレンジ大賞の結果にすごい期待していたらしく。結果発表をお母さんから聞いていなかったとのことで、ボードの貼り紙をみてショックを受けていました。逆に、期待していたのが意外だったので、何らかの闘志はありそうです。 お迎えのお母さんに、「スキル的には難しいことができているので、アレンジ大賞も親子大会も、作品の構成とストーリーをもっと考えられると上位入賞も狙える」と伝えました。 検定を進めていくのが良いかもしれません。', null, null),
  ('48a146a7-d301-5632-80f9-9920808b87b0', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-06-14', '17:30:00', null, '通常 / 大会ビギナーの作品をつくる', '集中力がなく、、、、トホホです。先週と今日で２回、ビギナーコースのふうせん割りをつくろうと、画面を開くがほぼ進まず、、、、。 中島なので、校長対応として「全然進んでない」状況を認識してもらうため、見本コードと見比べてもらいました。「タイピングと大会と、どちらかにするか？」選択肢を与えたところ、「両方がんばりたい」というセリフだったので,大会作品を引き続き作ることに。 両方お迎えの際に、お母様と相談。本人交えて３人で話をしました。 ・次回から残り３回しかないから、しっかり集中すること ・お母さんの母校が決勝大会の会場だから、お母さんがあそこに連れてって欲しいなと ・残り回数が少ないので、タイピングとアルファベットの練習は自宅で、 という話になりました。 次回、集中力切らしたら、〆切まで回数が少ないこととお母さんとの約束の話をしてください。', null, 'タイピング: 最近、タイピングにハマっています。アルファベットの１文字とキーボードの位置がわかってきているので。徐々に、短い単語にステップアップできるといいなと思います。 自宅で、紙のドリルでアルファベットを練習するといいと思いますとお母さんにお伝えしました。'),
  ('8de830aa-2c45-5bab-8888-46893e2813fb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-10', '17:30:00', null, '通常 / IT部とU16大会の書類を見てもらってから、本人の希望によりScratchかMonaca', 'U16大会については、わりとあっさり「やらない」とのことだったので、新しい資料をもとに、IT部の話をしました。探検隊は、やってることは少し面白そうだけど、今回の水テーマはあまり…という感じでした。ゆくゆく八王子のいろいろなところに広げたい、という話を少ししたら、高尾山やケーブルカーの話で反応してきて、そういうところにからめるのならやってみたい、とのことでした。ゆくゆくのためにIT部をやっておくのも納得はしているようで、一応チラシを持って帰って親御さんに渡してみる、とのことでした。 今日はScratchで何か新しいことに取り組んでみたいとのことだったので、見た目が新鮮だろうとシューティングゲーム「火星防衛軍Nodack」を提案しました。 ゲームをプレイしてから、敵スプライトのメインコードを考えて作成してもらい、続けてステージが進むにつれて難しくなるアレンジをしてもらいました。 結構熱心に取り組んでいて、ステージ番号の変数を活用した敵スプライトの動きの速さの設定をしていました。', null, '盛り上がり: 新しいゲームのアレンジは楽しかったようで、実際にプレイして見せてくれながら、作成したコードの説明を熱心にしてくれました。'),
  ('744b0874-a9ce-5a40-a99c-6dbeb3e9a093', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-10', '16:30:00', null, '通常 / 基本操作コース06の7、8 （見本では8、9）の完成版を見せてから 他のスプライトや背景の動きをきっかけに動かす方法を学習していることを理解させる 上記が終わったら、アルスタジオレッスン/サメからにげろ', 'プレイグラムのプログラム体験ゲームがとても楽しかったようで、はじめのうちは、こういうのがやりたかった、と集中して進めていました。同じ流れでHour of Codeのドラゴンブレストも大喜びで進めていましたが、途中でふと、自分のアイディアの通りにカスタマイズできないことに気付き、やっぱりScratchをやる、と自分から戻ってきました。 ふうせんをわろうも繰り返しプレイをしていましたが、話の流れでオリジナルの花子さんゲームを作りたい、となり、勇作君と自分のアイディアを披露しあいながら、盛り上がって作成をしていました。', null, 'タイピング: たまたま触れたプレイグラムのプログラミング体験版にすっかり気をとられ、タイピングはほぼできませんでした。
盛り上がり: どの教材も、基本的にはニコニコと楽しそうに取り組んでいましたが、やはり自分のアイディアが形にできる花子さんゲームに一番盛り上がっていたように見えました。'),
  ('32dbb16a-ac6b-5438-95e5-9603522a4fa1', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-10', '16:30:00', null, '通常 / 基本スキルの獲得、前回のおさらいをしてから「サメからにげろ」の完成', '前半は、岳くんが開いてしまって「これだけクリアしたい」とやっていたプレイグラムの体験版が気になって仕方なく、同じゲームが開けないことにかなりへそを曲げていました。 体験版のように、ステージクリア型のプログラミングがやりたいと言い張り、Hour of Codeをそれなりに一生懸命やっていましたが、途中で好きなようにカスタマイズできないことが面白くないと気づいたようで、雑談の流れで花子さんゲームを作ってみたい、となりました。 そこからはやりたいことが見えてきたせいか、一気にやる気モードになり、熱心にゲームの仕様を考えながら作成をしていました。', '花子さんゲーム続き', 'タイピング: タイピングを始めてすぐに、たまたま岳くんが触れてしまったプレイグラムのプログラミング体験版に気がうつってしまい、ほとんどできませんでした
盛り上がり: 授業の後半は、どんな花子さんゲームにするか、岳くんとアイディアを披露し合いながら、楽しそうに作成をしていました。'),
  ('06b47c2c-efde-5fb7-9005-61e2d8acd914', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '18:40:00', null, '通常', 'U16大会に向けて、スマブラのゲームをアレンジしていくことに決めました。そのままの使用は著作権に引っかかると思うので、キャラ、すてーーじの変更をお願いしました。ステージの作り方のも着地の判定を崩さずに治せていたので良かったです。また、勝敗判定がすぐ落ちてしまうことはメッセージをはさんで、その判定を遅らせる提案をしてあげました。この大会は、書類審査なので、何を思って作ったのかその理由背景を固められるといいですね。', null, '盛り上がり: 景品二とて主悩ませていました。'),
  ('9d0946e9-7f46-50e3-936e-7c5b9d922110', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '17:30:00', null, '通常 / 親子大会の作品作り', '着々とオープニングを作り上げていきましたが、一部、予期せずしないタイミングで消えていきバグが発生していました。その際、原因を起こしているコードまでは把握できていましたが、その修正方法がわからず、作業が終わってしまいました。なので、次回はそこを見てくれると助かります', null, '盛り上がり: おなかに挟む人形を持って帰っていきました'),
  ('ce26a351-9a96-5974-aa9e-e218c7c1396b', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '17:30:00', null, '通常 / 図形の作図＆花火の作成', '図形をコードを使って描くことは前にやったことをかすかに覚えてもらったので、服してもらいした。正方形、円はすぐに書けましたが、正三角形は上手くできず悩ませていました。こちらから法則性について、ヒントを与えると、ひらめきで答えることできました。 花火大会を開こうの者では、ペンの使い方や先ほどの幾何学的図形を作ることにはまっていたので、それを組み合わせたダイナミック物を作れていました。', null, '盛り上がり: らーめんげっと'),
  ('a7b795d6-3e55-521b-b866-09da5003fd32', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '17:30:00', null, '通常 / 親子大会作品づくり', '親子大会にむけたアイデアがなかなか思いつきそうになかったので、ビギナーズ部門の作品の方に制作に取り掛かりました。ゆづきくんはある程度はできるので説明書を見ずに、細分化をしながら進めていきました。最初のスタートの仕組みを順調に作れていましたが。風船(ボール)の仕組みはなかなか形で来ていませんでした。一緒に、方針を立ててやりました。乱数の範囲の決め方やまで繰り返すの使い方は、こちらが誘導していけば、使い方に気づく程度です。', 'ふうせんわりのつづき', 'タイピング: お得までまだ及ばずでした
盛り上がり: アレンジ大賞優勝おめどと'),
  ('5ff82da7-2a05-579b-b675-62cd401521c8', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '16:30:00', null, '通常 / ビギナーズ部門の作品を作ろう', '最初に、自分でゾンビを倒せ風のゲームを作っていました。常に上下を動かす仕組みがわかららず、そこ向きの固定の仕方をおしえたくらいで、ほかの当たり判定や点数などは自らできていてびっくりしました。そこで、親子大会のビギナーズ部門も作れてると思い、作成しました。とてつもなく順調に進んでいき、完成の7割くらいまで制作できました。なので、次週からアレンジを作れると思います。', '学年の割りにスキルが高いので、ある程度のものはサクサク作れます。一方で、じっくり深めることがなく、次々次々と作品を作っていくのが気になっており。お迎えの時にお母さんと話をしました。今回、大会の決勝進出を目指さないか？と。そのスキルがあるので、次は構想力。全体でストリーやテーマを考えていこうね、という方向になりました。', null),
  ('375376e8-d528-5420-ac8f-b53cfd2cf510', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '16:30:00', null, '通常 / 親子大会作品づくり', '今回はRPG風ゲームさくせいするために、主に主人公のイラストを描いてついていきました。背景の切り替えを縦スクロールのようにしたいそうでしたが、過去の小技がみてほしいでしたが、うまくできずに終わってしまいました。次回は、そこの支えをしてもらいたいです。', null, 'タイピング: よくできていました
盛り上がり: とらくんのイラストのコラージュの仕方を面白かっっていました。'),
  ('9be48627-3519-52b2-9048-f44121d57b68', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-14', '16:30:00', null, '通常 / U１６大会へ向けて作品作り', '作品制作に向けて、アイデアをひねらしていました。学校の夏休みの宿題で、八王子の移籍に関してまとめるレポートがあるみたいで、それを活用して、にゃんこ大戦争みたいなゲーム形式を作りたいそうです。ただ、形にしてコードを組んでみようとしても、全体像に引っ張られすぎて、手が進みませんでした。次回からは参考しているものからコードを読み解くことも必要だと感じます。この作業が若干本人がめんどくさがっているので、', null, null),
  ('5b966b1c-8e53-57e9-a86f-7bd27b11ef16', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-13', '17:30:00', null, '通常 / 中学生大会作品作成', '検定問題の続きをやることも視野に入れていましたが、集中できそうだったのでU16大会の作成を続けてもらいました。テトリスのステージに関しては、外部に出すものだから著作権には気を配ってねと伝えました。ただ、マス目のスプライトを自分で作って配置したりペンで描こうとしたりと試行錯誤して大変そうだったので、タイルのフリー素材イラストを提案し、それでうまくいきました。テトリミノのスプライトやスコア変数など必要不可欠な準備はだいたい終わり、来週から本格的なコード作成に入れそうです。', null, 'タイピング: ブランクから再び腕が慣れてきてスコアが伸びたようでした'),
  ('edbdc448-cade-53f0-9708-d03d3b06b390', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '18:40:00', null, '通常 / アレンジ大賞作品の評価', '最初に提示したアレンジ大賞の評価は、こちらの予想以上にのってきませんでした。 ゲームのプレイ自体が難しかったのか、数作品をプレイして完全につまらなそうな様子になってしまったため、ビギナーズ部門の作品作成に切り替えました。 もともと何かを作ることが好きなようで、こちらにはすぐにのってきて、機嫌もなおり、集中して作成に取り組むことができました。 スプライトの色にもこだわり、丁寧にスポイトを使ってコスチュームの編集をしていました。 ふうせんのかわりにじゃんけんのスプライトを使い、そこにレアキャラとしてキャシーのコスチュームを混ぜて、大うけしていました。', '軽く乱数の復習をしてから、作成の続き', '盛り上がり: 前半のアレンジ大賞評価と後半の作成ではまったく態度が違っていました。とにかく、今は作っているのが楽しいようでした。 乱数の意味はまだ理解しきれていないと思われますが、一定の確率でレアキャラを出せる面白い機能、と思ったようで、乱数を色々変えて楽しそうにしていました。'),
  ('b2837b81-3979-548a-81f1-7cccdd035bb6', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '18:40:00', null, '通常 / U16大会の紹介、やる気があれば計画、イマイチならprg？', '今回のアレンジ大賞で少し自信がついたのか、以前ほど大会や試験の結果を悲観してしり込みすることもなく、U16大会にもチャレンジしてみたい、と、わりと即断でした。 アレンジ大賞のスマブラをもっと改良するか、他の作品にするか、しばらく自分の作品をいじって考えているようでした。 自分の作品や、Scratchで探したゲームをかなりたくさん参照していて、次回から作成に入ろうかな、とのことでした。', null, '盛り上がり: 大会などに関してはこれまで悲観的な発言が多かったみずきくんが、前向きな姿勢を見せてくれました。気持ちの部分ももちろんですが、やりたいことにスキルが追い付いてきたのか、ゲームやコードをいじるとき、終始楽しそうにしていました。'),
  ('5ba8f0e0-a077-598f-b0c0-a584875138f8', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '18:40:00', null, '通常 / Excel学習 またはU16大会へのチャンレジ', 'U16大会の説明をしたところ、チャレンジしてみたいとのことだったので、こちらを進めることになりました。 過去の大会の資料などを熱心に見て、構想を練っていました。', null, null),
  ('418cb5e1-bbe3-5d32-a8aa-5f925254613c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '17:30:00', null, '通常 / アレンジ大賞作品の評価 他の人が作った作品を楽しんで遊び、自分なりの評価をする', 'アレンジ大賞の評価は、こちらの想像以上にはやく、30分ほどで終えていました。 タイピングをやりたがったり、自主休憩7分くらいを申請してきたりはしましたが、ふうせんをわろうを作成する気にはなったようで、スプライトを選び始めたところで終了しました。', null, 'タイピング: タイピングにとにかくはまっているようで、授業中も少し目をはなすとタイピングをしていました。
盛り上がり: ゲームを作成する気にはなっていて、楽しそうに取りかかりはするのですが、そのときのやる気が細切れにしか続かず、トータルでの進捗度はほとんど進んでいませんでした…が、タイピングを熱心にやり、新しい作品にも取り掛かったということで、本人としては充実していたようでした。'),
  ('cbf9a52e-fdb1-5a0a-ad7a-aaef4c035d1e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '17:30:00', null, '通常 / 親子大会の説明、作品の計画', 'アレンジ大賞が終わって少し気が抜けたのか、評価したときのテンションが残っているのか、どちらかというと気持ちが上ずり気味でした。 コンテストの説明はしっかりと聞いてくれましたが、けいとくんのやっていることに気を取られがちで、カニカニハンマーのブラッシュアップやふうせんをわろうの作成など、こちらの提案にも乗りかけては他に目移りしてしまう、という感じでした。', 'コンテストに向けて何をしていくか、はっきり決められなかったので、一度気持ちをリセットして課題を決め直すと良いかと思います。', 'タイピング: 久しぶりだからとすすめてみましたが、けいとくんと一緒に「やらなーい」という感じでした
盛り上がり: けいとくんのゲームを見てアドバイスしたりと、終始楽しそうではありました。'),
  ('9ea9c49d-fbce-525a-bf86-a19db6a1c5a0', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-13', '16:30:00', null, '通常 / 大会作品作成', '自動音声によるアナウンスを考えているようで試していました。 ゲーム本体のほうは、一つのステージとして「引っ越し作業のアルバイト」を作ると話してくれ頭の中で細分化はある程度できているようでした。箱やぬいぐるみなどのスプライトを自分で編集して作ったり、最初のほうの流れをコードで作ったりしていました。', null, '盛り上がり: 前回のアレンジ大賞で作ったキャラがお気に入りになったそうでここでも使っていました。'),
  ('971bac63-2fba-5954-abb1-412026b4f622', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-13', '17:30:00', null, '通常 / 親子大会作品の作成 著作権を意識させると同時に、オリジナリティをアピールするためのキャラクターやステージの見直しを。それができたら、オリジナル部門のテーマに沿うようなストーリーを決めて、うまくゲームに取り入れるように促して。', 'アイデアをだすところから始めました。かなり悩んでいたのでブレストカードを使いました。飴をもった男の子と犬を組み合わせることで、「犬が出した問題に正解させることで画面上に食べ物（スイーツ？）を出し、最後にそれを男の子に届ける」テーマになりました。 リストを作って出題と正誤判定をするプログラムを作りました。プログラムの仕組みについては細かく一緒に確認しました。もんだい番号が１番目のときに、シュークリームが出現するようなプログラムが完成しました。次回は問題を作成、スプライトを増やしていきます！', null, 'タイピング: 集中して取り組めました。
盛り上がり: 次回以降楽しみなようです！よかった！'),
  ('07182304-4d8b-5d08-8e2b-dc0f1cd2dad8', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-13', '16:30:00', null, '通常 / 親子大会作品の作成 先週の続きでキャラクターの決定から。素材にこだわって時間をかけて探しているようなので、締め切りを意識させて少しペースを上げた方がよいかも。', 'ボタンで背景をコントロールできるようにしました。アレンジ大賞で作った作品を参考にプログラムを作りました。現在の背景と移動先の背景の両方を指定することで、いってほしくない背景をうまく隠すことができました。 スプライト選びも難航していましたが、アルスパークにあるものを使うことで落ち着いたようです。クリックする箇所も作成を始めました。', null, 'タイピング: 集中して取り組めていました'),
  ('29ade629-4d13-572d-b86c-8c85d0a65bd9', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-13', '16:30:00', null, '通常 / 親子大会ビギナーズ部門「ふうせんをわろう」 前回の続きから できれば今日完成させてアレンジに入ろうと声掛けを。', '集中して取り組めました。前回やったところからスムーズに取り組めました。本人は「できない、分からない」とよく言っていましたが、紙で作り方を確認しながらだと自分で進められていました。途中コスチュームを変えるプログラムを場合分けで乱数を使いましたが、すごろくを交えて説明するとなんとなく役割を理解できていました。 点数が入るところまで進めました！次回続きです。', null, null),
  ('b9349e5e-321a-594e-895f-917f87eccfd6', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-13', '16:30:00', null, '通常 / 大会作品作成', '前回までで野球のトレーニングをゲームを作りたいとのことでしたが、改めてその中でもバッティングに特化したゲームにしたいとのことで方向性を少し変えました。作成の手順や方法に迷ったようだったので、紙に書きながらキャラクターの動きを細分化してもらいました。旗を押した後の流れをつかめてきて、コスチュームの変更やメッセージを使って最初の方のコードを作ることができました。', null, '盛り上がり: レッスン終了後、りょうやくんの作っている作品を面白そうに横で見ていました。いい刺激になったかもしれません。'),
  ('16bd6e41-fd27-5f86-8ca4-85feb35e7e88', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-11', '17:30:00', null, '通常 / 演習でスキルアップを目指す（変数と演算）', '10秒間のクリック回数を数えるプログラムを作成しました。あまり自分で文章が読めないようなので最初は大変そうでしたが、一緒に文章を確認してうながすと考えてプログラムが出来ていました！タイマーはあまり使ったことがなさそうでしたが、なんとなく理解できたようです。 G3のカエルのアニメーションも文字が多くて面食らっていましたが、読んでかみ砕いて説明するときちんと理解できた様子でした。文章とプログラムがあまりリンクしていないのかもしれないです。 最後にタコのゲームで遊びました。難易度変化の方法を考えてもらうと、「変数」との返答でした！興味があって少し作ってみたいそうです。', null, 'タイピング: 少しミス率が高かったですが、集中して取り組めました。'),
  ('501b3249-af19-564a-a2b9-3c3d6bc6635e', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-11', '16:30:00', null, '通常 / 親子プログラミング大会の準備', '楽しく取り組めました。リストを使った正誤判定のプログラムを見本を見ながら一緒に作成しました。繰り返すポイントや問題の長さなど本人が気づけているところもあり良かったです。ゲームの中心要素はほぼできたので、後半は音を付け加えたり見た目を変更したりしました。', null, '盛り上がり: さらちゃんとたくさん話せていて楽しそうでした。'),
  ('b07c8a44-cd66-5d25-924e-285d84e03517', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-11', '16:30:00', null, '通常 / 親子プログラミング大会の準備', 'まつげの動きからプログラムを始めました。少しこだわりすぎているように感じたので、大枠から作成するように勧めました。まつげの動きは納得がいくようになり、寝ている音もそれなりに満足がいく完成度になりましたが、あまり進められませんでした（本人も言っていました）来週からは締め切りを気を付けつつスピード間隔をもって進めたいです。', null, 'タイピング: 今日は少し調子が悪かったそうです。
盛り上がり: まこちゃんと楽しく話せていました！'),
  ('c8ab7115-bc65-5daf-be97-12a31a480d35', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-06', '17:30:00', null, '通常 / U16大会の計画、作成をおすすめ', '前半は受賞した作品一覧のpdfを見ながら方向性を考えました。環境問題ばかりで少しつまらない???様子でした。後半は作成をすすめました。テトリスをモチーフ？にするようで、スプライトの作成を頑張っていました。', null, 'タイピング: 集中して取り組めました。'),
  ('e799537b-9043-5277-b1dd-dcbc2b7d4a00', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-06', '16:30:00', null, '通常 / 親子大会の作品の計画、作成 一から作成するのが苦手そうなら、とりあえずビギナーズ部門の「ふうせんをわろう」を作ってアレンジさせてみる', '作り方の紙を見ながら一緒に作成を進めました。プログラムする場所に関して、比較的注意しながら進められたのでよかったです。細かいところの理解は難しそうですが、大枠はつかめていました。途中、私がいなくても自分でしっかり進められていた部分もあってよかったです。次回続きです。', null, 'タイピング: 集中して取り組めていました。'),
  ('eb31a297-9bc5-59d6-b6eb-6afb0a9ed2d3', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-10', '17:30:00', null, '振替 / ビギナーズ部門の作品を作ろう', 'タイピングに時間をかけて、休憩もはさんだことから、残り時間が少ないときから始めました。その中でも、大きさ変更の遊びに走ってしまい、今回はほぼ進むことができませんでした。コードの紙を見せれば、一瞬やる気は進むので、その手法でやっていきたいと思う。', null, 'タイピング: 20分以上かけて熱中してました。
盛り上がり: タイピングは最近落ち着いてできるようになりました。'),
  ('d52a2767-26ba-5fb7-883f-3ca0dfec6b65', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2024-06-10', '17:30:00', null, '休み（未対象）', null, null, null),
  ('23e29ebc-40ee-54f2-8361-8473d4510430', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-10', '16:30:00', null, '通常 / 親子大会づくり', '前回からPIXTAでイラストを選んでくれたので、選んだイラストのページのスクリーンショットを生徒のひろとくんのフォルダに入れておいたので確認お願いします。 こんかいは、クイズに答えて機織りが進ませる仕組みを作っていきました。糸をそろえる動きなどがメッセージのやり取りでうまく書けていました。ただ、縦糸の全体図をを遠近感出したいそうでしたが、なかなかうまく描けていなかったので、きれいに見せる描き方を教えてあげました。喜んで実践してくれました。今後もイラストの描き方に悩むと思うのできれいな書き方を教えてあげてください', null, 'タイピング: 銃長にやっていました。'),
  ('adb438f4-2938-51de-8aab-d0f1f6fdc67c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-07', '17:30:00', null, '通常 / アレンジ大賞の評価', '最近はまっているのか、授業の合間にもタイピングを何度もはさんでいました。 いろいろなゲームで遊べたのは楽しかったようです。 決断は意外とはやく、30分ほどで評価を終了していました。 アレンジ大賞の評価が予想以上に早く終わったので、新しい課題等を勧めましたが、今日は自由にタイピングなどをして、次回からちゃんとやる、という約束をして、残り時間はタイピングで過ごしました。', null, 'タイピング: とても熱心にやっていました
盛り上がり: タイピングでも、たまにキーボードをカチャカチャ適当にたたくことはありますが、きちんと打てばいい得点が出ていることをほめると、きちんと打つようになりました。よいスコアを出してアイテムを購入するのがとても楽しいようでした。'),
  ('70fd0373-596f-53bc-8d8e-cb24ef04c6a0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-08', null, null, '通常 / 親子大会の製作を始める', '最初はモチベーションがない様子でしたが、大会のテーマや賞品についての紙を改めて見せると取っ掛かりができたようで制作を始めました。今までの入賞作品にはストーリー性のあるものが多いという話をすると、場面の切り替えも考えながら作っていました。コスチュームの編集などに終始せずコードもたくさん書けていたので良かったです。', null, '時間帯: その他
タイピング: タイピングは久しぶりということもあり基礎の文字から復習していました
盛り上がり: スイッチが入ると別人のように集中することができます。'),
  ('f8e84b7d-4de4-5955-b58b-a428149e1924', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-08', null, null, '通常 / 検定練習', '作成中にバグが起きることは多いのですが、挙動を見て怪しい場所を確認することはできたのでだいたいは自己解決していました。唯一直せなかったのが、問題文中で「～の間、ずっと繰り返し以下を行う」と書いてあるところに「まで繰り返す」だけでなく「ずっと」も使っていたというものでした。「ずっととは書いてあるから紛らわしいけど、まで繰り返すだけでその意味になるよ」と伝えると納得したようでした。ブロックの入れる場所や繰り返しの範囲に関するミスはなくなってきているので、理解度は上がってきていると思います。 最後中学生大会の案内をしましたが、乗り気ではないようで出さないそうでした。', null, '時間帯: その他
盛り上がり: 集中力は高かったです'),
  ('6159f011-8d9c-56f2-b2e1-d5f2a2d9571c', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-08', '17:30:00', null, '通常 / 親子大会のためにつくる', 'レベル的にビギナーズ部門の作品で進めました。このゲームを遊んだ時に、横からもとんででてくるようにしたいと早速アレンジアイデアが浮かんでいました。まずは内容づくりはゆくっりと進めていき、スイカ(風船の代わり)が浮かび上がるようにはできました。次では完成はできると思います。 最後の親御さんとの会話の中で、やりたいことがノートににメモってあるとのそのアイデアも入れてもいいかもしれません。', null, '盛り上がり: アレンジ大賞優勝おめでとう！'),
  ('d2147d95-bcbb-5598-93e1-52cc085d26e4', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-08', '16:30:00', null, '通常 / 親子大会作品作り', '親子大会にビギナーズ部門のことも紹介しましたが、引き続き、カニハンマーで出すつもりです。そこで、カニのイラストはそのままには使えないので、代案となるコスチュームを考えてもらいました。自分で絵が描きたいそうだったのでl、タブレットで絵をかかせてみましたが、使えるらしい絵はなく、ただの自由絵描きになっていました。その後も、アルスタジオに戻り、剣や骸骨になる変化が見られました。 のらりくらりと進めてしまったので、しかりと最初にやることを示した方がいいかもしれないです。', null, 'タイピング: 進めるとこまで来たので次回からプレイグラムです'),
  ('73d980fc-aba2-5370-b232-39a362fd430c', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-08', null, null, '通常 / 作品をきちんと完成させる', '自分の作りかけの作品やバイクランなどに対して、作成のやる気が出ては無くなるのでなかなか進みませんでした。こちらがインベーダーゲームを提示するとようやくやる気が継続的に出たようでした。手順書の順番通りにやって完成させるという目標を共有し、その後は集中して最初のスプライトのコードを最後まで作ることができました。', '続き', '時間帯: その他
盛り上がり: ゆき先生がこうしろうくんの親御さんと話し合い、以下の方針でやっていくことに決まりました。 ・未完成で終わるゲームが多いので、完成を大きな目標とする ・授業のうち前半30分は先生が提示したゲームを、アレンジ、キャラ変更、作成順の変更など一切なしで作る(他の子だと問題ない程度の変更でも大きく脱線しかねないため) ・残りの30分は、集中力が持たないので自由時間'),
  ('84662b68-e0c6-51f4-922c-d83cb9bfde99', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '16:30:00', null, '通常 / Unityに触れてみる', '今回は、Unityエンジンを用いて基礎的な操作方法や取り扱い方について学習していきました。内容としては、モデルの動かし方やカメラの使い方などを学んでいき、Unityを扱っていく上で必要不可欠と言えるものを学んでいくことで、本人としてもやる気がみなぎっていたようです。次回以降では、Unityに対して高いモチベーションを持って取り組むことができると思うので、どれくらい集中して取り組めるかが今後成長できるかの基準となっていきそうです。', null, 'タイピング: 正確に打つことができていました。
盛り上がり: Scratchではできなかったことができるとわかって、嬉しそうでした。'),
  ('9d968864-9e92-5656-94be-42a43fe3e0da', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '17:30:00', null, '通常 / 大会作品制作', '前回からの続きで、アレンジ大賞で制作したカニカニハンマーのアレンジをさらに施していきました。作品の中にオリジナリティを多く入れていきたい様子でしたので、様々なアレンジ内容をとりあえず作品の中に入れていきました。キャラクターのデザイン変更や新たなアイテムの追加など様々なことを行いました。しかし、次回からはカニカニハンマーでは大会にて上位を狙うことが難しいとのことで、全く新しい作品へと着手していくようです。内容としては、化学式を使ったものや計算問題を取り入れたものなどがあるようです。', null, 'タイピング: 結果でプラスを出すことを目指して一生懸命打っていました。
盛り上がり: 作品をどのようなものへ仕上げていくのか悩みながら楽しんでいました。
備考: 大会上位を狙うため、作品を1から作り直すようなので考えをまとめてから作り始めた方がいいかも？'),
  ('fe53cc63-1ec8-56ba-ac64-891b026082d5', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-08', '16:30:00', null, '通常 / U16大会作品作り', 'U16大会にもともとつくる意欲があったので、制作に取り掛かりました。今回は、クローンを使ってものが積み重なるような仕組みを作りたいのことでした。リストや色判定で方法を試していたが、なかなか積み重なるようになりませんでした。移動幅と記録してある座標が倍数的に合わないことが発覚したら、少しは解消できました。リストを使う方法だと、x座標のずれは乱数でなかなかそろわないこともあったので、離散的乱数の作り方も提案しておきました。', null, '盛り上がり: アレンジ大賞2位おめでとう！！'),
  ('8147999d-f88e-5379-a73d-32cbfeadf4bb', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-08', null, null, '通常 / 検定練習、中学生大会の作成', '1級の2回目の問題に取り組みました。リストは検定問題で初めて出てきましたが、説明せずともすぐ使いこなせていました。アレンジまでして時間を余らせて終わることができました。答え合わせをしてもほとんど完璧で、指摘するなら「コスチュームを乱数にする」という書きかたを知らなかったため「乱数回次のコスチュームにし続ける」で対処していたというくらいでした。 その後中学生大会の説明をすると意欲的だったので早速作成を始めてもらいました。ゾンビを銃弾で倒していくという構想ができているそうで、コードも書き進められていました。', null, '時間帯: その他'),
  ('d8ca5a6b-f42b-5050-9862-6684868571f8', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-08', null, null, '通常 / 親子大会作品作り', '親子大会の作品は、アレンジ大賞で未完成だった、スマブラのゲームを続きをやっていきました。それぞれのキャラクターに合わせた色合いになっていて、わかりやすい感じになっていました。そして、キャラクターセレクトのときに選んでいない選択肢が画面上に残っていしまうバグがあって困っていたので、キャラクターを仕向けるメッセージを流用するよう提案したら。スムーズな流れになってよかったです。', 'キャラクターがそのままだと著作権的によくないので、変更するようお願いします。', '時間帯: その他
タイピング: 何度もチャレンジしていました。'),
  ('6ce82771-8a87-51e5-86f7-f21421da88d9', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '16:30:00', null, '通常 / Excel練習', '前回まで進めていた箇所からの続きをやっていきました。今回もExcelの基本的な使い方であるページの追加や削除、保存の方法などがほとんどでした。なので、特に迷うこともなくサクサクと進めていきました。おそらく関数などが出てくるまではこの調子でサクサクと解いていくことが可能であると思うので、次回もこの調子で問題を解くことができると思います。', null, 'タイピング: 早く正確に打つことができていました。
盛り上がり: 問題をサクサクと解いていくことができて、楽しそうでした。'),
  ('0f06c1c8-6b28-5cfd-a87b-4c0106d7c3da', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', null, null, '通常 / 風船ゲーム作成', '今回から親子プログラミング大会へ向けてビギナー部門の作品である風船ゲームを作っていきました。今までにやってきたことが多く書かれていたため、サクサクと進めていくことができました。その中でも間違っていた箇所は座標部分のみであったため、すぐに修正して間違った原因も理解することができていました。今回で基本部分は完成させることができたため、来週以降でアレンジに入っていきたいです。アレンジの内容に関しては、来週来るまでに考えておくとのことでしたので制作にはすぐに取りかかれると思います。', null, '時間帯: その他
タイピング: 的確に鬱ことができていました。
盛り上がり: 作品を完成させられた際には、自身の実力が上がっていることを感じられて喜んでいました。'),
  ('094a85f1-c7b0-5980-b3eb-986edfdd85a0', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-08', null, null, '通常 / 親子大会作品作り', '親子大会に向けて作品を考えていきました。そう簡単には、アイデアは持ち合わせていなかったので、過去の入手う作品の動画を考えていきました。その流れで、何となく作っていくうちに卵からかえったばかりひよこの冒険をもとに作っていくことを決めました。ただ、今回はそこまでアイデアが固まっていないので最初の導入を作り、次回にスムーズにできるようアイデアを練るように宿題を出しました。', null, '時間帯: その他
タイピング: 久々にやりました
盛り上がり: アレンジ大賞の入賞をおめでとう！！'),
  ('8481ddc7-c122-5207-b8b4-0d15c2600338', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '18:40:00', null, '通常 / 親子大会', '前回に引き続き、親子大会に向けて作っていきました。とうき君も途中で方向転換をしてゾンビを倒していくストーリーを作っていきした。話の流れは面白いですが、ただのアニメーションになっている感じなので、こちらから何か動かせるようにできればなおいいです。', null, null),
  ('e4d7e10e-f79e-5ae0-8e4c-436eb954ca59', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '18:40:00', null, '通常 / 親子大会', '前回にサッカーのゲームを作っていたが、うまく先が思いつかなったので、作る作品テーマを変えました。授業の途中にドラクエ話が出たので、RPG風のものを作るそうです、今回はオープニングから作っていきました。小技の残像まで追加して動きがよくなっていました。スマブラで養った要素（重力など）も次回から使いたいそうです。', null, 'タイピング: よくできていました。'),
  ('0ed8fbdb-6aef-5b97-9046-3e9a38ce65ca', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '18:40:00', null, '通常 / アレンジ大賞評価＆U16大会の案模索', '最初は、アレンジ大賞の評価をしました。自分の作品が選ばなかったので、自ら作品を公開してました。U16大会については、出す意欲はあるが、どんな作品を作るか悩んでいました。過去作品やスクラッチでさがしましたが、なかなか決まらかったです。', null, 'タイピング: よくできました。'),
  ('150798f3-7782-54a2-8795-438b9430a0d2', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '17:30:00', null, '通常 / 親子大会作品作り', '前々回に引き続きオープニングを作っていきました。横長モザイク絵のデザインがとても個性があらわていてよかったです。ただ、スケジュールを考えずに作っていそうだったので、残りも回数も確認しました。', null, null),
  ('c98c62eb-724f-590a-8880-ad7a6602255a', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '17:30:00', null, '通常 / オリジナル作品', '親子大会は出したくないそうでしたが、前々回作ったタイマーの使ったゲームを作りたいのことだったので、そうしました。早打ち銃のゲームを作りました。だが、途中で様子をうかがうと、全く活かされていませんでした。その中で、押すまでの時間を表示したいが、時間が進んでしまうバグがありました。性質上タイマーは常増加変数なので、変数に一度収める方法を教えました。この中で、変数を同じ変数に入れることに節がっていたが、屋はうちのゲームは完成できました。', null, '盛り上がり: ゆづきくんの作品案を一緒に考えてくれました'),
  ('bb5c7751-dfd2-5f2d-ba1e-07e51bc238ce', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-07', '16:30:00', null, '通常 / 乱数や「まで待つ」の使い方を理解しよう', '今回は、追跡ゲームの応用としてチーズを探せのゲームを作成しました。上下左右の動きを作る際に、一つ一つの動作をバラバラに作っていたので、一つの「ずっと」の中に作成できることを教えてあげたら、コードがすっきりして見やすさを体感してくれました。迷路の貫通できない仕組みを作るときには、こちらが貫通できない動きを細分化して説明したら、自ら同じ歩数分戻るコードを作れていて、動きをコードの文章に直す能力ができていました。乱数によるランダム移動はスプライトを動かして乱数の範囲を決めるやり方を覚えました。その動きを幽霊でも活かせていました。幽霊に触れた際に、一時的に動けなくなるようにしたのことだったので、メッセージ使った方法を一緒に取り組みましたが、使い方があまり見についてなかったので、ゲームの中でメッセージを使う作品も作ってもいいかもしれません', null, 'タイピング: ミスなくできました'),
  ('2dc74143-526a-51d7-9f30-340b53f02c6a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-06', '16:30:00', null, '通常 / 親子大会の作品の計画、作成', '放課後、保健室に寄ったそうで、少し遅れて来室しました。 親子大会の作品について、すぐには思いつかなかったようで、アレンジ大賞の作品とビギナーズ部門の課題をそれぞれプレイして悩んでいました。 ビギナーズ部門の「ふうせんをわろう」にあまりピンとこなかったようなので、オリジナル部門のジャンルの紙を見せながら、こたろうくんの好きなもの、力を入れているものを聞き、野球をテーマに入れたい、ということになりました。そこから自分で要項を見て、「夢」と「つながり」のどちらかをテーマにしたい、というところまで決定しました。 野球ゲームそのものではなく、野球選手になる夢をかなえる過程をゲームにするということで、野球の練習メニューを考えてきてもらい、次回から作成に入っていく予定です。', null, '盛り上がり: 力を入れている野球がテーマにできそうということで、何をしたらいいのかわからないところから少し道筋が見えてきて、前向きになれたように見えました。'),
  ('11958092-feda-5fc5-9378-9f989f396e4d', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-06', '16:30:00', null, '通常 / アレンジ大賞の投票をしながら他人の作品の良さを学ぶ、親子大会の作品の計画と作成', '自分の作品が入賞したこともあるのか、とくに脱出ゲームは熱心にプレイしていました。評価自体はわりと即決で、この後なにするの？と自分から聴いてきました。 当初はアレンジ大賞の作品をブラッシュアップする、と言ってコスチュームをいじり始めていましたが、自分の昨年の作品のどこが良かったんだろう、グランプリを取るにはどうしたらいいんだろう？と聞いてきたので、昨年のスーパーは独自性が良かったのではないかと話したところ、「一から自分のアイディアで作りたい！」と盛り上がり、「フィギュアを買う」という夢のために色々なアルバイトを頑張る、というストーリーを作成することになりました。アルバイトに八王子ネタを使う予定だそうです。（高尾山でゴミ拾い、など） 昨年、会場で見ていてグランプリの子の何が良かったか、ということも自分で考えてもらい、自分が発表する時にきちんと話しやすいように、建前ではなく本音の夢を作品にしたい、とのことでした。', null, '盛り上がり: 作品の方向性が決まって、気持ちも盛り上がっているように見えました。 今年の親子大会の話が出た時は、発表が大変だったから今年はもういい、というようなことを言っていましたが、実際にホワイトボードの要項などを見ていると、昨年よりも賞品の金額が上がっていることもあり、気分が盛り上がってきたようで、昨年から苦手と言っていた発表も頑張る気になっていました。'),
  ('9b5b4d24-53f3-5493-bfbc-12ce6eded965', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '17:30:00', null, '通常 / アレンジ大賞評価、U-16大会制作', 'アレンジ大賞評価では、作品のアレンジ部分に注目してどれくらい面白くなったのかを基準にして評価していました。評価はスラスラと終えることができ、そのままU-16大会の制作に取り掛かっていきました。大会作品のアイディアはまだ浮かんでいないようで、Scratchなどを探して自分の中にある想像力を刺激して制作を捗らせていきました。基本部分の構想は固まったようなので、次回は今回と同じように他の作品などを見てアイディアを出しつつ基本部分を完成させていきたいです。', null, '盛り上がり: 大会用作品の構想をしっかりと固めたいようで、作品のアイディアを出そうと努力していました。'),
  ('b1d16157-d5dc-50bb-ac05-43d1696ccbcb', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-06', '16:30:00', null, '通常 / 親子大会の作品計画、作成', '家で親子大会のアイディアを考えてきた、と、やる気満々で来室しました。 学校でなぞなぞ係をしているそうで、それをゲームにしたいというので、リストの勉強をしてから取りかかろうと促しました。上級のスキルだと伝えると、いそいそとレッスンを始めていました。 レッスンの後でオリジナル作品の作成に入り、なぞなぞを少し入力するところまでできました。', 'リストを使ったなぞなぞがうまく動くようになったら、ストーリーやゲーム仕様の工夫をしてより面白い作品になるよう、計画をたてさせていきたいところです。', 'タイピング: 親子大会のアイディアを考えてきたそうで、すぐに取りかかりたいとの要望により省略
盛り上がり: なぞなぞを作るという思い付きと、初めて習うリストというスキルを使うということに、とても盛り上がっているようでした。'),
  ('5b18f1cf-b763-599e-9e52-3cd642bfd440', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '17:30:00', null, '通常 / アレンジ大賞評価、親子プログラミング大会作成', 'アレンジ大賞評価では、作品をどんどん進めていきサクサクと評価を行っていました。作品内から新たなアイディアを得られたようで、親子プログラミング大会の作品にも入れていきたい様子でした。大会用作品の制作では、対戦型のシューティングゲームを作っていくようでしたが、基礎的な部分はかなりありふれたものとなっているため様々な要素を作品内に入れていくことで上位を狙っていく様子でした。基礎部分に関しては既に決まっているようなので、次回以降はその基礎部分を作りながらそれ以外の部分に関しても考えられるといいです。', null, '盛り上がり: 大会作品を独創性の溢れるものにしたいと張り切って取り組んでいました。'),
  ('04fe2cf4-c411-5c66-a81f-e61c18178111', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-06', '16:30:00', null, '通常 / アレンジ大賞評価、親子プログラミング制作', 'アレンジ大賞の評価では、次々とゲームを試していき作品が面白いかどうかを決めていき、自分自身の中で評価をしっかりと決めることができていました。後半の親子プログラミング大会の作品制作では、どんなものを作るのかはある程度決まっているようなので、フリー素材から背景や立ち絵を探していきました。この部分にはかなりこだわりがあるようで、背景素材はお気に入りのサイトがあったためすぐに決まりましたがキャラクターに関しては終わりまで決めることができませんでした。そのため、来週はキャラクター探しと同時に作品に着手していければ良いと思っています。', null, '盛り上がり: 大会用作品では、どういったものを作るのかを決めていたので良いスタートを切ることができました。'),
  ('f9ba2657-555a-5a2f-8604-69e9bb9c9270', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-04', '17:30:00', null, '通常 / アレンジ大賞の人気投票', '入賞作品を遊んで投票してもらいました。全て遊びきるのは大変そうな様子でしたが、りょうやくんの作品は難しく諦めがつかなかったようなので、勉強も兼ねて中のコードを見ることを促しました。当たり判定のスプライトとそのコードを見てゲームを攻略しました。 投票後、親子大会のモチベーションもなく、だれた様子だったので、上級へステップアップするためと説明して単元別演習に入りました。レベルの高い変数の使い方には慣れない様子でしたが、問いかけで誘導して1問完成できました。', '単元別演習G[演算(計算式を使う)] 続き', '盛り上がり: 単元別演習に入ってもやる気が高まったわけではなかったようでしたが、目標を示すことでなんとかメリハリをつけてできました。'),
  ('9e7f1d99-f5d1-5785-919b-10a33175cc45', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-04', '16:30:00', null, '通常 / アレンジ大賞の人気投票', '全ての入賞作品を楽しく遊んで投票まで済ませました。面白かった作品はリアクションしてくれました。時間が少し余って親子大会の製作にやる気がある様子だったので、去年の親子大会の入賞作品をyoutubeで流すと、興味を持って見ていました。', null, null),
  ('63c05ec6-7e2c-5f8e-abf3-b6bfce07203f', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-04', '16:30:00', null, '通常 / アレンジ大賞の採点', 'アレンジ大賞採点。自分の作品が入賞していなくて、かなり落ち込んでいました。次回頑張ろうと声をかけたのですが、どこまで伝わっているか正直怪しいです。', null, null),
  ('dc233637-2ab9-5f88-a4ff-ca28e08c16ff', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2024-06-04', '16:30:00', null, '休み（未対象）', null, null, null),
  ('68ee6532-8248-5034-81ef-c90bbcafc913', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-03', '16:30:00', null, '通常 / 親子大会の作品作成', '前回しもさんと話し合った内容を、メモを見せてくれながら嬉しそうに教えてくれました。 家でも画像を探したけれどなかなかよいのが無かったとのことだったので、ゆき先生のお勧めで、PIXTAを教えました。家でゆっくり見てくるとのことでしたが、とりあえず、女性が機織りをしている絵が気に入ったようでした。 機織りのアップのところを自分で描いて、黙々とコード作成に取り組んでいました。', null, '盛り上がり: 学校の先生と話して「ためになるものを作ろう」と思ったそうで、機織りとタイピングゲームを組み合わせたいと嬉しそうに説明してくれました。作りたいものがはっきりしていて、やる気も十分といった感じでした。'),
  ('e759192b-88be-5b09-b6c5-5b6e3f3bd7d5', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-03', '16:30:00', null, '振替 / リストの学習、検定1級にチャレンジ', '自宅でも検定2級応用課題2問にきちんと取り組んできたようで、出来も問題ないようでした。 検定1級にチャレンジしてみたいとのことで、1級から試験範囲に入るリストに慣れてもらうため、都道府県クイズとアルスタジオレッスンのリストに軽く取り組みましたが、どちらも手を抜かずにきちんと完成させていました。 残り30分で検定1級①に取り組みましたが、35分でアレンジ以外はすべて完成させていました。今回の問題はわりと余裕だったとのことでした。', '検定1級①のアレンジをやりたいとのことだったので、今回の残り時間の15分でやらせてあげてください。 終わったら検定1級②をおねがいします。', '盛り上がり: 新しいスキルや問題にも積極的にやる気を見せて取り組めていました。検定問題でいろいろな形式の問題に触れられるのが楽しそうでした。
備考: アレンジ大賞が公開されていなかったのを気にして、自分で公開してくれました。 ずいぶん前に家できちんと完成させていたみたいで…申し訳ないことをしました。'),
  ('a84ffbd5-76df-5d67-9fe0-3c00aed3c64f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '17:30:00', null, '通常 / 親子プログラミング作品作成', '今回から、親子プログラミング大会に向けて作品制作を開始していきました。アレンジ大賞にてアレンジした作品をさらに発展させていきたいようなので、自分自身のアイディアを次々と作品に入れていきました。ひたすらに内容を試していったため、エラーなどは多く出ましたが１つづつ解決していくことで確実に進めることができました。本人としては、ここからより動きのあるものを作っていきたいようなので、もっとたくさんのアイディアを取り入れていきたい様子でした。なので、次回以降どのように作品を作り上げていくのか気になるところです。', null, '盛り上がり: 作品にアイディアを入れていく際に、こういう作品にしたいというイメージを考えながら入れていきました。'),
  ('9a709dc7-9ba1-52de-99ac-12ef3e1054f2', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '17:30:00', null, '通常 / アレンジ大賞評価', 'アレンジ大賞作品の評価を行っていきました。作品を見ていきながら、自分と違う箇所はどこなのか、どう言った点が優れているのかを考えながら評価を行っていたようです。作品内でも、同じ作品元である謎解き脱出ゲームについては特に真剣に観察及びプレイをしていたようです。作品ごとの特徴がどういった面白さを出しているのか、そしてその面白さは自分の作品にはあるのかはしっかりと評価していたようです。評価はサクサクと終えていくことができ、残りの時間は好きなものをしていました。', null, 'タイピング: 間違うことなくしっかりと打てていました。
盛り上がり: アレンジ作品で自分との違いを見つけようと真剣になっていました。'),
  ('f8c5efcb-b4f4-5f30-bc5e-66d91b746527', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '17:30:00', null, '振替 / 親子プログラミング大会作品制作', '今回から、親子プログラミング大会に提出する作品制作に着手していきました。スマブラ風アレンジを作っていたため、それをさらにアレンジしていくところから始めていきましたが、構想自体はそれほど固まっているわけではないため、どれから手をつけていいかイマイチわかっていない様子でした。なので、まずはデザインから変えてはどうかと提案したところ、その部分から取り掛かっていき黙々と作業に取り組んでいました。作品としては、オリジナリティの溢れる作品にしたいとのことなので、今後の作成でどれだけアイディアを出していけるかが鍵となると思います。', null, '盛り上がり: アレンジにて１歩を踏み出すことができたため、この調子で行きたいと言っていました。'),
  ('7530be96-0f88-5dfc-8f3f-851d7e99c2c3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '17:30:00', null, '通常 / アレンジ大賞評価、検定３級②', '少し早くきていたため、先にアレンジ大賞の評価を行っていき授業開始と同時に検定問題に取り組んでいきました。アレンジ大賞の評価については、サクサクと進めていき自分の気に入った作品をすぐに決めていて、アレンジされていた内容に関してもしっかりと把握できていたようです。検定問題に関しても、間違っている箇所はなく完璧にできていました。しかし、少しめんどくさがりな一面がある為、つまづいたり長かったりすると放棄してしまうかもしれません。そしてアレンジ部分に関しても、あまりアレンジしたがらないためその部分を直していければさらに高得点を狙っていけそうです。', null, '盛り上がり: 検定問題を完璧にできていたため、喜んでいました。'),
  ('cb6177f6-72f1-5043-a215-be0e57cc90d3', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '16:30:00', null, '通常 / アレンジ大賞評価', '今回は、岳君と一緒にアレンジ大賞の評価を行っていきました。入賞した作品を岳君と一緒に遊んでいき、作品ごとのアレンジ内容や工夫を楽しんで学んでいきました。その中でも特に、スマブラ風アレンジは気に入っていたようで、2人で対戦しながらどういった技やギミックがあるのかをやりながら感じていました。今回遊んだことにより、作品を作るモチベーションも上がった様子でした。', null, '盛り上がり: スマブラ風アレンジをしている際には、真剣に戦っていて集中しつつ作品のアレンジ部分に注目できていました。'),
  ('d9b2357d-4bff-5769-8c4f-dae57e651d68', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-03', '16:30:00', null, '通常 / アレンジ大賞評価', '今回は、アレンジ大賞の作品評価を勇作君と一緒に行っていきました。作品を遊んでいき、2人で謎を解いたり戦ったりとしっかり楽しみながらアレンジの内容を学んでいくことができていました。様々な作品に触れていくことで、作品制作への熱量も上げていくことができた様子でした。', null, '盛り上がり: 勇作君と作品を遊んでいくうちに、お気に入りの作品ができたようで、その作品を高く評価していました。'),
  ('dfabba87-93c0-584a-b94a-ac6a2b04afb6', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-01', null, null, '通常 / アレンジ大賞の人気投票', 'すべてのゲームを遊んだうえで、自分自身や「面白かったから」と兄のゆうとくんにも投票していました。投票が終わった後、ゆき先生から「入賞作品のコードを見てアイデアを盗んでみよう」と促されたところ、カニカニハンマーのアレンジ作品のコードを見て、難しいと言っていました。その中でも自分に理解できるコードを探し、「(右腕が)ずっと胴体に行く」に注目して、腕が胴体にずっとくっつくという意味だと分かりました。そして、「これは今家で作っているゲームに使えそう！」と関連を見出していました。', null, '時間帯: その他
盛り上がり: 入賞したので、もらえる可能性のある景品が気になっていました。'),
  ('fddc5758-9298-51ca-84a0-ceb68b2707b3', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-01', null, null, '通常 / 細分化を身に着ける', '細分化する力をつけるために、手順書を見ながらカニカニハンマーを作りました。最初に全体の流れを確認するため、「このキャラクターはどういう動きをする？どういう条件の解きこの動きをする？」というような問いかけをたくさんしました。だいたいの問いかけには自分で考えて答えられ、流れはつかめたようでした。そのあとで手順書の通りに作成を進めました。こちらもおよそ順調でしたが、3種類の「止める」ブロックの違いなど検定で狙われがちなポイントは一緒に学習しました。最後にきちんと動いているかを確認してもらうと、よく観察したうえで、カニの右腕だけが叩く動きをしていないことに気づきました。そして、コードが合っているか怪しい場所の見当をつけ、ブロックの不足に気付いて直すことができました。', null, '時間帯: その他
盛り上がり: 教室に来る前にゲームセンターのクレーンゲームで取ったフィギュアを嬉しそうに見せていました。'),
  ('b17164ef-63cf-53eb-bef8-ed6d580100e7', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', '17:30:00', null, '通常 / アレンジ大賞評価', '今回のアレンジ大賞評価では、今までに作って生きた作品を遊ぶことができるということで喜んでいました。自分自身が作った作品としての難易度には自信を持っていたようでしたが、他の作品の難易度の高さに驚きながらもしっかりと楽しみながらクリアすることができていました。作品に使われたものを理解しようとしながらプレイすることができていたため、作品に対する興味を大きく上げていたようでした。', null, '盛り上がり: 作品をプレイしていく際に、どんなアレンジがされているのかを楽しみにしながらプレイしていました。'),
  ('b1a45b1a-273e-5b25-8a8f-cb4de6dee8cf', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-01', null, null, '通常 / 親子大会の製作', '振替の授業で人気投票は終わっているので、親子大会の製作を進めようと伝えました。しかし隣ののあくんにつられてゲームを遊ぶモードに入ってしまい、実際に作り始められたのはしばらくしてからでした。作りたいゲームのイメージは浮かんでいるとのことでしたが、方向が二転三転して、作っては消してを繰り返すような状況になりました。最終的には、問いかけに沿ってキャラクターの上下移動のコードを途中まで書くことができました。', null, '時間帯: その他
盛り上がり: のあくんにゲームのコツを教えて得意げでした。'),
  ('dedca17a-48e9-5cf0-aa2f-7035b6141605', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', '16:30:00', null, '通常 / アレンジ大賞評価', '今回のアレンジ大賞でしっかりと優勝を狙っているようで、自分の作品と他の作品ではどちらが面白いのかを話しながらプレイしていました。そして、投票が終わった後には自身の作品を他の子にアピールして票を獲得しようと努力していました。本人としても、気に入っている作品のようなので、熱量が違うようです。', null, 'タイピング: なし
盛り上がり: 他の子に自身の作品をアピールしている際は、とてもウキウキしながら説明していました。'),
  ('a5e52792-0668-5d71-816f-154a96a57c8b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', '16:30:00', null, '通常 / アレンジ大賞評価', '今回の入賞作品のプレイにて、本人が作っていた謎解き脱出以外のゲームを特にやっていました。そうすることで、自分の作っていた作品だけでは思いつかなかったアイディアがないかを探していたようです。投票自体は早く終えて、残りの時間は各作品と自分の作品を比べてみていました。', null, '盛り上がり: 自分の作品と違う箇所を見つけて、どちらが面白いのか比べて考えていました。'),
  ('78d33614-6121-5a7e-be53-a886e006e6cd', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-01', null, null, '通常 / アレンジ大賞の人気投票', '入賞ゲームを一通り楽しく遊んで投票しました。時間が余ったので親子大会の製作に取り組み、前回同様やる気がありました。ロケットを左右に動かしたいけど作り方がわからないと質問してくれたので、一緒に細分化して座標を動かすコードを作りました。', null, '時間帯: その他'),
  ('344f52a6-6372-5817-9085-cd8b11e0d359', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', null, null, '通常 / アレンジ大賞評価', '今回、アレンジ大賞作品を評価していくにあたってそれぞれの作品の面白さを探しながら遊んでいました。作品ごとの面白さをプレイしながら感じることができていたようで、プレイした後はどの作品が楽しかったかしっかりと決めて投票することができていました。', null, '時間帯: その他
盛り上がり: 入賞作品の面白い部分を見つけることができて、しっかりと楽しめたようでした。'),
  ('cb3d02bf-9d9b-5d4b-b988-10986606ebbf', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-01', null, null, '通常 / アレンジ大賞人気投票', '最初の方はなぜかスクラッチのゲームを遊んでいましたが、しばらくするとアレンジ大賞の入賞ゲームを順番に遊んでいきました。スマブラは先生に対戦を申し込み、ゲームの内容が面白いなど言いつつ楽しくやりました。親子大会については話をしましたが現状モチベーションはあまり高くないようです。', null, '時間帯: その他
盛り上がり: 今日の授業はいろいろな人のゲームを遊び倒せると聞くと嬉しそうな表情でした。'),
  ('0b181c48-8a3e-5d1a-b25c-a5a147ac50df', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', null, null, '通常 / アレンジ大賞評価', 'アレンジ大賞にて入賞した作品を遊んでいきました。遊んでいく中で、どんなギミックが使われているのか、どんな面白さがあるのかをしっかりと味わいながら遊んでいました。投票を行った作品においても、本人が参考にしたいものを選んだようなので、満足して選べているようでした。', null, '時間帯: その他
盛り上がり: 自分の作品と比べて、どのような違いがあるのかをしっかりとプレイしながら考えていました。'),
  ('ba2fb8be-32c0-5324-bf91-d4726fb8003b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', null, null, '通常 / アレンジ大賞採点', '採点。りょうやくんの脱出ゲームが難しかったようで長い時間挑戦していました。', null, '時間帯: その他'),
  ('551859c6-7574-5b33-9b73-869cbf6f1c10', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', null, null, '通常 / アレンジ大賞採点', '採点。ヘッドフォンもつけて丁寧に作品を採点してくれました！着眼点も高学年らしく、細かく注目してくれました！', null, '時間帯: その他'),
  ('26f8d5a8-054e-574b-9764-bef5995645d2', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', null, null, '通常 / アレンジ大賞採点', '採点。最初はいくつか作品を見るだけで済まそうとしていましたが、なんとか伝えて全ての作品を確認してもらいました。投票先も変えていました。 後半は八王子親子プログラミング大会の作成をしました。去年の受賞作品も確認しました！', null, '時間帯: その他'),
  ('f7844975-2e54-5cdf-b01b-ceac6bf8cd89', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '17:30:00', null, '振替 / アレンジ大賞採点', '時間内に全ての作品を確認することができました。最後のお気に入りの作品の発表もトップバッターだったのですが、はっきりとポイントをおさえて話すことができました。', null, null),
  ('7a09045e-76b5-5319-a7ed-e2f95e649957', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '17:30:00', null, '通常 / アレンジ大賞採点', '採点。けいとくん、はるくんと一緒に楽しく取り組めました。スマブラがとくに気にいった様子です。', null, null),
  ('a93ad051-4490-5fa5-a766-f9f0340b8f6f', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, null, '2024-05-31', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('da1881d3-f9f0-5203-8248-4dc749f25432', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '17:30:00', null, '通常 / アレンジ大賞採点', '採点。ゆづきくん、けいとくんと一緒に楽しく取り組めました。最後のお気に入りの作品の発表もしっかりできました。', null, null),
  ('1ab777f4-e40e-55ae-a324-604d647d893d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '17:30:00', null, '通常 / アレンジ大賞採点', '採点。ゆづきくん、はるくんと一緒に楽しく取り組めました！最後の発表も頑張った！', null, null),
  ('5026ba5d-ca36-5da0-955f-541000051f62', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '16:30:00', null, '通常 / アレンジ大賞採点', '採点→オリジナル作品（まで繰り返す） 楽しく取り組めました。', null, null),
  ('bb8f6980-506c-51da-bab6-051f00796d48', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-31', '16:30:00', null, '通常 / アレンジ大賞採点', '採点→八王子親子プログラミング大会準備（サッカーゲーム） プログラミング大会の提出作品の方向性が少しずつ定まりそうです。', null, null),
  ('6946a506-c447-59e1-809a-e5228b681433', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-05-18', null, null, '通常 / アレンジ大賞', 'とにかく、自由に作りたいモードが激しく。しばらく好きに作らせましたが。スプライトの絵、構図にこだわりがあり、そこを作るのだけで精一杯でした。 お父さんもお母さんもお迎えに来たので、その時に状況は伝えました。 最近、課題制作が続き見本通りに作ることをやってきたが。少しそれが飽きてきたのでしょうと。今回、少し自由に作ってもらいますが、うまくできないので、癇癪起したりなかなか進まないと思いますが、その辺ご了承いただきました。', 'とりあえず、続き。イメージしているキャラクターがいるので、場合によってはiPadでイラスト作ってもいいかもと思います。', '時間帯: その他
タイピング: 割愛'),
  ('576722a3-686d-50cc-b3f8-5354e7d4fa8e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, null, '2024-05-30', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('f41793c4-0e4e-5a68-8562-3330a7d4eb03', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-30', '17:30:00', null, '通常 / アレンジ大賞を評価しよう', '毎度、評価のときにはじっくり評価してくれるので、中学生になったことから、気になったものにはコードも見て評価してほしいとお願いしました。ちひろくんやみずき君のものはしっかりと作りこまれていて、感心していました。優柔不断なので、最後までしっかり見てくれました。', null, 'タイピング: 久しぶりスコアが伸びないことに嘆いていました'),
  ('4e2ff798-4ff7-55cc-8921-6b8f21060df3', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, null, '2024-05-30', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('a3f72d16-8211-570a-a4f2-c4b9180bcb24', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2024-05-30', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('830667d4-1907-5fe0-98a9-467522f8ac1d', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', '16:30:00', null, '通常 / アレンジ大賞評価', '今回は、今まで作成を続けてきたアレンジ大賞の作品評価をしていきました。本人も入賞した15人の中に入っていたため、作品を遊んでいく際にはとてもワクワクした様子でした。実際に遊んでいく中でも、どの作品でどんな新しいものが追加されているのかを楽しみながらプレイしており、自分の作品との比較も行っていました。今回の入賞作品の中でも、同じお題であるカニカニハンマーのものに関しては特にどのようなアレンジをしているのかを観察していました。投票の際には、激しく操作していく作品が好みだったようで、そういった作品に多く投票をしていました。', null, 'タイピング: しっかりと集中して取り込むことができていました。
盛り上がり: 自身の作品が入賞することができたということで、とても喜んでいました。'),
  ('30ba01a6-fbc0-541d-bf51-c63e43755241', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-30', '16:30:00', null, '通常 / アレンジ大賞を選ぼう', '入選作品から好きなものを選んでもらいました。最初は、一通り遊んでもらっても重しいものがないと選考放棄しようとしていましたが、アプローチを変えて何度も遊びを繰り返したゲームはと？聞いたところ、選んでくれました。好きな動きとかの判別には至らなかったです。次の親子大会には意欲的でした', null, 'タイピング: 久しぶりに進めてもらって、感覚を戻してもらいました
盛り上がり: やっぱ同じ時間のりょうや君の作品がお気に入りらしいです'),
  ('e4a4df76-8b13-5b8b-95e1-cd609a34e7f5', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-30', '16:30:00', null, '通常 / アレンジ大賞評価', '今回はアレンジ大賞の作品を実際に遊んでみて評価していきました。作品を遊んでいく中で、どの作品でどのようなアレンジがなされているのかを楽しみにしながら遊んでいました。自分ならどのようなアレンジを入れるのかを考えながら遊んでいて、とても楽しそうにしていました。好みとして、画面に動きがあるものが好きなようで投票していたものは動きが激しいものが多い印象でした。プログラミング大会の入賞商品に興味があるようなので、そちらの大会は入賞を目指していきたいようです。', null, 'タイピング: しっかりと丁寧に打つことができていました。
盛り上がり: 作品をプレイして様々なアレンジを体験することができて楽しそうでした。'),
  ('8fb2f145-a4f6-5c15-ad04-a4d8059d9b41', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-28', null, null, '通常 / 時間に関するゲームを作る', '作りやすい「5秒で止めろ」を選びました。スタートボタンを押した後の動きを問いかけると、時間が動き始めてストップボタンが出てくることに気付いたようでした。ストップボタンを出すためにはメッセージを送らないといけないこともわかったようでしたが、ストップボタンを押したときの動きまでは時間が足りず完成まではいきませんでした。', null, '時間帯: その他'),
  ('e4a09ecb-52d6-57b9-90b4-fc808e21af0a', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-25', null, null, '通常 / 検定練習', '前回で1回目をやったとのことで、「大変だったと思うけどだんだん慣れていこう」と声をかけて2回目に取り組んでもらいました。答え合わせすると、使うブロックは合っていたが入れる場所が間違っていたという場所がいくつかありました。「もし～なら」ブロックの中身はどこからどこまでかと聞くと、考えて修正できました。アレンジをする時間はなかったようですが、それより前がきちんとできていれば合格できるからまずそっちに集中していいことを伝えました。', null, '時間帯: その他
盛り上がり: 前回より成長を感じたようで少し嬉しそうでした。'),
  ('7a1ecfc1-f326-5b20-aa79-44331983d9f8', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-25', null, null, '通常 / 時間に関するゲームを作る', '時間に関するゲームを作ることにし、その中でもレベルが高いタイムアタック25に挑戦することにしました。最初の方は自力でできましたが、途中で詰まったので写経しながら作りました。変数の値を観察して、クローンの番号である[なまえ]と、今までにクリック出来た数である[かず]が一致していない(ように見える)のはどういうことかと質問してくれました。スプライトのローカル変数を更新しながらクローンを生成していくと、クローンごとに違うローカル変数が記録されて識別できるようになることを伝えました。そのことに若干戸惑った様子ではありましたが理解したようで、自分がそれまでに作ったコードにうまく組み込んで完成させることができました。', null, '時間帯: その他'),
  ('5dc292b7-5ac9-5044-b95f-247caa6d42e1', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-28', '17:30:00', null, '通常 / 単発のゲームを仕上げる', '親子大会と単発のゲームから後者を選びました。時々作成に詰まることがありましたが、「ボタンを押した後の動きは？」など問いかけると自分で考えて組み立てられました。途中、背景を変えるときに必ずステージにメッセージを送っていたので、どこのスプライトでも背景は変えられることを伝えました。一通り作り終わった時、成功しても失敗の背景に移ってしまうバグがあると報告してくれました。原因を探るうちに集中力が切れてきたようなので休憩してから再開すると、時間の変数の値が中途半端になっていることに気づきました。そこで、お手本のゲームにもある「変数の値を小数第一位までで四捨五入するテクニック」を教えると、それを使ってデバッグできました。', null, '盛り上がり: あまりモチベーションが高いわけではなかったのですが、休みを取りながらある程度メリハリを持ってできました。'),
  ('65cb707f-885c-5766-ae2d-924116e9585c', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-28', '16:30:00', null, '通常 / 基本操作コースを進める', 'スタンプを全部埋めることを目標として共有し始めました。背景を変える、画面の外からキャラクターが出てくるといった動きを作りました。使うブロック自体は知っていたようですが作り方に困っていたので、細分化をして、旗を押してからの流れを一緒に確認しました。x座標の数値を調整したりもして、座標の感覚もつかめてきたと思います。', null, 'タイピング: 「とっくん」を進めると熱心にやっていました。
盛り上がり: 隣のゆうさくくんが違う題材をやっているのに気を取られたりもしましたがなんとか自分の内容もできました。'),
  ('cccbd59b-63cd-5841-b977-9e94a6840e3f', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-28', '16:30:00', null, '通常 / 基本操作を身に着ける', '前回で基本操作06が終わったので、そのアレンジか別のゲームを作るか提示すると後者を選びました。原作は逃げる側を操作しますが、追いかける側を操作したいとのことでアレンジを加えながら作りました。どう作ればいいかわからないと困っていましたが、キャラクターの向きや動きについて元のゲームを観察してもらい、整理すると途中まで作ることができました。「～秒でどこかへいく」、「～を向く」のブロックは使い慣れていないようでしたが習得してもらいました。', '続き', 'タイピング: いきなり「うでだめし」に挑戦していて、難しそうでしたが楽しくやりました。
盛り上がり: がくくんが来るのがいつもより遅かったので、「もっと早く来てよー」と言っていました'),
  ('47fbc8c3-ab58-5243-9feb-b78afb3eda7c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-28', '17:30:00', null, '振替 / タイムアタック25(変数)', '八王子親子プログラミング大会の案内もしたのですが、今回はタイムアタックの作成に移ることにしました。 イチから作るのはかなり大変だなと感じたので、一度完成させてから中身を一緒に確認しました。プログラムの大枠は良くつかめていました（クローンや条件分岐） クローンの親分で色や大きさを変えること、判定などをおさらいしました。変数の使い方がかなり難しかったので紙に書いて確認しつつ、スプライトが持っている変数とプレイヤーがクリックしたときの変数の役割を見直しました。 最後に少しアレンジをしてもらいました！かわいいお花のアニメーションができました！', null, 'タイピング: 集中して取り組めました！'),
  ('9f995628-a4be-59ec-8b12-424cbc71472b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-28', '16:30:00', null, '通常 / 八王子親子プログラミング大会準備', 'プログラム作成に入る前に、去年の受賞作品を確認しました！さすが上級生。じょうたろうくんの去年の作品が気に入ったようです。 タイピングゲームを作ることになりました。ストーリーを設定する重要性を説明しつつ、リストを使ったタイピングゲームのプログラム方法を少し紹介しました。 リストは使い慣れていない様子でしたが、正誤の判断はしっかり理解できたようです。次回本編に進みます。', null, 'タイピング: 集中して取り組めました。'),
  ('e2412927-50b9-57a3-ab30-25bf87d79b84', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-28', '16:30:00', null, '通常 / 八王子親子プログラミング大会準備', '作品を作る前に去年の入賞作品を確認しました。さすが上級生！ テーマからきちんと決めることができました。すぐにプログラムに移る様子だったので、予め紙に書いておくようにお勧めしました。 瞼を動かして目を開くようなプログラムを作りました！スプライトの作り方はかなりアドバイスをしましたが、プログラムは自分でよく考えながら作成できていました。', null, 'タイピング: 集中して取り組めました。'),
  ('f8fa2dff-7de6-5ef7-89a1-5bc1dc05bee6', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-27', '16:30:00', null, '振替 / アレンジ大賞作品を完成させる', '家でがんばってみたけどわからないところがあったので完成していない、と言いながら来室しました。 隔週受講でもあるので、わからなかったところを学習しながら完成を目指しました。 手順書を見ていくうちに、どうしても「おまけ演習」がやりたくなって家でやってみたけど、背景が消えてしまった、と悲しそうにしていました。背景と、背景に似せたスプライトの違いや使い分けに気付けていなかったため、タイトル画面として表示するスプライトと背景の違いを一緒に確認していきました。時間がなくてタイトル画面はうまく活用できませんでしたが、違いについてはなんとなく理解したようでした。 時間とHPの変数を自分で作成していて、それを条件に使用してゲームクリアとゲームオーバーを作りたかったそうですが、変数の増減までは自力でできても、それを使った演算式や制御ブロックとの組み合わせがあやふやでした。なんとなく、これを使うのではないかというところまでは合っているのですが、条件分岐と～まで繰り返す、～まで待つなどの使い分けをもう少し慣れていきたいところです。 あるスプライトでの動きを受けて別のスプライトや背景を変えたいという要望が多かったので、メッセージの使い方を徹底的に学習し、最後の方では自力でどんどん進められるようになりました。', null, '盛り上がり: 制御ブロックの学習のあたりで、「先生に教えてもらってばかりで自力でアレンジできていない」としょんぼりし始めたので、この作品でわからないところを学習していけばいいのだと言うと、ほっとしたようで、こちらの解説もとても熱心に聞いてくれるようになりました。何度も使用したメッセージやパーツの背面、前面への移動についてはかなり慣れてきたようで、最後の方ではほぼ自力でできるようになり、満足そうにしていました。'),
  ('dc4e694b-4e10-5c77-b584-269fa56fb920', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2024-05-27', '17:30:00', null, '休み（未対象）', null, null, '備考: 宿泊遠足とのこと。前日21時にご連絡あり。振替未対象？'),
  ('c9acd493-5d5d-54a4-8ae9-4dd6d53cbbed', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-27', '17:30:00', null, '通常 / 検定練習', '親の希望で検定問題に取り組みました。3級の問題にチャレンジしました。10分に余らすほど、余裕そうでした。終わった時も得意げに報告してくれたので、検定のような形式は向いているそうです。親子大会も同時並行で進めるので、来週までにアイデアを考えてくるそうです。', null, '盛り上がり: 目を離したすきにスクラッチでゲームしていることが目立ちました。'),
  ('173b6a8f-1792-5aa1-b347-34237e419772', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-27', '17:30:00', null, '通常 / タイマーについて詳しくなろう', '30分ほど遅刻したので、5秒のゲーム軽く見てもらいました。このゲームの肝である、桁数を決める四捨五入の使い方の意味を考えてもらいました。答えることはできたので、理解は進んでいました。', null, null),
  ('677da2d4-85ca-531b-91cf-9f6d7695d5b6', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-27', '16:30:00', null, '通常 / 親子大会へのアイデアづくり', '親子大会に向けてすでに作りたいアイデアがあったので、それについて話し合いました。八王子の機織りのゲーム作りたいそうで、まずはゲームの大まかの流れを紙描いて作っていきました。クイズ形式で進む層で鵜s。ここで、一番の問題のとなったのが、機織りをどのように見せるかの構図を悩みました。すべてを描こうとするとイラストにできないので、必要な部分に絞って、表現することにしました。また、紙に織る作業をイラストで共有できたので、大方はやりたいことが固まったので、次回から作れそうです。', null, null),
  ('c9798560-d7cf-52c4-81e0-5f2c74e89202', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-05-24', '17:30:00', null, '通常 / 時間テーマのゲーム制作の予定が、タイピングデーに変更', '今日はタイピングデーと自分から宣言したので、それを尊重しました。', '連続してタイピングの練習して、スキルアップしようと声かけしてください。', 'タイピング: タイピングをやろうと、ももたろう始めたらハマってしまい。本人が「今日はタイピングデー」ということで、３０分やり続けました。 ローマ字の一つ一つは大文字小文字を概ね理解しています。言葉で入力ができないので、帰りにお母さんに状況伝えました。今後、せっかくローマ字がわかるので、単語で入力できるようになるために、毎回タイピング頑張ろうか、となりました。'),
  ('5868d8ba-cd4a-5f18-90dd-9dc90ff77c5e', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-05-24', '17:30:00', null, '通常 / 「時間」ゲームに興味持っもらう', 'どうしてもスマブラをやりたいというので、スキル敵には冒険すぎたのですが、やることに。途中、変数の名前を入力するのもままならなかったのですが。必死にアルファベット票をみながら入力しており。「入力だけ先生手伝うよ」というも、かたくなに自分で取り組もうとしていたので。本人の好きにさせ。わからなかったら聞いてね、スタイルに切り替えました。 スマブラのキャラクターをオリジナルにしたい（「ニワトリ登場」）という意欲もかなり高いです(^^)v お父様がお迎えに来たので。本人がかなりレベルの高い作品にチャレンジしたがったので。なかなか大変ですが、やらせてますと報告。お父さんから「最後までやりきれよ」と言われていました。', 'スマブラの続き→手順書をみながら。最初の１P目。キャラクターを変えたので、ネコという単語をトリに変換するのに、やや苦戦してました。', '盛り上がり: とにかく、必死でした(* ´艸｀)'),
  ('78a56695-bdf5-5037-8e43-8f53c7e5f401', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-25', null, null, '通常 / アレンジ大賞', 'スマブラのバグを確認していきました。以外にも猫のペンギンの入れ替えができていない所が合って直しましたが、それでもバグは残ってしまいました。先生とともに待たせるのもったいないので、途中でタイマーのゲームをやらせたが、コードはあっているが見つかりませんでした。ペンギンの吹っ飛び半手気が上手くいかないことです。', null, '時間帯: その他
盛り上がり: 待ち時間に5秒と目にはまってくれました。'),
  ('e7c22a9a-2f5d-5e64-8fa7-7e09e7b1a323', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-25', null, null, '通常 / アルスタジオ/検定練習', '前回の2級1回目は余裕でしたが、2回目の問題はレベルが上がるのでやってもらいました。結果としては全くミスなくパーフェクトでアレンジもできていました。「(じゃんけんで)自分が相手に勝ったら」という部分は、自分で条件をかみ砕かないとできない難所ですが、「かつ」「または」を駆使してきちんとできていました。 もう少し検定問題を家でやりたいとのことだったので、問題文のプリントとsb3ファイルを渡しました。', null, '時間帯: その他
盛り上がり: まだまだ余裕をもってやりきれているのを感じました。'),
  ('9ac25e32-30d2-5db8-b8f3-64637293feb2', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-25', null, null, '通常 / 親子プログラミング制作', '親子プログラミング大会への提出作品の制作を始めていきました。アレンジ大賞へ作品を提出した時点でストーリーを重視した内容となっていたため、その部分をさらに伸ばしていきたいようです。ノベルゲームのようにスタート前に文字を出して物語を説明している場面や、キャラクターが喋っていくことでプレイヤーが楽しめるような工夫を施していました。今回の制作でやりたいことはある程度決まったようなので、この調子で自分自身のアイディアを入れていきたいようです。', null, '時間帯: その他
タイピング: 間違うことがないように打つことができていました。
盛り上がり: 作品にやりたいことを次々と入れることができて嬉しそうでした。'),
  ('22385c80-d235-5fa5-82fc-bb35ac6b8ee8', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-25', null, null, '通常 / タイマーの応用を学ぼう', '5秒で止めろのゲームを簡単に作れると意気揚々で作り始め、桁数の絞り方に四捨五入を使うことに気づいて、目の付けところは良かったです。ただ、スクラッチブランクでボタンのやり取りの際に、メッセージの存在を忘れていました。教えると、使い方を忘れているわけでもないので、うまく使いこなせました。最後までがんばってねばりさせ、完成までとはいきませんでしたが、10倍１０分の一の発想に感心してました。', null, '時間帯: その他
盛り上がり: 今日は運動会だったので、自由にだらけた姿勢でも寛容に許しました。'),
  ('fb2c47cd-dfde-5a5c-b9f6-e1a6fa396703', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-25', null, null, '通常 / アレンジ大賞をもう一度', '親子大会と単発ゲームの話をみんなと一緒に聞いてもらいましたが、アレンジ大賞をもう一度やって完成させたいと申し出てくれました。家で取り組んだもののバグが取れず困っていたそうです。そこで一緒にバグの動きから原因を特定していきました。手順書の通りにやったつもりなのに技のコスチュームが変わらなかったことがわかりました。手順書の中でそのコスチュームを変えているはずの場所はどこなのかを問いかけると、その場所を探してそこから間違いを見つけ出せました。そしてバグが直ったのでようやくアレンジの作成に集中でき、特定の条件で背景を変えたり技のコスチュームを追加してみたりと色々試していました。', null, '時間帯: その他
タイピング: タイピングをするのは久しぶりながらある程度速く打てていました。
盛り上がり: 最後までやり遂げたいという思いからか、いつにも増して真剣でした。'),
  ('f8a795dc-8465-54e7-8cda-bc1074e712f5', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-25', '16:30:00', null, '通常 / Excel練習', '今回は、Excelの問題集を解いていきました。初回ということもあって、内容は関数を使うこともなくセルの選択などを基本的に行っていました。本人的にもこの内容は難しくないようでスラスラと詰まることなく終えることができていました。本人が様々なものに対しての理解度が高いこともあってか、次のページにもある内容を見て理解することができていました。次回Excelを使っていく際にも今回のように順調に進めていくことができると思います。', null, 'タイピング: しっかりと打つことができていました。
盛り上がり: 問題をスラスラと解いていくことができたため、楽しそうでした。'),
  ('516d0c7d-03e2-5ec7-b044-a0f5818eb913', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-25', null, null, '通常 / タイマー関連の知識をつけよう', 'タイマーのゲームについて遊びは、ぴったり止めるのは上手でしたが、1から25まで止めるのはかなり苦手の印象でした。ぴったり止める方で作り始めると、ボタンでのメッセージやり取りはできましたが、やる気が上下が端いので、スムーズには進みませんでした。そこで、キーとなる条件式のところだけを穴抜きしてコードを見せながらやったら、そこではやる気がわいて、しっかり考えて完成させることができました。', '最後の方に話していたアレンジ大賞が未完成な話は授業中では聞かなくて、最後に知りました(下迫田)', '時間帯: その他
盛り上がり: 初見2回目で5秒ぴったり止められて、その後も成功率がたかったです。'),
  ('51c0deeb-a7ed-59e9-9ff1-fceb9731d5d9', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-25', '16:30:00', null, '通常 / 親子プログラミング制作', '親子プログラミング大会への提出作品を作り始めました。カニカニハンマーにて作品の中にバトル要素を加えていきたいようで、カニをビームを使って倒すようにしたいということでその部分を作っていきました。ビームをクローンして端やカニに当たった際に消えるというプログラムを作っていきました。内容が少し難しかったようで、イマイチ理解ができていない様子でしたがコードの内容を読み直していくことでなんとなくではありますが理解することができていた様子でした。しかし、コードについては未完成のまま終わってしまったため、次回作っていく際にはその部分から入っていく予定です。', null, 'タイピング: 基本的な部分をしっかりと打ち込むことができていました。
盛り上がり: コードの内容を理解できていない状態から、理解していくことができたため納得することができていました。'),
  ('eaf2bce2-8e49-5dc2-baed-1ded93ad1c70', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-25', '17:30:00', null, '通常 / 親子プログラミング制作', 'アレンジ大賞に提出した作品をアレンジしていき、親子プログラミング大会への提出作品の作成を始めていきました。時間内でとにかくたくさんのアイディアを出していこうと頑張っており、思い浮かんだものはとりあえず作品内に取り入れて試していました。アイテムの追加やカニを倒していく案、キャラクターへのバフなど様々なものを思いつくことができていました。本人のやる気はかなり高いため、この調子で制作を続けていくことができればかなりクオリティの高い作品を作り上げることができそうです。', null, 'タイピング: 詰まることなくしっかりとうつことができていました。
盛り上がり: 作品のアイディアを次々と出していくことで、自分の納得のいくものを作り上げようと頑張っていました。'),
  ('80cf1f06-8693-57b7-8636-9d01f65dba81', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-25', '16:30:00', null, '通常 / 基本操作コース04_追跡ゲームアレンジ', '前回作ったゲームを確認しました。前回のプログラムに少しアレンジを加えましたが、もうすでにオリジナル要素が多かったので前半のみで終わりました。 後半は、「～へ行く」と「〇秒で～へ行く」のプログラムを使って銃弾を動くようにしました。銃弾の動きをもとにひとつずつブロックを置いていこうと思いましたが、あまりよく理解ができなかったようです。 ゲームエンドのプログラムを作りました。撃った回数と当たった回数をカウントしてゲームクリアとゲームオーバーを作るプログラムを終盤に作成しようとしましたが、終わっていません。', null, 'タイピング: 集中して取り組めていました。'),
  ('1bd31996-3958-5bec-bdce-b708bf8e43a2', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-25', '17:30:00', null, '通常 / 5秒で止めろ！（コード確認、アレンジ）', '八王子親子プログラミング大会の説明の後、5秒で止めろ！に取り組みました。イチからプログラムするには少しハードルが高かったので、見本をリミックスした後にコードを一緒に確認しました。メッセージの送られ方などおおよその部分はなんとなく理解できている様子?でした。判定の部分（~でなければを使っている部分）については強調して説明しました。 後半は、けいとくんと一緒に楽しくアレンジを加えました。スプライトを出したり、音を加えたりして自分なりの作品を作りました。小数点以下の桁に関しても検証することができていました。', null, 'タイピング: 集中して取り組めました。'),
  ('055ebf07-3d4d-59e2-bfbd-b9129209dd30', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', '17:30:00', null, '通常 / アレンジ大賞の作品をアレンジ', '前回作ったものをパワーアップさせていました。演出に凝っていたようです。また今回は取り組みませんでしたが、勝利モーション（ムービー?）にも取り組んでみたいと言っていました。 炎がメラメラする演出ですが、特定の時間キーを押し続けていると出たり出なかったり(!?)するようです。本人も悩んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('680d7a8d-a998-503d-86c8-af802d0d0610', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', '17:30:00', null, '通常 / 5秒で止めろ！（コード確認、アレンジ）', '八王子親子プログラミング大会の説明をした後、バックパックを使って見本を持ってきてプログラムを作成しました。途中動かなかったのですが、自分なりに考えてミス（メッセージ名）を発見することができました。プログラムの中身もほぼ理解できていた（定義は難しい様子）ので良かったです。 後半は小数点以下の桁数を変えてみたり、邪魔するスプライトを追加したりしてアレンジをしました。ゆづきくんと相談して楽しく取り組めていました。授業後にははるくんに遊んでもらい、公開もしました。', null, 'タイピング: 集中して取り組めました。'),
  ('3cfe8cf9-78e8-5ac1-8d1d-e079410d31eb', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', null, null, '通常 / タイムアタック25', '他の誰も作っていなかったのでリクエストして作ってもらいました。 数字が重ならないように出現するプログラムが少し難しかったので一緒に見本を確認しました。単純なプログラムでしたがずっとともしを効果的に使っているプログラムだったので、本人も興味深そうに見ていました。着眼点が良かったです！ 一方でクローンは少しプログラムが甘い箇所（非表示。表示）があったので少しコメントしました。大枠はよくできていました。', null, '時間帯: その他
タイピング: 集中して取り組めました。
盛り上がり: バイクランの最高記録を伸ばし続けています。'),
  ('8a37f0e1-3fc6-5f1a-8e5f-3dcb7241a446', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-25', null, null, '通常 / 八王子親子プログラミング大会の準備', 'スプライトから丁寧に作品していました。テーマの話も伝えましたがどこまで理解できているのかは分かりません...日本刀をもっているキャラが出てきたので八王子刀??を提案してみました。 授業始まったころは大会参加に少し後ろ向き(不安だったのかな?)でしたが、最後には「家でやってもいい？」と聞いてくれました。まだかなり時間があるのでやらなくていいと伝えましたが、家でもいろいろ考えてきてくれそうで嬉しいです。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('ee6ddeb6-7cf8-50bc-a8b0-b037bb1274a2', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', null, null, '通常 / アルジュラパーク', '見本を見ながら作成してもらいました。クローンと表示が大きくなっている箇所のプログラムについて質問したところ、しっかりと答えられていました。また最後にはプログラムの終了判定について一緒に確認しました。 アレンジまでは時間がありませんでしたが、もとの作品と同じように完成させることができました！', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('6d7912c0-7ac9-51ab-9eed-3638f8ae1cd0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', '17:30:00', null, '通常 / 八王子親子プログラミング大会の準備', '八王子親子プログラミング大会の準備をすることになりました。 前回作った脱出ゲームの雰囲気がかなり気に入っている様子で、今回はホラー要素を取り入れつつ、ミニゲームを各所でクリアしていく作品になるようです。 今日は構想に加えてオープニングムービーを作っていました！たまにけいとくんの会話に入りつつも集中して取り組めていました！', null, 'タイピング: 集中して取り組めていました。'),
  ('20565901-7417-5425-a57d-8550a1faeb5d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-24', null, null, '通常 / 5秒でとめろ！', '見本を見ずに挑戦してもらいました。変数の作り方や条件分岐はよくできていました。タイマーの使い方が少し分からなかったようですが、完成品を見たところ見本よりもシンプルなコードで作れているのかな?と思います。', null, '時間帯: その他
タイピング: 集中して取り組めました。
盛り上がり: かにかにハンマーをコンテストでやりたいそうです。（得意らしい）'),
  ('80b5cb7c-0611-5f4a-a378-ae40db1f6064', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2024-05-23', '17:30:00', null, '休み（未対象）', null, null, '備考: 遅刻のご連絡がありましたが、間に合わなかったのか、来室はありませんでした。'),
  ('e2dbbcf1-0967-5e85-b150-e4bf267208e2', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-23', '16:30:00', null, '通常 / アレンジ大賞作品の完成', '前回終了時には、もうこれで完成でいいや、といった感じでしたが、今日になって精度を上げたくなったようで、1時間以上集中して手直しをしていました。 登場するキャラクターを10秒ごとに切り替えるようにした際、つぶれたスプライトをどう切り替えるか、など、これまでは適当に済ませていたところの改善を頑張って考えていました。 まだ使用できるブロックが少ない中で、ひたすらメッセージを駆使して思い通りに動くように工夫をしていました。 景品がとても気に入っていたようで、優勝したいなあと何度もつぶやきながら、時間いっぱいあきらめないで、きちんと動くコードを完成させていました。', null, '盛り上がり: 少しでも高評価をもらいたいと、最後まで投げ出さないで熱心におかしいところを直す集中力が素晴らしかったです。'),
  ('f60901c9-93f3-5ecd-b639-e59c8542baf6', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-23', '16:30:00', null, '通常 / 基本的なゲームの細分化をする', 'アレンジ大賞の作品を少し見直して「完成」となったので、最近頑張っているから次のステップに入ろうと声掛けをすると、何をやるのかと食いついてきてくれました。 教材を提示すると、「前にお姉ちゃんがやってたやつだ！自分もこれができるようになったんだ！」ととても喜んでいました。 今回はアレンジではなく最初から作るということで少し不安そうにもなりましたが、口頭での細分化は一生懸命に考えることができていました。 ダイヤに触れたら隠してどこかの場所にいく、など、ブロックにある言葉を使って説明することもでき、そこを褒めると嬉しそうにしていました。 えみちゃんが、脱出ゲームの背景などを既存のスプライトではなく他から持ってきているのがうらやましかったようで、キャラクターをマリオにしたい、というので、アルスタジオのマリオゲームからスプライトを流用しました。途中でやり方を覚えて、自分で熱心に取り込んでいました。 コードの作成に入るところで、他の子のアレンジ大賞作品発表会になったために中断しました。', '【Prg】08 海にしずんだダイヤを探せゲームを作ろう！のコード作成から', '盛り上がり: まだ少しずつではありますが、自分が理解できること、自力でできることが見えてきた実感があるようで、ひたすらおしゃべりしながらではありますが、手を動かすこともできるようになってきました。自分で考えようという姿勢も、以前よりよく見られるようになっています。遊ぶだけではなく、作ることも楽しいと感じることができていたと思います。'),
  ('c919a35c-db6d-5d69-ae01-99faee011aa7', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-23', '17:30:00', null, '通常 / アレンジ大賞の完成、検定1級のお試し', '今日はアレンジ大賞を修正してもいいことを伝えると、前回残ってしまったバグを直す作業に入りました。スプライトの表示する/隠すが上手く制御できていないようでした。一人では大変そうだったので一緒に原因を探ると、背景の番号の指定方法が間違っていたことが判明し、直すことができました。バグもなくなって完成させられました。 時間が少し余ったので、検定1級の受検を見据えて問題を試しに解いてもらうことにしました。問題文にリストが出てきて、ちゃんと使うのは今日が初めてのことだったので、リストについての基本的なブロックを教えると使い方を理解したようでした。 今日検定の問題を解けたのは20分間だったので、残りの(50-20=)30分間を次回でやることになりそうです。', '検定続き(30分)', null),
  ('8804b818-ed70-56e3-9bd1-43692889e7aa', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-23', '17:30:00', null, '通常 / アレンジ大賞', '休みもあり、学校も忙しくアレンジする暇がなかなかありませんでした。スタート画面の操作方法を作ろうとしましたが、時間が来てしまいました。アレンジ大賞はここまでかとしれませんが、ほかのコンテストを目指してほしいです。じょうたろう君のお母さん的には無駄にせず作ってほしいそうです。', null, null),
  ('0453c1da-88f5-54e1-8ae6-dc17c63c81aa', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-23', '16:30:00', null, '通常 / アレンジ大賞の完成', 'ゲームの本筋はほぼできていたので、プレイヤーを混乱させるダミーを作っていました。完成すると、周りの子にテストプレイしてもらい、「部屋を一つ戻れると嬉しい」とのコメントに応じて、戻るボタンを実装していました。完成度を高めて終わることができました。', null, '盛り上がり: 作品をみんなに楽しく遊んでもらって嬉しそうな様子でした。'),
  ('4e0f2882-2224-57de-be60-97fa218f0572', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-23', '16:30:00', null, '通常 / アレンジ大賞', '花のデバックは勘違いで、直せていたした。とりあえず、ゲームの流れを先に完成させようと促しましたが、ヒントの制作に取り掛かりました。ひんとのボタンからコードの順序はこちらから指摘することなく自力で作り上げていました。最後に、ゲームクリアの際に対応する変数が異なっていたので、そこは修正しながら、笑顔に校門から脱出することができ、完成できました。', null, '盛り上がり: 細部までの画像のこだわりがよくて、見栄え演出がよくなっています。'),
  ('de7621ea-97cc-5c62-ad53-0202c4f0cb83', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-23', '16:30:00', null, '通常 / アレンジ大賞の完成', '今日もう一回アレンジ大賞を修正してもいいよと伝えると、時間が経過するごとにメッセージを表示するようにしたいと言っていました。それの作り方について少し困っていましたが、すでに作った「時間切れになったときの処理」と同じ流れで大丈夫とヒントを出すとできました。体の大きさを小さくして逃げやすくしていますが、定期的に大きさを強制的に戻されることでゲームバランスを保つ工夫もできていました。最終チェックをして、本人が満足できる完成度で終わることができました。', null, '盛り上がり: 隣のこたろうくんに自慢げに見せていました。'),
  ('a3405faa-55b5-572c-ae42-441e56d6ad51', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-21', '17:30:00', null, '通常 / アレンジ大賞をアレンジしてみる スマブラ・カニカニハンマー', '最初はスマブラに取り組みました。新しくスプライトを追加するように伝えましたが、プログラムの内容が難しかったようでアレンジが進んでいませんでした。趣向を変えてカニカニハンマーをアレンジすることにしました。 もとの内容に干渉することなく、音や見た目のプログラムを作成できていました！かなり面白いゲームになり、本人も嬉しそうでした！良かったです！！', null, null),
  ('05f682dd-7bfc-553c-973b-90cc88995a56', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-21', '17:30:00', null, '通常 / アレンジ大賞脱出ゲーム', '前回から引き続き取り組みました。猫と鍵を両方取ったときに出る特別演出に少し困っていたようなので、せいぎょのブロックの使い方についてアドバイスをしました。演出画面についても、ゴールが分かりやすいように工夫するように伝えました。 他にもうまくいかないことが多々あったようですが、ほぼ自力で解決できていて良かったです。集中して取り組めました。', null, null),
  ('2bcaec68-3981-5a37-b11f-71f1ac300c95', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-21', '16:30:00', null, '通常 / 基本操作コース06物語', 'ほぼ休憩なしで最後まで頑張っていました！ 話すプログラム、交互に話させるプログラム(〇秒待つ)、クリックしたときに色を変える、録音するなどをメインにやりました。話している間に待つのは新しかったようです。録音も楽しくできていました。最後に移動をさせるプログラムを作成しましたが、まだ座標はかなり苦手な様子です。', null, 'タイピング: 初めて挑戦してみましたが、あまり好きではなかった様子です。プレイグラムの方がいいかもしれないです。
盛り上がり: 授業後にゆうさくくんと楽しく遊んでいました！'),
  ('3977825e-d483-5a23-ac45-5ae3602e2b07', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-21', '16:30:00', null, '通常 / 基本操作コース06 物語', 'スプライトの色変更にかなり時間を割いてしまったので、あまりプログラムは進みませんでした。話す順番を整理してメッセージを一度やってみました。少しわかりにくかった様子です。また最後に背景が変わったときの表示非表示をコントロールしました。ひとつのスプライトを考えられると、同様にして他のスプライトについても考えられていて良かったです。非表示にした後の表示を忘れてしまうので、次回以降また取り組みたいです。 オリジナル作品を作る？？かもといったところです。', null, 'タイピング: あまり好きではない様子でした。プレイグラムの方がいいかもしれないです。'),
  ('c29b7b67-d6f6-5b0f-8893-43b70aa8352f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '16:30:00', null, '通常 / アレンジ大賞', '前回でアレンジ大賞の内容を完成させることができていたので、今回は別のアレンジ大賞作品を遊んだりコードを見たりして、作品のアレンジ内容について考えていきました。一通りやってみて、カニカニハンマーのアレンジに取り組んでいました。キャラクターを変更したり、障害物を追加することで難易度の上昇を試してみるなどさまざまなことをおこなっていました。結果的には、アレンジをしっかりと行うことができ、本人の創造性を刺激することができたと感じています。しかし、アレンジを決めた理由がなんとなくなど明確に決まっているものが少ないため、その部分を明確にすることができれば今後さらに成長することができると思いました。', null, '盛り上がり: アレンジにてやりたかったものをしっかりと入れられた様子でした。'),
  ('a0e9ba58-d9df-5590-8b9a-0db9847c8528', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '16:30:00', null, '通常 / アレンジ大賞', '今回は、残っていた部分の修正とアレンジ部分の仕上げをおこなっていきました。作品の修正に関しては、ほとんどつまづくことなく順調に進めていくことができていました。アレンジ部分に関して、決めていたアイディアなどがなかったようで何を入れるか非常に悩んでいました。なので、キャラクターや背景のデザインを変えていくところから始めていきました。その結果、デザイン変更にかなりハマったらしくアレンジ部分をデザイン変更へと決めて、最後までアレンジを完成させることができていました。', null, '盛り上がり: アレンジ部分の完成と、作品の理解度を深めることができていました。'),
  ('1960d62b-3c07-5edc-a5ec-073e2f78b82d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '16:30:00', null, '通常 / アレンジ大賞', '前回までで完成させていた内容をさらに発展させていきました。今回は、ギミックの鍵を獲得する場所を謎を解く前にタッチした場合に鍵を獲得してしまうため、鍵を獲得することができないようにギミックを変更していました。作業はかなり難航し、さまざまな箇所を手治していくことでコードの流れを掴みながら修正をしていました。そして授業時間が終わっても考えており、最終的に２時間かけてその部分を終えることができました。この作業が終わったことで、作品は100％完成したらしいので発表の回を楽しみにしていました。', null, '盛り上がり: 今日1日をかけて作業に取り組んでいたため、完成した際にはとても喜んでいました。'),
  ('1feb2b2a-93f4-5e94-887b-f5bb8cfe7e81', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-20', '17:30:00', null, '振替 / アレンジ大賞作品の完成', '家でやりたいアレンジを考えてきたということで、お母さんから授業前に補足の説明がありました。その後でのあくん本人にも確認しましたが、本人もきちんとやりたいことを言語化できていました。 時間をカウントダウンしていって、0になったらゲームを止めたいとのことで、カウントダウンまでは作成してきていました。0になったら止めるのがわからないということで、「ずっと」で繰り返していたカウントダウンを、いつまで繰り返せばいいのか、ということで考えさせました。○○まで繰り返すを使うというヒント、演算式の作成のやり方を教えると、そのあとは自分で考えて作成することができました。 コインをとったらスコアが増えてコインが消え、しばらくしたら復活するという動きを作りたがったので、コインに触れたあとにやりたいことを口頭で細分化し、一つずつ作るように促すと、ほぼ自分で作成することができました。 やりたかったことが完成して時間が20分ほど余ったので、時間の初期値を検討したり、背景としてのスプライトを足したりと思う存分楽しんで作成を終えました。', null, '盛り上がり: やりたいことを細分化すると（本人には、まだその意識はあまりないようですが）これまでの知識で作成できることが多いことに、なんとなくではありますが、自信が持てたようでした。 考えてきたことがきちんと実現できて、満足そうでした。'),
  ('6403e31a-6da1-5425-bce1-7d4ecd488a5b', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-20', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '来室時から、今日の完成を目指して熱心に作成していました。 各ステージの作成なども、自分できちんとイメージできているようで、しっかりと自力で作成できていました。 最後の方のステージを、特定のボタンが押されてからでないと進められないようにしたいということだけ、具体的に質問をしてきました。 他の脱出ギミックと同様に、クリアしているかどうかの判定のための変数を作ってはどうか、というヒントで大体わかったようで、変数作成、初期値の設定、条件を満たしたときに変数を1にする、というところまでは自力でできました。その後どうするか、というところで質問をしてきましたが、ステージが進められる条件のコードを探させて、対話していくうちに理解できたようでした。 最後はミニゲームで出てきたスプライトを全部表示させるエンディングを作成して、満足そうに作成を終えていました。', null, '盛り上がり: 終始熱心に、たまにノアくんからの会話に答えたりしながら、楽しそうに取り組めていました。 こちらの口頭でのヒントをすぐに理解して、その後の作成が自力でできることも満足そうに見えました。'),
  ('673dc594-6a0a-52d5-bec6-10c004c78705', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-20', '17:30:00', null, '通常 / アレンジ大賞脱出ゲーム', '時間中ずっと集中して取り組んでいました。かなり大きなアレンジがされていて完成がとても気になります。時間が足りず完成しませんでした。残りは家でやる（木曜日中にはやるように伝えました）そうです。途中まででも確認したかったのですが断られました...', null, null),
  ('9a3ddf95-0c26-55dc-a1a5-fc76ff427a71', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-20', '17:30:00', null, '通常 / アレンジ大賞脱出ゲーム', 'ラジオが飛び出てヒントを言うプログラムを作成しました。考え方の道筋は何度も示しましたが、「分からない」ばかりで、こちらとしても対応が難しかったです。 変数を使うことは理解できたようですが、変数をコントロールするプログラムの考え方が少し難しかったようです。一方で、ヒントを言うラジオのプログラムは自分で考えて作成することができていました。完成しました。', null, null),
  ('238f4d2d-b0c7-5eba-9395-80f9b07935db', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-20', '16:30:00', null, '通常 / アレンジ大賞スマブラ', 'まだアレンジに入っていなかったので、見本の紙をみつつプログラムを整理しました。キーのプログラムが間違えていたり、数字が数字として認識されているのかを確認してもらいました。それでもペンギンのダメージが入らなかったので、一緒にプログラムを見直し、ペンギンのダメージに関連するプログラムを確認しました。 またアレンジとして、盾を追加しました。うまく縦が追随するようにプログラムし、上必殺以外の攻撃がはじけるようにしました。 授業時間が終わってもペンギンのダメージが入るようにならなかったので、原因についての自分なりの考察をネコのスプライトのコメントに記入してもらいました。 投げ出すことなく、最後まで頑張っていました！', null, null),
  ('40917567-696a-598a-93d9-4dcdfdd63087', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-20', '16:30:00', null, '振替 / 基本的なブロックを活用する', '宇宙バトルとゾンビをたおせをプレイして、宇宙バトルを選んでいました。 基本的にはレッスンのチュートリアルを活用しましたが、一人で熱心に視聴しながら自力で進めることができていました。 ベーシックの最後までしっかりと進めてから、自分でクリアやゲームオーバーのスプライトを作って表示させるなど、楽しそうにアレンジをしていました。 一つ完成すると先生を呼びに来て、嬉しそうに見せてくれていました。 作成中の自走は基本的によくできていました。', null, '盛り上がり: 自分のアレンジがうまくいったことが嬉しそうで、何度も得意げに見せてくれました。'),
  ('c1e3be40-52fb-5038-85b8-498a4162cf79', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-20', '16:30:00', null, '振替 / 基本操作コースをすすめる', '振替でいつもと違う曜日なのが緊張したそうで、お母さんに抱き着いて泣きながら来室しました。ドアのところでお母さんにしがみついて、行かないで！！となっていましたが、中まで入らなくていいからロビーのところで少し遊ぼうと声掛けをし、ドラえもんの絵描き歌を教えてボードに描く間に気分が持ち直したようで、その後は自分でスリッパを持ってきて中に入り、ご機嫌で授業を受け始めました。 アレンジ大賞は完成しているからもういい、とのことで、基本操作コースを学習してスタンプを押すことを目標にしました。 スプライトの色を変えたり声を録音したりするのも、提示するたびに「それはやらなくていい」などという反応を見せましたが、スタンプが押せないとわかると、がんばってやってみる、となり、結局は楽しそうにできていました。 スプライトを押すと色が変わるのが気に入ったらしく、たくさんスプライトを出して、全部同じコードを丁寧に作成していました。 声を録音するのは恥ずかしそうだったので、やまとちゃんに録音してもらったセリフがとても気に入って使いまくっていました。 最後に、途中からライオンが登場して指定した場所まで動くコードを作成し、それが思い通りの動きだったようで、とても喜んでいました。', null, '盛り上がり: 最後に作成したアニメーションが、自分の思い通りに動いたことが相当嬉しかったようで、目を見開いて大喜びしていました。'),
  ('825d20a3-7040-56ba-95b9-5cd4ce3d9dab', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / アレンジ大賞の完成を目指す', '手順書の続きからやりましたが、ネコのコードをペンギンにコピーするときに変数やメッセージを変えない状態で困っていたので、「例えばここの変数は違うものに変える必要があるんじゃない？」などとヒントを出すとそれ以降自分で考えてできました。それとは別のバグも発生して原因がつかめなそうだったので、バグの内容から怪しい場所を絞り込む作業を一緒にやり、無事に直りました。教室に来られる回数が少なかったこともありアレンジまで行けなかったので、家で完成させて賞を狙うか後でゆっくり完成させるかを提示したところ前者を選びました。', null, '時間帯: その他
盛り上がり: 少しでもたくさん進めようと頑張っていました。'),
  ('35ac485a-b350-5bcc-b639-756e268c23a0', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / アレンジ大賞の完成を目指す', '今日は最初からアレンジをやりました。キャラクターの動きに応じて演出をつけたりしたいとのことで、そのためにキャラクターの座標をリストに入れて管理していました。新しい技も追加するとのことでその技の見た目もデザインしていました。', null, '時間帯: その他
盛り上がり: レッスン時間が終わっても集中して1時間くらい作り続けていました。'),
  ('a2eebd3a-7e1e-5226-87e1-39d4988e4946', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', null, null, '通常 / アレンジ大賞', '前回の続きで手順書の内容を作っていきました。授業内では黙々と制作に取り組んでおり、とても集中している様子が見て取れました。作業内でつまづく様子もなく作り続けられており、授業内にて手順書の内容を完成させることができていました。しかし、アレンジ部分に関しては触れていくことができなかったようで、その部分に関しては自宅で作っていくことで、作品の完成を目指していくようでした。', null, '時間帯: その他
盛り上がり: 手順書部分のみではありましたが、作品を完成し終えることができたため、ひとまずは安心していました。'),
  ('12f9977b-b3a1-5b5c-8355-09bda7773b47', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / アレンジ大賞の完成を目指す', '手順書の続きからやりました。メッセージや変数も理解しながら作っていき、自分なりのペースですが手順書の内容は終わりました。アレンジはほとんどできなかったのですが、家で完成させるとやる気でした。おじゃまキャラを作りたいと言っていました。', null, '時間帯: その他'),
  ('f66ac95b-0ff8-5502-a0ac-91ff249f4b5b', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', null, null, '通常 / アレンジ大賞', '前回までおこなっていたアレンジ作成の続きに取り組んでいきました。キャラクターの動きやスコアなどではなく、ゲーム自体のストーリー性を大事にしていきたいようで、なぜこのような状況になっているのか、ゲームオーバーとなったらどのような結果となるのか、キャラクター同士での掛け合いなどをアレンジにて取り入れていました。その結果、視覚的なインパクトは抜群であり、ゲームとしての面白さも上がっている様子でした。そして、この授業内にて完成させることができたことは本人にとっても驚きだったようで、スムーズに作ることができたと喜んでいました。', null, '時間帯: その他
盛り上がり: 作品としての完成度や、作業スピードの意外さに驚きながらも喜んでいました。'),
  ('6397a45b-b352-56fb-ad0c-b268eee76ae4', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / アレンジ大賞の完成を目指す', '勝敗をつけるところができていなかったのでそこから始めました。手順書でもやり方は伏せられていたので考えてもらいましたが、案外苦戦したようでした。どちらかが落ちたら勝敗がつくことはわかったようですが、「落ちたら」をどう表現するか迷っていました。ヒントとして「何座標がどうなったら落ちる？」と問いかけると腑に落ちたようで作れました。 アレンジとしては小技の体力ゲージを使うことを考えていたそうで、すぐにアレンジの作成を始められました。小技のお手本を見ながら進めましたが終わらなかったので家で完成させるそうです。', null, '時間帯: その他
盛り上がり: しっかりと考えながら進められていました。'),
  ('5d2947a5-4d46-510e-abbb-05c0377d0b25', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', null, null, '通常 / アレンジ大賞', '手順書の部分の続きに取り組んでいきました。実際に手を動かしている際の作業効率は悪くないのですが、本人の集中力がかなり切れやすいようなので、何度かサボってしまう箇所がありました。そのため、全体としての作業はあまりスピードが出ているものではありませんでした。結果的に手順書の部分については授業内に終えることができましたが、アレンジ部分に関してはほとんど手をつけることができていないため、自宅にて作品を完成させてくるようです。', null, '時間帯: その他
盛り上がり: バグや理解のできていない箇所を解決できた際には、作品へ取り組むモチベーションが上がっているように見えました。'),
  ('1ac840d8-a346-59dc-9b0a-359f40d03ebc', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '16:30:00', null, '通常 / アレンジ大賞', '前回までで手順書の部分を完成させることができている為、今回はアレンジに取り組んでいきました。キャラクターの技部分にアレンジをおこなっていきたいらしく、必殺技を取り入れてゲームとしての面白さを上げていくようでした。途中でつまづくこともなく順調に進めていくことができていましたが、規模が大きいためか授業内にて完成させることが叶いませんでした。なので、自宅にて続きを作成していくことで作品としてのクオリティを上げていき、優勝を目指してくるようです。', null, '盛り上がり: 必殺技をどのようなものにするのか悩んでいたため、作りながらしっくりとくるようなものを決められたようで、モチベーションを上げて作っていました。'),
  ('10fc0b35-dd18-59a6-a349-add526851fec', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / アレンジ大賞の完成を目指す', '手順書が途中だったので続きからやりました。スコア以外で変数を使うのには慣れておらず戸惑っていましたが、「スコアじゃなくても好きな数に自分で名前をつけられるよ」と伝えると納得して作成を進められました。以前扱ったメッセージについてはよく覚えていました。左腕のコードを右腕にコピーするとき、コスチューム名を変え忘れて動かず困っていましたが、変な場所がないか観察するよう促すと気づいて直せました。 手順書はなんとか完成しましたがアレンジはできていないので、家でやってくるそうです。', null, '時間帯: その他
盛り上がり: 問いかけなどをきっかけにミスに気付いたとき、驚きながらも気づけてうれしいような様子をしていました。'),
  ('6d17f369-870b-55c1-882c-b98a06c0fa46', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '16:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞期間に来ている日数が少ないこともあってか、あまり進めることができていなかったようでした。今回の授業内で、手順書の内容については全て終わらせられるようにと頑張って取り組んでいました。花びらの色を変える部分のギミックに苦戦していたようでしたが、仕組みを教えたところすぐに間違いに気づき修正することができていました。結果的に授業内に手順書の内容を終えることができていたため、アレンジ部分に関しては家で取り組んでいくことで完成を目指していくようです。', null, '盛り上がり: 少ない時間で手順書の内容を終えることができ、途中ではありますが達成感を感じている様子でした。'),
  ('e9914a7e-d880-505e-a865-262c3f707c63', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-18', null, null, '通常 / 検定問題を解く', 'アレンジ大賞と検定問題の2択を提案したところ、後者を選びました。3級は余裕だったようなので2級を解いてもらいました。制限時間の40分ちょうどくらいでアレンジまで終わりました。答え合わせをしましたが一か所数字の写し間違いがあっただけで他は完璧でした。アレンジも、ゲームの幅を広げるために新しい変数を考えて設定したりと凝っていました。', null, '時間帯: その他
盛り上がり: 2級になると新形式の問いが出てきますが冷静に対処していました。'),
  ('10167fc6-b6ff-5339-acef-2c9fcd6f126b', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '17:30:00', null, '振替 / アレンジ大賞', '前回までで、作品のゲームオーバーの条件とゲームクリアの条件については固まっていたようでしたので、今回の制作にてその内容を取り入れていきつつ、スコアのマイナス要素や背景の変化を取り入れていくことによって、プレイヤーを飽きさせないような工夫を多く取り込んでいました。その中でもゲームの難易度に対してこだわりが強いようで、スコアのクリア条件やゲームオーバーの条件に関してはかなり悩んでいました。結果として自身の納得のいく難易度調整となってようで、作品の完成に満足していました。', null, '盛り上がり: 作品のアレンジにて、自身の入れたい内容及び難易度調整を適切に行うことができ、作品としての完成度にとても喜んでいました。'),
  ('023167b6-c705-5c7f-bdc1-a30d7d92cb67', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-18', '17:30:00', null, '振替 / アレンジ大賞', '今回で作品の完成まで持っていきました。前回までである程度のアレンジができていたため、その内容を進めていきつつ新たなアレンジ要素を入れていくことによって、コンテストにて上位を狙えるようにアレンジをおこなっていきました。時間経過にて難易度を上げつつ、視覚的にもインパクトを与えるような作品を作り上げることができていたため、コンテストではしっかりと優勝を狙っていくよう動いていたようです。', null, '盛り上がり: アレンジを完成させた際には、自身の作品に強い満足感を感じていました。'),
  ('149fa296-29f1-5ed9-bdf1-6164c7c7234b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-17', null, null, '通常 / アレンジ大賞スマブラ', 'かなり疲れていたようで、アレンジの方向性も決めかねて頭を抱えていました。途中、背景スクロールを見てからしっかり手が動くようになり、もともとあるプログラムを参考にしながらですが、うまくプログラムすることができました。 プログラムの中身もかなり高度ですが、演算のプログラムも取り入れて自分で考えられています！集中して頑張っていました。', null, '時間帯: その他'),
  ('b3390735-c0f1-5b13-bad0-24f0592755d6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-17', '17:30:00', null, '通常 / アレンジ大賞', '今日はライトのバッテリー残量という名の時間制限も追加していました。時間が切れると、襲われてゲームオーバーするらしいです。ガスマスクとバッテリーの要素が増えて脱出ゲームがかなり難しいものになりました。もし公開するときは、操作するボタンが多いので、説明文に操作方法を書いておく方がいいです。', 'ゲームの流れは完成していますが、若干作りかけがあるので、そこを聞いてみて下さい', '盛り上がり: 難しくてなかなかクリアできません'),
  ('a026cb9a-c64b-5d69-a4d6-5239d87da162', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-17', '18:40:00', null, '通常 / エクセル学習', '今日からエクセル学習を始めした。', null, '盛り上がり: 今日は高尾山登った後に部活で走らされてかなりお疲れでした'),
  ('c429fedd-6764-5541-b442-af5056555a15', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-17', null, null, '通常 / アレンジ大賞カニカニハンマー', 'ほぼプログラムは完成していましたが、今日は最後の仕上げとして邪魔をするスプライトを増やしたり、コスチュームを整えたりしていました。コスチュームは自分の好きなキャラクターを調べて色を似せたようです。プログラムの内容的にはレベルは簡単めだと思いますが、全体像を意識してプログラムを作れていて良かったです！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('c494ce6c-a725-526c-aa85-81e3a053816b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-17', '17:30:00', null, '通常', '前回、無敵モードを使いしたので、これを生かして落下する剣を作りました。当たり判定やランダム落下は無敵薬のコードを用いて、うまく作れていました。剣が刺さった絵が欲しかったが、ゆづきくんは絵が描くことが苦手だったので、元の絵を分解して真っ二つにするする方法を教えました。これがなかなか好感触で、喜んでくれました。最後は駆け込んで完成をできました', null, '盛り上がり: そうすけくんの奇声に少しビビっていました。'),
  ('5173777c-9842-534a-bbe4-bb3dd28be0cf', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-17', '17:30:00', null, '通常 / アレンジ大賞カニカニハンマー', '今日が締め切りなことを何回も説明したのですが、まったくやる気が起きなかったようです。前回左腕のプログラムは一通り自分でやったので、今日は右腕を中心にやりました。タイピングの部分はいくつかあったのですが、ほぼ自分で頑張りました。かなり気が散るようで、他の人が楽しそうだと勝手に観に行ってしまいます。 右腕も終わらず、左腕の位置がうまくいかないバグ?も直すことができていません。プレイヤーの最後のプログラムも終わっていません。', null, 'タイピング: 授業前にも集中して取り組んでいました。'),
  ('8a1dd25b-3f24-58e4-97ed-387a7ab9d7f7', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-17', '17:30:00', null, '通常 / アレンジ大賞脱出ゲーム', 'オリジナル要素になやんでいたので、いくつかアイデアを共有しました。ゲームの前にストーリーを作るようになりました。キャラクターだけでなく、ガチャガチャ要素を増やすことができました。またストーリーが終わる前に次の画面に行かないようにキャラクターが邪魔をする工夫もあって良かったです。作品はちょうど完成していました。 ガチャガチャ要素をゲームにも追加したかったと悔しがっていました。', null, null),
  ('24d44d80-975f-5cc2-bfcb-d7fda89d3416', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-17', '16:30:00', null, '通常 / 追跡ゲームの作成', '「〇歩あるく」で動かそうとしていましたが、方向の必要性を説明し、座標を使うことにしました。座標を使うときに方向設定が必要ないことを理解できていて良かったです。ランダムに爆弾を動かすのも自力でできました！ 点数を入れるときに、プログラムがずっと動いてしまうため、「〇秒待つ」を使うことを説明したのですが、こだわりがあってプログラムはしませんでした。オリジナル要素として、特定の点数になったらコスチュームが変わったり、クリア画面がでたりするようにしました。最初にどの画面（コスチューム）にするのかをしっかり考えられています。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 次回はアレンジ、もしくは次の単元に入る予定です。'),
  ('6d3406ce-1239-5d8c-9507-3c4db0bf5f01', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-17', '16:30:00', null, '通常 / アレンジ大賞', '前回完成といっていたが、景品を見てもう少し作りこみたくっていました。ステージセレクトの画面を作ってくれました。そこで、たまにスタートしたらすぐ勝敗がついてしまうバグが発生してしまいました。こちらからは初期位置と判定のコードに順序をつけるアドバイスをしましたが、その内容を別のメッセージを追加することで、コードの形に自力で表していました。ただ、若干のコードの汚さが見えまし。た言わなかったけど。', null, null),
  ('300f421f-6210-52a6-8b4c-c059b75532ec', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-17', '16:30:00', null, '通常 / アレンジ大賞完成', '新たにこーげきパターンを増やしました。身体が伸びるのは、なかなか面白うそうになっていました。今までダメージの％変数を表示していなかったので、ダメージ判定のコードを作ることに気が付きけていませんでした。後半間際だったので、ほかのアレンジの途中で割り込んで忙しめでした。本人的には、まだ終わらせることができなっったので、家で続きをやるそうです。', null, '盛り上がり: フリーの画像から自宅の猫に似ているのを探しているのはかわいかったです。'),
  ('e2bf3f48-495c-5642-8da7-f66a4f7bcbb4', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-16', '16:30:00', null, '通常 / アレンジ大賞の完成を目指す', 'ルール説明をゲーム内につけたり、カニのせいで文字が隠れてしまわないように対策するなど、プレイヤーのことを考えられていました。場面によってスプライトの表示/非表示を切り替えたいと言ったので、謎解き脱出ゲームのような[ステージの背景#]の使い方を伝えると活用できました。', null, '盛り上がり: 時間が終わってもできるところまでやりたいと粘っていました。'),
  ('5cd5fb87-7e06-567d-b05a-a7cd57f6d4f0', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-16', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '今日やることはイメージしてきたようで、黙々と作成をし、完成したからプレイしてほしいと自分から申し出てきました。 実際にこちらがプレイしているのを見て、りょうやくんが想定していたのと違う手順でプレイされることがあるということに気付いたらしく、途中でテストプレイの手を止めてコードを直したりもしていました。 電気が消えて懐中電灯がつけられるアイディアはとても面白いのですが、それに対するヒントがないことを指摘すると、素直に付け加えたりもしていました。 一応は完成したようですが、ヒントの出る順番や、3つの鍵がそろわなくてもクリアできてしまうあたりを調整できるととても良い仕上がりになるのではないかと伝え、本人も少し考えている様子でした。', 'ヒントの表示と電気が消えるタイミング、3つの鍵のフラグなど、余裕があれば作り込めると良いかと…', '盛り上がり: 脱出のための手段が、最後のドア以外は完全に変わっていて、アイディアを考えるのも作成するのも、とても楽しめていた様子でした。'),
  ('6a87a401-74bc-5fd0-876d-02b6d3b490ed', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-16', '17:30:00', null, '通常 / アレンジ大賞の完成を目指す', '手順書の部分はできたので、最初はアレンジの内容を考えていましたが、比較的すぐに決まりました。猫、お金、ガチャなどのアイテムを追加して、うまく連結するようなストーリーを考えられました。アイテムをゲットしたかどうかの管理は、アイテムボックスのコスチュームを使って簡潔に行えていました。「作成→テスト→デバッグ」の流れを順調に回して作成を進めていました。あと少しで完成というところまで行けました。', null, '盛り上がり: やることが多くなってしまったと言いつつも手を止めずに作成を続けていました。'),
  ('02dd95fa-eb57-58a0-baf4-9c7364902196', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-16', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '途中先生に構ってほしくてキッチンに入ろうとしたり甘えてまとわりついてきたりと、気が散っている様子も見られましたが、ローマ字表を見ながら日本語入力を自分でやろうとする進歩も見られました。 日本語入力は先生にやらせようとすることが圧倒的に多かったのですが、今日は、最初に少しほめたところ、その後は頑張っていました。 数値のイメージがまだ弱いようで、クローンができるタイミングを遅らせるのに、0.8秒待つを1秒待つに直して「コードを変えたのにあまり変わらない」とぼやき、1秒も0.8秒も体感としてあまり変わらないのではと説明しても納得できないようでした。 タイトルは楽しんで考えていて、タイトルから連想した図書館の注意書きを頑張って入力し、満足そうにしていました。', null, '盛り上がり: 苦手だと言っていた日本語入力を頑張っていて、自力で図書館の注意書きを完成できたときは得意そうにしていました。 授業開始時には「もう完成している」といって遊びたがったりもしましたが、小休止をはさみながらも、最後まで取り組み続けることができました。'),
  ('fdae122e-2afd-551a-80a7-7c4ff45cdeb6', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-16', '16:30:00', null, '通常 / アレンジ大賞作成', 'ゲームの基本システムとアレンジ部分を同時並行で進めていきました。アレンジ部分については、前回まででほとんど完成していたため、残りの基本システム部分を重点的に進めていきました。数字の全角と半角で間違っている箇所がいくつかあったので、一度見直すことを習慣づけていくとより間違いを減らすことができる様子でした。最終的には花びらのギミック部分のみバグがあるようなので、次回でその部分のデバッグを行うことで完成へと持っていける様子でした。', null, '盛り上がり: 指示書に書いてある部分についてはひとまず全て書き終えることができたようで、残りのバグ部分に向き合えると気持ちを切り替えていました。'),
  ('9e7a401f-db31-5e50-a4d5-09fe4ac672c3', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-16', '16:30:00', null, '通常 / アレンジ大賞作成', '前回までの作成でアレンジ部分もほとんど完成していたため、今回は全体のまとめとゲームオーバーについて作成していきました。時間経過で出現するキャラクターを同時操作していく必要があるため、難易度上昇を可能にした部分を微調整していき、より丁寧な表現としていました。次に、ゲームオーバーについて作成していき、基本的な文字の表示と全てを止めるを作成していきました。最後に、全体の見直しと開始画面にて操作説明などを書き足していきました。結果として、かなり完成度の高いものとなったため、本人の達成感も大きかった様子でした。', null, '盛り上がり: 作品が完成した際には、本人が入れたかったことを全て入れてバグもなく終えることができてとても満足している様子でした。'),
  ('77a1b685-bc44-5f52-903f-aa15fd207331', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2024-05-16', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('2a10c052-16b9-520a-8c68-1526733c2717', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-14', '17:30:00', null, '通常 / アレンジ大賞の完成', '前回までで手順書通りにはできたようなのでアレンジに入りました。最初はどうアレンジすればいいか悩んでいたのですが、「間違い探し」のような要素を入れることを思いついていました。作り方に関しては、雑巾など手順書の作り方をまねするといいかもとアドバイスするとうまく活用できたようでした。似たキャラクターを何体も置いて、一つだけ違うキャラクターをタップするとアイテムが手に入るようにして、間違い探しと謎解きを絡めて完成させられました。', null, '盛り上がり: 方針が立ってからの集中力が高かったです。'),
  ('2f2a39f5-cd8a-52b2-88c5-6ab4ea76da29', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-14', '16:30:00', null, '通常 / アレンジ大賞の完成', '金庫を開けて鍵を取れるようにするときうまく作れず困っていましたが、金庫と鍵を同じスプライトではなく違うスプライトに分けることで解決しました。アレンジの流れはしっかりイメージできていたようで、止まることなく製作を続けていました。最後にドアが開かないバグが起こってしまったのですが、メッセージや変数の変化を一緒に追って確かめると直すことができ、完成しました。', null, null),
  ('e7b307ee-a4f9-582f-9cf2-7c9e618eb770', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-14', '16:30:00', null, '通常 / アレンジ大賞カニカニハンマー', '前回やったところまで自分で確認することが出来ました。時間の変数を使ったので少し仕組みを説明しましたが、理解は難しい様子です。アレンジしない作品の方が好きそうでしたが、何とかアレンジをしてもらいました。両方にHPをつけたかったそうですが時間がなかったので、スプライトに見た目のアレンジを加えることにしました。マウス操作が難しかったと思いますが、うまくできていました！', null, '盛り上がり: 授業後にがくくんとスマブラで楽しんでいました。'),
  ('ec5b4035-ad4d-576f-982b-f83be148b813', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-14', '16:30:00', null, '通常 / アレンジ大賞カニカニハンマー', '前回やったところを自分で確認できました。右腕と左腕のプログラムは先週と同様に全てをひっくり返して考えてしまうので、少し難しかったようです。カニが見本と動かなかったので紙と作製したプログラムを比較してもらいました。私よりも早く自分のミスを発見できていました！また音を鳴らすブロックの種類を説明しました。アレンジとしてスプライトに剣を持たせていました。自分で全部操作して頑張っていたので良かったです！', null, '盛り上がり: 徐々にブロックの場所を覚えてきているようです！授業後にゆうさくくんとスマブラで楽しんでいました！'),
  ('604de058-48b0-5bcf-8f4e-ad24a7d089d4', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-13', '17:30:00', null, '通常', '今回も謎を多く追加していました。１つの謎を追加することに、メッセージセリフやら変数やらの相互作用が多くてなかなかボリュームのあるものになってきました。後半になっても進捗としては本人的に終わらない感じでしたが、なんとか来週には間に合わせるそうです。', null, 'タイピング: プレイグラム'),
  ('7cc5c717-2df6-588d-92c9-dc5e7fb8453f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-13', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '土曜日のバイクラン優勝がとても嬉しかったようで、機嫌よく来室しましたが、いつもより浮ついてしまっているようにも見えました。 開始後、ゲームから作成にうつるのも少し時間がかかりましたが、作成に入ってからしばらくは集中して、手順書のところまでの完成とバグつぶしをしていました。 花の絵の謎を解いた後、どうしても鍵がゲットできずに20分以上コードを見直したりしていましたが、そこで疲れてしまったようでした。 結局、一緒にコードを見直した結果、花びら5のコード内の変数名を、複製元の花びら1のままにしていたことが原因でした。解決したときはとても喜んでいましたが、どうやらそこで完全に集中力が切れたようで、その後は目を離すとScratchのゲーム、こちらが声掛けをすると、背景やスプライトの色を変える程度のアレンジをするという繰り返しでした。 色の変更のアレンジだけでは、こんなアレンジをした、というアピールにはならないと説明すると、「次回は必ずラジオのギミックを作るから」ということでした。', 'ラジオのアレンジを必ず完成させるという約束をしています', '盛り上がり: バグ探しの途中までは、一生懸命に解決しようという姿勢が見られましたが、電池が切れてしまってからはちょっと残念な授業態度でした。 それでもこちらの話は聞いてくれて、今後のアレンジ予定についても一応考えているようではありました。'),
  ('b3283a92-0a43-52e4-af6d-5c49ad335487', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-13', '17:30:00', null, '通常 / アレンジ大賞', 'それぞれのミニゲームについて作っていきました。最初の石から避けるものはこちらが見て不自然なところ(乱数なのに右側しか落ちてこない、終わっても石落ちてくる)など指摘しましたが、自分のアイデアで修正できていました。そして、「まで待つ」を使った制限時間のやり方も教えました。これで、作品の幅が広がったように見えた表情をしてました。第2のミニゲームとして、むらっちたたきを取り込んでいました。そして、3つ目にスマブラを取り入れようとしたが、さすがに難しすぎて断念して、次回に別の案に持ち越しでした。', null, null),
  ('29f99168-1f72-594b-91b8-5984ce6a8b4e', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-13', '17:30:00', null, '振替 / アレンジ大賞作品の作成', '3月以来の来室だったため、アレンジ大賞の説明を簡単にして、対象作品をプレイしてもらい、コードの簡単な確認をしたら、リミックスからそのままアレンジに入りました。 カニカニハンマーのゲームにストーリーを付け、終始楽しそうにアレンジをしていました。 作成中もとくに困ることはなく、定期的にできたところまでを見せては満足そうにしていました。', null, '盛り上がり: 久しぶりの作成で、常に楽しそうでした。 ゲームの説明を先生たちが聞いてくれるのも嬉しかったようでした。
備考: 土曜日に習い事が入ってしまって、隔週でも通うのが難しくなってしまったため、アレンジ大賞が終わったら退会したいとのことです。 かんたくん自身は楽しんで通っているため残念ですが…という感じでした。 お母さんには、18日か25日に、書類を書いてもらうようお願いしてあります。'),
  ('198b23f4-8d34-533f-ae8c-b476e3548ccc', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-13', '16:30:00', null, '振替 / アレンジ大賞作品の作成', '開始時は、もう完成しているからと言ってダラダラとScratchのゲームをしたりしていましたが、むらっちの他に動物のスプライトが無秩序に出てくるアレンジの状態で自分自身でプレイさせて、本当にこれで面白いか、自分より下の学年の子が遊んだときに楽しいと思ってもらえるかと問いかけると、少し考え直したようでした。 動物が出すぎてしまうのがなぜなのかわからないというので、自分で作成したコードなのだから自分で見直せるはず、と声掛けをすると、コードを適当に他のスプライトから複製しまくったため、スプライトごとに余分なコードがたくさん入っていることに気付くことができ、一つ一つ丁寧に見直して重複部分やいらないコードを削除する作業を熱心にやっていました。 上記で疲れて10分ほど休憩をはさみ、その後は、すっきりしたコードを見直して、クローンを作成するときの繰り返しの回数を変えることを思いついたようで、自分で調整をしていました。 残り10分でまた遊びそうになったため、直前に作成したクマのスプライトをレアキャラ扱いにして、ゲーム中に一瞬だけ出すようにするのはどうかと持ち掛けたところ、すぐにノッてきて、時間ギリギリまで作成に励んでいました。乱数の使い方の復習にもなりました。 最後に、今日はコードを見直す作業を自力でできたのが良かったと褒めると、満足げに帰っていきました。', null, '盛り上がり: 前述の通り、コードを自分で見る努力ができたことと、レアキャラのアレンジが楽しかったようでした。少しでもできたことを褒めると、その先を自分でやってみようという意欲が見られ、本人も楽しそうに作成ができていました。'),
  ('e8eeaebc-a7cc-5961-bab7-49b3acaabfad', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-13', '16:30:00', null, '通常 / アレンジ対賞', '猫の動きについて前回まで時間をかけて作っていたので、コードの動きについてしっかり対応していました。ただ、使われているコードのブロックは正しいが、組み方がずれていてバグが発生してる場面が何度か見られました。本人だけでは見つけにくかったので、一緒に補助しました。勝敗判定も自力で座標判定で作れていました。今回で、やっと元のゲームが完成したので、次回でアレンジです。', null, null),
  ('e818a674-88e3-54cb-a650-707a8b5f515f', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-13', '16:30:00', null, '振替', '今回は、脱出のドアについて作りました。学校全体を舞台にしているので、ただのドアでなく校門を鍵で開ける仕組みにしました。背景のイラストに合うように学校名や装飾を特にこだわっていました。基本はスプライトを変えた時のコードの対応はできているので、コード面に対してもスムーズに作れました。 最後に手順書ではコードの修正があるが、次回そこがこんがらがらないように補助した方がいいと思います。', null, null),
  ('2ce42f2c-20eb-5ac0-a58c-75bd48cc33c9', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-13', '17:30:00', null, '通常 / アレンジ大賞スマブラ', '途中、猫がうまく動かないバグがありましたが、自分で解決できていました！またアレンジとして炎がメラメラしているようなアニメーションを作っていました。ペンギンがまだ動かないので残り時間が心配ですが、本人は大丈夫だと思っているようです。授業時間が過ぎても頑張って取り組んでいて良かったです。', null, null),
  ('6107a017-9f74-57d9-bb8b-a4970a1874e2', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-13', '17:30:00', null, '通常 / アレンジ大賞脱出ゲーム', '家でも少し取り組んできたようです。新たなギミックが追加されていました。スプライトの絵を作るだけでなく、プログラムも少し作ってきたようです。けいとくんにたくさん褒められて嬉しそうでした。教室ではプログラムではなくスプライト作成を頑張っていました。楽しく取り組めていて良かったです！', null, null),
  ('11d07599-a826-5a72-aa46-74cd06fec4dd', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-10', '17:30:00', null, '通常 / アレンジ大賞カニカニハンマー', 'ゲームを遊ぶために頑張って進めていました。コードの意味を隣から説明しても聞いている感じはなく、作るのに一生懸命でした。タイピングの箇所も多かったですが、ほぼ自力で頑張っていました。 進みがかなり遅いので元のゲーム作成が終わるかがかなり不安です。', null, null),
  ('12c2fb8a-4587-5652-af56-b7d6148bea1c', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-10', '16:30:00', null, '通常 / 基本操作コース', '前回から引き続き基本操作コースを埋めました。家でもプログラムを作ってきてくれたようで、サメから逃げろ！に似たような追いかけっこゲームが出来上がりました。まだ条件分岐の使い方は慣れない（ずっとを使う）ようです。サイズ変更や移動をやった他、メッセージの使い方を特に大事にやりました。使ったのは初めてだったようです。 下のアニメーションメインの基本操作コースはまだほぼやっていませんが、今回やったアニメーション、背景の変更、話させる、〇秒で移動させるで大枠はできているので、本人がやりたがっているゲームに進めたいです。追跡ゲームがいいかな？と思います。', null, 'タイピング: 学校でも少しやったことがあるようで、スムーズに取り組めていました。'),
  ('4fe32a03-15c2-57fc-aebf-2b324c189cfd', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-10', null, null, '通常 / アレンジ大賞・計算のしくみ', 'アレンジ大賞は本人的にはもう完成だったようです。少し手直しして完成になりました。次の内容として自動計算機（数値を入力したら答えを返してくれるプログラム）を提案しました。面白そうとのことで取り組みましたが、かなり眠かったようで完成には時間がかかりました。「聞いて待つ」を使ったのですがあまり覚えていなかったようです。完成したときは嬉しそうでした！', null, '時間帯: その他
タイピング: 授業の合間に取り組んでいました。'),
  ('1e74292d-71d2-5800-968c-b71d9319c0ac', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-10', null, null, '通常 / アレンジ大賞スマブラ', 'いつもは手が先に動くのですが、今回はしばらく考えてからプログラムを始めていました！同い年のとらくんが少し気になる(?)様子でした。 とても面白いジャンプ台が完成していました。見た目も綺麗に振動しているのでプレイもはまりそうです。集中して取り組めていました！', null, '時間帯: その他'),
  ('bd26e0f5-d488-573d-97ce-f4f593eadf3f', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-10', '18:40:00', null, '通常', '前回からかなり空いたこともあって、まずゲームからおもいだしてもらいました。そして、自分の作品をみたら、やりたいことが思い出してきました。そう長くは集中力が続かない子なので、少し自由にしながら、むらっちのイメチェンやねこの停止ボタンなどを作りました。', null, '盛り上がり: 結構ほかの子が作っているものに興味を示すので、曜日が変わった今日はいろんなこのそばに行っていいることが多かったです。'),
  ('312f9858-0916-5348-bcb4-62631e5ec2b8', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-10', '17:30:00', null, '通常 / アレンジ大賞', '前回、無敵状態を作りたいとことで終わっていたので、変数を用いた方法を教えました。まず、どこの動きのコードを止めればいいかを探してもらい、その動きメッセージの送り元で判定を作りました。止めるコードを探すところまでは意欲的に作れていましたが、変数の判定では少し疑問が残るような表情になっていました。アレンジが終わったら変数条件判定の仕組み近辺をやった方がいいかもしれません。その後、ステージが時間移動したりして、無敵アイテム以外に不利になるアイテムも追加の構想も上がっていて次回も続きそうです。', null, null),
  ('88351666-42a7-5bfd-bb76-67a02a7b43dc', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-10', '17:30:00', null, '通常 / アレンジ大賞', 'GWに少し進めていたのもあり、最初から勢いよく進めていました。新しく金庫の謎を追加すようとしてました。場所の隠しボタン判定が上手くできないといわれも、今までの作り方を確認していなく、気を付けてくれよと思いました。ダイヤルの合わせを桁ごとに判定したいとことでした。「何番目の文字」のブロックがあったので、それだけ教えてました。自力でできるかなすこししたら、うまく組み合っていなかったので、基本の演算の捉え方とともに一緒にやっていきました。逆文字にしたりすることは謎要素として、センスがいいとおも増した。', null, null),
  ('cdbcde33-fd41-5c89-a63e-0afb62ef0607', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-10', '18:40:00', null, '通常 / アレンジ大賞', '無限ジャンプがあるおかげで、動きのあるものをだいぶ変化していきました。動く小足場もあったが、ステージ全体も動くようになっていて、戦うというよりかは落ちないゲームになっていました。早々とアレンジ終わらせていたが、ほかの指示も与えたが、ゲームにいそしみ、なあなあに時間をつぶしていました。', null, '盛り上がり: ほかのスマブラの作品を見れて、新鮮な表情をしていました。'),
  ('ea2421b0-a133-5927-9437-203dc46817d8', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-05-10', '16:30:00', null, '通常 / アレンジ大賞', 'GW明けで前回のバグ残しを探すところから始めました。それで、元のゲームは完成したので、独自に勝敗判定を作りました。最初は色判定で考えていましたが、なかなかうまくいかず、座標判定に自分で修正できました。ほかに、色や背景を変えて、雰囲気を変えていました。最後に、くさびのを振らせたいそうでしたが、時間いっぱいになってしまいました。次回で終わりそうです。', null, null),
  ('f663a68f-335e-5141-a89a-8159c564938e', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-09', '16:30:00', null, '通常 / アレンジ大賞を進める', 'アレンジとしていろいろな動物を出して邪魔するというものを考えてきてくれました。動物はむらっちよりも数多く出てきて、それらに触れたら減点とのことで、アイデアとして面白いものでした。ただその作成も比較的すぐに終わり、それ以上のアレンジは思いつかないとのことで、「ゲームが終わった時に何か演出する？」など問いかけをすると、また次回までにアイデアを出しておくと言っていました。', null, null),
  ('9b80a6f4-bff8-5ab6-9550-450977600d6c', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-09', '16:30:00', null, '通常 / アレンジ大賞を進める', '前回より前に変えた背景以外は手順書に沿って進めていました。スプライトが色々あることに混乱したり、「割ったあまり」の演算に戸惑ったりして、質問されたところは手助けしましたが結構時間はかかっている印象でした。気が散っているわけではないですが、締め切りを意識して完成を目指そうと伝えました。「ステージの背景# = 2」を見て2番目の背景を見直すなど、できる範囲で内容は理解しているようでした。 花の絵の謎を解くところまで終わりました。手順書はなんとか終わりそうですが、飛ばせるところは飛ばしてアレンジに充てることを考えてもいいかもしれません。', null, null),
  ('4cc5d37d-27bf-522c-bf33-419dedfac10a', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-09', '16:30:00', null, '通常 / アレンジ大賞', '今回からアレンジ部分の制作へ取り掛かっていきました。基本的には背景デザインの変更や、文字の追加など視覚的に感じ取れる部分の変更を行っていきました。それ以外でもタイトル画面の追加や、キャラクターの大きさの変化など様々な箇所へアレンジを取り入れていくことができていました。次回の作業で残りの部分の完成と、全体の見直しをおこなっていくそうなので、しっかりとまとまった作品を完成させていくことが可能だと感じました。このまま最後まで頑張っていってほしいです。', null, '盛り上がり: アレンジでタイトルを作っているときに、どのようなデザインにしようか悩んでおり、最終的に自分の納得のいくようなものにできたようで喜んでいました。'),
  ('8732f667-5926-50d5-842f-1c4cb2771cea', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-05-09', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '脱出のギミックを考えてから来室したようで、どういう順番にアイテムを取っていくということをきちんと説明してくれました。 一つ前の段階のアイテムを持っているかどうかで、引き出しが開けられるかどうかを変えたいと質問してきたので、ぞうきんや花の絵のコードやフラグとしての変数の使いかたの復習をしたところ、納得できたようでした。 フラグとしての変数は、「〇ずつ変える」ではなく「〇にする」を使うことなども、始めは少しとまどっていましたが、コードの意味を理解していくうちに、なんとなく使いわけがわかってきたようでした。 考えてきたギミックはほぼ完成できたようで、満足そうに帰っていきました。', '作品の見直しとバグチェック', '盛り上がり: 初めて？お母さんの送迎ではなく自転車で来室しました。 お友達が2人一緒で、授業が終わるまで待っていたのですが、授業開始後は気が散ることもなく、集中して作成できていました。 考えてきたギミックを説明するときは、嬉しそうでした。'),
  ('3f17d49f-39eb-50ea-9c8e-6549a2834e16', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-05-08', '16:30:00', null, '通常 / アレンジ大賞', '今回からアレンジの部分へと入っていきました。アレンジでは、一定時間が経過した際にキャラクターの数を増やしていくことによって、難易度を上げるという工夫を凝らしていきました。本人の中でも、このアレンジではゲームの難易度が変わっていくということに気づきながら作り上げ、作品としての完成度もぐんと上げていくことができました。来週には、くるまでにどのようなアレンジをしていくのかを考えてくるそうなので、この調子で最後まで走り抜けていけたら良いと思います。', null, '盛り上がり: アレンジで本人の思い描いていたものを作品へと取り込むことができたため、より高順位を狙おうと張り切っていました。'),
  ('22a8dc61-4ea3-55dc-8059-21b64a1292c5', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-07', '16:30:00', null, '通常 / アレンジ大賞脱出ゲーム', 'もうすでにアレンジしながら取り組んでいるようで、作りたいものも自分の中にあるようです。金庫を出して扉を開けるプログラムに苦戦していました。（見本と違ってクリックエリアと金庫を同じスプライトにしたのが原因）また、作りたい内容をプログラムの言葉に置き換えるのが少し難しいようです。 クリック回数で①大きくなる②扉が開く の操作を整理する方法をアドバイスしました。次回（おそらく）②からプログラムです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('884b943a-4ec0-5108-9ec7-95dd1884ac19', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-07', '16:30:00', null, '通常 / アレンジ大賞カニカニハンマー', '作りたい作品の全体像はしっかり把握できていて良かったです。ひとつひとつのブロックの意味までは作りながら考えるのは難しいようですが、スクリプト同士の関係や制御のブロックは一つ先まで考えながらプログラムできていて良かったです。（もし～とでなければ～の状態を一緒に考えられていました） 右腕の途中まで終わったので次回は最後までプログラムしてアレンジも少しできるかな？と思います。', null, null),
  ('8c6b5a6f-81aa-5ec1-8ce1-be3e28e0f531', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-05-07', '16:30:00', null, '通常 / アレンジ大賞カニカニハンマー', '前回やったところまでをしっかり覚えていたので良かったです！タイピングも苦手ながら丁寧に取り組めていてよかったです。右腕、左腕の考え方はなかなか慣れなかったようですが、左腕との変更点は一か所説明すると理解できたようでした。途中検証してみると数字がうまく入力できていなかったので、入力のときの注意点を詳しく説明しました。 右腕までプログラムできたので、次回にはアレンジに入りたいです。', null, null),
  ('76e7251f-324f-5454-a473-a1b413f74161', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-29', '16:30:00', null, '通常 / アレンジ大賞 謎解き脱出ゲーム', '前回の続きから作成していきました。作成内容はそれほど難しくなかったようで、サクサクと完成へ近づけていくことができていました。作成も黙々と続けており、時間いっぱい集中して取り組んでいました。次回では、アレンジ部分へと入っていけるようでしたので、それまでにどのようなアレンジを施すのかを考えていくようです。次回もこのペースで進めていければ良いと感じました。', null, '盛り上がり: 順調に進めていくことができているため、自分の実力を実感することができて嬉しそうでした。'),
  ('e047d770-e20d-577a-afbe-2b25cb4828bc', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-29', null, null, '通常 / アレンジ大賞 スマブラ風ゲーム', '前回の続きを作っていきました。今回の作成ではキャラクターの攻撃部分の続きと、ペンギンにも同じものを作っていきました。作成途中では２段ジャンプについてバグがあったようで悩んでいましたが、ヒントを与えながら自分自身で解決をすることができていました。次回では、残っている遠距離攻撃部分と勝敗判定、ダメージ部分を完成させることができればアレンジへと行くことが出来るのでこの調子で進めていきたいです。', null, '時間帯: その他
盛り上がり: ２段ジャンプのバグを自分で解決できたことで、自信がついた様子でした。'),
  ('84dc6133-3e36-5bd5-88f3-0d62a1d53338', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-29', null, null, '振替 / アレンジ大賞 スマブラ風ゲーム', '今回からアレンジ大賞の作成に入っていきました。ゲーム性をかなり気に入っていたようで、スマブラ風ゲームを作っていく際にはどのコマンドがどの動きをしているのかを確認しながら作ることができていまいた。キャラクターの攻撃のコードに関してかなり苦戦していたようで、複数の定義や変数を使っていたため一度整理することで部分ごとに組み立てていました。全体の半分ほどを完成させることができていたので、次回で大体の部分を完成させていきたいです。', null, '時間帯: その他
盛り上がり: 今回から作り始めたので、少し遅れているためより頑張っていきたいと張り切っていました。'),
  ('7297ab77-c236-5504-90a9-1606d508c118', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-29', '16:30:00', null, '通常 / アレンジ大賞 スマブラ', '前回の続きとして作品のアレンジ部分以外を完成させていきました。手順通りに進めることができていましたが、本人にサボり癖がついているのか目を離すと別のことをしていたようなので、その部分を解消していくことでさらに効率を上げられそうです。内容的には詰まることもなく進められていたので、次回には残りを仕上げてアレンジに入れそうでした。サボってしまわないようにしていけばかなりクオリティの高いものを作り上げられると思います。', null, '盛り上がり: 作品のアレンジについてはイメージをできているようでしたので、次回作品へと入れていきたいと話していました。'),
  ('d506c101-8b3d-5f64-8aa3-e8a2f2631fcd', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-06', null, null, '通常 / アレンジ大賞を始める', '今日作成を始めましたが、スピーディーに進めたため手順書は今日で終えることができました。アレンジもすでに考えていて、カニを2体に増やしたいとのことでした。そのためスプライトを複製しましたがそれだけではうまくいかず、変数や定義なども増やさないといけないので、動作の仕組みをしっかり理解してもらう必要がありそうです。', null, '時間帯: その他
盛り上がり: むらっちたたきよりもカニカニの方が面白いとのことで、モチベーション高く取り組んでいました。'),
  ('c19abbaf-1bbb-589d-823c-1872d4b838f7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-05-06', null, null, '通常 / アレンジ大賞を進める', '乱数を初めて見たそうで、(今回は)0か1かのランダムな数だと説明したところ納得できた様子でした。「～ではないまで繰り返す」は仕組みが難しいので写経になりましたが、複数の種類のブロックを組み合わせて自分で作ることはできました。背景を少し変えるアレンジを考えているらしく、ペンで描き加えていました。手順書の作業はおおむね終わりましたがバグで動かない場所がいくつかあるので次回修正したいです。', null, '時間帯: その他
盛り上がり: 楽しみながら作成を進められました。'),
  ('1409c303-5bc3-5ede-a3a7-a22ce373d81e', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-27', null, null, '振替 / アレンジ大賞を始める', '先週欠席のため今週からアレンジ大賞をスタートしました。比較的要領よく、理解しながら進めている様子でした。引数つきの定義は初めて使ったようですが、技名がその引数になっているところを見るとすぐに飲み込めていました。ネコのコードはだいたい書き終わったのですが、ネコが空中に浮かぶなどのバグが出てきました。まだ直せていないので、どこに問題がありそうか推測してから探してもらうなどの誘導をしてもよさそうです。', '手順書続き', '時間帯: その他
盛り上がり: テーマが面白いのでモチベーションは高そうでした。'),
  ('9275de01-6d86-58a8-922b-3f55288947ed', '80660755-d846-5cdd-91a4-0ab78fe29034', null, null, '2024-04-20', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('134d2ee9-d3c4-572a-846d-b91ea1ef0f7f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-27', null, null, '通常 / アレンジ大賞の作品作成', 'アレンジ大賞という具体的な目標があるせいか、「わからないこと、やりたいことを質問する」→「考え方のヒントをもらう」→「自分で作成してみる」という繰り返しがうまくできていました。 むらっちを5回叩いたら背景を変えたいという要望に対し、叩いた数を使うためにはどうする？程度のヒントですぐに変数作成に入れたりと、細分化の最初をこちらが言語化すればその先は自分でできるようになってきているようでした。 今日は脱線もほぼなく、ヒントのあとは自走して、できたら先生を呼んで見せて、次に進む、というのができていたと思います。', null, '時間帯: その他
タイピング: 授業開始前に、ゆうとくんと一緒に挑戦していました。
盛り上がり: 自分がやりたかったアレンジがいくつか実現できたので、とても満足そうでした。 アレンジの時間が欲しくてあえて入門を選んだ、とのことでしたが、元のコードを理解した上でアレンジできているのが実感できるのか、熱心に自走しようとする様子も見られました。'),
  ('7bbe990c-d459-5c95-98a9-8aa151de5baa', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-27', null, null, '通常 / 検定の問題に慣れる、アレンジ大賞の作品作成', '検定問題では、これまであまり触れたことのないと思われるPKゲームにチャレンジしてもらいましたが、全く戸惑うこともなく、25分くらいでできましたと言ってきました。 アレンジをしていなかったので、5分間でアレンジをしてもらいました。 3級に関しては全く問題がなさそうなので、次回は2級をやってみようと声掛けをすると、少し嬉しそうな様子でした。 残り20分ほどでアレンジ大賞を勧めましたが、こちらも楽しかったようで、自主的に20分ほど残って作成を進めていました。 家でも作成をしたいとのことだったので、Comiruにてアカウント情報を送りました。', '検定問題は2級①', '時間帯: その他
盛り上がり: 検定問題がよくできることで自信もついてきたようで、レベルアップの提案も嬉しそうに聞いてくれていました。'),
  ('69a30306-1c29-5c0d-b2c0-8b021db1087f', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, null, '2024-04-27', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('670315d2-200a-5b3e-9ca8-01018f78a17c', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-27', null, null, '通常 / アレンジ大賞を進める', '花びらのスプライトを作るのに苦戦していて、複製などを使ってうまくやる方法は伝えると、難しそうにはしていましたがなんとか作ることができました。また、カレンダーが掃除できないバグが発生したところで、一緒に確認すると「カレンダー拡大？」の変数が「1にする」ではなく「1ずつ変える」になっていたので修正してもらいました。この変数について理解が浅いと思われたので、0か1かで拡大しているかどうかを表すことを伝えると分かったようでした。デバッグなどに時間を使ったこともあり、手順書の中盤までで終わりました。', null, '時間帯: その他
盛り上がり: 終わらないかもしれないと少し焦っていましたが、集中はできてるしこのまま頑張れば終わるよと励ましました。'),
  ('928ccb15-a3fe-5ede-a4f1-6e65b1716190', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-26', '16:30:00', null, '通常 / 初回。レベル確認と基礎', 'Scratchの経験はかなりあるようで、自分の作りたいものがポンポン思い浮かぶようでした。初回でしたが、レベルチェックやシートの穴埋めも兼ねて、おいかけっこのゲームを作りました。マウスの方に動かすのは自分で考えられていました。一方で「おいかける」の内容を方向や歩数に分解するのは初めての経験のようでした。 自分の名前を動かす作品を作るのは気が進まない様子だったので、ジャンプゲームやピンポンゲーム（かなり興味を持っていました）に進めるためにシートの穴埋めを提案しました。 ゲームを作りたい気持ちが強いようでした。また自分のやりたい方向にもっていってしまう傾向があるので、声かけはかなり必要かな？と感じました。', null, 'タイピング: 嫌いではない様子でした。ぽけてぴだと物足りないかなと思い、プレイグラムを進めました。'),
  ('2a23cd94-f8bc-5374-b050-21bc82c5a0a3', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-26', null, null, '通常 / アレンジ大賞2024 カニカニハンマーアレンジ', 'アレンジに入りました。絵文字をたくさん話させて応援させるスプライトを作りました。50分ずっと集中して取り組んでいました。戦闘機や応援スプライトが画面いっぱいに配置されていたので、サイズを調整するようにアドバイスしました。また明らかにカニが強かったのでプログラムを見直しました。制御の条件が違ったので、原因を確認しつつ修正しました。', null, '時間帯: その他'),
  ('bf13a0c1-9319-54fe-ba70-deaa2083c0f3', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-26', '17:30:00', null, '通常 / アレンジ大賞2024 カニカニハンマーアレンジ', '集中して取り組めていたので良かったです。アレンジ内容は事前に自分で考えていたようで、①回復アイテム②無敵時間 の2つでした。 ①に関しては上から下に落ちて回収できるようにするとのことだったので、キャッチゲームの作り方を見ながら考えてもらいました。よくできていました！ 落とす時のプログラムが動きと制御が入り乱れて混乱していたので、話しながら整理しました。体が光り出すトリガーをメッセージにすることで確実にプログラムが動くようにしました。 ②の途中でパソコンの調子が悪くなってしまいました。変数を使って場合分けをすることを紹介しました。変数の値の変化はプログラムしました。場合分けをする前に終わってしまったのでまた次回です。', '無敵時間のプログラムを薬を持っているときとそうでないときで場合分けして実現する', null),
  ('32811bff-8f99-5b9e-87ed-76712b6ede7a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-26', '17:30:00', null, '通常 / アレンジ大賞', 'ケイト君と同じような進捗だったので、同じようなバグも発生していました。花びらの並べ方のバグでは、直し方として、変数の順番を変える、配置を並び変えるの2パターンがあるが難しい変数の順番で治していました。背景のコードの修正がまだ残っていたが、アレンジのやりたさが先行して、作り始めていました。ガスマスクで視界が狭くなるのが、脱出ゲームぽくて雰囲気が増していました。', null, '盛り上がり: いえでもあれんじするそうでう'),
  ('cf073b35-c34e-584f-a8c5-6d9f2aac0406', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-26', '17:30:00', null, '通常 / アレンジ大賞2024 カニカニゲーム', '気が散って集中できていませんでしたが、賞品の話をしてなんとか乗り気になってもらい、見本を見てもらいながらなんとか進めました。 見本と見比べて作るのはかなり苦手そう？で、間違ったときも順番から違うのになかなか気が付けないようです。定義のブロックについては大枠を説明して使ってもらいました。隣に人がいないと手を動かせず、集中力もあまりなく、かなり厳しいです。左腕に少し入りました。', null, null),
  ('0d128457-a570-5f79-8fa2-2c79b8f29d6b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-26', '16:30:00', null, '通常 / アレンジ大賞2024 スマブラ', 'ペンギンのプログラムを作りました。出だしは比較的順調でした。うまく波動が表示されなかったり動かなかったりしたときは、こちらから提案して紙を見て確認してもらいました。ほぼ自己解決できているようでした。 ペンギンのコスチュームがうまくプログラムできていなかったので確認しました。波動のプログラムが最後まで終わっていないのと、プログラムする場所が混乱しているようでした。次回修正かな?と思います。', null, null),
  ('59c6dc45-4a52-5f41-b6b8-80619e36d790', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-26', '17:30:00', null, '通常 / アレンジ大賞元作成', '今日はかなりバグと共存な時間が多かったです。花びらの判定などは今週の子を見ていれば、並び方を気をつけるべきでした。ものを並べるのは自然と右回りが多いのか？ひと過程進むごとにバグが起きり大体はコード忘れや、修正忘れで少し過信が多かったと思います。最後、コードはあっているが進まないバグがあったが、漢字とひらがなのメッセージが混ざって進まなくなる日本特有の間違いって感じました。探す注意力が少し鍛えてもいいかなと思いました。', null, '盛り上がり: やっとアレンジができるようになったので、家でも作る気が満ち溢れていました'),
  ('b7b199c6-812b-5b17-bbd2-e5a90bb76087', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-26', '16:30:00', null, '通常 / アレンジ大賞', 'ペンギンへの写しの際にいろいろとバグが発生していました。意外にもバグは操作キーの違いとかで紺くらいなら自分で探してほしいです。ゲームセットの判定は、自己流コードで見やすくなっていたので良かったと思います。 CPUを作れればいいと思っているが、本人的に作りたくないそうです。', null, null),
  ('61b9e5e9-d211-5389-9d2b-44bccd20cf3b', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-26', '16:30:00', null, '振替 / アレンジ大賞', '前回作っていたプレイヤーの動きにばぐがあったんので、そこを見直してみました。最初の方が一緒に探して、ブロックの使い間違いを直してきました。間違いがあっても落ち込まず、楽観的でした。カニの動きについては、新しく使うようなブロックには軽く説明を加えてやっていきました。動きが完成するたびに、喜んでくれて楽しそうでした。そこまで熱中してやっていたので、初めて教室で飴を食べたそうです。腕の動きも作り、途中のバグもこちらがおおよそヒントを与えつつもじぶんで見比べて直すことができました。', null, '盛り上がり: 熱中して楽しく作りこんでいたので、時間になっても続けた気持ちがあふれていました'),
  ('90464199-cc1b-5530-a3ff-ce7d5e74c50c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-25', '16:30:00', null, '通常 / アレンジ大賞の作品制作を進める', '先週から作成していた、ぬいぐるみをクリックすると部屋が真っ暗になり、スペースキーを押すと小さなライトが点灯するというギミックの続きを熱心に作っていました。 アイテム枠に取ったアイテムを表示させるコードが理解できたようで、ぬいぐるみが表示されるよう自力でアレンジしていました。 ぬいぐるみは新しいスプライトとして作成したため、次は背景の絵をクリックしたときに反応するように、エリアを作成して幽霊効果で隠すやり方を手順書を見ながら理解していきました。ベッドをクリックしたら反応するように作成ができて満足そうでした。 背景がすべてベッドルームなのが怪しい！などと、自分でツッコミを入れながら楽しそうに取り組めていました。', null, '盛り上がり: 教室に入るまでに、車内で時間がかかったため少し心配しましたが、自分でうまく切り替えられたようで、入室後は終始楽しそうに作成していました。 絵を自分で描くのも熱心にやっていましたが、お絵描きとコード作成のバランスもよく取れていて、どちらも楽しんでできているようでした。'),
  ('1e7f7ec7-a5af-5d2c-8501-f2f1f6693a14', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-25', '17:30:00', null, '通常 / アレンジ大賞', '花びらの仕組みから作っていきました。基本は順調に進んでいくが、しゅうくんの少し癖である読み飛ばしがたびたび発生して、ブロックがなかったり変数が違うかったりしました。このうっかりが今となってはちゃんと修正ができるようなっていたので世それは良かったです。最後まで、切り詰めて終わりまであと一歩のとっころまでできました。', 'アレンジ', '盛り上がり: 紙の印刷の粗さに愚痴をこぼしていました。'),
  ('976d3a06-d996-5214-bfc6-bc0e69d7076f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-25', '17:30:00', null, '通常 / アレンジ大賞2024 スマブラ', 'スプライト限定の変数かどうかがプログラムに影響する（操作できる変数など）が、見本のプログラムをもってきた際にそれらがうまく動作しない可能性があり？？、今回見本のペンギンからプログラムを拝借したものの、うまくいかなかったので見本を見ながら自分で作っていく方針になりました。 作業もはやく、ペンギンのプログラムもほぼ終わりました。ダメージをうけたペンギンが思うように動かないことがありましたが、プログラムの中身をよく確認して関係性を確認するよい機会になりました。 ひととおりプログラムは終わりましたが、攻撃をうけたペンギンが後ろに動かない、ペンギンにダメージが入らないので次回改善する予定です。', null, null),
  ('4d6a5d3e-b461-5259-8c2e-54a5d1aae678', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-25', '16:30:00', null, '通常 / アレンジ大賞', 'カニの腕の動きを作っていきました。特に悩むこともなくバグも起こらず順調に作れていました。ただ、座標の打ち間違えで判定が過剰に反応してしまうとあったので、そこは一緒に見ていきました。そのまま、最後までかんせいできたので、次からアレンジです', null, '盛り上がり: 飴がやる気の成分です'),
  ('2d1e3522-1470-5721-8c70-b7131102c7c1', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-25', '16:30:00', null, '通常 / アレンジ大賞', '最初はゾンビの動きが片方にしか動かなくなっていたので、バグ探しをしてもらいました。きほん、コードの紙があるのでそこから探せばいいですが、探すのすぐあきらめがちな性格だが、不等号の向きなどは過去にあったので、自力でできいました。うでの動きは変数の買えるところは自ら変えてできていました。だが、腕が下がらないばぐが残りました。最後の方だったので、ある程度一緒にやって、紙の基本的な動きは完成しました。', 'アレンジ作成', '盛り上がり: 中盤はすっぱい飴で気力を保っていました'),
  ('85123c3c-72b9-5505-8f78-da48fd450a4a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-25', '16:30:00', null, '通常 / アレンジ大賞2024 むらっちたたき', '見本と違う動きをしていたことに本人も納得がいかなかったようなので、見本の紙を自分の作ったプログラムを見比べてもらいつつ、プログラムを作成してもらいました。納得のいくものになったそうです。 また、アレンジとしてむらっちに「いたいっ」て言わせることを考えました。もしを使って一緒に考えてみましたが、クローンに話させるという都合もあり、時間も少なかったのでうまくいきませんでした。次回にむけてアレンジも考えてくるように伝えました。', null, '盛り上がり: いつもよりも集中して頑張っていました！'),
  ('10880c65-8b75-5b83-837f-46eb722b0d63', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-25', '16:30:00', null, '通常 / アレンジ大賞2024 脱出ゲーム', '背景がうまく切り替わらない、変数が変わらないなどうまくいかないこともありましたが、本人に紙を見ながら自分で確認するように伝えると、解決できていました。 カレンダーや雑巾がクリックできる仕組みについて本人と話しました。幽霊の効果をあまりよく知らなかったようなので解説しました。その後、自分の言葉で言い換えられたので、仕組みについてはしっかり理解できたと思います。 お花にまだ取り組めていないので時間的に厳しいです...間に合うか心配です。', null, null),
  ('b417502c-ed22-5dca-b66b-5daf691ba6a6', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-23', '17:30:00', null, '通常 / アレンジ大賞を進める', 'アレンジを入れながら手順書を進めるスタイルで行きました。アレンジとしては、「～と聞く」やメッセージを活用してゲーム内のパソコンにパスワードを打ち込めるようにして、うまく動くことを確認していました。また、雑巾の手順に習って金庫をアイテムとして取り入れていました。一方で手順書の方は中盤のカレンダーあたりで終わりました。まだ問題はないですが、全体として完成できるかどうかなんとなく計画をイメージしてもらってもいいかもしれません。', null, null),
  ('26cc0382-7676-56f0-9a82-7a94ec3bbd85', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-23', '16:30:00', null, '通常 / スマブラ風ゲーム作成', '前回からの続きで作成を行っていきました。作成中に詰まってしまうこともなく順調に作っていくことができていました。勝敗判定の部分まで作り終えることができていたので、残りの部分である体力表示や計算、そしてキャラクターの動きや攻撃の部分に多少のバグがあるようなので、その部分の作成及び修正を行えれば完成まで持っていける様子でした。なので、次回で完成からできればアレンジへと入っていきたい量となっています。アレンジに関しては、内容としてはぼんやりではあるものの決まっているようなので、来週完成できれば入っていけると思います。', null, 'タイピング: 素早く打つことができていました。
盛り上がり: ネコのプログラムをペンギンへと変更しながら写していくのが大変だったようで、やりきった際には疲れていたようでしたが嬉しそうでした。'),
  ('b2ee1953-bf00-5c6f-830d-aeca79e8438d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-23', '17:30:00', null, '通常 / 手順書を終わらせ、アレンジに入る', '前回で調子がつかめたのか今回はあまり手順書に頼らず、自分で考えながら手順書の動作を再現していきました。ダメージの%について、お手本のゲームの挙動を見ながら数値を調整していました。途中ダメージが正しく入らないバグを発見しましたが、メッセージ名や変数名においてペンギンと猫が逆になってしまっていたことを解明できました(結構紛らわしいです)。 時間の最後の方で手順書の再現が終わり、アレンジに入りました。実際の作成はほとんどできませんでしたが、大きいキャラクターが降ってきたりジャンプ台を設けたりするアイデアを思い付いたそうで、スクラッチ内のメモに残していました。', null, '盛り上がり: 同じゲームを作っている人が何人いるか質問するなど、本気で入賞を狙っている様子でした。'),
  ('c880c56e-13c7-572c-be70-0bde9b2c0fec', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-23', '17:30:00', null, '通常 / 謎解き脱出ゲーム作成', '前回からの続きで、作品完成に向けて作成していきました。花びらの部分にて表示が上手くいっていないようだったので、一度コードを見直してみたところ自分自身で間違いに気づくことができていました。絵の判定に使っているスプライトの調整にこだわっていることが多いので、そこで時間を使ってしまっていると感じました。しかし、今回で全体の８割以上は完成できているので、次回で完成とアレンジに入ることができると思います。アレンジ内容に関しては考え中のようで、次回に期待です。', null, '盛り上がり: 花びらの間違いに気づけた際には、問題を発見して自分で解決できたため、嬉しそうでした。'),
  ('c3792feb-7f25-5588-899d-0d25e5dc26fe', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-23', '16:30:00', null, '通常 / アレンジ大賞を通して基本スキルの習得', '今回が勇作くんにとってアレンジの初回だったので、説明してからむらっちたたきとカニカニで選んでもらいました。カニカニの方が面白いし、がくくんと一緒だからということで決めました。作っている途中には初めて見る基本スキルがたくさん出てきたので学習しながら進めました。「x座標を～ずつ変える」は横向きに動くときに使うことを抑えると、そのあとでもう一回同じブロックが出てきたときにもそのことを思い出せました。不等号については算数でもまだやっておらず、説明しても混乱してしまったようなので、次出てきたときにまたやろうと言って飛ばしました。メッセージについては、手紙に例えてみると面白がって理解してくれたようでした。途中、ブロックの複製で楽できる場所がありましたが「やりかたは分かるけどもう一回自分の手ででやっておきたい」と意欲的でした。', '手順書続き', 'タイピング: がくくんと競うように楽しくやっていました。
盛り上がり: ブロックの動かし方などの操作に慣れておらずたまに失敗するときもありますが、嫌にならずにゲーム作成を楽しんでいます。'),
  ('4665eed7-ed5b-5a70-a4af-1289f4c77737', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-23', '16:30:00', null, '通常 / カニカニハンマー作成', '前回の続きからの作成で、本体の動きについて作っていきました。キャラクターの動きがどのようにして動いているのかを、乱数の内容について理解していきながら学んでいました。ブロック定義を作っていく際には、表を見ながら自分自身で文字を打ち込んでいくことで、アルファベットの名前についても覚えていくことができていました。最終的に左腕の途中まで完成させることができたため、本人としてもかなり満足しているようでした。次回も同じペースで進めていけるように頑張っていきたいと意気込んでいました。', null, '盛り上がり: 文字を打っていく際には、打ち切った時にとても嬉しそうにして続きを作っていました。'),
  ('0579fcf7-d436-508f-bd6a-bc5519291401', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-22', '17:30:00', null, '振替 / 3級応用課題1 → カニカニハンマー（細分化を知る）', '応用課題1は読み飛ばしはあったものの、30分ほどでほぼ完答することができました。スプライトを「けす」に少し困っていたようです。検定の独特な言い回しに慣れてほしいです。 カニカニハンマーは残りの20分ほどで取り組みました。ゲームの仕組みについて細かく分けて質問し、質問と答えの内容が細分化につながっていることを説明しました。その後、紙を見ながらプログラムしてもらいました！紙の内容はほぼ終わったそうなので、次回はアレンジに移ってみたいです！', null, null),
  ('9467cc4f-8d96-51dc-86d4-48aaf9cc70e2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-22', '17:30:00', null, '通常 / アレンジ大賞2024 脱出ゲーム', 'アレンジというよりは完全新作の作品になりそうです。背景を変えるときにっもしに加えて「～でなければ」を適切に使えることができました！また、マウスでクリックするを「触れる」「押す」に分解して考えることができていました。 クローンを使うときの方法や、モノが落ちてきたときに消すプログラムを忘れてしまっていたので、ヒントのブロックを持ってきてプログラムを少し説明しました。楽しく取り組めたので良かったです。よく集中していました。', null, null),
  ('f3952c14-4166-5b75-b850-cc82b07d570c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-22', '17:30:00', null, '通常 / アレンジ大賞2024 脱出ゲーム', 'お花をクリックできる仕組みについて質問しました。聞くとようやく自分で考えられている様子でした。考えられると分かるようでした！返答もよかったです。 スプライトの役割は頭の中に入っているようで、うまくいかないときはプログラムを確認して調整できました。アレンジもやりたい内容があるようなので、作ったプログラムを参考にしつつ取り組むことを進めました。一通りみて完成しましたが、お花の色を変えるところ、お花の位置がうまくできていないのでまた次回確認する予定です。', null, null),
  ('9be197fb-5aa2-5002-8228-d87dd3a91ccb', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-22', '16:30:00', null, '通常 / アレンジ大賞2024 スマブラ', '前回はほぼ紙を確認せず、骨格だけを作っていたようです。今回は紙をみて今まで自分が作った内容を整理してプログラムしました。 引数つきの定義の作り方を説明しました。いままでわざわざ定義を作る意味が見いだせなかったそうですが、引数がついていると納得できたようでした。またnullの部分も注目して質問をくれました！リストで猫パワーをためているところもうまくイメージできて良かったです。 スケジュール感もしっかり持てています！本人によると次回で元の作品を作りきれる予想です。', null, null),
  ('afad844a-8bbf-5ca5-b7b1-71c17d3b8b52', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-20', null, null, '通常 / アレンジ大賞を始める', '雑巾のところの紫色のスプライトは何のために使っているかを分かっているかを問いかけると、きちんとクリックの当たり判定のためだと説明してくれました。部屋の切り替えの処理で、ボタンを押しても部屋が変わらないバグが出たとのことだったので、怪しい場所を考えてみたり手順書とコードを一つずつ見比べてみることを促しました。しかし違う背景を入れてアレンジをしながら作っていたこともあり、原因は不明のままでした。その部分は一旦飛ばして残りの部分の作成に入っていました。', null, '時間帯: その他
盛り上がり: アレンジのイメージはなんとなく頭の中でできていそうでした。'),
  ('879703e4-ffa9-5875-9a01-56c91b457a27', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-20', null, null, '通常 / 刀剣ゲームの続き', 'アレンジ大賞を始める予定でしたが、前回の刀剣ゲームをまだやりたい気持ちが強かったので続けました。最初は別のゲームの音をアルスタジオで使いたいと言っていましたが、音源を使うのは難しいかもと伝えるとアルスタジオの音から似たものを探してくれました。音がうまく鳴らなかったときは、「音を鳴らす」と「終わるまで音を鳴らす」の違いを伝えると今回は後者を使えばよいことに気づけていました。メッセージを使ってスプライトを表示するするときに、「誰が送るのか」と「誰が受け取るのか」などを問いかけで整理すると作ることができました。', null, '時間帯: その他
盛り上がり: 問いかけにきちんと答えてくれることは増えてきたと思いますが、わからないことがあるとすぐに正解を欲しがることはまだ多いようです。'),
  ('2dc665d0-6239-5d73-8e17-749b33cd6ccb', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-20', null, null, '通常 / チャレンジ大賞2024 スマブラ', '最初は紙を見ないでチャレンジしていましたが、最終的には作り方の紙を見ながら作る方針になりました。ペンギンから作っていたので、変数には気を付けるように伝えました（忘れていたようです）。また見本をそのまま作るのではなく、いろいろ実験しながらプログラムできていました。 途中、もとからできているものを紙を見ながらどうして作るのかを聞いてくれたので、「①プログラムを読む助けになるから②アレンジしやすい③移すように見える作業も言語を習得する一助になる（by自分の経験）」ことを回答しました。納得した様子でした。 家でやりたい様子だったのでIDパスワードと作り方の紙を渡しました。', null, '時間帯: その他'),
  ('18d09019-fa46-58f0-9149-bfde35db8160', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-20', null, null, '通常 / チャレンジ大賞2024 カニカニハンマー', '進みはゆっくりでしたが、自分のペースで取り組めました。1ページが終わりました。プログラムの仕組みはなんとなくわかったかな？といった感じです。複製の使い方も共有しました。知っていたようです。右と左で混乱していたので確認しながら修正しました。 家出も取り組むそうです。', null, '時間帯: その他'),
  ('7ca0a280-5554-5fc3-9ee9-8e04ca6da45d', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-20', null, null, '通常 / チャレンジ大賞2024 スマブラ', 'かなり賞品が気に入ったようで、スマブラの作成にも最初は熱中していました。変数が空欄であることも説明すると、リストの使われ方も自分でよく確認して納得できていました。必殺技の向きと操作性に疑問があったようなので、アレンジのときに自分で変更するようにアドバイスしました。 またステージ下にキャラがいるときに複数回ジャンプできてしまうことについて、原因（ステージの色）を自分で究明できていたので良かったです。 家にもってかえってもやる時間がなさそうとのことで、持ち帰りはしませんでした。', null, '時間帯: その他'),
  ('72b4e60f-e429-53c9-b0e3-d9c9a4bb6ba2', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-20', null, null, '通常 / アレンジ大賞2024 脱出ゲーム', 'ゲームプレイに熱中してしまうかと思いましたが、比較的自分で進められました。「～でなければ」の考え方が少し浅かったので、具体例を用いて詳しく説明しました。3ページほど進められました。 プログラムを比較的理解できているので、隣に座っているだけで比較的自分で進められる印象です。隣に座りつつ、他の人の指導ができれば、あおしくんに自走してもらうきっかけになるかも？と感じました。', null, '時間帯: その他'),
  ('65205fff-5373-5373-8b1a-90c56127298a', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-20', null, null, '通常 / アレンジ大賞2024 スマブラ', 'スマブラを選んでいたので少しびっくりしました。アレンジの種類が考えやすかったのかな...? 定義の数字入りを使うのは初めてだったようなので、数字入りのプログラムの使い方について共有しました。また、ねこの基本動作のプログラムがおわったときに地面を抜ける問題が発生しましたが、自分で改善点で改善することができました。（私より早かった！！）プログラムを作る順番も非常に論理的で良かったです。nullの概念について少し説明を加えました。', null, '時間帯: その他')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('93bc42f5-2ae5-5cd0-a102-0e81ee702165', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-20', null, null, '通常 / アレンジ大賞を始める', 'デザイン的なアレンジがよりしやすいとのことで、スマブラと迷いつつも謎解きに決めていました。大事なポイントとして、「～済？」系の変数は使い方がいつもと違うので、どういうときに値がいくつになるのかを整理しました。「もし～でなければ～」のネストやステージの背景番号など普段あまり見ない形のコードについても、見たらすぐに内容を飲み込めているようでした。カレンダーの部分まで終わりました。', null, '時間帯: その他
盛り上がり: アレンジの内容はまだあまり思い付いていないようですが、集中して作成を進められていました。'),
  ('2f9e9784-21c8-5645-8981-068011c0a9c4', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-20', null, null, '通常 / アレンジ大賞をやりつつ基本スキルを身に着ける', 'むらっちたたきよりカニカニの方が面白いとのことで、やや難しいとは伝えましたがカニカニを作ることに決めました。初めて見るスキルもたくさん出てきたのでそれを身に着けることも重視して進めました。最初の方でx座標を変えるブロックが出てきたので理解を確認したところ記憶があいまいだったようで、x座標とy座標の違いについて復習しました。不等号についても確認すると、どちらが大きいか決めるものだと答えられていました。メッセージは一度使ったもののあまり覚えていなそうだったので復習しました。かんたろうくんが「メッセージってハガキみたいだね」と言ったので、スプライトどうしの伝言の様子をハガキを送ることに例えたところ納得してくれました。', null, '時間帯: その他
盛り上がり: あまり集中を途切れさせずに頑張っていました。'),
  ('07d84ce5-9da6-5b22-ad18-455158e253a6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-19', '17:30:00', null, '通常 / アレンジ大賞', 'どのゲームも楽しくアグレッシブに遊んでくれました。レベル手kに脱出ゲームを選びました。順調に進めると思いきや、途中で確認すると、表示されないバグが発生していました。何個か重なったバグでっしたが、一人では探せず、一緒に手順書を見ながら見返しました。そしたら、ぞうきんの幽霊効果で消す隠しボタンのスプライトを作っていませんでした。本人曰く、コードしか目にはいっていなかったそうです。 脱出ゲームの隠しボタンは見落としがちなので、注意した方がいいです。', null, null),
  ('bb64fdbc-b660-5d3e-a1fe-768c44c0b2bc', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-19', '17:30:00', null, '通常 / アレンジ大賞の作品をつくる', '授業開始後しばらくはスマブラで遊んでいましたが、アレンジしたいのは脱出ゲームかな、と言っていたので、向いていそうだと声をかけたら嬉しそうにしていました。 作成し始めたときにアレンジから入ろうとしていたので、先生達でまずは元のゲームの通りに作った方が後々困らないと声掛けをすると、素直に手順書を見てそのまま作成をしていました。今日は脱線もほぼなく、集中して手順書通りに素直に作成できていました。 花びらの作成など、自己流でやるとややこしくなるところも、きちんとこちらの補足説明を聞いてその通りに作成していたので、スムーズに進んでいました。コスチューム内での位置の理解も速く、操作も手慣れていてさくさく進められるのが自分でも楽しかったようでした。', null, '盛り上がり: 晴くんの好きそうな題材だったせいか、終始楽しそうに作成していました。 アレンジのアイディアを嬉しそうに話しながらも、今日の時点ではきちんとこらえて手順書通りに作成していたところに、晴くんの成長を感じさせられました。'),
  ('fdeb433f-9f8c-5a2d-842a-ea7fbf4e7b63', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-19', '18:40:00', null, '通常 / アレンジ大賞', 'すっと遊んで、賞に向けてすぐに作り始めました。いつもながらコードはサクサク進み、右腕へのコピーも変更箇所を自分で判断して作れていました。不等号による右へ行かないバグあったが、そこはまだ低学年でうまく気が付けませんでした。 アレンジに関してはカラフルになり、外野も増えて、戦闘機も増えて次回が気になるところで終わりました。', null, null),
  ('8de86d84-e357-5ded-8cbd-ff13eb11c684', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-19', '17:30:00', null, '通常 / アレンジ大賞2024 スマブラ', 'アレンジ大賞も楽しみなようで、スマブラも集中して作成していました（少し体調が悪い様子でした？）最初は自分で作るといっていましたが、プログラムの見本を見せてポイント（リストの長さをプログラムで作っているなど）を伝えると、紙をみてプログラムする方にシフトしました。 家に持って帰って少し取り組むようです！回数が少ないことも伝えました。', null, null),
  ('b8daadd7-8db4-5e83-9766-c0f6dabd0c7e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-19', '17:30:00', null, '通常 / アレンジ大賞', '試遊では、カニの理不尽さに切れ気味でしたが、楽しく遊んでくれました。まだ使ったことない定義などあったが、繰り返しに使うときに役立つことに驚きを感じていました。カニの片腕の動きを作り終えた時、もう片腕に作り写すときに、どこを変えたらいいかじっくり悩みました。途中でほかの子の様子も見ながらやっていたので、コードの作成完成で疲れおわえていました。', 'アレンジ追加', '盛り上がり: 今日はいつもよりうるささ目立ったので、逆に集中できていました。'),
  ('d389d709-1447-528b-b7b8-fb32c5a78b13', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-19', null, null, '通常 / アレンジ大賞2024 脱出ゲーム', 'Excelではなく、アレンジ大賞に挑戦することになりました。用紙を確認しながらひとつずつ丁寧に進められていました。花びらの作り方はテクニックが必要なので、スプライトの作り方を説明しました。画面を少し確認しましたが、きれいにお花が作れていました！ 今まで自分の作品で変数を0, 1の指標として使っていたので、このプログラムと考え方が似ている部分もあり理解しやすいかな？と感じました。 紙を持って帰って家でも少し(?)やるそうです。', null, '時間帯: その他'),
  ('2b5b5937-4e5f-5cb4-bf85-cb10f99df51c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-19', '17:30:00', null, '通常 / アレンジ大賞2024 カニカニハンマー', '遊ぶのにはまってしまったようで、なかなかプログラムを始められませんでした。むらっちたたきも紹介しましたが、反応がイマイチでした。作り方の大枠をプリントを見ながら一緒に確認しました。（理解できたかはかなり微妙です）その後、ひとつひとつ確認しながら進めるように促しましたが、集中力も続かず、1ページ目をプログラムしたところで終わりました。 カニの手を消してしまった（コスチュームはある）ので、今後が少し心配です。', null, null),
  ('a9afbfdf-10d0-59db-a8df-7eace69fe829', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-19', '16:30:00', null, '通常 / アレンジ大賞2024 スマブラ', '変数を空白で最初に定義するところがあり、nullについての質問がありました。0にするのと少し違うので丁寧に説明しました。地面の色のプログラムに少し困っているようでした。アレンジの種類としてステージ変化がでてきました。 ネコのプログラムが終わった様子です。ペンギンのプログラムは家でやってくるようです。紙を持って帰りました！', null, null),
  ('050dd401-6241-514e-a97b-9b14fda75f7d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-19', '16:30:00', null, '通常 / アレンジ大賞を作ろう', '最初に一通り遊びつくして、どれをアレンジするか悩んでいました。悩んだうえ、虎君と同様のスマブラに挑戦しました。レベル的には速いものの歴的にできなくはないので、そのまま進めした。途中にリストなどわからない所をもあったが、とりあえず一言で教えました。 落ちるスピードが遅くなるバグがあったが、重力がおかしいことは気づけていました。猫だけで作るで大変だったので、ここまでとなりました。', null, '盛り上がり: むずかしいながらも景品目的にスマブラにチャレンジしてくれました'),
  ('99d8c023-4d71-55d8-af04-8342cf5cd214', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-18', '16:30:00', null, '通常 / アレンジ大賞の作品作り', '手順書など、これから作成しなければいけないコードを見ると、基本的には「むずかしい」「めんどくさい」という反応をします…が、とりあえずここまで、と細切れの指示を出すと素直に取り組み、結局その先も自分でさっさと取りかかるというパターンが多いです。 口ではぼやいていても、励まされたり、話をしたりしながら作成することは、それほど嫌でもない様子。タイピングなどを繰り返し間違えても、そこであきらめずになんだかんだで最後まで自力でできています。 今日も作成しながらキャラクターをすべて変えて、アレンジしながら作成ができていました。今後の課題は、口でぼやいた後に、先生がそばにつかなくても取り組むことができるようになることですが…現状ではまだまだ、君ならできる！という励ましが必要です。', null, '盛り上がり: キャラクターをすべて変えて、腕の動きなどを真似して作ろうと頑張っていました。ぺらぺらになったプレイヤーを作るためのコスチュームの編集と、コードの作成を交互にやったため、飽きずに楽しそうにできていました。'),
  ('40fa0158-922c-56c9-8ba9-afed1f20c719', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-18', '17:30:00', null, '通常 / アレンジ大賞を作ろう', 'まだ歴が浅いので、むらっちたたきをつくりました。遊んでいる最中からゲームする時間が短いと長くやりたいやる気を出していました。コードは初めて作るところは一緒に作っていきましたが、似たようなコードは自分で判断して作れる場面が増えてきました。アレンジとして無限に続くようにしたいから、別にあきらめるボタンを作りたいのことで、飛び回る猫を作りました。話を聞くだけで、アレンジの候補は良くでき来ています。', null, '盛り上がり: うまくて1回で30点以上を取ってました。'),
  ('367b6506-295f-5927-b649-86013ee16119', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-18', '16:30:00', null, '通常 / アレンジ大賞を作ろう', '歴が積み重なっていないので、るいくんはむらっちたたきを進めました。コードづくりに関しては、基本は一度は使ってあるコードではあるが、それがどこにあるかまだ判別できていなかったです。やはり、40分くらいたつと集中力が切れるので、ゲームをはやんで、なんとか元のコードは作り終えました。まだ、アレンジの構想が聞けていないので、次回はそこからです。', null, null),
  ('134b0ea2-2ada-509f-b561-f1ac539a0362', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-18', '17:30:00', null, '通常 / アレンジ大賞2024 脱出ゲーム', '30分ほど遅刻してきました。だいぶ悩んだ様子でしたが、脱出ゲームに挑戦することになりました。見本を見ながら丁寧に進められていて良かったです。 隠したいものが別にあるようだったので、考えるときにキーポイントになりそうな変数の使い方、メッセージの送り方については詳しく説明しました。 アレンジは家でも考えてくるように伝えました！', null, null),
  ('38d9f8a8-955b-50a1-aedd-d3a741ce875b', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-18', '17:30:00', null, '通常 / アレンジ大賞2024 スマブラ', '本家の方は遊んだことがないようで、ゲームの仕組みの理解に少し時間がかかったようです。プログラム自体はスムーズに進めていました。 ほぼネコのプログラムは完成したそうです。次回はペンギンのプログラムに移ります。アレンジについては家でも考えてくるように伝えました。', null, null),
  ('7d6316cd-f038-586d-983f-c57854c51660', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-18', '16:30:00', null, '通常 / アレンジ大賞2024 脱出ゲーム', 'すぐにプログラムに取り掛かっていました。ぞうきんのスプライトをクマに置き換えつつ、部屋のギミックをかんがえていました。花びらのプログラムの考え方が少し複雑だったので少し丁寧に説明しました。（位置が額縁上に一致する必要があるので、文章にはないけどサポートが必要なように感じました）背景の色を変えるために線を使ったりなど、かなり工夫して頑張っていました！ プログラムは「めんどくさい」といっていましたが、なんだかんだ進めていました。次回で見本のプログラムに近づけたいです。', null, null),
  ('55aafdf9-fc1d-5dfd-935b-f04bcfde5267', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-18', '16:30:00', null, '通常 / アレンジ大賞の作成', '始まる前からホラー系の脱出ゲームをよくやっていたので、今回あるものをホラーに変えて作るそうです。今回は、アルスタジオに元からあるイラストだと怖さが足らないので、主にフリー素材から背景を選んででいました。画像の保存の使えるもの選別を教えました。テーマは決まったので次回からコードを作っていきたいです。', null, null),
  ('1aa3cb6f-7250-57fa-8b84-608fc9747b0c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-18', '16:30:00', null, '通常 / アレンジ大賞2024 カニカニハンマー', '脱出ゲームとカニカニハンマーを比べて遊んでもらいましたが、脱出ゲームはルールが少し難しいのもあり、カニカニハンマーを選んでいました。 ブロック定義を使うのは初めてだったようなので、使い方や仕組みを説明しました。またwindowsの大きいパソコンを使うのも久しぶり（初めて？）だったそうですが、大文字タイピング、半角全角の切り替えも何なくできていました。 途中、プラスマイナスを間違えている部分もありましたが、おおむねよくできていました。カニの胴のプログラムがほぼ完成しています。', null, null),
  ('94f61815-6f5c-5463-8ae7-4367a60fcd37', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-16', '17:30:00', null, '通常 / アレンジ大賞を始める', 'まずは手順書通りに完成させようと頑張っていました。前半はさくさく進んで花の途中まで行きましたが次第に集中力が切れてきて、流れを一緒に確認するなどしました。最終的には中断して残りの時間はゲームをすることにしました。まだ回数はあるから気楽にやろうと伝えました。', null, null),
  ('6bf42cf5-4a06-5961-8217-9214857a516c', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '17:30:00', null, '通常 / アレンジ大賞作成', '3つあるアレンジ大賞作品の中でもアクションゲームであるスマブラ風ゲームを気に入ったようで、制作へと取り掛かっていきました。今までにやったことのある表現も多かったようで順調に作成を進めていくことができていました。結果として本日で基本部分の８割ほどを完成させることができており、次回にはアレンジも一部完成させることができる様子でした。アレンジ部分に関しては、キャラクターの技を増やしていく方針のようでしたので、PvPであるこのゲームの完成度を大きく上げていくことを目指しているようです。', null, '盛り上がり: 作品のアレンジにてどのようにして動きやダメージを決めていくのか、ゲームバランスを考えて作っていきたい様子でしたので、完成度の高いゲームをしっかりと目指していきたい様子でした。'),
  ('2c18f4aa-b6e7-5a32-aaa1-0a4ac0669a28', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-16', '16:30:00', null, '通常 / アレンジ大賞を始める', 'スマブラと迷って謎解きに決めました。ステージの背景#のところでどういうことかわからなかったようですが、今の背景の番号によってアイテムの動きを変えていることを一緒に確認しました。スプライトを色々使うので少し迷っていましたが雑巾やカレンダーのところまで進められました。', '手順書の続き', '盛り上がり: どういうアレンジを加えようか楽しそうに考えながらやっていました。'),
  ('7a134df5-b05a-56c7-8ab0-ffffa2e0fc1e', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '16:30:00', null, '通常 / アレンジ大賞作成', '今回のアレンジ大賞では、3つの中でスマブラ風ゲームの作成を行なっていきました。キャラクターの動作では少し複雑なコードとなっているため、どこがどのようにして動いているのかについて少し悩んでいたようでしたが、コードを１つ１つ見ていくことでどのような動きをしているのかを理解できている様子でした。制作の進捗としても順調で、来週には完成まで持っていきアレンジを開始できる様子でした。アレンジ内容については現在考え中のようで、どのようなアレンジを作るのかは次回までに考えてくるそうで作品の完成度を高めたいと言っていました。', null, '盛り上がり: キャラクターの攻撃モーションについて理解できた際には、どのようにして発展させていこうかと考えていたようで、新たなアレンジを生み出してくれそうでした。'),
  ('3fa4a37d-a919-537e-a21a-8670ccf8738e', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-16', '16:30:00', null, '通常 / アレンジ大賞の作品作成', '最初はゲーム自体の手順がわからなかったようですが、やっていくうちに、絵をいじったりするのが楽しくなったようで、脱出ゲームを選んだようでした。 手順書を見て作成しながら、その場でアレンジを加えていました。 ベッドの下からパスワードが書かれた紙を出す演出を、手順書を見ながら丁寧に作っていました。 作り始めたときは、背景の絵をクリックした判定のためのエリア作成の意味がよくわからなかったようですが、自分でパソコンのスプライトを作成したことで、エリアを作成する必要性の有無がなんとなく理解できたようでした。 パソコンのスプライトをクリックすると拡大するのも、元作品とは違うアレンジをして楽しそうでした。', null, '盛り上がり: さらちゃんらしく、イメージが先行するようで、それを形にしようと頑張っていました。 パソコンの動きを思うようにできたようで、満足そうにしていました。'),
  ('c91eb69f-14aa-5bbd-85ef-554aac6cff32', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-16', '16:30:00', null, '通常 / アレンジ大賞を始める', 'レベルに合ったむらっちたたきをやってもらいましたがつまらないとのことで、「これから岳くん好みに改造できるよ」と伝えましたがカニカニに惹かれたようでした。少し難しいことは伝えましたが、カニカニを作ることに決めました。難しい所は写経しつつ基本的な所の内容を学習していきました。x座標で左右移動する方法や、メッセージ・変数とは何かなどを扱いました。また、行き止まりの定義のコードは難しいですが、どういうときに行き止まりにするか質問すると、右端か左端に行ったときだと分かっていました。コスチュームについては覚えていて、プレイヤーの足の位置がコスチュームによって違うことを確認していました。', '手順書の続き(カニ胴体から)', '盛り上がり: いつも休憩を取るという岳くんが今日は最後までずっと集中していました。'),
  ('2c9e3b11-6576-5460-8e98-0080083c8431', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '16:30:00', null, '通常 / アレンジ大賞作成', '3つのゲームを行なって謎解き脱出ゲームを選んでいましたが、理由として多くのアレンジを入れることができるからと言っていたので、完成品としてのボリュームを重要視している様子でした。終始集中力を切らさずに作成に取り組んでおり、今回の授業中に基本部分を完成させてアレンジまで行っていました。授業時間が終わっても作品を完成させたかったようで黙々と取り組んでいました。アレンジとしては、パソコンを追加してパスワードを集めさせる要素を入れているようなので、パスワードを集めるために謎を追加している部分が多くあることに期待です。', null, '盛り上がり: 驚きの集中力で基本部分を完成させており、本人としてもかなり張り切っているようでした。'),
  ('4587879a-4054-5a28-8c15-ecd910d3fcdf', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '17:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の作品では、謎解き脱出ゲームを気に入った様子でどんな謎を入れていくのかをプレイしながら考えているほどでした。作成では、基本部分に関してはスラスラと作ることができており、作品作りは順調に進めることができていました。ですので、次回か次次回にはアレンジに入っていきたいと言っていました。本人としてもアレンジの部分で差をつけて入賞を狙っていきたい様子でしたので、今後もより作成のスピードを上げてきそうです。', null, '盛り上がり: アレンジでどのようにして差別化を図っていくのかをしっかりと考えていました。'),
  ('71b3eaab-8d2c-5c46-a5a0-b5df9737baa9', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '17:30:00', null, '通常 / アレンジ大賞作成', '今回のアレンジ大賞作成では、謎解き脱出ゲームを作り始めました。作っていくペースもは早く非常に順調に作っていくことができていました。途中で止まってしまうこともなく作れていたので、来週の作成で基本の部分は完成させることができる様子でした。アレンジ内容に関しては、基本が完成したらすぐに取り掛かりたい様子でした。新たなエリアを作り出して、そこに謎を複数入れていきたい様子で、どんな謎を入れていくのかじっくりと考えていました。', null, '盛り上がり: 基本部分を作りながらアレンジではどのような謎を入れていくのかをとても悩んでいて目標に向けて作ることができていました。'),
  ('72e87705-8723-5320-87bf-4eef15e05ef1', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-16', '17:30:00', null, '通常 / アレンジ大賞作成', '今回のアレンジ大賞作品では、謎解きゲームが気に入ったようで作品の制作に取り掛かっていきました。結果として、制作は順調に進めていくことができ、手の止まる箇所もなかったようなので、来週の授業で完成まで持っていけると思います。アレンジしたい内容はある程度決まっていたようでしたので、来週には完成させてアレンジへと移っていきたい様子でした。', null, '盛り上がり: 作品が順調に仕上がっていくので、やる気もどんどん上がっていた様子でした。'),
  ('f02ba73f-7b8f-585d-8404-f9127f548409', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-04-15', '16:30:00', null, '通常 / アレンジ大賞作成', '今回から全4回を通してアレンジ大賞の作品制作を開始していきました。大翔くんは3つの中でもスマブラのゲームが気に入っていたようで、その作品の制作を始めていました。作っていく中で大小関係についてはかなり苦戦していたようで、ジャンプのコードを作っていく際にジャンプ回数の変数をどのようにして設定していくのか悩んでいました。ですので、大小関係について説明をしたところ、コードの組み立てをしっかりと行うことができていました。', null, '盛り上がり: キャラクターの動きでもそれなりにボリュームのある内容なので、作ることに集中してできていました。'),
  ('3cdb516c-31f6-5fb3-a5f1-d9eae36d34c2', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-13', null, null, '通常 / 刀剣ゲームから自分が使いたいと思うスキルを1つゲットする', '「アレンジ」ということで、のあくんのクリエイティブスイッチが入ったようで、スプライトのコスチュームや向き、大きさ、音楽などにとてもこだわって、熱心に作成、検証していました。 ソニックのキャラクターを入れてあげたところ、大いに盛り上がっていました。 コードのアレンジはなかなかできませんでしたが、既存のコードについての質問には答えられていて、これをこの後どうしていきたいか、などは熱心に話していました。 （次回からアレンジ大賞の対象作品に切り替えられるか…）', null, '時間帯: その他
盛り上がり: 新しい教材でのストーリーを考えるのがとても楽しそうでした。'),
  ('de013339-8e98-59ad-aa7b-8d819b891284', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-13', null, null, '通常 / 刀剣ゲームでスキルを身に着ける', '刀剣ゲームを遊んだあと手順書を一通り読んで、「全部理解した」と言っていました。部分的に自分の手で作り直すことやアレンジを促しましたがやる気は出なかったようでロブロックスをやっていました。本当に内容を理解したのか確認するためいくつか質問しましたが、それにはきちんと答えられていました。アルくんの向きの変数は何のためにあるのか聞くと、後ろの方のコードを見て「向きによって剣の座標を変えている」と答えていました。また、「状態」の変数のそれぞれの値はどういうポーズに対応しているかを聞くと、だいきくん自身が実際に正しいポーズを取れていました。', null, '時間帯: その他
盛り上がり: アルスタジオのスマブラを見て、アレンジにはある程度興味を持っていそうでした'),
  ('5f7d70a0-96a2-5158-97ec-50ef93095fcc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-13', null, null, '通常 / 刀剣ゲームから自分が使いたいと思うスキルを1つゲットする', '今日の目的よりも「アレンジ」に完全に気を取られてしまったようで、自分の好きなようにアレンジする方向に暴走気味でした。 1か月以上ぶりの授業で、本人もそれを自覚して「いろいろ忘れてしまっているから」と、最初はモチベーションがイマイチだったため、今日はやる気をもどすことを目標に切り替え、ある程度は本人の発想を優先する方向でいきました。 こうしろうくんが好きなソニック.exe？のキャラクターを取り込んだところ、とても盛り上がって、体力設定のための変数の復習などを少しやることができました。 コスチュームの編集が多かったため、ベクターとビットマップの違いなどを細かく検証していました。', null, '時間帯: その他
盛り上がり: 久しぶりの自由作成はとても楽しかったようで、時間をオーバーして盛り上がっていました。'),
  ('f74cb26c-3a34-5922-90c4-c2cf57e3f346', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-13', null, null, '通常 / 身に着けたいスキルを見よう', 'あるくんの動きについては、向きと何歩動かすの関係に迷っていて、なかなか思った方向に進みませんでした、そのコードができた後、ちゃんと券の向きが違和感あることに気づけていてよかったです。剣について早く作りたいのことでしたが、コードは難しすぎるのので、何か持たせることができることや、実際に動かしているコードはどれか探してもらって、選べて位rました。アレンジは、大きなソードに代わっていてかなり大ぶりな動きになっていました。バックアップの機能も教えることができました。', null, '時間帯: その他'),
  ('53c26940-4357-5e3f-ab48-371a18adc248', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-13', null, null, '通常 / 刀剣ゲームでスキルを身に着ける', 'アルくんとりんごについては、できるだけ手順書を見ずに作成してもらいました。アルくんはすぐにできましたが、りんごはクローンの扱いに慣れておらず難しそうだったので、一緒に意味を追いつつ写経しました。レイヤーの定義については、最前面と最背面を切り替えていることは見抜きました。しかしなぜy座標を比べているのかはわからなかったようでした。', null, '時間帯: その他
盛り上がり: JavaScriptをやるつもりで来たようでした'),
  ('f29fd438-413d-51dd-9772-3f4ed2cd9b08', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-13', null, null, '通常 / 今後の学習の方向性を決める、Scratchのスキル確認', 'お母さんと一緒に話し合って、なるべく早めにScratchの履修をして7月の検定合格を目指し、JavaScriptに進みたいという意向を確認しました。 Scratch基本スキルを確認するという同意のもと、本日の教材2つを細分化してシートに書いてもらいました。口頭で説明しながらスラスラと書くことができていました。 どのコードを使用するか思いつかなかったのは、チーズを探せの「ねずみが壁にあたる」動きくらいでした。 マイナス方向に動くことで先に進めないようにする、というコードには感心していました。 座標の乱数は自力でできていて、虫の回転方向をランダムにするための乱数の使用についても、コードを見たらすぐに理解できていました。 追跡ゲームですべてのロボットのコードをつなげて書いていたので、一つのコードはなるべく簡潔に、違う要素のコードは並列で書くメリットの説明も熱心に聞いていました。 30分で2つの教材を終えられたので、検定問題を勧めたところ、すぐにやりたがりました。 時間内に完璧にクリアして、アレンジもできていました。簡単だったという感想でした。 検定の出題範囲を提示したら熱心に見ていました。一覧に書いてあるスキルをこちらの教材で確認して、検定問題に取り組むという繰り返しで試験対策をしていこうというと納得したようでした。', 'キャッチゲーム、ブロック崩しをやっておきたいです', '時間帯: その他
盛り上がり: Scratchを覚える、というよりも、今後の学習に役立てるようにScratchを学習するということは納得してくれたようで、どの課題にも素直に熱心に取り組んでくれました。
備考: 数学も国語も好きだそうです'),
  ('4a7f524c-36a3-500d-947d-ea7124e64fe3', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-13', null, null, '通常 / 見につけたいスキルを見よう', 'アルくんの動きは、向きと何歩動かすの関係にうまく気づかず苦戦していました。途中、アレンジをしながら、進んでいくので、リンゴの作業になかなかたどり着けませんでした。だが、ジャンプを加えたり、リンゴでなくスイカに変え、切りのコスチュームも作っていて、アレンジの思想は十分に発揮してました。', null, '時間帯: その他
盛り上がり: 最終的には、カラフルになりにぎやかなものになっていました。'),
  ('4ed4fdd0-3f52-5ab5-a628-3d6037d34419', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-13', null, null, '通常 / 刀剣ゲームでスキルを身に着ける', '序盤は作成に乗り気ではなかったですが、一緒に細分化すると手を動かしてくれました。左右移動やキャッチゲームのようにリンゴを落とすなど、今までやった基礎の組み合わせだったので、やり始めるとできました。クローンについては小技で扱った程度で記憶が薄かったそうですが、作りながら、クローンは自分の分身であることや使い終わったら削除すればよいというポイントが身に着いたようです。剣のレイヤーについては理解が追い付かなそうでした。', null, '時間帯: その他'),
  ('a25bc8f4-539c-51c1-9443-a9448e30b0c3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-13', null, null, '通常 / アレンジ大賞のためスキルを身に着けよう', 'リンゴの動きまで、しっかり自分で考えて、形ある同じ動きまで作れていたので、読み取りが上手くできていると思います。剣については、コードの中身までは理解は無理なので、何か物を持たせるときに使えることを伝えてあげました。', null, '時間帯: その他
盛り上がり: ゲームをなかなかコツがつかめず手こずっていました。'),
  ('95ab6175-59f2-5a14-8c41-7a4e2786e3a0', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-13', null, null, '通常 / アレンジ大賞のためスキルを身に着けよう', 'アルくんの動きは理解して作れていました。リンゴについては、y座標初期位置が上手くせってできておらず、悩み止まっていました。xを乱数で動かすことは把握できていたが、ほかの目立たない条件が見落としがちでした。紙を見ながら作っていけば、キャッチゲームの感覚を取り戻せたそうです。', null, '時間帯: その他
タイピング: 頑張っていました'),
  ('c1fa97c1-38c1-5f40-b604-212208a93653', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-12', '18:40:00', null, '通常 / アレンジ大賞のためスキルを身に着けよう', '2，3回遊んでだけで、すぐに製作に進みました。特に、コードに関しては思い止まることなく、サクサク作り上げていました。難しいコードに対しても、屈しない細かいやる気が身についていました。アレンジも、明るいファンシーなものに変えて、いつもの応援の犬たちもうまく躍らせていました。', null, '盛り上がり: カラフルにするの結構好きですね。'),
  ('a8d5b6f5-deed-5eed-bdd3-6d123f1dbc67', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-12', '17:30:00', null, '通常 / アレンジ大賞のためスキルを身に着けよう', '剣の少し離れた感覚が苦手として遊びはスコアを伸ばすのに苦戦していました。リンゴまでが慎重に作っていたので、ミスすることなく作れていました。剣のところについては、コードが難しくて、かなりへこたれていました。けど、少しずつ雨で補給しながら、まだ理解はできないコードを組み立てて、剣のカッコい動きを作れました。残像まではできませんでしたが、やる気は最後まで続きました。', null, '盛り上がり: 競争相手がいると、進みやすいです。'),
  ('5acacbe0-8b8c-5374-a1c0-43847441da6f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-12', '17:30:00', null, '通常 / アレンジ大賞のためのスキル習得', '剣との距離感が鳴れず、苦戦しながらもとても盛り上がっていました。リンゴの落としは自分で作ったバグをこちらからは助言せずに、自力で解決させました。コード自体は簡単だったので、どこが違うのか見つけることができていました。剣の位置について、アルくんの位置を基づいて、(20,20)ずれた位置にある説明してもピントは来ていませんでした。それなら、とりあえず作って楽しくできることがメインで完成まで作れました。', null, '盛り上がり: 剣の形を変え、自分だけのオリジナルを槍を作っていました。'),
  ('dac568c0-8933-5346-b437-416fc7d421f4', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-12', '17:30:00', null, '通常 / アレンジ大賞のためのスキルを得よう', '試遊から剣の離れたリーチにもすぐに慣れ、45点ととてもハイスコアを出していました。作り始めると、はやり、コスチュームから世界観に合わせた配色になっていきました。リンゴまでは、理解しながら難なく進んでいきました。剣のところについては、即答で分からないと解されていしまったので、とりあえず作ってみて、こうゆう動きをできるくらいの感覚で進めました。残像も色を変え、ほんと世界観をにあっていました。', null, '盛り上がり: ゲームのコツを得るのが速い。自分のスタイルで進められていました'),
  ('b0a8bc71-d5e3-5cf3-a989-b5b23096da61', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, null, '2024-04-11', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('02cb1289-59d4-5dad-92ae-b46c6b9b7142', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-12', '16:30:00', null, '通常 / 探知機能を身に着けよう', '刀剣ゲームは今週1度授業がああり、紙通りはできていたので、アレンジを行いました。ジャンプやEDを付けました。その際、スコアの条件の範囲が不等号の一方向だったので、範囲が絞られる条件ができるかくれんぼのゲームを作りました。少し近づいた時が、範囲を不等号で挟んだ時なので、そこを一緒に考えました。見つけた時の条件から不等号の意味を理解し、時間はかかりながらも一人で活用できていました。', null, 'タイピング: スコアが伸びてました
盛り上がり: スイカゲームはスイカが2つ消えるくらいに上達してました。'),
  ('cc37611b-a74f-5a12-963e-4f644b0a0e88', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-11', '17:30:00', null, '通常 / 基本的なスキルを獲得する', 'オリジナル作品の壮大な？構想が自分の中にしっかりとあるようで、これを作るまでは他にはいかないと断言するため、好きなものを作る代わりに必ずファイルの表のスキルをいくつか覚えてスタンプを押していくことを目標にさせました。 作りたいもの自体は、あさひくんはゲームと言っていますが、アニメーション要素の大きいもので、ストーリーもかなり先まであるようです。今はまだ、「これを作るために教室に入った！」という意識が強いですが、もう少し回数を重ねて落ち着いたら、教材をやる時間と作品の続きをやる時間をどちらもとっていきたいところです。 大砲の弾が出てくるタイミングが思い通りではなかったようだったので、旗が押されたときとメッセージを受け取った時の違いを復習しました。 あとから作成したスプライトの後ろでアルくんが見えなくなっていたので最前面のブロックを、大砲の弾の軌跡を指定するため座標に移動するブロックを、地面をぐるぐる回転させるために〇度まわすブロックを学習しまし、ファイルの1枚目にスタンプを押しました。 他の子のやっていることが気になったようで、そうちゃんとスマブラをしたり、こたろうくんとかにハンマーをしたりと楽しそうでした。', 'やりたいことを口頭でしゃべりまくるので、それを細分化→基本操作のどのスキルに該当するか→思い通りの作品を作るために基本操作コースのスキルを学習、という流れに持っていきたいです', 'タイピング: モグラたたきゲームを2回やったあと、プログラミングがやりたいと切り替えていました
盛り上がり: 今日はそうちゃんとこたろうくんがいたせいか、何度も席をたっては嬉しそうに話しかけていました。 立ち歩きも多かったですが、いきなり「続きやる」と席に戻ってみたりと、切り替えも速かったです。'),
  ('964fdc2b-776b-5734-b8e8-5941ac1b0a1f', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-11', '16:30:00', null, '通常 / 刀剣ゲームから自分が使いたいと思うスキルを1つゲットする', 'スプライトを矢印キーで左右に動かす、上からりんごが落ちてくるなど、既習のことについて発問してみると、「習ったのは覚えてるけど忘れた」「わからない」という反応をします。とりあえず間違えてもよいから自分でやってみる、ということに抵抗がある様子。一緒にやりながら思い出していこう、と促すと素直に取り組み、ブロックもある程度自分で「これかな？」と選ぶことができています。基本的に、先生に見ていてほしいタイプ。 アルくんを左右に動かすところはわりとすぐにできたので、りんごの動きを口頭で一緒に細分化しながら作成しました。出てくる座標のxのみを乱数にするなども、口頭では自分で説明できていて、ブロックも少し思い出せばできるといった感じ。細分化して最小単位のコードを一緒に確認して、実際の作成じには少しずつ先生が離れる、といった感じで少しでも自走できるように仕向けてみました。 クローンの説明は簡単にして、りんごが落ちてくる間、刀の残像にあたったら切れるという箇所を一緒に作成しながら、条件分岐や○○まで繰り返すの復習をしました。', null, '盛り上がり: パッと見てわからないと思ったことでも、話をしながら細分化していくと、意外と自分が覚えていたり自己解決できたりするのが楽しそうでした。
備考: 4年生になったので、クラブは野球を選ぶつもりだそうです。 普段のチームでは背番号24で、5番セカンドを任されていると得意そうに話してくれました。'),
  ('b5f85ba1-d6a2-59cb-a60d-c7814504bc54', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-11', '17:30:00', null, '通常 / アレンジ大賞のためいにスキルを身に着けよう', '剣の位置について、最初はノーヒントでいったん考えさせました。当然のようにうまくはいきませんでしたが、アルくんからの距離から決める考え方はたどり着いていました。次に、先に、変数「状態」の変わるようにスペースキーで簡単に作らせてから、県の4つの位置について場合分けをしました。アルくんに対して、点対称的にハチになっていることは自力で理解できていました。その後、そのコードを考えてもらったができず、紙から転記しました。そのコードについて解説を入れる前に、向きのマイナスの数学的仕組みを理解できていました。 しょうじき、剣の位置のコードを理解するには、承太郎君くらいのレベルで義理だと感じました。', null, null),
  ('f752e715-f8e8-5f30-892d-979d473d7eb2', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-11', '17:30:00', null, '振替 / 刀剣ゲームでスキルをゲットする', '16:30～の続きをやりました。リンゴまで終わったので剣に入り、「アルくんと剣の座標はズレている」などのポイントを伝えてからブロック定義「レイヤーを決める」を作り直しました。そのブロック定義を消すと表示がおかしくなるのを確認してもらい、じゃあどのブロックを使えばいいかなと聞くと、最前面と最背面を使うことはすぐにわかっていました。しかしどういう条件で最前面と最背面を入れ替えるのかを考えてもらうと難しかったようで、座標の上下関係が入れ替わっていることを伝えながらコードを写経しました。', null, 'タイピング: あさひくんがやっているのを見て興味を持って遊びましたが、マウス操作はすでにほとんどマスターできているのでうまくプレイしていました。
盛り上がり: 2時間連続でしたが、最後まで集中してよく頑張っていました。'),
  ('2013dcc4-1de6-542d-a314-5f1e5b604ccd', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2024-04-11', '17:30:00', null, '休み（未対象）', null, null, null),
  ('4db0ebd0-b423-50f0-872c-20af24b3f28a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, null, '2024-04-11', '17:30:00', null, '休み（未対象）', null, null, '備考: 小学校で卒業と勘違いされていた模様、授業時間内にお母さんと挨拶に来訪した際、簡単に中学生でも続けるコースがあることを説明。'),
  ('f8aaabe2-9c6a-5de8-98b6-852ac8c7c123', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-11', '16:30:00', null, '通常 / アレンジ大賞のためにスキルを身に着けよう', 'アルくんの動きについては少し向きのかえかたにてこづっていました。リンゴについては、そうちゃんはクローンについて苦手反応がありました。ただ、クローンとは何か聞いてみたら、しっかりと答えられていたので、ゆっくり進んでいけば問題なかったです。リンゴが落ちる動作については、最初何から始めればいいか進んでなかった迷っていたので、キャッチゲームの要領でカードを見せたらスムーズに進めていました。音もしっかり自分のものに変えられていました。17時続く', null, '盛り上がり: スマブラもどきのゲームが入っていたことにとても興奮してました。授業前に先生も交えて遊んでいました。'),
  ('11eba9f5-0b11-597d-8659-2cc5452f1082', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-11', '16:30:00', null, '通常 / 刀剣ゲームからスキルをゲットする', '最初の方はアルスタジオのスマブラに気を取られてしまっていました。しばらくすると本題の刀剣ゲームを遊んで作り始めてくれました。アルくんは左右のキーが押されたら動くことは分かっていましたが、それをコードに直す方法を忘れたようで、一緒にやって思い出しました。残った時間でリンゴのコードを少しだけやりました。', null, '盛り上がり: 久しぶりということもあり、頑張るモチベーションがあまりわかない様子でした。'),
  ('0a510841-1be9-5a29-a8a9-aa160f9c506a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-04-11', '16:30:00', null, '通常 / アレンジ大賞のためにスキルを習得しよう', 'アルくんの動きやリンゴのクローン作製は悩むことなくできていました。途中残像などを形を変えてかっこよくなっていました。剣の位置については、アルくんと少しずれていることは理解できていました。だが、位置の仕組みを理解させるには、教え手側も伝え方に悩んでしまってうまく進めませんでした。なので、剣の4か所の位置(右向き振り上げ時)を場合分けを感覚的にどの位置になるか把握させようとしたところ、理解できていました。不満をためずにできたので良かったと思います。', null, '盛り上がり: エフェクトが音も含めかっこよくなっていました。'),
  ('bef23bac-1c76-5961-aede-425039dc296a', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-04-11', '16:30:00', null, '通常 / 刀剣ゲームでスキルを一つゲット', 'アレンジ大賞の準備として刀剣ゲームを作ると言ったところアレンジに気が向いてしまったようで、落ちてくるリンゴや背景を、時間をかけて自分で描きなおしていました。コードの部分については、「キーが押されたとき」や向きの変更をして、アルくんの動きは自力で作れました。その次のリンゴは時間がなくて、作ったり理解したりするのは厳しそうでした。', null, '盛り上がり: 矢印キーよりもwasdで移動するほうが好きとのことでその方法で作ってもらいました。'),
  ('d33d2265-935b-5558-9964-02b2dfc8d146', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-09', '17:30:00', null, '通常 / アレンジ大賞に向けて、使えそうなスキルを増やす', '今日の目的を説明したあと、とりあえず最初からプリントに沿って作成することを促しました。その後様子を見ていると、コードを見てつまらなそうに作成し始めたので、スキルチェックに合格したら、アレンジから入ってもよいと声をかけると、背筋を伸ばしてきました。 プリントの[Think]を中心にコードの意味を聞いたりしたところ、大体答えることができていたので、完成版をリミックスしてアレンジから入ることをOKしました。 そこからは集中してアレンジに取り組み、可愛らしい作品に仕上げていました。今年は図工クラブに入ったということで、見た目のアレンジにとても熱心でした。', null, '盛り上がり: コスチュームの編集と、それに伴うコードの編集に黙々と取り組んでいました。 できた作品を先生たちや瑞くんが見に来た時も、変に隠したりせずにちょっとだけ得意げにしていて、お迎えのお父さんを自分から呼び込んで見せたりしていました。'),
  ('3d2e6b0c-969d-5c30-98f0-1a7a7933acf0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-09', '16:30:00', null, '通常 / アレンジを意識しながら、条件分岐を使った左右の動きをマスターする', 'ファイルの基本操作コース04_追跡ゲームの01左右に動かそうを見せて、今日はこれをマスターすると説明してから授業に入りました。 前回、イベントの「○○キーが押されたとき」を使ったことを覚えていて、すぐにできる、と言ってきたため、もっと上級のコードの書き方を覚えようと促したところ、素直に説明を聞いてくれました。 右向きの動きを作成してから、左を自力で作成させたところ、向きについてもすぐに「マイナスにするんだ！」と気が付いて作成できていました。 これまでに教えたブロックは比較的良く覚えていて、ずっとを使うことなどもすぐに気づいていました。 コスチュームの編集も、勇作くんが教えられているのを見てすぐに自分も取り組んでいました。', null, 'タイピング: 前回マウスの右クリックで教えたコピー＆貼り付けをしっかり覚えていました。 勇作くんと同時に初めて楽しそうに競い合っていました。
盛り上がり: 16時過ぎから17時半過ぎまで、終始楽しそうにしていました。 ゲームをするのも作成するのも、勇作くんと見せ合いながら常に盛り上がっていました。'),
  ('a6c4ec72-2c27-56c5-a60a-8fb7242c6c1e', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-09', '16:30:00', null, '通常 / アレンジを意識しながら、条件分岐を使った左右の動きをマスターする', 'ファイルの基本操作コース04_追跡ゲームの01左右に動かそうを見せて、今日はこれをマスターすると説明してから授業に入りました。 ファイルのスタンプの数を岳君と一緒に数えて、自分の方が1つ多いと嬉しそうにしていました。 お試しでゲームをプレイさせたときも、岳君より得点が上のことが多かったのですが、自慢しすぎたらいけないと自戒してみたりと、仲良く取り組めていました。 自分のやりたいことの説明を先生が誤解して受け取ったりすると、イラっとした様子を見せることがあります（そうじゃなくて！と強めに伝えてきたりします）が、こちらが落ち着いて再度の説明を求めると、言い直そうと努力してくれるところもあります。 今日の課題をクリアしたいという意志は強く、できあがるまでは集中してがんばることができました。条件分岐をずっとで囲む意味など、説明しても完全に理解はできていないようですが、こういうものなんだ、という感じで作成していました。左右の動きについては大体わかったようでした。 コスチュームで刀を2本に増やし、楽しそうに色を塗ったりして編集していました。', null, 'タイピング: 岳くんと同時に初めて楽しそうに競い合っていました
盛り上がり: 岳くんと一緒に、お互い見せ合いながら作成することが、とにかく楽しそうでした。 それぞれ、相手ができたことをやりたがるので、良い刺激になっていたと思います。'),
  ('1808b881-0673-5ad8-b7bc-5e4ef65930d9', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-09', '17:30:00', null, '通常 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '剣の振り方、位置取りについて最初に説明しました。振る部分を理解するのは少し難しかったようですが、位置のプログラムについては差分も含めてなんとなく理解できたようです。プログラムもスムーズに進めました。アレンジはそうすけくんのプログラムを参考にしつつ、コスチュームを変えて楽しんでいました。', null, 'タイピング: 集中して取り組めました。'),
  ('aa222478-5b64-5ad0-81b8-54310725267a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-09', null, null, '通常 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '最初に一通り仕組みを説明してからプログラムしてもらいました。少し難易度的には簡単だったようです。最後に「Think」とあった部分を説明してもらいましたがバッチリでした。アレンジとして背景を変えて虫が切られるようなプログラムに変更していました。 最後に少し話をしてみたところ、数学とかきらいじゃなさそうだったので物理現象をプログラムで表現してみるのとかが面白いのかな...?と思います。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('0b987939-17f6-5c20-bf07-b565bf4fc2d4', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-09', '16:30:00', null, '通常 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '刀がふれる仕組み（場合分けの変数、手に持っているように見せる方法）を紹介しました。刀を回転させて差分を変化させるプログラムが難しいようでしたが、差分の変化の仕方と状態の変数を使って場合分けする方法はなんとなく理解できたようです。 最後に検証したときにリンゴがうまく出てこなかったので、リンゴが落ちる仕組みについて一緒に確認しました。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 小学1年生たちと同じ時間帯で少し楽しかったようです。'),
  ('6feb4460-e76f-5870-ba38-1d1fb2ded392', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '17:30:00', null, '振替 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '剣の位置の決め方、場合分けについて一通り解説しました。うまく剣が触れなかったので（かなり嫌そうでしたが）プログラムを一緒に見直しました。見直すときのポイントとして場合分けの変数が指標になったので、質問しながら進めました。最後にうまく完成させることができたので良かったです。 途中、休憩を時間を決めて取りました。', null, 'タイピング: 集中して取り組めました。'),
  ('ae9ca75a-fcc1-5721-841a-032e9ec1b347', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '16:30:00', null, '通常 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '丁寧に取り組めました。刀の位置の場合分け、手に持つように見えるプログラムについてはしっかり説明しました。条件分岐と変数が入り組んでいたので全てを理解できていたかは分かりませんが、大枠は理解できている様子でした。 最後検証したときにうまく動きませんでしたが、自分で見本と見比べつつ改善することができました！時間いっぱいまで取り組んでいて良かったです。 作品は完成しました。', null, 'タイピング: 集中して取り組めていました！'),
  ('6d444390-3b69-50da-8c63-59ac0ebff023', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '17:30:00', null, '通常 / 検定2級応用課題2', '遅刻してきたので授業時間全部を使って取り組みました。答え合わせはまだです。 まだ数字が揃っていないのにお金が出てきてしまう不具合があるそうです。', null, null),
  ('406ec2b6-e9eb-5f30-a9f5-9c17c916874b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '16:30:00', null, '振替 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', 'あるくんの向き、りんごの落ち方についてはしっかりできました。リンゴがクローンされているところが少し難しかったようです。解説しました。 剣の最初の場所、回転しているときを変数を使って場合分けしていることを説明しました。 完成した後アレンジとしてスイカが落ちるてくるようにしました。リンゴのコスチュームのプログラムも参考にしつつ、納得のいくプログラムになったようです。', null, 'タイピング: 集中して取り組めていました！'),
  ('ce21e44a-e6ec-5c37-91f5-4925719f88ae', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '16:30:00', null, '振替 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '剣の振り方もよく理解できていました。実際にはプログラムとして作りませんでしたが、アレンジとして剣ビームを考えてくれました。方向によって場合分けしたり、残像を動かしたりなど、想像上ではありましたが細かい部分まで考えられていました。 リンゴの動きをアレンジしてたっちゃんと遊んでいました！', null, 'タイピング: 集中して取り組めていました！キーボードの間隔がいつもと違うようで難しいそうです。'),
  ('c2c38db2-c070-5d55-ac4d-e057e551a365', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-08', '17:30:00', null, '通常 / 刀剣ゲームで剣の振り方を確認 （変数の使い方、条件分岐）', '剣とリンゴの当たり判定が少し気になったようですが、剣のプログラムだけでも作ろうということで始めました。 剣の位置によって場合分けされていること、剣の位置があるくんから相対位置を足して調節していることは分かったようです。最後（残り5分くらい）、剣を振ったときにうまく場所が決まらなかったのですが、途中で終わりになりました。疲れた様子でした。', null, 'タイピング: 集中して取り組めました。'),
  ('2968aa82-4f16-5b3b-8e2d-5dceee7c21c4', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-04-01', '16:30:00', null, '通常 / 基本的なスキルを身に付ける', '授業前にやっていたアルスタジオのマリオゲームに盛り上がってしまい、始めはやや集中力にかけていましたが、ファイルを開いて今日やりたいことを伝えると、スタンプを押したい！という気分になったらしく、いそいそと授業モードに入ることができました。 前回までに作ったところを丁寧に解説してくれて、背景や音も熱心に選んでいました。 前の席にいたひろとくんを見てバイクランを思い出したようで、そちらがやりたくて気が散ってしまったので、基本操作コース03が終わったご褒美に10分間、バイクランで遊びました。ゲームをしながらひっきりなしに、図鑑で知った宇宙のこと、恐竜のこと、動物の生態などを話していました。 追跡ゲームで遊ばせて、どんなゲームだったかを口頭できいたところ、スコアの上がる条件、レベルアップの条件などを答えることができました。 追跡ゲームの背景にあるストーリーを考えて、登場するキャラクターや背景を何度も推敲しながら選んでいました。スプライトを並べて、これがどうして追いかけっこをすることになるのか、など、自分でストーリーを膨らませて、お母さんにも得意げに見せていました。', '追跡ゲームのステージができたところなので、次回は01の左右に動かそうから順に', 'タイピング: なまえさがしで文字の選択と右クリックのコピー、貼り付けを練習しました。 3回ほどやって、「はやくプログラミングしたい」ということで終了しました。
盛り上がり: 一つ一つの動きにストーリーをつけるのが、とても楽しそうでした。'),
  ('a5b213a1-75e6-533c-8ad5-7edcfb07ae13', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-01', '17:30:00', null, '通常 / 検定2級（応用課題1）に挑戦 腕試し', 'プログラムの修正・追加は初めてだと思うので、演習を始める前に紹介しました。演算子の向きを間違えてしまったり、文章の「それぞれ」「ずつ」に惑わされて適切なブロックを選びきれなかったりしていましたが、その他は大きなミスなく時間内に終えられました！！', null, 'タイピング: 100点でした！よく集中できていました。'),
  ('e135f339-81b3-5202-b033-58e22cdc0489', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-04-01', '16:30:00', null, '通常 / バイクラン続き', '前回やったことを風習して、ゲームオーバーからプログラムを始めました。演算子の向きについては少し詳しく説明しました。タイマーの使い方と伏せて道の速さのプログラムを一緒に確認しました。仕組みはなんとなく理解できた様子です。 完成した後もジャンプがうまくいかなかったり自動的にゲームオーバーになったりしてしまいました。プログラムを修正したりしゅうくんに聞いたりして、最後にはきちんと完成できました！！楽しく取り組めてよかったです！', null, 'タイピング: 集中して取り組めました。'),
  ('e250a0dc-1043-5c0a-b350-1e9da7b98311', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-25', '17:30:00', null, '通常 / バイクランの完成', '先週途中まで行ったので完成を目指しました。コスチュームを乱数にするところで、その乱数は何の数なのか問いかけると、少し考えてコスチュームの画面を見ると各コスチュームの番号に対応していることに気づけました。コードの写し間違いによるバグを直す時、完成版と自分の作品の挙動を比べることで原因を探ることができました。また、「タイマー」で計った1秒と「1秒待つ」ブロックには時間の誤差があることを以前知ったらしく、今回もその影響が出ていると教えてくれました。', null, 'タイピング: 100点を決めて達成感を感じたようでした
盛り上がり: 作成を楽しみながら完成できました。'),
  ('78e45457-97bf-5455-b0b2-46d9383abc2e', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-25', '16:30:00', null, '振替 / バイクランのアレンジ', '先週でほぼ完成したのでアレンジに入りました。自転車の見た目や道の色を変えたりと自分好みにしていましたが、道の表示のしかたがおかしくなるバグが出てきました。怪しい場所を一緒に探して直そうとしましたが原因はつきとめられず、できる範囲のアレンジだけして終わることになりました。', null, 'タイピング: なし'),
  ('e5226fa2-ba93-5958-bd75-f843d986b009', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-25', '16:30:00', null, '振替 / バイクラン完成、アレンジ', '先週までで完成に近いところまで行っていましたが、地面にめり込んでゲームオーバーになるバグが直らず、まずは怪しいところがどこか考えたうえで直すことを促しました。ジャンプのところが怪しいといって確かめてくれましたが原因は見つかりませんでした。全体的に探しましたがそれでも見つかりませんでした。アレンジまで行けなかったので、動いている完成版をリミックスしてアレンジすることを勧めましたが、あまり乗り気にならなかったようでした。', null, '盛り上がり: デバッグが出来ずに諦めモードになるまではしっかり問題に立ち向かえていました。'),
  ('91c44c67-396f-5ff3-92f1-63aa3e8e04c6', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-25', '16:30:00', null, '通常 / バイクランに挑戦', 'ゲームも気に入ったようで、授業前に集中して取り組んでいました。 条件分岐もよく理解できていました。地面に触れているor触れていないの判定もばっちりでした！ ブロック定義は知らなかったようなので紹介しました。下の道路をつくるところまで完成しました。切れている道についてもいろんなパターンがあることを気づけていたり、きちんと飛び越えらる距離だったことに感心したりしていました。来週続きの予定です。', null, null),
  ('15d70a63-5df6-5f6d-ad71-55aeb8450754', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-25', '17:30:00', null, '振替 / バイクラン続き', '前回の途中から作成しました。切れている道、下の道路を作成しました。切れている道に関しては、タイマーの役割と速さの変化、コスチュームが複数個あることを紹介し、プログラムと完成がリンクしていることに気が付いてもらいました。 最後まで終わらなかった（最初の画面なし、バイクが地面にめり込む）のですが、途中休憩5分ほどでしっかりと取り組めていました。話している中で2桁の数字をジャッジするのが苦手なように感じました！2年生なるとなれるのかな?と思います。', null, null),
  ('e954e447-0bf1-5413-b30c-a837a87d0d9b', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-25', '16:30:00', null, '通常 / 基本操作復習など（北極のプログラムを振り返りつつ） 世界を創造しよう', '前回の復習の後、あちこちに動かす、左右に動かす、拡大縮小をするプログラムを確認しました。プログラムが始まるトリガーをしつこくやったので、「旗を押す」「キーを押す」が区別されてきたようです。あちこちに動かす、左右に動かすではブロックこそすぐ分からなかったものの、北極のプログラムでやったことは覚えていました。 バイクランが気に入ったようです。途中で休憩しつつでしたが最後まで頑張っていました！', null, 'タイピング: 集中して取り組めました。'),
  ('61b86e03-dccf-5c9b-8c8d-ca09b81727bf', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-25', '16:30:00', null, '振替 / コンテスト作品(バイクラン)作成', 'バイクランは初回だったので、しばらく遊んでもらって十分ゲームのしくみを頭に残してもらってから始めました。最初のほうに出てきたマウスポインターについて、マウスとマウスポインターが一緒だと思っていたそうなので違いを伝えました。メッセージをいくつか扱ったので、どこで送ってどこで受け取っているのかという流れを一緒に確認しました。スタートボタンと棒人間の動き(ゲームオーバー以外)まで終わりました。', null, '盛り上がり: あまりこういうゲームのプレイが得意ではなかったようで、遊ぶより作るほうがいいと言って作成を頑張ってくれました。'),
  ('ec1c387e-fcac-514f-acf8-1c38c57fcaf8', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-03-25', '17:30:00', null, '休み（未対象） / 当日お休みです。連絡し忘れていましたとのことです。', null, null, null),
  ('fcdd57a6-0f50-55a9-9738-927e9e22b70f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2024-03-25', '17:30:00', null, '休み（未対象）', null, null, null),
  ('640410d3-8dd3-526f-bcbc-5c0d32d3cfa1', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-03-18', '16:30:00', null, '休み（未対象） / 体調不良で欠席、当日コミルからの連絡のため、振替え未対象', null, null, null),
  ('a1429815-8183-55cd-98a3-a30a68a057ab', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-18', '17:30:00', null, '通常 / コンテスト作品(バイクラン)作成', '作成はスムーズに進み、内容をわかっているか問いかけもしましたが、しっかり考えて理解することができました。「地面に触れてる」という変数は少し使い方が特殊ですが、着地してるとき0で跳んでいるとき1だと説明できました。ブロック定義については使ったことはあるがどういうものだったか忘れたというので概要を説明しました。すると、動きの定義を作り終わった後、「じゃあこの動きはどこで使っているんだろう」と流れをたどれていました。', '続き(下の道の部分から)', 'タイピング: コンテストにバイクランとタイピングがあると伝えるとすぐにタイピングをやる気になりました。先生も参加する中ランキングで1位を取れてうれしそうでした。
盛り上がり: タイピングに続いてバイクランでも優勝して二冠したいと楽しく頑張っていました'),
  ('ae291520-4e51-5eb2-bf36-dbccd78ecc7a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-18', '16:30:00', null, '振替 / コンテスト作品(バイクラン)の作成', 'マウスポインターやゆうれいなど中心となるポイントについて理解しているか問いかけをするときちんと答えられました。変数を使うことにはあまり慣れていないようだったので、「きょり」はスコアのようなもので段々変えることができると説明するとわかった様子を見せていました。', null, '盛り上がり: 最初のうちは記録を伸ばそうと遊ぶことに夢中になっていましたが、一つのパートが作り終わったらしばらく遊んでいいと約束するとある程度メリハリがつきました'),
  ('b5ee776f-8cda-5c86-a66a-8ded1f6c6792', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-22', '18:40:00', null, '振替 / バイクランの完成', '1時間しかなく歴が浅かったので、ひと部分だけ作成しました。作りえたブロックに対してなにができるかをきいても、正しく答えられていました。クローンはおそらく初めてであったが、何となくは同じものを作る認識は持っていました。 完成してもも物足らなかった出の、最後に背景を変えて満足してました。', null, '盛り上がり: 完成できて楽しかったそうです。'),
  ('adbdac04-6a0e-55cb-bc58-a908aea2a4dc', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-22', '18:40:00', null, '通常 / バイクランの完成アレンジ', '前回で完成していたので、今回はアレンジをしました。はるくんのアレンジアドバイスもあって、背景を変えたり、ジャンプを大きくしたりして、ゲームがやりやすいようになっていました。', null, '盛り上がり: 残り時間はスコア更新を目指してがばっていました。'),
  ('5593164a-9455-5bb9-af2e-3f3a7ac38c9e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-22', '17:30:00', null, '通常 / バイクランの完成', '最初15分ほど遊んでから、ゲームオーバーの続きから作りました。画面上から色を持ってくるやり方を知らなかったので、教えてあげました。そこで、一通り完成させると、いくつかバグが残っていました。y座標のマイナスや使うブロックを間違っていたりあったが、特に注意が必要なミスとしては、「かつ」「または」の入れ子になっていました。そのミスに気づいたとき、最初本人はどんなミスかわかっていなかったので、ケイト君のフォローもありながら一緒に学びました。', null, '盛り上がり: 同じ時間帯の子で楽しく盛り上がっていました。'),
  ('285a216b-df7a-5aac-bb99-e15d9800c122', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-22', '17:30:00', null, '通常 / バイクランの完成', '一つのブロック塊ごとに、確認しながら、作れていたので、よかったと思います。けいとくんやゆづきくんが先にジャンプを完成させていたので、それに追いつきたいと後半は楽しんで定義のブロックを完成させていました。ジャンプの回数のところをどこでいじるかわかっていたため、何回もジャンプできる仕組みになっていました。', null, '盛り上がり: 安定して200まで行けるがそこから先はむずかしいそうです。'),
  ('9a5b8056-322d-5603-b5d7-006e71e88abc', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-22', '17:30:00', null, '通常', '前回に少し難しく感じたため、アレンジをしながら、作り続けていました。ジャンプの回数を増やしたり、足場の黒の面積を冷やしたりして、遊びやすいようにしていました。背景も変えて、派手な見た目のゲームに代わりました。', null, '盛り上がり: 時間がなくてできなかったアイデアをとうきくんに見せて、与えて楽しそうだったです。'),
  ('41429a7e-73ed-5ca1-9c82-13495e71acc7', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-19', '17:30:00', null, '通常 / プレイしたゲームの細分化と作成に挑戦', 'バイクランをプレイしてみましたが、こういうゲームがあまり得意でないのか、わりとすぐにやめてしまっていました。そのせいか作成にも気が乗らなかったようで、他の課題がしたいと言ってきたので、なんとなく他の作品を探し続けたり、先生が一つ一つ「これはどう？」と提示するではなく、自分でしっかりと「今日はこういう形のゲームを作成したい」という目標を言えるのならOK、そうでないなら、先生が決めてきたこのゲームをしてもらう、と伝えました。しばらく逡巡していましたが、いつものようになんとなく画面をいじったり、姿勢を崩したりすることもなく、きちんとこちらを見てから、「上から落ちてくるものをよけるゲームを作りたい」と言ってきたので、許可を出しました。 今日は一から作る時間はないので、【Prg】29 カミナリをよけろゲームを作ろう！を見せてどのようなコードを使っているかを確認し、ある程度理解ができたら、時間内に完成するように計画的にアレンジをする、という課題を出しました。 最近はダレることが多く、あまり乗り気でない授業態度が続いたので、自分自身で目的を決め、責任を持ってそれに取り組むことを優先させてみましたが、それがよかったのか、今日は最後まで集中できていたようでした。 一通りのアレンジができたところで先生を呼んで、どんな風に自分が工夫したかを口に出すこともでき、その先のアレンジ計画についても「今日はここまでやりたい」と説明してから取り組んでいました。 最終的に、こちらからも攻撃可能にしたり、セリフや背景の変化にストーリーを感じられるような作品に仕上がり、久しぶりにお迎えのお父さんに嬉しそうに見せていました。 モチベーションの回復という点では、よいレッスンになったかと思います。', null, 'タイピング: 自分から、少しだけやっておくといって取り組んでいました
盛り上がり: 久しぶりに集中して取り組めていて、発言や笑顔も多く見られました。 授業態度だけでなく、自分の考えていることを言葉で伝えようと努力している様子も見られ、とてもスッキリした感じで帰っていきました。'),
  ('47511082-ef8f-5a62-9bd7-fd458536309e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-19', '17:30:00', null, '通常 / プレイしたゲームの細分化と作成に挑戦', '手順書を見ながら、ゲームのどの部分がどのコードに対応しているかを説明してもらい、その後コードの方を見て、どの動きに対応しているかなどをできるだけ説明してもらいました。初期設定のところやクローンのところも、きちんと理解して説明することができていました。 時間があまりなさそうだったので、コードの解析をしっかりして、作成はシンプル版にしましたが、予想以上に早く作成できたので、残り時間で「ゲームを簡単にする」アレンジをしてもらいました。 自分で何度もプレイして、ジャンプの可能回数が何回ならうまく進められるか、丁寧に検証していました。「この回数がいい！」とプレイさせてくれたアレンジ版は、確かに私でもプレイしやすかったです。', null, '盛り上がり: もともとの課題もアレンジ版もきちんと仕上げることができて、コンテストの方もランキング入りの成績を出せ、スッキリした感じで今年度の授業を終えることができていました。'),
  ('bcc4918d-9455-5bda-b1a4-e001cd77be65', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-19', '17:30:00', null, '通常 / バイクラン', '前回作成していた続きから始めていきました。作成に集中していきたい様子で、ゲームのプレイはほとんどせずに作品の完成を目指してひたすら作っていました。作品を作っていく上で、つまづくような箇所もなく順調に最後まで作る事ができていました。しかし、子どものボタンを押した際にすぐゲームオーバーになってしまうバグあるようなので、金曜日の授業にてデバッグをしていきたいと言っていました。', null, '盛り上がり: 作品完成を目標に頑張っており、バグは残っていますが最後まで作る事ができたので一息つくようにランキングにチャレンジしていました。'),
  ('120a7006-db0c-5604-9460-8927ef1005b9', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-19', '17:30:00', null, '通常 / バイクラン', '前回作っていたバイクランの続きを作成していきました。半分ほど完成していたようなので、残りを作っていく際にもさほど時間はかかっていない様子でした。作品としてどこがどの動きを司っているのかをしっかりと理解しながら作れていた様子で、キャラクターの動きをアレンジするにはどうすれば良いかを考えていました。プレイでは、かなり上手く距離を稼ぐ事ができており、最終的にはランキングにて1位を獲得することができていました。', null, '盛り上がり: ランキングで1位を取れた際にはかなり喜んでおり、自分に嬉々として知らせに来てくれました。'),
  ('c4ba8115-9760-5621-b9c8-c66ec7f945bd', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-19', null, null, '通常 / プレイしたゲームの細分化と作成に挑戦', 'ゲームを始めて数回目で、ランキングに入る好記録を出していましたが、その後女の子たちとゆうさくくんに囲まれてしまって、困惑していました。 手順書を見ながら、ゲームのどの部分がどのコードに対応しているかを説明してもらい、その後コードの方を見て、どの動きに対応しているか、この順序や場所である意味などをできるだけ説明してもらいましたが、定義やクローンの箇所も含め、きちんと理解して説明することができていました。 作成時は手順書を見ずにできる限り自力で頑張っていましたが、自動運転になってしまうバグを修正するところまではできませんでした。 時間すぎまで、自力で修正しようと粘っていました。', 'Scratch、Monaca、ロブロックスなど、自分でも興味があることややってみたいことが色々あるので、何を学びたいか春休みに考えてみるそうです。', '時間帯: その他
盛り上がり: とにかく自分でやってみようという姿勢が見られ、ずっと集中して取り組めていました。'),
  ('44e08fe5-30d2-5921-bac6-1f8ec58b8a59', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-19', '16:30:00', null, '振替 / バイクラン作成', '今月最後の授業で、バイクランの作成とプレイをしていきました。プレイでは、本人がゲームを苦手なこともあって、イマイチな結果が多かったため本人としてもかなり悔しい様子でした。ですので、作成をする際にはどのようにしたらよりスコアを伸ばせるのかと絡ませながら作っているようでした。その結果、作品に対しての理解度を深める事ができ、作品でのスコアの伸ばしやすさを見つける事ができている様子でした。', null, '盛り上がり: 咲良ちゃんと一緒に作品をプレイしてスコアを競っており、両者とも楽しそうにプレイしていました。'),
  ('a3932b5a-08e1-5053-8e5c-c3bce2ce4acd', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-19', '16:30:00', null, '通常 / ゲームを楽しみながら使えるコードを増やす', 'バイクランのゲームにはとてもハマって、ランキングに入るまではやめない、だから今日は授業はできない、と言い張って、かなり真剣にプレイしていました。最高記録が140点台くらいで、とても悔しがっていました。 授業開始後20分以上プレイして、ランキング入りできなかった気晴らしに3回だけマリオをプレイしてようやく授業モードになることができました。 バイクランのスタート画面を作ろうとしましたが、そこだけではつまらないようでやる気が出なかったので、基本操作コース06に切り替えました。 完成版を見てから同じものをつくるのを、最初は「難しいのでは」と警戒していましたが、やってみたら面白かったようで、〇秒待つも自分で思いついて得意そうにしていました。 やっていくうちにストーリーも思いついたようで、ストーリーを実行するために「表示する」「かくす」「〇秒で座標にいく」などのブロックを覚え、嬉しそうにスタンプを押していました。〇秒待つではなくメッセージを使用する意味も納得できたようでした。', null, '盛り上がり: 最初のうちは、「今日はゲームしかしたくない」と言っていましたが、作成に入ってからはよく考えて楽しそうに取り組めていました。お話を考えて形にできるのが嬉しそうでした。
備考: 明日は卒園式だそうです。'),
  ('66a58989-cb5a-5365-9acf-3df954230ef3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-19', '16:30:00', null, '通常 / バイクラン作成', '今回が3月最後の授業ということで、コンテスト作品のバイクランをプレイしてから実際に作っていきました。とても楽しそうにプレイしており、ランキングに乗れるように一生懸命挑戦していました。眞子ちゃんと競っていたり、陽色くんのプレイをみて学んだりと積極的に取り組んでいました。作成においては、30分ほどで完成させる事ができており、内容についても作った部分だけでなく全体の動き、特にスピードアップの部分を理解しようと考えていました。', null, '盛り上がり: 作成が終わり、作品の理解度が深まったことでより良いスコアを目指して頑張っていました。'),
  ('b89448a1-3050-5378-8d0b-5f95d79dd050', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-18', '17:30:00', null, '通常 / 前回の修正 ＆コンテストの作品作成（バイクラン）', '自由作品には「もっている」という変数を追加して、鍵が出現する場面を限定したりかごに触れて最後の画面にいくようにしました。変数を使うことは理解できたようですが「まで待つ」の考え方が少し難しかったようです。 バイクランはイチからプログラムを始めました。グレーに触れたときにゲームオーバーになる仕様が気に入らないようです。 少し気分も上がっていなかったようで、方針を変えて（学習効果が低いかもしれませんが）、写した後に動かしてプログラムの内容を確認することにしました。ジャンプの部分、スタートボタンを押す部分、地面に触れている変数のプログラムはしっかり確認できました。', null, '盛り上がり: 気分が下がり気味だったのでプレイする時間を途中にも作りました。プログラムを読むのが得意な様子ですが、「自分がこれしたい！！」の気持ちがあるときに真価が発揮されるのかもしれません。'),
  ('7eec362f-9481-55d8-b4ba-beff7377c7cc', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-18', '16:30:00', null, '通常 / コンテストの作品作成（バイクラン）のスタート画面作成', '前回の復習（コスチューム変化や色の大きさ）をしてから、スタート画面のプログラムをしました。マウスをボタンの上に置いたときの大きさの違いとスクリプトの内容がリンクするように伝えました。まだ「もし」を使ったことがなかったので少し難しかった印象でした。数の大小も理解しながら進められました。また、幽霊の効果を紹介しました。言葉からブロックの役割をイメージできていたようで良かったです。後半は少し疲れた様子でしたが最後まで作れました。 アレンジとして鳥をあちこちに動かしました。たまたま色が合って上に乗れることもできました！楽しかったようです。', null, 'タイピング: もぐらたたきとパズルに挑戦しました。スムーズでした。'),
  ('20e70012-38b2-5009-a9cc-b1089227f8b3', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-16', null, null, '通常 / バイクランを理解しよう', '最初はだいぶ気に入ってもらって存分に遊んでもらいました。ほどほどに気になることろをブロックについて聞きましたが、時間をかけて自力で答えることはできました。少し難しい2段ジャンプのところについては少しこちらが補助しましたが、コード理解はできていました。ただ、作業量は多かったので、途中遊びをいれてストレスたまることなくできていました。', null, '時間帯: その他
盛り上がり: 最後まで終わらなかったものの、今期は最後だったので、紙を持ちって続きをやるそうです。'),
  ('385cbfc1-6c99-54fb-9d83-35be9d528538', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-16', null, null, '通常 / コンテストの作品作成（バイクラン）（難易度下げたver）', '10分ほど遊んで早々に作りました。 定義の部分は難しいかなと感じたので①初期化②距離の加算③ゲームオーバーのみを自分で作ってもらい、その後はアレンジを加えながらスクリプトの意味を確認しました。①②はとくによく理解できていてしっかり説明もできていました。ゲームをしながらゲームオーバーの条件も確認できました。 アレンジとしてジャンプの回数、はやさを変えました。はやさに関しては難しかったようだったので、地面にいるときいないときでの変数の変化に注目して解説しました。少し難しかったようです。その後、道の速度を変えました！タイマーが新しかったようですが条件分岐に気が付いてよく理解して変数をアレンジできていました！', null, '時間帯: その他
盛り上がり: 楽しそうで良かったです！'),
  ('1b23b4f5-8e0d-5eda-b988-02343229d830', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-16', null, null, '通常 / コンテストの作品作成（バイクラン）（難易度下げたver）', 'かなりプレイしていました。楽しかったようです。 定義の部分は難しいかなと感じたので①初期化②距離の加算③ゲームオーバーのみを自分で作ってもらい、その後はアレンジを加えながらスクリプトの意味を確認しました。③に関してはプレイしながらよく確認できていました。②は少し説明を加えると「なるほど！」という感じでした。 アレンジとしてジャンプの回数、ジャンプの最初の大きさを変えました。プログラムの仕組みは少し説明しました。その後ジャンプしているスプライトのコスチュームに風船を追加しました。（お気に入りのようです）コスチュームの切り替わりのプログラムを説明したかったのですが、時間切れでした。', null, '時間帯: その他
盛り上がり: ゆうとくんともかなり盛り上がりました！楽しかったようです。'),
  ('ce58302f-7215-5da0-9261-d6f259751ced', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-16', null, null, '通常 / バイクランの構造を理解しよう', '最初遊びだしたらかなりはまってくれました。作り始めるのは遅くなるかなと思ったが、作り終わった早くやりたいから、速くやっていました。途中、2段ジャンプの制御や、ゲームオーバーの判定、未知の動きなどどう動いているかコードを用いて説明してもらいましたが、特に悩み止まることなくすらすら答えらていました。しっかりとコードと画面上の対応ができていると思います。', null, '時間帯: その他
盛り上がり: 現段階までで9位まで最後詰めていきました。'),
  ('df887602-2fd2-5f62-97db-6508fb2d46dd', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-16', null, null, '通常 / コンテストの作品（バイクラン）作成', 'プレイもほどほどにかなり早いタイミングからプログラムを始めましたが、終わりませんでした。 「もし～でなければ～」を使うのが少し苦手な様子だったので、ボタンのプログラムの条件分岐のところを一緒に上から確認しました。プログラムの読み方がなんとなく?理解できたようです。地面の考え方は場合分けして考えられていました。定義を使ったことがなかったようなので役割を紹介しました。 少し疲れている様子でしたが最後まで頑張っていました！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('e2797504-4dd3-552a-b717-dd9917348be4', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-16', null, null, '通常 / コンテスト作品(バイクラン)の作成', 'それぞれのスプライトを軽く細分化してもらいつつ作成を進めました。一部のブロックを間違えるなど軽いミスはありましたが、基本的にスムーズに作れたのでほとんど完成まで行きました。また、タイマーや着地の処理など重要なところについて「ここのコードはどういう意味かな」と問いかけると考えて答えることができました。', null, '時間帯: その他
盛り上がり: 遊ぶときに上位を目指して粘っていて、ランキングに乗ることができました。'),
  ('91629775-d5c0-5ef2-a9ed-9106c9d83f7c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-16', null, null, '通常 / コンテストの作品（バイクラン）作成', 'ひとつずつ確認しながら取り組めました。作業がひとつずつ丁寧にできていました。 スタート画面のボタンの挙動や、ジャンプの変数の変化、地面の上にいるorいないなどの判定もよく理解することができていました！ゲームオーバーまで作って半分ほど終わりました。座標と演算子を使った判定も理解できている様子でした！最後まで終わっていませんが、あまり本人が気にしないなら別のことをしても良いかなと思います。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('a501aa36-6fd8-51ca-bbe8-57de85fda94c', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-16', null, null, 'バイクランの構造を見よう', '特に中止すべきブロックの塊についてそれが画面上でどのような動きをしているかたびたび聞きながら進めました。最初のスタートボタンの大きさについてはスムーズに答えられていました。だが、変数の初期化のところでは、少し言葉を詰まらせ、そのままコードを読み毛ていたので、ひとことで言うと？」とわかりやすく聞いたら、リセットと答えられていました。道との触れる判定のところでは、棒人間がどの状態か道に触れているときと否定形の受けごたえしかできていませんでしたので、一緒に考えてやりました。このようにこのコードが画面上でどの働きをしているかあまり対応はできていない感じです。 今回のジャンプは放物ジャンプだったので、放物ジャンプのシンプルなコードが今回ではどこに対応するか考えていきました。変数の初期化の部分は答えられたが、ｙ座標の制御や変数の下がり幅の部分は見つけられませんでした。自分と一緒に探して見つけましたが、顔的にはあまり理解していない感じの雰囲気でした。', null, '時間帯: その他
タイピング: 集中して取り込んでました
盛り上がり: 200以上の記録に刻んでいました。'),
  ('2e582785-e3d1-5e42-a751-d3b2d04123f3', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-16', null, null, '通常 / コンテストの作品作成', 'わりと長いことバイクランで遊んで熱中していましたが、「～回遊んだら作り始める」と約束してその通りにしてくれました。作成途中、ゆうれいの効果や着地の判定について問いかけて確認しましたが理解しているようでした。着地のブロック定義が何をしているかはよくわからなかったそうで、自転車が地面にめり込んだときに地面の上まで移動することを伝えました。中盤の道の動きの途中までできました。', null, '時間帯: その他
盛り上がり: バイクランによく似たゲームを思い出したようで、このあと久しぶりに遊んでみようかなと言っていました。'),
  ('42a30902-e6df-512b-9b77-2ba3afeedb3d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-15', '18:40:00', null, '通常 / コンテストの作品（バイクラン）作成', '20分ほどプレイしてからプログラミングを始めました。ゲームの難易度も少し難しかったようで、淡々としていましたが記録にこだわって挑戦していたようです。 プログラムは変数の使われ方や数の変わり方を追ったり、条件分岐の細かい部分を確認したりするのは苦手なようです。一緒にスクリプトの意味を確認して進めました。「かつ」と「または」を同時に使う方法も紹介しました。2枚目まで終わりました！次回から道のプログラムになります。', null, 'タイピング: 集中して取り組めていました。'),
  ('21524dc0-7bab-54a9-b913-09520e59c19f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-15', '17:30:00', null, '通常 / コンテストの作品（バイクラン）作成', '30分ほどプレイしてプログラムを始めました。ゲームが難しすぎて記録が伸びなかったのが悔しかったようです。ただ周りの人と同じゲームをするのが楽しかった様子でした。 プログラムを始めるように何度も声をかけましたがあまり進みませんでした。スプライトのコスチュームを変えたり、色をアレンジしたりしていました。1ページ目がなんとか終わったあたりです。次回頑張りたいです。', null, 'タイピング: あまりやりたくなかった様子ですが、なんとか取り組んでもらいました！'),
  ('d7525619-709c-5a1a-a58f-f0cd42422fb5', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-15', '17:30:00', null, '通常 / コンテストの作品（バイクラン）作成', '30分ほど同じ時間帯にいるメンバー全員とプレイしてから始めました。はるくんとは顔なじみになっていたようで、ゆづきくん、はるまくんも含めてかなり盛り上がりました。「棒人間の頑張りが足りない」と言っていました。 1つずつプログラムを確認しながら作ってもらいましたが、おおよその部分はよく理解できているようです。「かつ」「または」が両方使われている部分の構造が分かりにくかったようで質問してくれました。いい部分に注目できていると思います。ゆづきくんと刺激し合いながら(?)おおよそ半分ほど進めました。', null, 'タイピング: 集中して取り組めました。'),
  ('ede8954c-64e0-5901-a7e8-5782c834b6b5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-15', '16:30:00', null, '通常 / コンテストの作品（バイクラン）作成', '15分遊んでから作品作成に取り掛かりました。地面に触れている・触れていないの判定やジャンプのプログラム、地面のスプライトの動き方に注目してもらいました。スプライトの速さがタイマーによって制御されている部分も理解できていました！ 一通りプログラムは終わりましたが、次回アレンジに挑戦してみたいようです。', null, 'タイピング: 集中して取り組めていました。'),
  ('77bf2e85-6b12-5c15-9d09-b7714997c479', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-15', '17:30:00', null, '通常 / コンテスト作成', 'プレイではかなり夢中になっていました。最高点を更新しようと熱中して挑戦していました。その最中でも、作品の特徴である２段ジャンプやゲームオーバー、スピードアップの判定には気づく事ができていました。制作に関しては、プリントを見ながらブロックの内容を理解しながら作っていきました。最終的には目標としていた半分まで作り終える事ができていました。この調子で来週に完成させたいと言っていました。', null, 'タイピング: 丁寧に打つ事ができていました。
盛り上がり: 作品を目標としていた半分まで作り上げる事ができてとても満足した様子でした。'),
  ('f0c38ba4-9725-5b7d-a8fd-ad07ac474069', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-15', '16:30:00', null, '振替 / コンテストの作品（バイクラン）作成', '自由製作が作り途中でしたが、一度遊んでみてこちらに挑戦したいとのことでした。 15分ほど遊んでから取り掛かりました。変数の使い方やジャンプの仕組みなどはおおよそ把握できている様子でしたが、言葉にするのが難しい様子でした。あと半分ほど残っていて、道のプログラムがまるまる終わっていないです。 楽しく取り組めていました！', null, 'タイピング: 集中して取り組めました。'),
  ('949bffd9-8360-5dd0-a308-65c14c9c9ca0', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-15', '17:30:00', null, '通常 / コンテスト作成', '作品のプレイ段階では、作品を楽しみつつも２段ジャンプやゲームオーバーの条件について気づく事ができていました。制作時には、プリントを見ながらどのブロックがどの動きを指しているのかを確認しながら作っていきました。最終的にプリントの1枚目まで完成させる事ができました。かなりブロックの数が多い内容で1枚終わったのは良い結果だったと感じました。', null, '盛り上がり: プリント1枚を終わらせることができていたので、１つの区切りまで完成させる事ができて嬉しい様子でした。'),
  ('ba77ac95-9b41-5d84-a14f-222627ed2dbc', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-15', '17:30:00', null, '通常 / コンテスト作成', 'コンテストのプレイでは、シンプルながらも難しいということで、かなりハマってプレイしていました。スコアが表示されているので、自分の順位が把握できることでより上を目指そうと頑張っていました。作成に関しては、かなり早い速度で進めていました。プログラムの内容としても、どのようにして動いているのかについてかなり把握できていた様子でしたので、詰まる事なく作っていました。帰りの電車の時間が迫っているようだったので、残りはプリントを持って帰って家で作るようです。', null, '盛り上がり: 制作時に、今までにやってきたもののおさらいみたいで、内容がわかって楽しいと言っていました。'),
  ('1caf70bc-1bf3-51b0-9d81-c4bfa2a9a81d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-15', '16:30:00', null, '通常 / コンテスト作成', '今日から開始したコンテスト作品を実際にプレイしてから作っていきました。ゲーム内容がシンプルながら、一度のミスも許されないという状況なので、常にハラハラしながら楽しんで遊んでいました。スコアを伸ばして良い順位に入ろうと夢中になっていました。作成の段階では、プリントを見ながらこのブロックが作品のどの部分を動かしているのかを確認しながら作成していきました。ブロックの内容についてしっかりと理解をしていきながら作成をしていくことができていたので、前のブロックで送ったメッセージなどについても何のために送られているのかを把握していました。最終的に半分ほどしか完成させる事ができなかったため、本人としては完成まで持っていきたい様子でした。', null, 'タイピング: 素早く打つ事ができていました。
盛り上がり: コンテストで上位に食い込もうと熱中して遊びながらも、キャラクターの動きやゲームオーバーについて注目できていました。'),
  ('31e02417-95cf-5295-bdb1-7095c8447d19', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-14', '16:30:00', null, '通常 / 細分化と条件分岐に慣れる', '単元別演習のカードを見せると、何から手をつけていいのかわからないと言ってぐだーっとなっていたので、やり方のコツがわかればこたろうくんにもできる！と声掛けをし、口頭で細分化をしていきました。 完成版をプレイして、それぞれのスプライトの動きを説明させ、カードの表面を参考に、動きのきっかけとなるイベントを答えさせたあたりで、「作れるかも」と乗り気になって、自分でブロックを並べ始めました。 条件分岐のブロック、調べるブロックなども覚えていて、ほぼ自力でF1を完成させ、満足そうにしていました。 F2も、カードを見せたときはぐだーっとしかけましたが、このネコの動きは？と問いかけ始めたあたりで、「さっきと一緒だから、作れるかも」と言って手を動かし始めました。 まだ慣れていないせいか、一目見て「無理」と思ってしまう傾向もありますが、ほんの少しの方向性やきっかけの助言で習ったことを思い出すこともできているので、それを自信に自力で動き始めることができるようにサポートしていきたいところです。 F2もすぐに完成できたので、そこからタイマーやスコアを付け足して、楽しくアレンジができていました。', null, 'タイピング: 入会当時に比べてずいぶんと打てるようになりました。ココアを卒業したので、タイピングスコアシートに記入するようにしたら、初心者卒業という感じで嬉しそうにしていました。
盛り上がり: 意外と自分でできるかも、と気づいてからは、とても熱心に、楽しそうに作成ができていました。アレンジで使用する変数の使い方を覚えていたのも得意げでした。'),
  ('408c255f-40e4-59ba-81a6-61bc700c9827', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-14', '17:30:00', null, '通常 / バグがないかをチェックして作品を仕上げる', '前回が1月末だったため、バグがあったことしか覚えていないとのことだったので、一度完成版をプレイしてから自作の方をプレイしてもらいました。 最初に出た「スタート」が出たままになっているなど、明らかなバグから解決していくことにして、むやみにコードをいじるのではなく、バグの原因などをある程度予測してから、該当する箇所を見ていくようにすると、わりとスムーズに解決ができていました。 作成中の箇所を思い出すために少し動画を参考にしましたが、自分で辛抱強くコードを見直して、演算式の等号と不等号の使い方の間違いなどを見つけて修正できていました。', null, 'タイピング: 今日はミスタッチが多いとぼやきながらも、それなりの結果は出していました
盛り上がり: 1月から持ち越していたゲームが完成して、スッキリしたようでした。
備考: アプリを使った動画編集などをやってみたいとのことでした。'),
  ('5bfef998-bdd9-5d6e-b1c0-a7851d3400c4', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-14', '17:30:00', null, '振替 / 画像認識で機械学習を学ぼう', '最初はせいくんが来なかったので、とりあえずじゃんけんのポーズの認識の作りました。顔認証と同じ認識で覚えさせることが結構やる気になってそれぞれ100回も取って、うまく作れていました。 そのあと、画像認識でいろんなものに認識させました。いろんなものとってかわって持ってきて楽しんでいました。 画像の認識のデータ量について話すと、さっきのじゃんけんのポーズについて、背景のライトが余分なデータになっていることやその対策法も自分で判断できていてよかったです。', null, '盛り上がり: いろんなもので試すことがとても楽しんでいました。'),
  ('a3391317-c223-57ff-9369-62dd8a41455a', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-14', '17:30:00', null, '通常 / 物語を作ろうでスキル習得', 'スキルの習得を自覚させるため、このスキルを身に着けたらスタンプを押すよと伝えて始めました。途中まではできていたので、まだやっていない「クリックしたら変える」「登場人物に返答する」などの内容をやりました。「このスプライトが押されたとき」のブロックは見覚えがなかったそうなので覚えてもらいました。一通り終わったのでアレンジに入り、新しくハリネズミが上下に動くようにしました。そのときに向きの変更や「はじに触れたら跳ね返る」を復習しました。', null, 'タイピング: 楽しくやっていました
盛り上がり: 作成途中で集中力が途切れかけていたときに、やろうとしていたことを紙に書いて一緒に確認するともう一度集中を取り戻せたようでした。'),
  ('6e19aa85-5535-54f5-8d06-83e9a8a222eb', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-14', '16:30:00', null, '通常 / アイテム脱出ゲームを作ろう', 'ステージ転換をメインに作りました。変数のリセットメッセージのやり取りについてどう働いているか尋ねてみたところ、しっかりと関係性を把握して理解をしていました。一通り動画通り作り終えたところ、先生が作ったステージ3を見せて遊んでもらうと、はまって、自分でも新しいステージを作り始めました。ステージの作成だけで終わったので、次回は鍵や一のコードの修正をやっていけばいいと思います。', null, 'タイピング: 集中的にやっていました
盛り上がり: 最初は新しいステージを作る意欲はなかったが、先生が作ったものを見せれば、やる気がわいてきました。'),
  ('7ee44c76-392d-55a2-8370-3b0d77f4eb9e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-14', '16:30:00', null, '通常 / 変数の使い方のスキルアップ', '数学的な変数の使い方を学ぶため脱出ゲームに取り組みました。速さを変数にすることでだんだん速くしたり遅くしたりできることをポイントとして伝えました。矢印キーを押しているときは速くなり、そうでないときは遅くなるという流れを一緒に共有しました。どうやって減速しているのかを問いかけると、速さの変数を0に近づけていっていることを理解していたようでした。', '続き 動画13:14以降', 'タイピング: 真面目にうでだめしに取り組んだあと、お決まりの「伸ばし棒の練習」で遊んでいました
盛り上がり: コスチュームを変えたりして遊びながらではありましたが、やるときはしっかりやっていました。'),
  ('ad11f7e1-437a-5f0f-820d-14602be618ef', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-12', '17:30:00', null, '通常 / 自由創作発表', '恐らく今までの発表の中でも初めてクイズ形式の作品を出してきていました。ですので、本人独自の作品として仕上がっており、クイズ内容に宇宙要素を入れつつクイズをリストで管理する事がで、ランダムに問題を出すことを可能としていました。作品への理解度も高く、クイズを変更したり、動いているキャラクターや背景を変えようとアレンジも試していました。', null, 'タイピング: 素早く打つ事ができていました。
盛り上がり: クイズ作品ということで、教室全体でみんな静かにクイズを解いていました。正解不正解に一喜一憂している様子が見れて製作者としても良かったようです。'),
  ('bc2467c3-f711-559f-ac65-12d0ddc29889', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-12', '17:30:00', null, '通常 / 友達が作ったゲームを楽しんでプレイする、面白かったゲームを自分なりにアレンジする', '今日は1時間前に来ていたので、自由制作の発表をすると予告はしていたのですが、完成しているから大丈夫とのことで遊んでいて、授業が始まってからあわててバグを直し始めていました。 ゲームが完成していないので公開したくない、と意固地になりかけてしまいましたが、順番をパスして他の子のゲームで遊ぶうちに少し気分がほぐれたのか、合間合間に手を入れて、3番目あたりで「公開する」と言い出しました。 発表は、ある意味予想通り無理とのことなので、私がこそこそと話を聞いてスピーカー役をしました。私が代理でしゃべるかわりに、自分の気持ちを人に伝えるときにどういう話し方をするかをよく見ていてほしいと伝えました。', null, '盛り上がり: 友達のゲームは、それなりに楽しそうにプレイしていました。 発表は相当プレッシャーだったようですが、自分の作品を見てもらえたのはそれなりに嬉しそうでした。'),
  ('d69cab99-bfd7-5965-ba4a-dbe8025d5a9f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-12', '17:30:00', null, '通常 / 自由創作発表', '作品の発表では、シンプルながらも高い難易度を誇る作品について口頭で説明し切る事ができていました。作品に出てくるボスキャラクターの動きやそれ以前のステージについても、ゲームとしてかなり完成度が高いため、みんながクリアしようと真剣になって取り組んでいました。本人としてもかなり満足のいく作品にできたようでした。ゲームクリアとゲームオーバーになった際の背景では、明朝体で勝ち、負けと表示されておりオリジナリティあふれるものとなっていました。', null, '盛り上がり: 作品の難易度の高さから、みんなに遊んでもらう事ができつつ、夢中になってもらう事ができて良かったと言っていました。'),
  ('67e92e48-f205-5c92-baab-07d5f928ea8a', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-12', '17:30:00', null, '通常 / ゲームの公開と説明、ゲーム大会 ゲーム終わったら、ファイルの保存、Scratchでの開き方', '他の人の作品発表を待つ間にゃんこ大戦争で遊んでいたので、使われているプログラムと自分の作品を比較し、頑張れば作れそうという話をしました。 自分の発表はあっさりしていましたが、操作方法や使った小技など大事なところはしっかり伝えられていました。はるちゃんの宇宙クイズが少し気に入ったようでしっかりプレイしていました。 最後にアルスパークのIDを渡して、作品を移せる旨を伝えました。', null, 'タイピング: 集中して取り組めていました。'),
  ('889d9e17-8368-5512-98d0-979b66f36938', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-12', '17:30:00', null, '通常 / ゲームの公開と説明、ゲーム大会 ゲーム終わったら、ファイルの保存、Scratchでの開き方', '最後にゲームの終わりを作成しました。「全てをとめる」を使っても止まらないことに苦戦していたので、旗を使う必要性を説明しました。公開の際に説明も自分で入力できていました。 作品発表もインタビュー形式でしたが、聞きやすい声ではっきり発表できていました。本人も嫌いではない様子でした。他の人の作品も遊んで楽しんでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('34d6d0bb-2ee2-52a5-a801-74a253ad84b3', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-12', '16:30:00', null, '振替 / ゲームの公開と説明、ゲーム大会 ゲーム終わったら、ファイルの保存、Scratchでの開き方', 'さらちゃんが同い年ということに気が付いて嬉しそうでした。さらちゃんも満更でなく、一緒に話して盛り上がっていたので良かったです。 自分の作品のポイントをインタビュー形式ではありましたがしっかり伝えることができていました。（発表はきらいじゃないけどしっかり発表する場はそんなに好きではなそう）最後にさらちゃんの作品にファンタジー要素を足してアレンジしていました。HPのコードも中身をよくみて書き換えられていました！', null, 'タイピング: 集中して取り組めていました。'),
  ('00da87bc-a470-5ba0-8154-17bb65caef62', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-12', '16:30:00', null, '通常 / 自由創作発表', 'この時間の発表で恐らく最も多くのコードを書いていたのが咲良ちゃんでした。作品の操作説明やゴール条件、使った小技などをしっかりと説明する事ができていました。細分化に関してもできており、どこをどうしたらコードを書き換えられるのかをしっかりと把握している様子でした。発表後には、みんなで咲良ちゃんの作品をアレンジしていき、コードの内容についても把握していく事ができました。', null, 'タイピング: 素早く打つことができていましたが、間違うとリセットする癖があるようなので治していきたいです。
盛り上がり: 作品をみんなにアレンジしてもらい、様々な形の作品を見れて楽しそうに遊んでいました。'),
  ('8f892d51-31df-572e-be0b-b2f497253de8', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-12', '16:30:00', null, '通常 / 友達が作ったゲームを楽しんでプレイする、面白かったゲームを自分なりにアレンジする', '他の子がゲームの公開準備をしているときにも、遊んで待つのではなく、少しでも自分の課題を進めたいと意気込んでいました。 前回の復習を兼ねて、スプライトの拡大縮小や背景の変更、音の追加を見直しし、ファイルにスタンプを押して喜んでいました。 公開された友達の作成ゲームも、どれも熱心にプレイしていました。さらちゃんのゲームが気に入ったようで、スプライトを自分の好きなものに変えて熱心にアレンジしていました。 コスチュームの向きの変え方を覚えました。 眞子ちゃんと同じ机に座っていたので、よく話しかけていました。', null, 'タイピング: パズルのドラッグを得意そうにやっていました
盛り上がり: どのゲームもとても楽しんでプレイしていました。 よっぽど「すごい」と思ったのか、自分にはこんなゲームが作れるようになる気がしない、とも言っていましたが、周りの子から「すぐできるようになるよ！」と声をかけられて嬉しそうにしていました。 授業が終わったとき、「今日もとても楽しかった！」と言ってくれました。
備考: アルスタジオのマリオゲームがお気に入りです'),
  ('b24aa482-ecf2-544c-a1f3-e617b1a74572', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-12', '16:30:00', null, '通常 / 自由創作発表', '今回の発表では、自分の作った作品の操作説明とゴール方法について説明する事ができていました。工夫したところについては、イマイチわかっていなかった様子でした。ゲーム内容については、他の生徒からも面白いという事で好評でした。タイムアタックで競う事ができ、授業内で盛り上がって遊びながら学ぶ事ができていました。', null, 'タイピング: 素早く丁寧に打つ事ができていました。
盛り上がり: みんなが楽しく遊んでくれていたので、とても嬉しそうでした。'),
  ('a9306bfb-516e-5b86-b597-b75e2e3f7729', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-11', '17:30:00', null, '通常 / ⇒作品がもう少しで完成？続きをやろう。 ⇒その前に、他の子の作品を遊んでみるか。', 'クリア画面の作成をしていました。小技を使ってかわいい画面を作ることができていました。 最後にどうしても解決したいところがありましたが直らず、完成しませんでした。 鍵をとっていない状態で背景が変わると鍵がでたままになってしまうこと、あるくんが鍵をとってもあるくんと一緒に表示されつづけないことが気になったようです。最後はメッセージや制御を調査して一緒に取り組みましたが、問題が解決しませんでした。 本人に確認したところ「来週もやりたい」とのことだったので、こちらがある程度のプログラムを考えて、ポイントを説明しながら取り組む必要があると感じました。（考えてきます）', null, 'タイピング: 集中して取り組めていました。'),
  ('0270cac9-2df7-5f03-83ea-9137ba68ccc8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-11', '17:30:00', null, '通常 / ⇒作品完成しているので、いつも早く来ているから。発表一緒にしてもらおうか！ ⇒終わったらタイマーの復習 復習から。', '復習の後に取り組んでもらいました。変数を使う方はスムーズにできていました。変数とタイマーで考え方はほぼ同じことを伝えましたが、タイマーの秒数判定で「もし」を使うのか「まで繰り返す」を使うのか悩んでいました。また不等号の向きにも苦戦していました。 最後はタイマーと変数を使ったときの微妙な違いを見つけたり、爆発したようなアレンジを加えたりできました！', null, 'タイピング: 久しぶりの100点で喜んでいました！'),
  ('9da0dd7e-2ee5-5021-9c51-9ea4ac369879', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-11', '16:30:00', null, '通常 / 前半、ヒロト君の作品発表を聞いて、ゲームで遊ぶ。 ⇒動きの教材', '①コスチュームを変える②滑らかに動かす③「ずっと」を使う をやりました。コスチュームを変えるときに「～秒待つ」を使ってコスチュームを見せていることを伝えました。滑らかに動かすときには座標を使うこと、矢印キーを押したときよりもスムーズに動いて見えることを共有しました（スムーズに動くことについては本人もかなり納得していました） またずっとを使って、緑の旗を押したときにプログラムが動き続けることを確認しました。 作品の画面が一杯になってきているので、新しく作品を作ったほうがいいかもしれません。', null, 'タイピング: もぐらたたきとパズルをやりました。かなり慣れてきたようです。
盛り上がり: スタンプを押してもらうのが楽しみなようです。'),
  ('454d2501-fddc-5ae4-9e1d-03d676af6160', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-11', '16:30:00', null, '振替 / ロボットの振替えなので、岳君と同じ工程をやりましょう。 ⇒スプライトを２つ好きなのを選んでもらい、岳君の作っている作品をみて、同じように「座標で動かす」と「スプライトを変える」の２つを覚える ⇒動きの教材', 'あるくんのコスチュームを変えながら歩かせるプログラムを作成しました。学校でScratchをやっているようで比較的スムーズにプログラムできていました。見た目のプログラムと動きのプログラムのスクリプトを分けることをアドバイスしました。 背景を変えてアレンジもしました。背景を変えるタイミングも良かったです。背景の変え方にも2種類あることを伝えました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: がくくんが遊んでいるマリオが気になったようです。'),
  ('ec37c2ad-207a-53ad-9012-4764957061fa', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-09', null, null, '通常 / 自由製作の完成と発表', 'ブロック定義を使って作成する部分が難しくバグもあったので、簡略化する選択肢を示すと、ゲーム性を損なわないようにシンプルなコードで書きなおすことができました。「これ以上何を作ればいいの」と迷っていたときがあったので、ステージ2のクリア条件は何かを聞くと、ゴールとして新しい土管を設置してクリアの処理を作ることができました。 発表のときは、細分化はよくできていたと思いますが工夫した点はあまり思いつかなかったようでした。', null, '時間帯: その他'),
  ('3b996b3f-5bec-569f-9bd2-480b49ea2e4d', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-09', null, null, '通常 / 自由制作DAY(青)', '作品に少し修正を加えたのち、発表へと移っていきました。現在の作品でほとんど完成だったため、修正内容については慎重に考えていきました。結果として、タイマーをつけることによって、スコアが一定以上でゲームが終了するためタイムアタックにて競う事ができるようになりました。発表の際には、自分の作ったものがどのようにして動くのか、何をしたらゲームクリアであるか、工夫したところとしっかり発表する事ができており、細分化に関しても作品を理解して行う事ができていました。他の生徒に遊んでもらった結果としては、タイムアタックをしてもらう事ができており、本人としても満足のいく結果となったようでした。', null, '時間帯: その他
タイピング: 集中して取り組むことができていました。
盛り上がり: 作品への修正で本人の望むようなような完成へと持ってく事ができ、その作品を遊んでもらえたことで嬉しかった様子でした。'),
  ('94e9f4f3-e390-55b9-af60-330aa329099c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-09', null, null, '通常 / 自由製作を進める', '前回までで自由製作がうまく進んでいなかったため、誰が登場して何をするのかなど問いかけると次第に構想ができてきました。また、わからないところがあって止まってしまったら聞いてほしいと伝えました。スプライトの用意はでき、コードの作成に入りました。難しい場所から作ろうとして困っていたので、簡単な場所から順に作っていけばいいよと伝えました。すると、最初にスプライトを隠しておいたり音楽を鳴らしたりという部分はできました。ゲームの本筋については次回やることになりそうです。', null, '時間帯: その他
盛り上がり: 問いかけに答えてくれるときと、そうでもないときがありました'),
  ('c91e7a80-8d67-54f6-8c6b-36c6e368e5c0', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-09', null, null, '通常 / 自由制作DAY(青)', '前回で作品が完成していたこともあり、授業では作品の発表内容と公開する際の説明文を前半は考えていました。作品の操作説明と勝敗判定、そして工夫したことについてしっかりと考えている様子でした。公開する際の説明文についてはシンプルに書き、作品の発表部分で具体的な内容に関して説明していました。作品の卵を集めてゲームをクリアする内容では、卵がランダムに動きつつ、個数が30個と多いためそれなりに難しい難易度となっており、タイムアタックの部分で大きく盛り上がっていた作品でした。特にジャンプができないため、一瞬のチャンスを逃す事ができなくなっており、緊張感を味わうこともできるものでした。', null, '時間帯: その他
タイピング: 集中して取り組んでおり、早く打つことができていました。
盛り上がり: 作品にて他の生徒たちが試行錯誤して早いタイムを出して競っていたため、本人も一緒に楽しんで遊べていた様子でした。'),
  ('eb19a87f-6c20-58b9-836a-9a4c7e62ff74', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-09', null, null, '通常 / 自由制作DAY(青)', '前半部分で作品の仕上げに取り掛かり、後半部分で発表をしていきました。作品の仕上げでは、自機の位置が制限時間が一定になると初期位置が変わる、弾幕を避けていく際に上下移動の回避で微調整ができるように変更し、自機のサイズを小さくするなどしてゲームの難易度に関する部分を追加していました。発表の際には、その時間に発表された作品の中でもかなり難易度が高かったこともあり、何回もチャレンジしている生徒が多くいました。作品に対しての理解度もあり、細分化をすることもできていました。特に、弾幕の避け方については自分独自の解を見つけ出していたようで、周囲の注目を集めていました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。
盛り上がり: 発表で多くの人に遊んでもらい、難しいと言ってもらえて本人の想定した難易度になっていたようで喜んでいました。'),
  ('b7ac8726-72ef-515d-a3cc-79cb922027be', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-09', null, null, '通常 / 自由製作の完成と発表', '自由製作の作品は前々回に完成していたのですが、その中身をもう一度見てもらい、みんなに公開するにあたって手直しするかどうか聞きました。すると「これで完成でいい」とのことだったので公開し、プラットフォーマーゲームの復習と続きの作成を促しました。しかしあまり乗り気にはならなかったようでした。 発表の時は、細分化は問題なくできていました。また、「50点で背景を変える」「タイムを伸ばすゲームで、今までの最高タイムは150秒」などとこだわりポイントをいくつか説明してくれました。', null, '時間帯: その他
タイピング: 時間が始まってもしばらくゲームで遊んでいて、その後少しだけ寿司打をやりました。'),
  ('646a8c98-9b47-5e7c-a19d-a74f767daf27', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-09', '16:30:00', null, '通常 / 自由制作DAY(青)', '今回はゲームのバトル部分の制作から始めていきました。キャラクターがビームを出すコードで、ソードを発射していくようにアレンジして作っていきました。基本的に自分が今やっている事が終わってから出ないと新しいものに取り掛かるのが嫌なようで、一度待ってから取り掛かるのが良いと感じました。制作に取り掛かってしまえば完成までしっかりとやり遂げるので、作る気にさせることが重要だと感じました。その後に自機と敵の体力を作っていき、その時点で時間が来てしまいましたが、本人が最後まで作りたい様子だったのでゲームクリア画面とゲームオーバー画面まで作っていきました。そして、最後まで完成させて後悔もする事ができていました。本人もかなり嬉しかったようで、変える前にお父さんに完成した作品を嬉しそうに見せていました。', null, '盛り上がり: 作品を今日中に完成させたいという意志が強く、実際に完成させる事ができてかなり嬉しかった様子でした。'),
  ('aaa2f597-b09e-51d0-bb07-dd038f1718fc', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-09', null, null, '通常 / 自由製作の完成と発表', '攻撃だけでなくバリアをつけるなどゲームの構想はすでにできていて、製作の続きは順調に進みました。発表のときにゲームの内容や工夫した点を質問されると、少し困った様子もありましたが、最終的には「自分の戦闘機と相手の戦闘機が戦う」「HPがなくなったほうが負け」「バリアすると色が変わる」などと説明できました。', null, '時間帯: その他
タイピング: 時間が始まった後少しだけゲームを続けていましたがそのあとは頑張っていました
盛り上がり: 今日発表をすると聞くと、完成までもっていくモチベーションが高まったようでした。'),
  ('a387bd67-36b7-5797-b65e-a56b018fb715', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-09', '16:30:00', null, '通常 / 自由制作DAY(青)', '前半にて作品最後の仕上げを仕上げを行っていきました。ビームが壁に触れた際に消えるコードと、キャラクターの操作方法を独自のものへと変化させていました。この手入れによって作品を完成させる事ができたので、そのまま公開していきました。作品の操作方法と勝敗の決まり方について記載していきました。発表の際には、作品のどのキャラクターがどのボタンでどのように動くのか、どうなったら勝ち負けが決まるのかなど非常に細かく説明する事ができており、細分化はしっかりとできていました。作品への理解度も高かったため、ステージが動いているからこそ発生する挟まる状態や壁に埋まってしまう状態に関してもしっかりと把握し、ゲームの中に組み込むことでより難易度を上げていました。', null, '盛り上がり: 発表の際にみんなに遊んでもらい、面白いと言ってもらえて嬉しかったようです。'),
  ('180beaac-f3cd-5241-a0f7-baa3b67cfa1d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '18:40:00', null, '通常 / 自由制作DAY(青)', '作品が後少しで完成ということで、今回発表していた生徒たちの作品を参考にしていきながら続きを作っていきました。作品では、キャラクターの分身を制限時間まで避けるという内容でしたが、キャラクターの座標を変えることで難易度を変えることができていたので、本人が気に入っている様子でした。完成後は星をキャッチするゲームを作成していきました。座標で落下していく内容はまだのようなので、スプライトがずっと落ちていくリンゴと同じ方法で作っていきました。次回では、座標を使って星を完成させていく予定です。', '星をキャッチするプログラムを座標を使って作る。', 'タイピング: タイプミスをしないように注意して打ち込んでいました。
盛り上がり: 作品を完成まで持っていく事ができ、難易度も変える事ができて嬉しそうでした。'),
  ('9ab07a5c-48c5-59ee-9f57-c51c84309f17', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-08', '17:30:00', null, '通常 / 自由制作DAY(青)', '前回完成した鬼ごっこの作品についての発表をしていきました。本人も作品の完成度はかなり高いと感じているようなので、発表でも作品の概要と工夫した箇所を自信をもって発表していました。作品は他の生徒からもかなり高い評価をもらうことができていたので、とても満足していた様子でした。発表が終わった後は、サイコロを使ってスロットを作っているようでした。ボタンを押して停めていき、賽の目を揃えていくというシンプルなものでしたが、作品に自分なりのアレンジを加えていこうとかなり悩んでいた様子でした。この作品ではデザイン面に力を入れたいようで、構想を練っている様子でした。', null, 'タイピング: 間違う事なく打つことができていました。
盛り上がり: 作品の発表で高い評価をもらえて嬉しそうにしていました。'),
  ('41ad7282-51d6-5d14-ac38-86d8fcc55be8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '17:30:00', null, '通常 / 自由制作DAY(青)', '今回は現在出来上がっているところまでを発表していき、残りの時間では続きを制作していきました。現在７割ほど完成しているようなので、次回までには完成したい様子でした。発表では、作品の特徴と長所部分をしっかりと把握して発表する事ができていました。特に、ライトを使った部分はこだわりが強いようで、基本的にその部分に関しては妥協を許していない様子でした。次のステージでは、ライトに当たっている間は敵が動かなくなり、迷路を攻略していきボタンを押してゴールというものだったので、構想からプログラムへと落とし込むためのイメージもできているようでした。', null, 'タイピング: タイプミスする事なくスラスラと打ち込めていました。
盛り上がり: 現在完成しているところまででも発表する事ができたので、完成まで頑張っていこうと張り切っていました。'),
  ('615b0cd0-8580-5783-bb52-0e62b0e37d2d', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-03-08', '16:30:00', null, '振替 / みんなの自由作品を見る&自分の物語を作ろうの作品の発表と完成へ向けての作業', 'みんなの作品をみて、色々な作品と触れ合うことの楽しさを感じていたようです。自分の作品を発表する際に途中だから恥ずかしい〜と話していたものの、発表してみんなから「いいね」と言われてとても嬉しそうにしていました。', '今日の作品の完成、お母さんに見せる', 'タイピング: いままでよりも真ん中の列のタイピングがとてもスムーズになり、自信をもってタイピングできるようになっていました。学校でとても練習しているようで、意気込んでおりました。
盛り上がり: 色々な人の作品をみて刺激をとても受けた様子でした。自分の作品に再度取り掛かった際に、こうしたら楽しいかな〜など色々とアイディアもでききていたので、今回の発表はとても彼にとってよかったと思います。'),
  ('aab32d3f-35ca-53aa-ab83-ac0a3c46cd85', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-03-08', '16:30:00', null, '通常 / 自由作品 宇宙（青色）の発表とみんなのゲームを楽しむ', '自分の作品を公開し、色々と自分がやりたかったことなどを発表してくれました、 頑張った部分を犬が飛んだ時に残像効果をやってみたと話していましたが、先生たちや他の生徒さんからも落ちてくる時におにぎりの大きさが１回毎に変わっていたり、ランダムに落ちる部分が面白いと言われていたことが嬉しかった様子でした。', null, 'タイピング: タイピングはとてもうまいですが、なかなか早く打てないことにとても悔しがっていて、もっと上手くなりたい！という意欲が見えていました。
盛り上がり: 当初自分の作品に対してあまり達成感がなかった様子ではありましたが、みんなに説明している時に褒められる評価を受けて、とても嬉しそうにしていたのが印象的でした。 たっちゃんの場合には特におにいちゃんとの比較があるので自信を持つという部分では劣等感があるのかなぁとたまに感じることがあったのですが、今回の発表で今までよりも自信をもって発表できたような感じがしました。'),
  ('6912ba1b-b15b-5fe5-8a31-8b540b8323ca', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-03-08', '16:30:00', null, '通常 / 自由作品（青色）の発表とみんなの作品で楽しむ', '本人の作品を公開 （https://app.arstudio.fun/contents/55916） さすが年長さんなのか、最初に発表となっても動じず自分の作品の説明を自信をもって答えてくれました。 特に頑張った部分は上から背景が移動するようにし、ロケットが飛んでいるように見せたぶ部分、だそうです。先生たち的には、最後に距離がでてくる部分がきちんと演算を使っていてとても頑張ったと思うけど〜と話したところ、そこは全然がんばってないとのこと。 他の子達が遊んんでいるのをみて本人的にもとても大満足だったようです。', '今回は自分の作品は終了しているとのことで、新しい作品を作成してもいいかも', 'タイピング: レベルがあるようで早くタイピングができるようになるといいレベルを出せると頑張っていました、ブラインドタッチがやりたいと話していたので今後の練習が楽しみです。
盛り上がり: みんなと一緒に遊べたことがとても楽しかった様子でした。また、一番年下のこうしろうくんがやっていた作品にもちゃんとすごいねと言っていたり、たっちゃんの作品に対しても「へーおもしろいじゃん」と言っていたりと、とても人のことを思いやれるようになってきたと思いました。 人の作品の良さを見出せる楽しみを見つけているようです。'),
  ('95ea9b69-e882-5ce0-8565-f14c04bf5acd', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-07', '17:30:00', null, '通常 / バグをつぶして作品を完成させる、作品について皆に発表する', '今日は承太郎君と二人だったためか楽しそうにおしゃべりもしていましたが、時間内に完成させるという意識は持てていたように見えました。 ステージが変わった後でアルくんの動きが止まってしまうバグにしばらく悩んでいましたが、メッセージを受けて背景や変数が変わっていることから、メッセージの送信はできている、というところまでは自分で判断できていました。 メッセージを受けている側のコードの問題ということで一緒にコードを見直し、必要ないところにスクリプトを止めるブロックを入れていることを発見し、解決できました。 セリフによるゲーム説明などが丁寧な、由希ちゃんらしい作品に仕上げることができました。', null, '盛り上がり: 承太郎君との発表会は、それなりに楽しんでくれたようでした。 説明もきちんとできていて、達成感があったようでした。'),
  ('83ded6be-770a-5bca-84d1-79fcc906ca4a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-07', '16:30:00', null, '通常 / 基本操作コース06の細分化バージョン', '自由製作の作品名を決め、内容を少し確認した後にプログラムに移りました。あまり時間がなかったのですが、スキルとして習得したい項目を伝え、スプライトや背景を準備してもらいました。（1度やったことがあると言っていましたが、復習の意味があることも伏せて伝えました） 最後に自由製作の作品発表をしました。インタビュー形式で言葉を引き出しながら発表していました。', null, 'タイピング: 熱中してやっていました。評価が少し気になるようです。 30分ほど続けてしまってプログラムの方にスムーズに移行できなかったので、次回からタイピングを最後にしてもいいのかな？と感じました。'),
  ('50da1b28-81f4-5b00-a6c4-5a20303bb0ff', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-07', '16:30:00', null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！ 続き', '前回の続きから始めました。アイテムのカウントとゴールのボタンのプログラムをしました。見本をみることもありましたが、プログラムの順番がとても論理的で良かったです。 メッセージで「ずっと」を使うときの注意点を伝え、「まで待つ」を使って書き換えることを伝えました。自力で書き換えられていたので良かったです！ゴールのボタンのプログラムもスムーズに作れていました。 最後に自由製作の作品発表を行いました。楽しそうでした！ 集中してよく頑張っていました！', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 次回続きをプログラムする予定です。'),
  ('48475bd1-3597-511c-aa82-f1e2e32b0d12', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-07', '16:30:00', null, '通常 / 作品を完成させる、作品について皆に発表する', 'スプライトの大きさや座標など、初期設定の必要性を学習しました。 片方のスプライトの初期座標を設定していなかったため、前回のゲームオーバーのときの位置からスタートしてしまい、ゲームスタートと同時に双方のスプライトが触れた判定となり、即ゲームオーバーになることにしばらく悩んでいました。 また、ゲーム中にスプライトが大きくなる仕掛けをしていたのですが、毎回主導で大きさを戻していたため、コードのはじめに大きさを指定するブロックを教えました。 座標、大きさを指定回数変化させる、メッセージ、表示と隠す、カウントダウンの変数と、～まで繰り返すなど、基本操作コースの1枚目のスキルをうまく組み合わせて、ゲームを作成することができ、本人も満足そうでした。 発表についても、最初は「やったことないからできない」としり込みしていましたが、教室全体でゲームを見せ合う雰囲気で盛り上がってきたら「やってみたい」となり、きちんと皆に向かって説明できていました。', null, 'タイピング: だいぶ慣れてきたようです
盛り上がり: ゲームが完成できたこと、発表ができたことで、少し自信がついたように見えました。 発表会中も、そうちゃんと一緒によく反応してくれて、場をもりあげてくれました。'),
  ('15853253-89b7-5df9-b148-e3bb7dad590e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-07', '16:30:00', null, '通常 / 単元別演習G3～5 細分化されたコードをまとめる練習をしつつ完成を目指す', 'G3はすでにできていたのでG4から取り組みました。見本ではクローンを使っていなかったのですが、本人が使いたい様子だったので取り入れました。 クローンの使い方があまりはっきりしていなかったので親分と子分で分けて考える方法を共有しました。上から下へスムーズに動かすことはできていたので良かったです。クローンの数についてはクローンを作る速さでコントロールできることを伝えました。 最後に自由製作で作った作品の発表をしました。グループの中で学年が高いのもあって作品に注目が集まって嬉しそうでした！', null, 'タイピング: かんたんに挑戦しました。'),
  ('5907d5c0-46d7-566e-ad31-b24769e9a284', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-07', '17:30:00', null, '通常 / 由希ちゃんが完成したら自作ゲームの発表会 「宇宙」をテーマにするためにどうしたのか、使ったスキルや小技の紹介と、それを使ってよかったこと、ゲームのアピールポイントなどを話せるとよいかな、と 発表会後、時間が余ったら機械学習の2章かprg', '自由製作はしっかり完成していたので、ゆきちゃんの作成を待つ間にきょうりゅうとタイピングゲームのコードを一緒に見てクローン、リスト、変数の総合的な使い方を、Scratchの文字PVのコードを見て大まかな考え方や、木を育てようのペンの太さや変数の変化による木の種類の変化を確認しました。コスチュームを変えるときにリストを使って工夫するのは新鮮だったようです。また文字PVは見本の通り見て一度作ったことがあるそうですが、どうしてそうなるのかは分からないとのことでした。いつか作ってみたいそうです（初めの目標の設定方法について少し説明しました） ゆきちゃんとの作品発表もしっかりこなせていました。自分のゲームの魅力を深掘りするのは自分だけでは難しいなと感じました。', null, null),
  ('7c541fb1-de59-5f48-8888-fc764a9763d8', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-07', '16:30:00', null, '通常 / バグをつぶして作品を完成させる、作品について皆に発表する', 'ステージが変わった後の星のクローンの向きについて悩んでいました。 そもそもステージが変わったあとについてのコードを書いていなかったので、そのあたりを指摘、説明しました。 だいぶコードの数が多いゲームを作れるようになってきた反面、コード同士の関係が曖昧だったり、同じようなことを複数の場所に書いて干渉しあって動きがおかしくなったりしているところもありました。 きちんと細分化してから作成を進めるステップに進めてあげたいところです。 発表のぎりぎりまでバグがないか一生懸命検証していました。 発表後に不具合が見つかったようで、そのときもすぐに対応したりと、最後まで「きちんと仕上げたゲームを公開したい」という強い意識が見られました。', null, '盛り上がり: お互いのゲームをプレイして裏技を見つけたりするのがとても楽しそうで、どのゲームにも明るく反応していました。良いムードメーカーになってくれました。'),
  ('27774adb-de19-5dc5-aef7-92234eb071fb', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2024-03-07', '17:30:00', null, '休み（未対象）', null, null, null),
  ('2be0f5c7-f146-5473-b10f-9cdbc6b7798d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '17:30:00', null, '通常 / 自由制作DAY(青)', '前回から作っていた対戦ゲームの続きを作っていきました。鬼ごっこの要素をテレビ番組である逃走中のように賞金を増やしていく要素とタイマーを追加していました。キャラクターごとの判定が違うので、逃げる側と鬼側とでそれぞれ気をつけるべき箇所や特徴が違ってくることも面白さの一つとして追加していました。対戦ゲームということで、今までのように特定の動きをする敵ではないのでゲームとしてかなり面白いと喜んでいました。', null, '盛り上がり: ゲームに要素の追加をすることによって、自分の納得のいくものに仕上がったようで喜んでいました。'),
  ('a40de3fa-1707-5f73-84a6-b0c292c9c9d4', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '17:30:00', null, '通常 / 自由制作DAY(青)', '前回まで作成していたものの続きから作っていきました。作品自体の構想がかなり大きかったようで、授業内で作品に取り入れるものをかなり迷っていた様子でした。考えながらも手を止めることはなく、順調に作り続ける事ができており取り入れるものが決まってしまえば次回までには完成へと漕ぎ着ける事ができる様子でした。作品の中で、弾幕を使ったシューティングゲームを作ってるようで、特にキャラクターの判定部分にこだわっているようでした。ですので、残像を使って判定を作ってみる案を気に入っている様子でした。', null, '盛り上がり: 作品に取り入れる要素の選別にかなり難儀していたようなので、作品に取り入れてみてハマった際には喜んでいました。'),
  ('2a5bfebd-b863-51ca-a9be-2def9e4ffd88', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-05', '16:30:00', null, '通常 / 基本操作コース02、03 前回作成した「アイスを食べに1」を元にするか、または新規作成で、基本操作コースの完成例を見せながら一つ一つ作成し、ファイルにスタンプを押してスキル習得を意識させる', '1時間休憩なしで頑張りました！新規作成でプログラムを作りました。 項目として色を変える、滑らかに動かす、回転させる（右左）、大きさを変えるをやりました。「このスプライトを押されたとき」というのを集中的に確認しました。滑らかに動かすときには座標の話を少ししました。ドッジボールで疲れていたようですが、最後まで頑張りました！！ 基本操作コースのスタンプを埋めるのが目標のようです！！', null, 'タイピング: もぐらたたきをやりました。苦戦していました。'),
  ('8e908e61-929d-5bc9-9724-605f07505d04', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-05', '17:30:00', null, '通常 / 『自由制作DAY』（青） 作品の完成、時間に余裕があれば、共有の説明', 'お金のプログラムを作成していました。中身はよく書けていましたが、プログラムを動かすときの条件に苦戦していました。メッセージと「もし」の両方を使っていたので、プログラムを動かす条件を見直して、判定が必要なときにだけ動くようなプログラムを提案しました。少し苦戦していましたが、授業が終わるときにはお金がむやみに増えないプログラムが完成していました。 大枠はほぼできていますが、本人がまだやりたい様子なので次回時間を決めて取り組んでみるのがいいかもしれません。', null, 'タイピング: 集中して取り組めました。'),
  ('f9c486c1-422e-591a-8342-ab084ddf0afd', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-05', '16:30:00', null, '通常 / 『自由制作DAY』（青） ゲームとして成り立つように、自分が作成したプログラムを理解して整理する', '前回変数がうまくプログラムできていなかったので一緒に取り組みました。変数を戻すタイミングや背景を変えるタイミングを調整しました。また「～または～」の使い方を伝えました。対戦相手が変わったときのHPの表示をうまく調整することもできました。最後にリクエストしてゲームクリアとゲームオーバーの背景を作ってもらいました。 さらちゃんに部分ごとのプログラムの方法を共有することはあっても、どこにプログラムするのかまでは伝えなかったので少し苦戦したと思いますが、最後にしっかり完成させることができました。', null, 'タイピング: 集中して取り組めました。10000人中2900位くらいの高得点でした。'),
  ('2436f791-a43c-5b6d-bced-f05e0c7268ea', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-05', '17:30:00', null, '通常 / Scratch作品の共有とそれに関連した著作権やファイルについて等の学習 作品が完成しているので少しITの基本学習を。終わったら選んだ作品作成', '自分が作った内容を説明してもらいました。本格的な作品にするために手直ししたいところがあったようなので、15分ほど時間をあげて取り組んでもらいました。プログラムも制御とリスト、変数がたくさんあって難しいものでしたが、ひとつずつ整理して良く取り組めていました。スタートの文字もとてもかわいかったです。最後に私が作っている作品の発表（紹介？）をしたり、プレゼンに役立ちそうなサイトの紹介（DOTOWN）をしたりしました。 DKアートの木を作るプログラムに興味がありました。', null, 'タイピング: 集中して取り組めていました。'),
  ('e1d4a266-c274-5f5a-8433-a82b34b604fe', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-05', null, null, '通常 / Scratch作品の共有とそれに関連した著作権やファイルについて等の学習', '授業開始時に今日の目的を話しました。学校ではChromeBook、自宅ではWindowsを使っていることや、Scratchのファイルの拡張子や保存などは知っているとのこと。 学校では技術の時間に3D CAD caDIY3D-Xを使っているくらいだそうです。 ファイルの種類やフォルダの構造、OSの違いなどについて少し話しましたが、きちんと聞いて受け答えもしてくれました。 著作権や共有についての注意点なども大体わかっているようだったので、後半は陽色くんの希望でScratchの自由作成に入りました。 以前は条件分岐をネストしまくって書いていたことを、リストでうまく作れるようになっていました。 鉄道名をロブロックスからとってきていて、ロブロックスの作成にはとても興味があるとのことでした。', null, '時間帯: その他
タイピング: バスの遅延で少し遅れてきたので省略
盛り上がり: 話もよく聞いていて、Scratch以外のことも、IT関連のことなら知っておこうという意識が見られました。
備考: ロブロックスの作成をやってみたいと話していました'),
  ('22304f0a-8c30-5efd-9643-5c4ed5904644', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-05', '17:30:00', null, '通常 / Scratch作品の共有とそれに関連した著作権やファイルについて等の学習', '授業開始30分前に来室したときは普通に見えましたが、授業時間になってタイピングを始めたら、ほとんど机に横倒しの状態でした。 うまくいかなかったりだるかったりすると、体勢を崩しがちのそうすけくんですが、何度声掛けをしても体勢が戻らなかったのは初めてで、本人は否定をしてはいましたが、体調もイマイチのように見えました。 今日の目的の課題をできる雰囲気でもなく、せめて何か新しいものを作ろうということで【DKアート】09 トンネルから脱出せよ！を指定し、この課題の目的（ベストタイムの残し方）を話しました。ゲームで「今日の記録」などが残っているものが多いよね、という話は、きちんと聞いてくれましたが、実際の作成に入るととにかくだるそうで、今日はプログラミングを考えるには疲れすぎているということでした。 一応真面目に話し合い、今日は作成をしない代わりに、自分が今後獲得したいスキルを探す日にするということに決めました。 「ストレス発散」というキーワードでScratchを検索していたので、確かに疲れてはいるようでした…。（普段は暖房で紅潮していることが多いのですが、今日は顔色が白かったです…） 最終的に、弾幕のゲームに興味を持っていたので、次回以降、「弾幕」のスキルを学習しようということで合意？しました。', null, 'タイピング: かんたんモードでやっていましたが、クリアしようという意志は全く見られませんでした
盛り上がり: 自分が操作する気力はなかったようですが、こちらの真面目な話はきちんと聞いて反応もしていました。'),
  ('361af27e-83f4-5788-8b0f-e79201d35f0c', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-04', '16:30:00', null, '通常 / 作品の完成、自分の作品について理解し、説明することができるようになる', '各要素の作成をどこまで進めて完成とするか、そのためにはどこを編集しなければいけないのか、よく理解していて順調に作成できていました。 ゲーム終了時に、メッセージがすぐに反応せず、終了画面になってもロケットが出てしまう問題があったようですが、タイミング等を切り替えて解決していたようでした。 時間に余裕を持って完成できたので、用紙への書き込みを促したら、熱心に長文を書いていました。ゲームの裏設定などもきちんとあるようなので、今後の作品にもそういうオリジナリティをいかしていきたいね、という話をしたら、熱心に聞いてくれました。', '相手がいれば、せっかくのゲームやプリントに書いた内容をおひろめさせてあげたいところです', '盛り上がり: 時間的に余裕があったのか、がくくんとの会話に参加してみたり、先生達に積極的に話しかけてきたりと終始楽しそうな様子でした。'),
  ('701f94b6-0217-51e5-ae84-4dbbf3f687c9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-04', '17:30:00', null, '通常 / 先週（自由製作（青））の続き。しっかり説明してもらいつつ。', 'クリアの画面とゲームオーバーのスプライトを追加して完成になりました。背景が切り替わるのは最初の部分だけで、他はスプライトの表示にしたそうです。全体的に滑らかな挙動になるようにプログラムされていて完成度が高いように感じました。 半分ほど時間があまったので、検定のタイマーの使い方を兼ねて単元別演習E-4をやりました。初めてタイマーを使ったそうです。問題を読み飛ばしていたため、少し困っていたので、書いてある通りに取り組むように伝えました。クリックした回数を記憶する変数や、タイマーが10になるまで待つプログラムなど内容は自力で作れていて良かったです。', null, 'タイピング: 99点でかなり悔しがっていました。'),
  ('1be8a751-2f2f-5895-8034-2a53e495523e', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-03-04', '16:30:00', null, '通常 / 動物園。基本操作コースの習得。基本事項', '前回やったことの復習をしました。内容は薄々覚えているようですが、スプライトごとのプログラムを確認したり旗を押したときにプログラムが動くのかを意識したりするのが少し難しいようです。 今日は①色を変える②音を鳴らす③左右に動かす をやりました。①に関してはコスチュームの部分で色を変えたいようでしたが、プログラムでの方法も一応説明しました。あまり話を聞いてくれず残念でした。 ②、③については一緒に確認しながら進められました。x座標のことを説明したときに「分からない！」と前向きなリアクションがあったので良かったです。数字が苦手（111、231など数字の並びに苦戦）大きいか小さいかの判断はできるようです。 次回はコスチュームを変える予告をしました。ペンギンのコスチュームを準備しました。', '次回はコスチュームを変える予告をしました。', 'タイピング: 前回よりもはやくパズルを完成できました（2:40くらい）'),
  ('c1170d71-96cf-5fe2-b361-6939c28977e2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2024-03-04', '17:30:00', null, '休み（未対象）', null, null, null),
  ('bc8a4752-4a5d-5136-a8de-0e053208d154', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-29', '17:30:00', null, '通常 / 自由製作の完成', '前回起こった体力ゲージが表示されないバグについては、ペンで描画したあとに背景のクローンが乗っかってくることが原因だとすぐにわかっていました。最前面/最背面などを使って対処しようとし、しばらく一緒に解決策を考えました。しかし解決は難しそうだということで体力ゲージは断念して、体力の変数を表示するだけにしました。 ただその後のアレンジは良いアイデアが浮かび、生存時間をタイマーで記録したり、10秒ごとに体力回復のアイテムが降ってきたりすることができました。', null, '盛り上がり: 体力ゲージについては多少残念そうでしたが切り替えて他の部分を作成していました。'),
  ('59ea4053-e8fd-536b-b61f-672120d292d9', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-02', null, null, '通常 / 物語を作ろうの完成', '物語を作ろうの後半を進めました。特定のタイミングでスプライトを動かすのに「～秒待つ」を多用していてしばらくそれにこだわっていたのですが、秒数の計算が複雑になってきたときはメッセージや「背景が～になったとき」を使うと楽だと伝えると納得してくれたようでした。他にも滑るように動かしたり、隠す/表示するの管理をすることができました。アレンジをするには至りませんでしたが、全てのスタンプを押して一通り完成させることはできました。', null, '時間帯: その他
盛り上がり: 細分化された動きをよく見て、脱線することなく作成を進めてくれました。'),
  ('77bad5ea-bda6-5efc-b2bb-b779fb34876f', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-02', null, null, '通常 / 自由製作day', '今回は最初だったが、低学年にも楽しめるものを作り始めてくれました。飛んでいく宇宙船を画面の奥に向かっていくように見せ、避けるゲームを作っていました。変数を漸近的に変化させたり、左右の動かしに傾きを出したり奥行きを出すために、コスちゅうーむの大きさも変数で制御して、ゲーム性が高いものになっていました。迎えが遅かったですが、ずっと集中的に作っていました', 'つづき', '時間帯: その他'),
  ('773968ae-c40d-5cde-bff6-715e5a51ab69', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-02', null, null, '通常 / 自由製作dayの完成を目指す', 'ステージ2の作成に取り組みました。アイデア自体はよくイメージできていたのですが、ステージ1の処理を止めるのに苦戦していました。見たところ、「このスクリプトを止める」「スプライトの他のスクリプトを止める」の違いを分かっていませんでした(スクリプトとスプライトを混同していた)。違いを説明すると理解して正しく直せました。また、「～色に触れた」と「～色が～色に触れた」の使い分けも分かっていなかったようで教えました。', '続き', '時間帯: その他
盛り上がり: わからないところがあったときに積極的に質問してくれたのは良かったです'),
  ('1a65b1b3-aed1-51ee-b569-449b78369a45', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '16:30:00', null, '通常 / 『自由制作DAY』（青）', '今回は、作品を完成まで持っていくように頑張っていました。スタート画面に自分の名前を入れたり、ゲームオーバーの画面にて猫の写真を使うなど、本人の独創性を存分に発揮できた時間でした。前回まで作品のコード部分を作っていたこともあってか、今回のデザイン面の作成では非常に楽しそうに作成することが出来ており、何回も自分に意見を聞いてきたりアレンジの評価を求めていました。次回は発表をすることを伝えたところ、作品を遊んでもらうため作品の説明をできるようにどのように説明しているかまとめている様子も見られてので、次回の発表は期待できそうでした。', null, 'タイピング: それなりに早く打つことが出来ていましたが、タイプミスが少し目立つようでしたのでゆっくりと打つことを意識したほうがより上達すると伝えました。
盛り上がり: デザインのアレンジで、自分のアレンジが認められてとても嬉しそうでした。特に、名前の部分に関しては気に入っている様子でした。'),
  ('82cbe9ca-3670-5fd3-ba28-6a54b1b2b54b', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-02', null, null, '通常 / 作品に使用したスキルの確認と復習', 'レッスン開始時は、「これはもうできている」といってひたすら自分のゲームをプレイしていたので、ファイルを持ってこさせて、プリントの設問に口頭で答えてもらいました。 自分が使ったスキルは「メッセージ」だということ、乱数で敵の動きをランダムにしたことの説明はきちんとできました。 迷路のスプライトの後ろに戦闘機が隠れるのが面白かったらしく、途中5分ほど、かくれた戦闘機が出てくる場所を予想するという遊びになってしまったので、元となった「チーズをさがせ」から雰囲気を変えてみる提案をしたところ、迷路のスプライトや戦闘機を回転させるようなゲームにしたいと言い出したので、後半の学習目標を「向き」に決めました。 戦闘機は矢印キーによって「動かす」ではなく「まわす」にしていました。まわす角度を色々入れて、数値と実際の動きを熱心に確かめていました。 戦闘機が回転した結果にビームの向きを合わせたいとのことだったので、「調べる」カテゴリの「スプライトの向き」ブロックを教えました。スプライトから座標の情報だけでなく向きの情報を持ってこれることに驚いていました。 ビームの向きを思い通りにできたことで気分が盛り上がったようで、時間ぎりぎりまで熱心に体力の数値を調節したりして動きを確かめていました。', null, '時間帯: その他
タイピング: 「これも意外と楽しいんだよ」と説明しながら取り組んでいました
盛り上がり: 今日は「メッセージ」と「乱数」が使えたことの確認と、「向き」関係のブロックを覚えて活用できるようになったということを2～3回言葉に出して確認しました。そのせいか、今日の学習内容について自覚と達成感が持てたようで、ご両親にも「今日はこれをがんばった」と報告していました。'),
  ('63f811f1-fa71-5a7e-97a6-6af35fa99d2b', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-02', null, null, '通常 / オリジナル作品を作ろう', '前回物語のところを一通り進めていたので、今回はオリジナル作品を作る予定でした。物語を作ろうの一つ上の基本操作コース03のスタンプの空きも気になっていたので、そこも埋めながらやりました。だが、スプライトの大量追加が目立ち、一つに絞ってやりたい話の展開をコードに一緒に落とし込んでいっても、また新たにスプライト追加されていました。とりあえず、やりたい話として、爆弾が自分で操作して皆に触れると吹き飛ばされるようなことをしたいそうです。今回は大量投入で取り乱れてしまったので次回は減らしてから考え直すといいと思います。', null, '時間帯: その他'),
  ('0ae107b9-af7b-5205-adfd-f63a36799efe', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-02', null, null, '通常 / 自由製作dayの完成を目指す', '敵の戦闘機が子供を産むようにクローンでどんどん増殖していくようにしていました。さらに、ボタンを押すと一定時間防御モードになれるようにもして、面白いアイデアを実現できていました。しかしクローンを出しすぎて生成数の制限に引っかかってしまったので、敵が増えすぎたらゲームオーバーにすることを提案しましたが、その作成までは終わりませんでした。', '続き', '時間帯: その他
タイピング: 最初はゲームを続けていてタイピングを始めようとしませんでした
盛り上がり: 一度作成に取り掛かった後は集中を切らさずに取り組んでいました。'),
  ('06b1ae2b-9508-515c-a10f-54ee1f96e119', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '16:30:00', null, '通常 / 『自由制作DAY』（黄）', '今回は、サッカーの試合があったため少し遅れてきていましたが、キャラクターのHPがどのようにして減っていくのかと、ゲームオーバーの条件について作成することが出来ました。。HPの減り方に関しては、敵に当たった時に減っていくためには何のコードが必要となっていくのかを答えることができていました。しかし、実際に作っていく際に脱線して別のことをしてしまうことがしばしばあったので、集中して取り組むことができれば、作成のスピードをより上げることができると感じました。ゲームオーバーの条件でも同じように、どうなったらゲームオーバーになるのかをコードでどう作っていくかに関しては答えることができていましたが、ゲームオーバーのスプライトの作成やメッセージの作成でふざけてしまう部分があるので、そこに関しては改善が必要だと感じました。', null, '盛り上がり: 少ない時間の中で、ある程度進めることができていたので喜んでいましたが、自分の思い通りに作っていくことが出来ていなかったので、少し不満げな部分も見せていました。'),
  ('e069db39-1fd9-5bd8-a89a-8471d96da13c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-02', null, null, '通常 / 作品の完成を目指して作成する、使用したスキルの確認をする', 'クローンされた弾丸の軌道や数が思うようにいかなかったようで、かなり悪戦苦闘していました。 元になった【小技】弾幕シューティング 02 いっせい発射のコードがきちんと読み取れていない状態で、数値をいじっていたのが原因だったので、元のコードの「へんすう」が何を意味しているのか、繰り返しの回数と「へんすう」が36になるまで待つにはどういう意味があるのか、ヒントを出しながら話していく上で、一つ一つのブロックの意味に気付けたようでした。 元のコードの意味がなんとなくわかったところで、自分のコードを見直して、余分なコードを削除したり（意味のないところでスクリプトを止めたりしていました）、最初の角度や回数などを調節していました。 残り時間が10秒を切った時の演算式で、とりあえず適当な？不等号を入れて、実際に動かした後で直していました。不等号の説明はしましたが、見てパッとわかるほどの理解ではないかもしれません。 時間やスコアを変数にすることはわかっているようですが、ゲーム途中で作成されるクローンの数を変えようとして、「途中で数値を変えたい場合はどうする？」との発問をしたところ、答えられませんでした。変数は漠然と、時間やスコアで使うものとの先入観があるかもしれません。 向きと変数を使った数が整理できてからは、楽しそうに作成をしていました。', 'この自由制作が終わったら、変数のさまざまな使い方や演算系を強化してあげてください。', '時間帯: その他
盛り上がり: 前半はきつそうな様子でしたが、弾丸の軌道や数を自分の希望通りにできてからは、普段のペースを取り戻せたのか、満足そうに作成をしていました。'),
  ('01d3cc2f-1c97-5e04-b2fc-b42de92bc5f0', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-03-02', null, null, '通常 / 追跡ゲームの完成とアレンジ', '作成途中の追跡ゲームの背景が宇宙ということもあり、完成したあとアレンジする際は自由製作dayも兼ねて行いました。算数で不等号はすでにやっていて意味もしっかり分かっていたため、「スコアが10点になった」の判定を不等号を使ってやってもらいました。厳密にはスコア>10ではなくスコア>9としないといけないことにも気づけて、よく理解していました。また、10点取ったときに背景を変えたり音を鳴らしたりもできて完成しました。 アレンジとして、10点と20点に到達したときはステージだけ変えて30点になったらゲームクリアにしました。全体的に、使うブロックをどの場所に入れるかをすぐに正しく判断できていました。', null, '時間帯: その他
盛り上がり: 集中力が高かったです'),
  ('c693d958-bf29-5fea-a46c-c2aa9cb29acd', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-02', null, null, '通常 / 花火を作ろう', '小技などでクローンの複製などを使った来たので、その技能がばエル花火を作っていきました。説明書を見ながら、随所気になるところに説明を加えました。スピードの変数がローカル変数に使うことになっていたので、その理由を聞いてみてもわからずだったので、クローンの個別の動きを持たせるためと説明してあげました。出来上がった際にどこの値を変えるれば、大きさを変えられるか聞いたとおころ、ゆっくり考えて何となくでスピードの変数を選ぶことができました。ほかにも正円の書き方も教えてあげました。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。
盛り上がり: 出来上がったカラフルな花火に喜んでいました。'),
  ('9fd8cd66-804e-5841-b2c9-187aa6cb65ec', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', null, null, '通常 / 『自由制作DAY』（青）', '前回完成させていたアイテム脱出のゲームをアレンジして作っていきました。小技の部分では、残像のコードを使っており慣性の入った作品を元としているので、面白い動きとなっており思ったより良いものができたと喜んでいました。アレンジとして、壁にぶつかった際に取得した鍵も元の位置に戻り再び取りにいく必要があるようになっていました。このアレンジは難易度を上げることが出来たと喜んでいましたが、ステージ２の動作がイマイチだったようで、次回修正すると言っていました。今回は特に、ステージ変更の部分があまり気に入っていなかった様子なので、その部分に関してはしっかりと教えていきました。特に、「ずっと」コードをどう使うのかを悩んでいた様子でしたので、特に焦点を当てていきました。', null, '時間帯: その他
タイピング: 伸ばし棒を使う部分で苦戦していた様子だった。
盛り上がり: ２ステージ目について修正していきたいようでしたが、１ステージ目に関しては難易度を上げたりと自分のしたいことを入れることが出来ていて満足していたようです。'),
  ('1404cef9-65ad-5388-a1bf-ccfec3ce4c3e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-03-01', '18:40:00', null, '振替 / 『自由制作DAY』（青）', '今回のレッスンでは、前回スロットのコードの続きを作成していきました。投入金額のデザインやスロットのリールでのデザインに悩んでいたようで、時間を使っていました。その後は、ボタン部分を全てスプライトへと変更することにしたようで、それぞれのボタンを作っていました。コードの内容としては、大枠は一緒なのでそこまで苦労している様子は見られませんでした。残りはそのボタンのスプライト部分のみのようなので、次回には完成させたいと言っていました。', null, '盛り上がり: ボタンのデザイン部分には特に拘って作っていました。'),
  ('f049f23a-1cb4-5017-b5d8-eba33f8345d3', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-29', '17:30:00', null, '通常 / オリジナル作品を作りながら基本スキルを身に着ける', 'オリジナル作品をまだまだやりたいようだったので作成を続けました。「作っている途中で新しいスキルを身に着けたらファイルのここにスタンプを押すよ」と最初に伝えると、スタンプを押すたびにとても喜んでくれました。スプライトの大きさを変える 、矢印キーで左右に動かす 、「～秒で座標を～にする」で滑るように動かす 、「もし～キーが押されたなら」で数字キーを押したときの動きを決めるなどのスキルを扱いました。 特定のタイミングでスプライトを表示するためにメッセージを使えることを理解してたくさん活用していたのですが、必ずスプライトごとに別のメッセージを作成していました。そこで、「同じタイミングで表示するなら同じメッセージを使いまわせるよ」と伝えると納得してくれたようで、それ以降そうしていました。', null, 'タイピング: 一応やってくれましたが、既にゲーム制作に気持ちが向かっていたようで一回終わるとすぐにやめていました。
盛り上がり: 制作のアイデアをたくさん話してくれます。一つずつ順番に作っていくことを促しました。'),
  ('69787a72-f666-5935-b814-a4bb0657dd02', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-03-01', '17:30:00', null, '通常 / 基本操作コース06の細分化バージョンからスキルを使用して作品に取り込む', '今日はピヨコムのもぐらたたきに盛り上がってしまったせいか、授業に入るまでに少し時間がかかりましたが、今日の目標はきちんと聞いてくれて、そうすけくんなりに達成しようとする姿勢は見られました。 途中でもぐらたたき休憩を自主的に入れてはいましたが、メッセージの使用、背景の変更とイベントとしての使用、座標の指定などを活用することができました。', null, 'タイピング: もぐらたたきと、アルファベットうちゲームをかなり熱心にやっていました。トータルで15分くらいはハマっていました。
盛り上がり: ストーリーとしてはバッドエンド？ではありますが、一つのお話が完成できたのは嬉しかったのか、お母さんにも得意そうに報告していました。'),
  ('d070badf-7996-5cc1-96bc-2de515fbdcc4', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-01', '18:40:00', null, '通常 / 自由製作day', '前回で8割くらい終わっていたので、ゲームの終わりのセリフの小回りや少しの手直しで完成はできました。変数での時間制限も難なく作れていました。 半分は時間が余っっていたので、弾幕の方で新しいゲームも作りました。ボール避けることがペンツールでうまく残像と組みわ去っていて鮮やかなものになっていました。 ボールにもセリフを持たせ楽しんでいました。', null, '盛り上がり: カラフルにさせることが好きなようです。'),
  ('ae63e8a0-b8ec-5ad2-8b07-e1e148e1adce', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-01', '17:30:00', null, '通常 / 自由製作', '地球から飛び出して攻撃を避けるストーリー仕立てになっていました。途中ロケットを自由に動かせるようになるのをやめたいとのことだったので、コードを止めるブロックの活用を教えてあげました。セリフのところだけは止まっているようにしたいメリハリあるストーリーで面白いものになっていました。最後に地球に帰還するシーンも作れて完成しました。', null, 'タイピング: 孫室から脱却するようがんばっています
盛り上がり: ケイト君に遊んでもらったところ、敵の攻撃から避けるところが癖になっていました。'),
  ('4891b86d-48c6-57ec-a869-07f382dee11e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-01', '17:30:00', null, '通常 / 自分のやりたいことをゲームに落とし込む', 'セリフを翻訳サイトで英訳して貼り付けるなど、こだわりを持って作成していました。 ドアが開く様子なども、はるくんのゲーム歴を感じさせる作りにしていて頑張って作成できていたようですが、ライトで照らしたところを少し透過した感じにするところでかなりてこずっていたようでした。小技の例は、照らしたところが完全にくりぬかれて下の背景がはっきり見えるところが嫌？なようで、例として見せた時に、「そうじゃない」とのことでした。 授業後10分くらい粘って、あきらめていたので、次回、「次回の予定」に記載したところを指導してあげてください。', 'スプライト9の円の中が、少し透けた感じになって、スプライト「壁」の照らしたところだけ見えるようにしたいようです。 問題点と解決例は以下の通り。 ・スプライト「壁」そのものを幽霊効果100にしているので、真っ黒になってしまっている。ここを透けさせて見せようとしても、そもそも見えるところがないということに説明が必要。 ・円以外の場所を暗くするには、小技のように黒（円以外の場所を見えないようにするもの）のスプライトが必要⇒円以外のところを黒くした小技のやり方がやりやすいはず。 ・小技と違って、うっすらと透ける感じで見せたいのであれば、上記スプライトとは別に円のスプライト（現在のスプライト9を流用でも）を作って、常に上記スプライトへ行くようにしつつ、幽霊効果を適当に設定してみる。 今日は幽霊効果と明るさ効果を一生懸命いじっていました。 下にあるスプライトがうっすらと透けて見えるというのは、それぞれのスプライトがどういう状態になっているか、混乱しているのを整理する必要がありそうです。', '盛り上がり: 前半は、自分でやれると熱心に作成していましたが、後半は「できない」「無理かも」と悩んでいたようでした。もう少し自分でやってみる、と言いながら時間切れになる寸前に、できないところを一緒に作ってみようかと声をかけると、ほっとしたようにも見えました。次回、一緒に解決しようと声掛けしてあります。'),
  ('1fe22fd0-6864-5507-b6cd-3c21863b9ea1', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-03-01', '16:30:00', null, '通常 / 自由製作day', 'ロケットが飛んでいく様子を縦スクロールにして表現していきました。小技のコードから自分で読み取って縦型に改良をできていました。結果発表でスクロールを止めるのが苦戦していたが、何を止めればいいか理解して解決できていました。', null, 'タイピング: 1000円以上のお得になっていました
盛り上がり: 昔世代以上の曲や本の知識があふれていていました。'),
  ('4ab4590c-2c81-584d-b1e4-1f8bed54c22d', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-29', '17:30:00', null, '通常 / 自由製作day', '30分ほど遅れてしまいましたが、最終的な見直しをしてもらいました。完成をしていたそうなので、少し残像のコードを気に入ったらしく、幾何学的な模様を作って試していました。', null, null),
  ('e20742dd-82e6-57d9-b5d7-1df94c910448', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-29', '17:30:00', null, '振替 / ジャンプの種類を覚えよう', '等速ジャンプにおいては変数の重要さについて教えました。本人的には2つ変えれば良いじゃんと言ってたがジャンプに限らず使えることの容易さを着目してもらいました。 次に、放物ジャンプを見せたら、プラットフォーマー的なジャンプと食いついてきました。原理のついて説明して、作ってもらおうとしたが、即答わかりませんだったので、等速ジャンプの改良から作っていきました。そのアプローチだと、直接なブロック指示はなくてもコードは自力で作れていました。変数をジャンプするたびに初期値する必要性とかも気づけていました。', null, null),
  ('571cbea7-cd10-5a96-87da-c989e9c417a6', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-29', '17:30:00', null, '通常 / 基本操作コース06のスキル確認', '先週の作品を見せてもらってから、ファイルの1枚目を見せたところ、結構忘れてしまっていると自己申告してきました。今日覚え直せたところにスタンプを押していこうと提案すると、喜んで作成に入ってくれました。 すべてのタイミングを「○秒待つ」でやろうとしていたため、「背景が○○に変わった時」を学習しました。「こんな便利なブロックが！」と喜んでいました。 背景によって、特定のスプライトの表示と隠すを切り替えるのは、イメージに合っていたようで、感心しながら作成していました。 滑るように動かす、○度に向ける、を学習しました。グリフィンを思い通りに動かせたようで、とても喜んでいました。', null, 'タイピング: 少し遅れてきたため省略
盛り上がり: 先週と今週の学習でどのスキルを使えたのか、スタンプで視覚化できてうれしそうでした。 「今日は結構がんばった！」と満足そうでした。 40分ほど集中して課題に取り組めたので、残り10分時間はコスチュームを編集するのを許可したところ、部屋の様子を変えたりして楽しそうにしていました。'),
  ('3c9b5772-36a1-5b87-9185-e50eec2956e1', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-29', '17:30:00', null, '通常 / バグの修正、全体を整えて完成を目指す', '最低限、どこを作成すれば完成形になるかを意識して進められていたと思います。 「○○まで繰り返す」の使い方に若干の混乱が見られましたが、コードを丁寧に見直すことで修正できていました。 シンプルなコードで書こうとしていたことは評価できるかと思われます。 「スプライトの他のスクリプトを止める」を、別のスプライトのコードを止めるつもりで使用していたので、「止める」ブロックの3種類の違いを整理しました。問題の箇所は、メッセージを使用することで解決していました。 ゲームクリア以外のところは完成できたようでした。', 'ゲームクリアのみ追加', '盛り上がり: 目標を決めて、計画的に作成しようとしていました。そのせいか、集中している時間も長かったようでした。'),
  ('73c38c62-f13d-5d10-ad95-7f27ec520ff7', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-29', '16:30:00', null, '通常 / 自由製作', '先週お休みで間が空いたので、前回書いた紙を見て思い出してもらってから始めました。まずはキャラクターを「～秒で～に行く」で動かし、これは基本操作コース06の復習にもなりました。「もし～に触れたら」は自力でコードを書くことができて、身についているようでした。変身として10秒経ったらキャラクターを大きくするのも作ろうとしましたが、複雑に考えすぎて困っていたのでシンプルに考えることを促しました。次回の前半くらいで完成までできそうです。', '続き', 'タイピング: レッスン開始後すぐに始めていました。
盛り上がり: 今日は社会科見学に行ったそうで眠そうでしたが頑張れました。'),
  ('2feeba44-8b13-5031-8088-eee979d72344', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-29', '16:30:00', null, '通常 / 演算式やクローンのスキル確認', '課題だった条件分岐の間違いなどは、自分で見つけることができました。 ステージがボス戦になったときに、クローンの多用でアルくんの攻撃のクローンがうまく出ないことがあったため、クローンの上限について説明しました。クローンを作るタイミングに○秒待つを入れることで対応していました。 最初のステージの敵スラボーと、ボス戦の敵トムのHPを、どちらも「相手のHP」としているために混乱が見られました。「相手のHP」として1つの変数で管理しようという発想も良いのですが、スプライトごとにHPの変数を別に持つことも含めて、次回、一旦整理することが必要かと思われます。 「旗が押されたとき」「メッセージを受け取った時」「クローンされたとき」のイベント発生のタイミングの違いが管理しきれていないようでした。文章にするのはあまり抵抗がなさそうなので、もっと詳細に紙に書いて整理してから作成に入った方がわかりやすいタイプかもしれません。', null, 'タイピング: ココアタイピングから進歩した実感があるのか、嬉しそうにやっていました
盛り上がり: ステージの段階がわかれているのを作成することは、嬉しそうに取り組んでいました。 バグの箇所を探すのも、楽しんでできていました。'),
  ('fdaf8824-5023-5ed9-9ba6-8cfc15a5a58d', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-29', '16:30:00', null, '通常 / 自由製作day', '授業前のゲームが長続きしすぎてタイピングが終わるまで20分くらいかかりました。ゲームのゴールが不明だったので、それを目指して作っていきました。とにかく生き続けることだったので、ゲームオーバーを作ろうとしました。るいくんが、ゲームオーバーの条件を何となくで体力が０にしたいそうだったので、使うブロックは補助しながら作っていきました。途中で無駄に増やしてしまうこともあって、少し休憩をはさんで、最終的には赤と青の者が画面に切り替わることで落ち着きました。おそらく完成はできたと思います', null, 'タイピング: Aが増えてきました'),
  ('bf214c50-0d0b-5ab0-b27a-80367f9ee612', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-29', '16:30:00', null, '通常 / 複数の条件分岐の組み合わせ、タイマー', '検定2級に必要なスキルであるタイマーなどを身に着けるためカエルの虫取りゲームを作りました。タイマーについては、「タイマー>20まで待つ」やリセットが作れて、機能をイメージすることはできたようでした。落下していく虫の動きについてはキャッチゲームと一緒でしたが、意外にも自力で作るのには苦戦していました。「x座標を乱数にする」や「一番下に来るまで繰り返す」など個々のブロックはできましたが、どうやって組み合わせるかで迷っていたので、時系列で考えるように促しましたが、完成まではたどり着けませんでした。', 'プログラミングにはある程度集中力を持って取り組めていました。', 'タイピング: タイピングにはやる気が出なかったらしく、伸ばし棒(-)の練習で遊んでいました。
盛り上がり: プログラミングにはある程度集中力を持って取り組めていました。'),
  ('e285706d-9c9b-5a40-ad7d-d89ae285a81c', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-29', '16:30:00', null, '通常 / 変数で動かす動きに慣れよう', '変数で制御する動きでなんとなくは最初に遊んでいた段階で気づいていました。動画を見ながら作っていましたが、ところどころスキップをしてうまく組み合わないことが発せしていました。ブロックの塊ごとにどうゆう動きの者なのかきいてみると、ほぼ理解できていました。滑る動きのところでは、だれもが陥る勝手に動いてしまう現象が起こっていました。そのバグの間違え探しに時間はかかったが自力で探せていました。', '続き', 'タイピング: 早々と終わらせてました
盛り上がり: 試遊のために遊んでいたが、滑る動きに慣れず苦戦していました。'),
  ('ca304745-719e-517d-9ebd-8221aa6cb366', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-27', '17:30:00', null, '通常 / 『自由制作DAY』（青） 今日で完成を目指す（スロットゲームの作成） 完成したら、今回新しく使ってみたコードの確認', 'スロットゲームの判定を作成しました。はじめに自分で考えたもののあまり良いプログラムが思いつかなかったようなので、「スロット」のプログラムを紹介しました。 あまり横に長いものは作りたくないとのことだったので、ベン図を使って整理しながら「もし～」を使ったときの論理関係を一緒に確認しました。また、スタートボタンも完成しました。 スロットが合わさったときのお金のプログラムを次週作りたいそうです。', null, 'タイピング: 集中して取り組めていました。'),
  ('2c4a4dbc-4992-5bd6-9b81-5bf8fa7c32f5', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-27', '17:30:00', null, '通常 / 『自由制作DAY』（青） 今日で完成を目指す（アクションゲーム部分の作成） 完成したら、今回新しく使ってみたコードの確認', 'リストの中身を整理していました。リストに文字を追加するときに「～と～」を使えば、2つの答えどちらも正解として判定してくれるのかなど新しい実験をしていてとても良かったです（しなかったそうです）。また出題順についても「～番目を削除する」と変数をうまく使って、分かりやすく整理することができていました。 作品は完成しました！！', null, null),
  ('255bb232-6c45-54e4-b5aa-3acacc6f9c92', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-27', '17:30:00', null, '通常 / 『自由制作DAY』（青）', '前回残っていたビームが所定の位置から出てこないバグについて解決していきました。座標の位置が間違っていたようで、本人も納得していました。ゲームの内容をPvPへと変更していたようで、新たな要素を追加していきました。結果として、今までの作品よりもオリジナリティがかなりで作品を完成させることが出来ていました。プレイヤー同士での駆け引きや早撃ちが鍵となるようなゲームを作り上げていました。', null, '盛り上がり: PvPのゲームを初めて作ったようでしたが、しっかりと完成まで持っていくことが出来たので、満足していました。'),
  ('e8e211a7-bae8-5f39-9ebb-a48c02b0c682', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-27', null, null, '通常 / Scratchの場合は、和ちゃん作のきょうりゅうとタイピングゲーム（https://app.arstudio.fun/contents/52761）からスキルの獲得 やりたがるようなら、MonacaでJavaScript', '初めに変数とリストを使って出てくる文字を操作しているプログラムの仕組みを伝え、取り組んでもらいました。出てくる問題が被らないように出題済みリストを作り、発生させる乱数を操作していることも伝えました。乱数についてはあまり知らなかったようなので良かったです。 時間中はずっと取り組んでいたようです。またアレンジとして音を追加していました。自分の作品を作るときに思い出してくれると嬉しいです。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('3b6a2616-0059-5fd4-95f2-0d8ed31dc72c', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-27', '16:30:00', null, '通常 / 『自由制作DAY』（青） 今日で完成を目指す 完成したら、今回新しく使ってみたコード（変数、定義等）の確認', '最後にボスが出てくるステージを作成しました。プログラムを足すときに、メッセージを送っていても、定義との順序が整理されていないため、うまく動いていないことがありました。またいろんなスプライトのHPが出てきているため、操作する変数名を混乱している様子でした。 かばのHPを出す時にも、リセットするタイミングが考えられていなかったためかなり困っていました。 HPのリセットとゲームの終わりをプログラムする必要がありそうです。', null, 'タイピング: 集中して取り組めました。'),
  ('04360476-0ab9-5a76-8a48-75a326d2cb1b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-27', '17:30:00', null, '通常 / 作品を完成させる', 'ゲーム部分は大体完成していたので、「ステージを変える」「小技を使う」を今日の目標にしました。 敵のHPが0になったときにステージを変えたかったようですが、不等号の向きが不安だったのか、そばで見ていてほしいと呼びにきました。一緒に見ていると安心するのか、「これを使う？」と自分で選んだブロックも合っていたので、このブロックを入れるとどういう意味になるのか口頭で言わせ、「HPが1より小さくなったら」と自分で言って、納得できていました。 条件を入れた後は、小技の元を見たりしながら自走できていました。', null, '盛り上がり: ゲームが完成できて、嬉しそうにお母さんに見せていました。 スプライトのコスチュームや音にもこだわって色々と編集していましたが、以前のように適当にいじって子どもの落書き感を出してしまうこともなく、きちんとした編集ができていて、自分でもそれがわかるのか、満足そうに授業を終えていました。'),
  ('c502b2fe-455a-59c6-a468-4c50145bc894', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', '17:30:00', null, '通常 / 『自由制作DAY』（青）', '今回から制作を始めたので、この時間内に完成を目指すということですごい勢いで制作を進めていました。今までに作った事のあるものを応用した内容ということもあって、途中でつまづくことなく時間内に完成まで持っていくことが出来ていました。本人の中でも満足のいく作品を時間内に作ることが出来たようで、とても満足していました。特に、UI部分や演出部分に関しては非常にクオリティの高いものを作り上げることが出来ていました。', null, '盛り上がり: 作品を完成まで持っていきつつ、満足のいくものへと仕上げることができていたので、達成感を感じていた様子でした。'),
  ('70848312-7981-5b55-87cd-108aa778bdc9', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', '16:30:00', null, '通常 / 『自由制作DAY』（青）', '前回までで大部分が完成していたようなので、作成自体は30分ほどで終えることが出来ていました。残りの時間で、作品をどのようにして楽しんでいくのか試行錯誤していました。特に、ステージを進んでいくごとに難易度が上がっていくので、どれくらい上げてくのかを悩んでいました。その後は、発表に向けてどのように説明していくのかについて考えていました。どちらも、本人の納得のいくものにできたようでした。', null, '盛り上がり: 難易度調整は、ちょうどいい塩梅を見極められるように様々な意見をもらっていました。'),
  ('5d684da0-33c6-5512-81a0-c09b25a0c0f3', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2024-02-27', '16:30:00', null, '通常 / 自由制作を通してScratchの基本的なブロックを学ぶ', '前回作成していた自由制作は、コスチュームを少しいじって完成させました。 「楽器を遊ぼう！」では、緑の旗を押す以外に、このスプライトが押されたときというイベントがあることを学習しました。楽器や音にもこだわって一生懸命選んでいました。押したときに音が出る楽器だからか、打楽器にこだわって選んでいました。シンバルの音をいろいろ試していました。 今はいろいろなことができるようになるのが楽しいのか、一つの課題をアレンジまで作り込むよりも、完成したら「次をやる！」という感じです。チュートリアルは自分でストップと再生を繰り返しながら熱心に聴くことができていました。 前回の授業では、矢印キーはマウスと混乱するから使いたくないと言っていましたが、「アイスを食べに」のチュートリアルで矢印キーの設定を視聴すると、素直に作成に入っていました。 右向き矢印キーを作成した後、チュートリアルが「同じように上向き矢印キーを作ってみよう」という指示だけになったのに困惑していたので、複製を教えたところ、楽しそうに作成できていました。 「アイスを食べに1」が完成したので、ファイルの1枚目の「コスチュームを変えよう」「上下に動かそう」「音を鳴らそう」にスタンプを押させました。「今日はこれを覚えた！」と嬉しそうに紙を見ていました。', null, 'タイピング: マウスのドラッグ操作に慣れたようでした
盛り上がり: 前回は覚えたスキルにこださって同じブロックばかりを使っていましたが、今日は、新しいブロックを覚えたことを喜ぶことができていたので、少しずつ使えるブロックを増やしていくことができそうです。'),
  ('0b2aa39b-3f8c-54f2-bccd-34bafc37b58f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', '16:30:00', null, '振替 / 『自由制作DAY』（青）', '前回から続けて自由制作DAYの制作を行っていきました。今回で完成まで持っていく予定でしたので、残っている部分をしっかりと確認しながら行っていました。タイマーの部分でストップウォッチの小技を使おうとしていて、どのようにして動いているのか悩んでいる様子でした。しかし、秒数の繰り上げや数値の変わり方をコードを見て理解することができていました。次回作品の発表ができるように作品の流れも確認していました。', null, '盛り上がり: ストップウォッチの理解が一番苦戦していたようなので、仕組みをしっかりと把握することが出来てスッキリした様子でした。'),
  ('7572aafa-cec9-52fe-8d85-473a56a887aa', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-22', '17:30:00', null, '通常 / 自由製作day', 'できれば今週で完成させたいねと伝えてから作成に入ってもらいました。残像の小技を実装してステージの移行、クリア、ゲームオーバーの処理なども作れたのですが、残念ながら完成まではできませんでした。', null, 'タイピング: 承太郎くんと競い合うように取り組んでいました'),
  ('889caf17-c448-516c-bb63-840bcdc070a7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-22', '17:30:00', null, '通常 / 自由製作day', '目指すものを最初に確認しましたが、アンダーテールのような弾幕ゲームを作るとのことで細かいところまでイメージすることもできていたようでした。放射状の弾丸発射、体力ゲージ、背景スクロール、残像といった小技もたくさん活用していて、小技は1つあればいいよと伝えてもやる気でした。体力ゲージがうまく表示されないバグは残りましたが、ほとんど完成までこぎつけました。', null, 'タイピング: 集中してやっていました
盛り上がり: 前回はやや苦戦していたようですが今回は調子よく作成を進めていました。'),
  ('3762252a-fa76-52d2-a5e6-eb92a2ede489', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-22', '17:30:00', null, '通常 / 基礎の復習', 'お休みが続いて久しぶりだったこともあり抜けている内容も多そうだったので、基本操作コースをもう一度やって復習しました。細分化されたものを見せて進めると動きのイメージがよくできたようでした。～秒待つやメッセージなどを使って、キャラクターを順番にしゃべらせたり背景を変えたりできました。少し問いかけをすると、どのタイミングでスプライトを表示する/隠すのかも判断できました。', null, 'タイピング: 楽しくやっていました
盛り上がり: 今回は比較的よく集中できていて、本筋を見失うことは少なかったです。'),
  ('ec7e07fe-55f3-5929-aca5-8bc66a23b8f5', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-26', '16:30:00', null, '通常 / 名前を動かそうにあんまり興味ないので、どうぶつを動かそう(動き重視) デジタル水族館とかで見本を見せてみる', 'こちらから動かし方を提案し実践してもらいました。 はじめに白くまの大きさを変えました。小さくするときに－をつけることを足し算と引き算の話を交えながら伝えました。次に卵を回転させました。理解は難しそうでしたが、方法があることを知ってもらいました。このときにキーやクリックで動かせることも共有しました。最後は座標を使って卵と鳩を動かしました。 ひとつ知ると応用が利くタイプのように感じました。', null, 'タイピング: もぐらたたき、名前を探す、ジグソーパズルと一通りやってみましたが、ジグソーパズルがしっくりきた様子でした。絵柄が毎回同じということですが、タイムアタックにしたら面白いかもしれません。'),
  ('78831c18-70ce-5204-855e-8a5a41738521', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-26', '17:30:00', null, '振替 / 自由製作（青）の続き なにを作るのかを説明してから。 世界観はあるようなので、内容も沿ったものにしたい', '自由製作（青）のプログラムを確認した後、プラットフォームのようなゲームを作れるようになりたいとのことだったので変数の演習をしました。自由製作のプログラムでは時間の変数がうまく作動していなかったようなので修正してもらいました。 変数の単元は難易度的には簡単だったようですが、ひとりで取り組むのが難しい様子でした。（ひとめ見て分からない！と言っていました）カーソルに向けて動かすのもうまくできていました。 話を聞いてみるとプログラミングが嫌いなわけではなく難しいのが嫌いだそうです。。', null, 'タイピング: 取り組んでいました。
盛り上がり: 現在時刻のプログラムで盛り上がりましたー！'),
  ('1039fbfd-2bbf-5007-8d6e-bc008d855f78', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-26', '16:30:00', null, '通常 / 自由製作（青） 前回の続き。予定を話してもらう。 やりたい構想はある模様。', '手のプログラムと地球の体力のプログラムを作っていました。手のプログラムはメッセージを使って表示非表示をコントロールしていてとても見やすかったです。戦闘機の動きも自分の考え方が確立していて、丁寧に作成できていました。ゲームの終わりの部分の演算子の使い方が慣れないようで苦戦していました。 ゲームの骨格の部分はできていますが仕上げがまだなので、次週もやりたいそうです。', null, 'タイピング: 集中して取り組めていました。'),
  ('998ef28f-700f-5a60-9c4c-afcf38cf004b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-26', '17:30:00', null, '通常 / 自由製作（青）の続き(細分化) 最初に作るものの確認。口で計画を説明してもらう。 考えてから手を動かす（←2級を今後受けるので結構大事に）', '紙がほぼ埋まっていなかったので書いてみるように促しましたが、難しかったようです。プログラムはほぼ完成していたので、ゲーム性を高めるように提案しました。ビームがコウモリに当たったときの挙動がとてもよくできていました。スマブラのようなスタート画面を作成していました。変数が動かなくなってしまったので一緒に見直しました。 次週完成予定です！', null, 'タイピング: 集中して取り組めていました。'),
  ('aef92ba8-06db-5c02-829c-fc769933a505', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-26', '17:30:00', null, '通常 / 自由製作（青） 前回の続き(細分化) 最初に作るものの確認。メッセージ。', '脱出ゲームの画面の切り替わりとアイテムのプログラムを作成していました。画面の切り替わりはあるくんの座標で制御していましたが、xとyの方向の違いと演算子の大小関係がうまく組み合わず、苦戦していました。最後にはメッセージを整理して、うまく画面が切り替わるようになっていました。アイテムのプログラムでは「～まで待つ」の使い方を説明しました。 1時間ずっと取り組めていて集中力が高くなったと感じました。あと1/3くらい残っているそうです。次週完成させたいです。', null, 'タイピング: 集中して取り組めていました。'),
  ('5eda3fd8-0c38-587b-a99d-505da30f1517', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-02-24', null, null, '通常 / Excel教材の体験', 'Chapter3-5まで', null, '時間帯: その他'),
  ('5d52c362-0a08-54e9-9b17-c9bd6ad77876', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-24', null, null, '通常 / やりたいことを言語化して設計書に整理してから作成することに慣れる', 'コスチュームの変更、座標を指定しての移動、○○に触れたらの条件分岐の習得を目標としつつ、やりたいことを思いつくたびに適当に口にするのではなく、最初に紙に整理してから順番に作成していくやり方をすすめていきました。自分が話したことをこちらが紙に書くことによって、どういう説明をすれば相手に伝わるのか、逆に、話し方によっては相手に誤解をさせるというのが少し意識できたようでした。 紙に書いた手順書に従って作成することで、何をしていたのか見失うことが減り、できたところに花丸をつけることでモチベーションアップにもつながったようでした。 スプライトのいんせきが地球にぶつかったら地球のコスチュームが爆発したようになる、というところで、色が触れたらのブロックを使っていて、位置によってはうまく反応しないことがありました。スプライトが触れたらへの変更を渋ってコードを複雑にしようとしていたので、見やすくわかりやすいプログラムの重要性（将来ゲームを公開したいとき、誰がどんなパソコンで遊んでもサクサク動いて楽しめることが大事、というようなことを話しました）を説明したところ、納得できたようでした。 背景の編集においても、写真の一部を切り取って大量に貼り付けることを家でよくやっているそうなのですが、教室でやると動きがとても遅くなるとぼやいていたので、必要のないところで無駄に容量を大きくしないことのメリットを話しました。やすのりくんなりに納得したようで、無駄な画像のコピペをやめてくれました。 まだ小さいからとうやむやにせずに、ゲーム作りのプロになって、いつか自作ゲームを公開をしたいなら、という前提で話すと、とてもよく聞いてくれました。 条件分岐にずっとを入れ忘れたりすることもありましたが、小さなミスには一度で気づいて、以降は自力できちんとできていました。', 'ゲーム作成続き（設計書に沿って） 設計書はプリントの裏にあります', '時間帯: その他
盛り上がり: 設計書に沿ってゲームができていくのを喜んでくれました。 50分くらい、課題に熱心に取り組んでから、残り時間でポケモンの取り込んだ絵を見せてくれました。'),
  ('a5b8179e-5309-5a0a-be41-3fc103ab038b', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', '16:30:00', null, '通常 / 自由製作day(赤)', '今回は、前回までに制作していたものを順序立てて組み立てていきました。自分自身でどのようにして動いているのかがイマイチわかっていない様子でしたので、一度説明できるように整理して考えていきました。結果として、本人がどのような作品にしたいのか及び何が現在できていないのかをしっかりと確認することが出来ました。そして、作品の大部分を完成させることが出来たので、次回で完成と細分化を完了していければ良いと感じています。', null, 'タイピング: 正確に打ち込むことが出来ていました。
盛り上がり: どこが足りなくて、何が間違っているのかを整理して問題点を洗い出すことができていたので、疑問が解消された様子でした。'),
  ('e942bdd4-cbdd-5560-89d9-36ccc82b0ee7', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-24', null, null, '通常 / 基本操作コース06_物語を作ろう 続き メッセージを受け取るところから (参考) 基本操作コース_06物語を作ろう【アレンジ】⑤タイミングに合わせて動かそう https://app.arstudio.fun/contents/56490 「メッセージを送る」と「メッセージを受け取ったとき」の確認 ここが丁寧にできたら、オリジナルの物語を作る 見本として、アルスタジオレッスンアドバンスの「デジタルアニメ」あたりを見せてみても https://app.arstudio.fun/contents/18185', 'メッセージを使ってプログラムを作るように最初にお願いしたのですが、自分で作りたいものがあったようなのでしばらく様子を見ていました。スプライトを新しく作ったり、いくつか背景を用意したり、音をプログラムで追加したりしていました。時間制限もあったので、メッセージは会話のプログラムに組み込むことにしました。一緒に確認しながらひとつずつ進めましたが、きちんと理解できているかは怪しいです。 最後に背景の切り替えも追加してプログラムを完成させました！！オリジナル作品がまだなので、来週以降作る予定です。なんとなく考えてくるように伝えました。', 'オリジナル作品がまだなので、来週以降作る予定です。なんとなく考えてくるように伝えました。', '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('aafb9e9e-cdaa-5513-ac46-4ad337bdf71a', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-24', null, null, '通常 / 【単元】リスト＿完成版 都道府県と県庁所在地クイズ、【単元】リスト＿リストでおばけのでかくれんぼ クローンと残像の小技を使ったゲーム自体は完成しているので、本人の希望があれば、オープニング画面を作るなど、ゲームの完成度を上げてみる。 他の作品に行きたがるようなら、リスト学習の続き', '都道府県とおばけのかくれんぼを比較してもらいました。見た目の好みもあり、おばけに取り組むことになりました。ヒントを見ても理解しにくかったようなので、見本を見ながら取り組んでもらいました。見本を見ても納得のいかない部分があった（ここで手が止まるのが素晴らしいなと思いました）ので、詳しく解説しました。 乱数を使ってリストを指定するプログラムでしたが、一度生成した乱数を後で使うために格納するのが新しい要素でした。3回ほど説明方法を変えて紹介しました。なんとなく理解できたようです。ゲームは完成しました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('e095bc58-d1de-52b6-a3aa-752dc7012715', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-24', null, null, '通常 / 自由製作day(青) 隔週なので、作りたいゲームのイメージを確認してから作成 残像がうまく消えていないので、小技の完成例を見直してみて ビームの動きが自己解決できなそうなら、レッスンエキスパートの宇宙バトル3や小技の弾幕あたりを見せてみて', 'ビームの挙動と残像のプログラムの修正、背景変更のプログラム作成を行いました。残像については見本をみてもよくできていなかったので、プログラムの仕組みを一緒に確認しました。ビームの挙動はおおよそうまくできていたので、「端に着いたとき」を基準に考えるようにアドバイスをしました。 背景変更のプログラムも色にこだわっていたので、スプライトで判断する方法を助言しました。 自分のやりたいことを最大限表現できていると思うので、使える道具をもう少し増やしていきたいです。作品は完成しました！', null, '時間帯: その他
タイピング: 集中して取り組めていました。
盛り上がり: 作品名をつけるときに盛り上がりました。'),
  ('041b6fd4-8d07-5bc1-97ac-919c96d55399', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', null, null, '通常 / 自由製作day(青)', '前回イマイチ構想が固まっていなかったようで、コードもあまり書けていませんでしたが、今回でどのようなものにしていくのかしっかりと決めることが出来たようで、順調に作成を進めていきました。時間内にキャラクターが弾幕を避け切るゲームのようで、タイムの部分以外はほとんど完成まで持っていくことができていました。ですので、次回には完成へと持っていくことができると思います。', null, '時間帯: その他
タイピング: 正確に打つことができていました。
盛り上がり: ゲームの概要をしっかりと定めることができていたので、制作の際にもやりたいことをしっかりと作ることが出来ていました。'),
  ('0c669351-0b29-5a23-9fe8-5ef753db4989', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-24', null, null, '通常 / 自由製作day(青)', '前回作成していたシューティングゲームの続きを制作していきました。前回の作成で大部分はできていたので、今回は気になる部分の修正と勝敗判定について作成をしていきました。何をやりたいのかが決まっていたので、つまづくことなく制作を進めていくことが出来ました。あと少し修正箇所が残っているので、次回でしっかりと完成まで持っていけるようにしていきたいです。', null, '時間帯: その他
タイピング: 素早く打つことができていましたが、間違いが多かったので正確に打てると尚良いです。
盛り上がり: 体力表示がはみ出ていたので、座標を工夫して修正することが出来ていた際には、原因をはっきりと導き出すことができていたので喜んでいました。'),
  ('00150460-a9e4-5ce7-95ae-60115bedab72', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-17', '17:30:00', null, '通常 / 基本操作コース０６', 'アルスタジオ内にある部分ごとに分けられた作品とカードの両方を使って学習していきました。作ること自体は楽しめて作れていましたが、お手本通りに作っていくのがイマイチ気に入っていない様子で、アレンジをとてもしたがっていました。進行度としては06_6まで進めることが出来たので、次回完成とアレンジをできれば楽しんで作っていけると思います。', null, '盛り上がり: アレンジのアイディアをどんどん出していて、早く完成できるように頑張っていました。'),
  ('5aaa6ce2-d812-55d2-a900-bf6bf88d7619', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-17', '16:30:00', null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', '今回は、前回で内容を理解していた脱出ゲームを完成させていきました。前回までで内容を理解することができていたので、完成まで持っていくことができていました。本人としてもこの内容でアレンジを作ってみたい様子でしたので、次回作っていければ良いと感じています。', null, '盛り上がり: 問題の理解が前回できていたため、黙々と作っていました。'),
  ('55c70b3d-07d9-5268-a16f-83cf9ae5f9f2', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-17', null, null, '通常 / 自由製作day', '前回はscratchを忘れかけてたことでモチベーションが下がってしまったとのことなので、作り方が分からなくなったら助けるよと声を掛けました。バトルゲームを作っていて、残像や体力ゲージの小技を取り入れたり、キャラを動かしたりすることはできましたが、少し面倒そうな様子を見せていました。途中隣のはるくんと作品を見せ合ってもらいましたが、「はるくんみたいなアクションゲームの方が楽そうだからやっぱり今からそっちを作る」と言い出しました。「バトルゲームはもう半分以上できてるからそれを完成させる方が絶対近いよ」と伝えると納得してくれたようでした。', null, '時間帯: その他
盛り上がり: 作ること自体はやろうとしていますが、できるだけ簡単な方法を探そうとしていました。'),
  ('69324717-5362-5446-83da-d22292fa6ec9', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-17', null, null, '通常 / 自由製作day', '基本的なコードを駆使してマリオ風のゲームの作成を進めていき、ミスした時の演出、次のステージへの移行など面白いゲームに必要な要素がいくつか作れました。しかしジャンプするコードは当たり判定やブロック定義など少しレベルが高く、バグが残ったままだったので一緒に修正したいところです。', null, '時間帯: その他
盛り上がり: 本物のマリオに寄せたいようです'),
  ('b7169a07-4db7-59d9-b170-6ca2458d0778', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-17', null, null, '通常 / 自由製作day', 'ざっくりしたゲーム内容は決まっていたようですが細かい内容を決めるのには迷っていたようだったので、「困っていたら選んだ小技に合うように決めていくといいかもね」と伝えると、製作を進めることができました。弾丸を撃つキャラとそれから逃げるキャラは作れていて、次回続ければ完成できそうです。', '続き', '時間帯: その他
タイピング: 集中してやっていました。
盛り上がり: よく考えながら作っていました'),
  ('e325f850-a42a-55da-91aa-575f7a828f2e', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-17', null, null, '通常 / 追跡ゲームの復習と完成', '追跡ゲームは以前途中までやって終わっていなかったので、前半は以前やったところまでをできるだけノーヒントで、後半は細分化されたものを見せながら進めました。 上下左右の移動など最初の方は、ブロックの置く順番を間違えるなどはありましたがだいたい自力で作ることができました。変数でスコアをつけるのは初めてだったそうですが、軽く説明するとすぐ分かっていました。ゲーム開始時に点数をリセットしないといけないことも自分で気づけていて、基本的な考え方はマスターしました。ゲームは一通り完成しました。', null, '時間帯: その他
タイピング: 楽しくやっていました
盛り上がり: できるだけノーヒントでと伝えたときに「できるかな...?」と多少驚いていましたが、やる気を持って頑張っていました。'),
  ('b99c736b-6580-593e-a25d-9710cb0d7069', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-22', '16:30:00', null, '振替 / 物語を作ろうの復習', '前回の続きから取り組みました。新しくキャラを追加してこういうストーリーにしたいと伝えてくれたので、その流れに沿ってキャラを滑るように動かしたり、背景を途中で変えたりというスキルを復習しました。キャラを移動させたときは旗を押したときに座標を戻さないといけないので、「x座標を～、y座標を～にする」の復習もして、「～秒でx座標を～、y座標を～にする」との使い分けを確認しました。', null, 'タイピング: まだplaygramには慣れない様子ですが頑張っていました
盛り上がり: 考えたストーリーを楽しそうに話してくれました'),
  ('838ceeb5-3625-5560-9cbb-5807f5f28477', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-22', '17:30:00', null, '通常 / 『自由制作DAY』（青） 続き もし発想が行き詰まるようなら、テーマは見た目に持ってこなくてはいけないというわけではないことを少し話してあげられれば…せっかくの自由作成なので、楽しんで取り組んでほしい', '他の人が宇宙から発想してどのような作品を作っているのか（戦闘系のゲーム、スロットなど）を伝えました。授業の前半では作りたいものが決まっていない様子でしたが、最後は完成できました。 迷路に当たったらぶつかって戻るプログラムについては原理を説明しました。懐中電灯のプログラムは自分で少し変更して、大きさが様々に変わるようにしていました！ 使っているプログラムはシンプルですが、仕組みの面白いゲームができたと思います！完成だそうです！！', null, 'タイピング: 集中して取り組めていました。'),
  ('5a336da7-049a-51f8-beef-0e8919071ef5', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-22', '16:30:00', null, '通常 / 『自由制作DAY』（青） 続き ゲームのイメージはできているようなので、なるべく完成を目指して', '魔法のステッキの動きを改変しました。クローンの方法の考え方を見直してｍ向きを統括する親と動くクローンに役割を分担させました。ここまではなんとなく理解できたようです。次に魔法のステッキが左を向いているときはクローンを作成しないようにしました。数字のラインを使って大小関係を説明してプログラムにつなげようと思ったのですが、大小関係の把握が難しかったようです。なんとかプログラムはできました。 最後にHPのプログラムを作成しました。ほぼ自力で作成できていますが、制御と演算が絡むと苦手な様子です。', '次週はクリア画面ができる条件を見直して、画面が切り替わり、ボス(？）を出す予定です。', 'タイピング: 初めてだったそうですが、集中して取り組めていました。'),
  ('4a72ec2d-040b-57ca-b3b3-31dd496194a8', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-22', '17:30:00', null, '振替 / 『自由制作（青）』の続き', 'クローンの原理を説明して、ビームのプログラムを変更しました。「端まで繰り返す」など、普段あまり使わないブロックの使い方は忘れてしまっている様子。一方で、スコアなどの変数はうまくプログラムできていました！クローンしたものが動かすのか、本体を動かすのかによってスクリプトの書き方が変わることを共有しました。 背景のプログラムでは「～まで待つ」を詳しく説明しました。≧≦の演算子を完璧にできていたので褒めたところ「もう5年生ですから」とのことでした。 前半は少し眠そうでしたが、中盤～後半にかけて集中して取り組めていました！すごい！！クリア画面までできているので、完成かと思います。（本人に確認し忘れました）', null, null),
  ('5d9fc395-ae3d-538c-92c5-4e4e3db273bb', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-15', '17:30:00', null, '通常 / 作品を作りながら基礎を身に着ける', '新しく自由製作day(黄)を始めることを勧めましたが、「前回までの作品が終わってないから完成させたい」と強く希望したので作成を続けてもらいました。キャラクターの向きを変えたいとのことだったので角度ブロックを教えると、次に同じブロックを使うときは自分でできていました。アイテムの場所も指定したいとのことでx座標とy座標のブロックも教えると、x座標は横でy座標は縦の位置だということもなんとなくわかったようでした。メッセージは先週から引き続き使っているようですが、不必要なところで使っている場面があったので今回は使わなくていいよと伝えました。ただ、どういうときに使うものなのか理解するのは難しそうでした。', null, 'タイピング: 少しずつ打ち方に慣れてきていました
盛り上がり: 作りたい意欲が前面に出ていて、これが完成したらお母さんにも見せたいと言っていました。'),
  ('34dce29a-11ef-5687-a7a8-7e2846901e2f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-15', '16:30:00', null, '通常 / 自由製作day', '敵を倒すシューティングゲームを作ることにしました。小技は初めてだったので色々見てもらいましたが、放射状に弾を発射するのが使えそうだと言って採用していました。連射でクローンを使う意味もわかったようで、敵が連射で攻撃してくるシーンを作れました。ゲームの構成はよくイメージできたようで、セリフなどもいくつか考えていました。', '続き', 'タイピング: 難しいようでしたが頑張っていました
盛り上がり: ストーリーを考えるのが少し楽しそうでした'),
  ('3469ad0a-741c-57ed-8149-ce06aec3822d', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-20', '17:30:00', null, '通常 / 工夫してオリジナル作品を作る', '先週はオリジナルのアイディアが出なくて少しだれていましたが、今日は気を取り直して、バグの修正からやろうとしていました。 クローンを使った弾丸と、弾丸を撃つスプライトの動きのタイムラグが気になっていたようだったので、ひたすら条件分岐をつなげたコードやメッセージを送るタイミングなどに着目させました。複数の要素をすべてつなげて一つのコードにする弊害はなんとなくわかったようですが、それをどう分けてよいのか悩んでいたので、シューティングゲームhttps://app.arstudio.fun/contents/1889などを参考に見せたところ、頑張ってコードを書きかえていました。 「クローンを削除する」ブロックをまったく使っていなかったので、必要性の説明をしました。 ステージを変える課題のために考えたストーリーが壮大になってきて、少し得意げにしていました。', '背景チェンジのためのストーリーを完成させる', '盛り上がり: 少し甘えたいモードになってはいましたが、課題を与えるとその間は自走ができていました。ストーリーが面白くなってきたことをお父さんと一緒にほめると、とても嬉しそうにしていました。'),
  ('144ba8ea-2ed9-5c3d-b89f-47d4236f5829', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-20', null, null, '通常 / 自由製作続き', '前回伝えたブロックの使い方を早速活用できていてよかったです。リストに攻撃パターンをいれ、変数と乱数も使って攻撃パターンを制御していました。プログラムも1回目攻撃時と2回目攻撃時で区別されていて、丁寧で良いなと感じました。最後に完成できました。 変数とクローンを使うといくつかの文字を一つのスプライトで表現できる方法があるのですが、知らないようです。ひいろくんだったらいろいろ活用できるように感じたので、機会があれば共有したいです。（きょうりゅうとタイピングゲームで使った方法）', null, '時間帯: その他'),
  ('470dbdd4-054c-5187-935a-098061585645', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-20', '17:30:00', null, '通常 / 自由製作', 'スロットのプログラムを作りたかったそうですが、テーマに合わず悩んでいましたが、スロットに至るまでのストーリーを考えて宇宙のスロットゲームを作ることになりました。（ストーリーは時間に余裕があれば作成するそうです） スロットのプログラムに苦戦するかなと思いましたが、メッセージや変数を使って自分で解決できていました。ボタンを押すリアリティを出すためにサイズを変えるプログラムも作っていました。 いつもは他のことに気が散りがちですが、今日はとても集中して取り組めていました。次週続きをする予定です。', null, 'タイピング: 集中して取り組めていました。'),
  ('cda75a0b-fcf7-56cb-98b2-047ecb358f5f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-20', '16:30:00', null, '振替 / 自由製作', '小技もよくみて選べていました。紙に書くのも苦手ではなく、いくつか質問はしましたがとても丁寧に書けていました。以前作ったプログラムをアレンジして作成するようです。丁寧に取り組めていました。制限時間を作る方針だそうです。次週はタイマーを設定していく予定です。', null, 'タイピング: 集中して取り組めていました。'),
  ('01636ac5-71e8-5cdd-bd7e-dd33efb47278', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-20', '16:30:00', null, '通常 / 自由製作続き', '前回やったことを確認しました。HPのバーについて少しまだ理解が足りていない印象です。一緒にプログラムを確認して変数の役割について共有しました。 ステージがかわるプログラムは大枠は自分でできていましたが、細かいタイミングの管理は難しかったようです。制御のプログラムの使い方が苦手なようです。 定義のプログラムを使ったりしました。2回目に出てくるカバのプログラムもおおよそできているので、最後に制御の部分を整理するとあと30分くらいで完成するかな？と思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('63252e2a-75d4-5929-82ab-286c10dc1d32', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-20', '17:30:00', null, '通常 / 工夫してオリジナル作品を作る', '今日作成する箇所のイメージを持って来室したようで、スムーズに作成の続きに入っていました。 クイズ問題をネット上からとってきて、テキストファイルからリストへの読み込みを活用できていました。 クイズ部分が完成したので、次はゲーム部分の作成に入るところで授業終了でした。', 'アクションゲーム部分？を作成して完成を目指す', '盛り上がり: クイズの部分を、ただ問題が表示されるだけではなく動きのある可愛いステージにできて、楽しそうでした。続きのアイディアもあるようで、もう少し作成を続けたいとのことでした。'),
  ('0aa27f27-dc2a-5379-8b6e-fc720cd553a0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-02-19', '16:30:00', null, '通常 / Scratchの基本的なブロックの使い方を学ぼう', '名前を動かそうをやってもらおうと思ったのですが。その前に、アル君が上下左右に動くブロックの基本をやってもらいました。 年長さんなのでマウスを使わずに画面タッチでいいよと何度も言ったのですが。マウスをどうしても使いたいようで。マウスの使い方で教えるのに苦労しました。角度と数字を入力するということをマウスを使うとなかなかうまくいかず💦 それでも、マウスに固執しておりかなり疲れてしまったようです。 名前を動かそうの「色が変わること」について。コスチュームで描く方に気持ちがいきました。ここも手で描く方がよかったのですが、マウスで絵を描こうとしたため、重い通りにいかないものばかりになってしまいました。 初回でつまらなくしては良くないと思い。動物好きなとのことなので、「動物園をつくろう！」ということで、好きなスプライトをたくさん配置させて終わりました。', 'マウスの件をお母様にお伝えすると、家のドラえもんパソコンでマウスの練習をしてきます、とのことでした。 が、しばらくは、最初にマウスの練習用ゲームをやるといいかと思います。 次回、「動物園をつくろう」ということで、セットしたスプライトを動かすコードをいくつかやってみようと思います ＝名前を動かそう⇒動物を動かそうに切り替えです。', 'タイピング: 割愛
盛り上がり: 最初に入室する時だけとまどっていましたが、すぐに画面に夢中になりました。'),
  ('b06f03a8-2dc8-5090-b9ba-71da85abf1eb', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-02-17', null, null, '通常 / 自由制作（黄色）を活用し、基本操作06のメッセージと座標で移動のスキルを確認したい', '最初に自由制作の条件などを説明。基本操作コース06で使った技を使うというところで、復習だよと思い出してもらったが。ほとんど覚えていなかったで。「じゃあ、06を最初から作ろうか」となりました。 しかし、最初の会話を「何秒待つ」でコントロールするところに大苦戦しました。2人（くまとへーげる）の登場人物が、同じタイミングで「２秒待つ」と「●●●と言う」いうコードを入れており。全部が同時にスタートしてしまいました。 図を書いて説明したものの、きちんと理解できたいない様子？でした。改めて、紙に丁寧にくまとへーげるのやりとりを交互に書いて説明すると良いかもです。', '次回、自由制作からは離れて「基本操作コース06」をマスターすることを目標にしたいと思います。🌟注意🌟基本操作コース06は、カードと画面の見本が違うので、間違えて使うと子供が逆に混乱します。再度説明しますのでよろしくです。', '時間帯: その他
タイピング: 見逃しました
盛り上がり: 録音機能を初めて使ったようですが。教室のザワザワの音が録音されて、それを「宇宙人が話しているみたくする？」と適当な文字を入力すると。今日一番、面白そうにキーボードを適当にうって入力するのを楽しんでいました。'),
  ('84886a53-6cbe-52f8-9ca7-2646eb094438', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-02-17', null, null, '通常 / 自由制作（黄色低学年）', '地球が隕石にぶつかって爆発する。それをネコが助ける（？予定か？このあたりはやや不明）ゲームを制作。前回は、各スプライトの配置とネコの動き、地球が左上から右下へ移動する動きまで完成。 前回の続きで、地球が移動するところがイマイチだったので「基本操作コースの「滑らかに動かす」」を復習し座標指定を活用することになった。移動までは上手くできたが。 ①誰が誰にあたるとどうなるかが、ごっちゃになってしまった。地球と隕石がどっちがどっちか、わからなくなったようだ ②地球がぶつかって爆発するコスチュームを作り出したら面白くなったのか、後半はずっとコスチューム作りでした。画像制作のメニューを覚えるのにいい機会だったので、そのままコスチューム制作で終わりました。', '次回、続きから。 その際に、「誰が誰にあたるとどうなるのか？」を改めて整理させてください。', '時間帯: その他
タイピング: 割愛
盛り上がり: 地球が爆発というか、崩れるコスチュームつくりで、なかなかアイデア創発！という感じでした。爆発か？火花を丁寧に赤い線で描いたり工夫が楽しかったようです。'),
  ('a7858481-d4f6-54dd-a814-5258e0da27c1', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-19', '17:30:00', null, '通常 / 自由製作day', '自由製作で宇宙戦艦内の会話劇から始まりました。前回からかなり空いたので、すこし、メッセージのやり方や演算の作り方など最初は忘れていましたが、きっかけを与えればその後大丈夫でした。ステージを何回も行き来できるようにすることに悩み、背景のの条件の違いを質問で分からせながら作っていきました。', null, 'タイピング: 何回かチャレンジしていました。
盛り上がり: 素材画像は少しリアルすぎてあまり気が向いていませんでした。'),
  ('4cf56024-de1f-506c-ae48-f086efc84cdb', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-19', '17:30:00', null, '通常 / 自由製作day', '終始漢検勉強疲れでおねむでした。アイデアは弾幕で作ろうとしたが、カックンが多く少し目を覚ましてあげると、直後の集中力手の回しは良いですが、持続力は今日はあまりなかったです。考えはたまっていると思うので、次回集中してできればいいと思います。', null, 'タイピング: 100点届かずでした'),
  ('d3649592-8848-5972-80f7-dbcee45934e0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-19', '16:30:00', null, '通常 / 自由製作day', '今回が初回だったので、まずは小技を選んでもらえました。耐力ゲージを選んだが、ペンについてわからないことがあれば、すぐに聞いてくれたので、とても助かったです。自分の耐力ゲージの説明も変数で作動していることも一発で理解してくれました。少し手を放してしまったが、構想を聞くと、凝ったものができそうだったので、次回は紙に書くことを忘れてしまったので、書いてからやってください', null, 'タイピング: スコアも上がってきました。
盛り上がり: 地球を守る仕組みおもしろそう'),
  ('bbe875b0-8268-5174-bd48-d0eb47cd1ac2', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-19', '16:30:00', null, '振替 / 自由製作day', '今週はダメージを作ることでした。体力を変数で作るとき、新しく変数を作れるが、変数の値をどうやって変えるか質問を揺さぶってみました。だが、スコア作った時を何のコードを作ったか思い出させてみたが、二択を外していました。覚えてほしいです。ほかに、幽霊の効果で遊んでいたので、ダメージを受けるごとにその効果も付けることを提案したら、前向きに取り組む姿勢が見えました。一緒に作って、見ごたえあるものになりました。', null, 'タイピング: 進んでいました。'),
  ('5e036ec9-a8b3-5957-8c4a-1e00f834bcf1', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-19', '16:30:00', null, '振替 / 自由製作day だるまさんがころんだ細分化からの作成', '前回でほぼ完成していたので、すこし背景のバリエーション増えてiして完成していました。 自由製作前にだるまさんがころんだの細分化したものがあったので、その作成をしました。 途中、あまり目をつけられていなかったが、ほとんど思い悩むことなく自力でゲームの形になっていました。負け条件の重ね合わせが上手く作れなくて悩んでそこは一緒に向きの演算式を使って考えました。見本物とはコードはかなり異なるが、動きは再現できていたので、コードに落とし込む力はついていると思います。', null, 'タイピング: スコアは上がっています
盛り上がり: だるまさんが雪だるま仕様になっていて冬でした。'),
  ('f2cb6e7b-3afb-5502-891a-eb697e009d7d', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-17', null, null, '通常 / 自由製作day', '最初に、ビームが連打式に直しました。ある程度使うコードを予想しながらやって一発で選べていたのでよかってです。やりたいことがごちゃごちゃしていたので、整理しました。聞いてみると、敵の体力が3以下になったら敵のビームの打つ間隔を短くなり、背景も変えると支離滅裂ではなく、筋は通っていました。要望のために、何秒待つに変数を入れて制御することや敵とビームの向きのそろえ方は新しく教えましたが、それを動かす条件式などの演算は自力でスムーズに作れていました。体力制も程よいバランス調整もお困っていました。 なにか1つ新しいコードが作り終わると、試しプレイで遊びすぎちゃって、次やることを見失うタイプに感じます。考えていることは芯が通っているので、たびたび気づかせるために、設計書は書くことがよりよくなると思います。', '続き', '時間帯: その他
タイピング: 順調にストーリーが進められていました
盛り上がり: 敵のビームが4法に向くようになったらどっぷりはまってしまいました。'),
  ('2ab09959-21d3-5ad9-97f4-f71d45062b79', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-17', null, null, '通常 / 自由製作day', '犬の動きに残像をつけてよりダイナミックな卵取りゲームになりました。残像のコードを利用する際も特に迷うことなく理解はできていました。その後も順調に作り続け、結のゲームクリアまで制作できて、完成できました。', null, '時間帯: その他
タイピング: 進んでいました'),
  ('8cd28592-7f62-55a0-8587-690d5d417f1c', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-17', null, null, '通常 / 自由作成day', '先週からの続きで、体力バーを主に作りました。ただ写し替えただけではうまく作動しなくて、そのバグに悩まされていました。途中、scratchでゲームに逃げちゃうことはあったが、めげずにほかのスプライトでのペンツールがかみ合ってなくてバグであることを自力で見つけ出せていました。変数によるHPバーの長さも自分で調整できていて、よかったです。「どこかへ行く」とクローンの組み合わせでダミーの分身の表現ができていて、ゲーム性の高いものになっていました。クローン体は1度撃てば消えることになっていて、面白そうです。', null, '時間帯: その他
タイピング: お得に届かずでした
盛り上がり: バグからの解放でうきうきで分身のコードを作れていました。'),
  ('e66b8f39-ab03-5580-9292-6798bf671d6d', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-16', '17:30:00', null, '通常 / 自由制作DAY（青）', '作っているゲームの内容としては、東方Projectを元とした弾幕シューティングを作っているようでした。小技の弾幕を最大限利用して作品を作っていきたいようだったので、キャラクターの体力や判定など、様々なことにこだわって作っていました。自機と敵の配置から鹿k理と作っていたようなので、作品としてはかなりレベルの高いものが出来上がっていくのではないかと感じています。こだわりすぎて時間がなくなってしまう点にだけ注意が必要だと感じます。', null, '盛り上がり: コンセプトがはっきりとしているので、作っていく手を止めることなく順調に作り上げていました。'),
  ('5b35bfca-3c1b-5f22-a08b-ec4646fc4161', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-16', '17:30:00', null, '通常 / 自由制作DAY（青）', '作品内容としては、脱出ゲームでキャラクターがボタンを押して出口を開けていくというものでした。今日の進捗では障害物や敵キャラクターを配置することが出来ていないようで、何を配置するかを熟考している様子でした。本人の考えとしては、さらに難易度の高いものにしていきたい様子だったので、次回の制作で自分のやりたいことを作品へとしっかり入れることができると感じています。', null, '盛り上がり: ボタンのコードを試行錯誤していたので、出来てからはスラスラと作ることが出来ていました。'),
  ('6da090e3-1dd6-5b14-82e4-25efad3cbd82', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-16', '17:30:00', null, '通常 / 自由制作DAY（青）', '作成していた内容としては、迷路のようなコースを使った対戦型の鬼ごっこでした。PvPのゲームを作っているので、キャラクターやステージの調整に苦戦しているようでしたが、上手く決めて作品に入れることが出来ていたようでした。今回で基礎はほとんど完成しているようでしたので、次回の制作でさらに要素を追加していければより内容の濃い作品を作り上げることが出来そうです。', null, '盛り上がり: 対人戦のゲームなので、細かい箇所の調整を試行錯誤しながら行っていました。'),
  ('399dff88-19f8-56a3-9817-c8cfbe193603', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-16', '18:40:00', null, '通常 / 基本操作コース06 物語～を使った『黄色Ver』', '一旦上記の感じで話をつたえてみて追いかけっこ（おにごっこ）で作成することに。 背景は、常に変わるようにしてみたり、ちゃんと猫ちゃんが歩くとレインボーのスタンプを打ちながら歩くという動作を加えたりしていた。 途中小技〜の話をして、どれでも小技は加えられるけど、２人の関係性がどうなるかによってどれになるか？を話し合って決めてみました。 弾幕〜のもので、追いかけられている人が鬼に向かって発射して簡単に捕まらないように工夫をしていたので、本人的には結末が見えた感じで最後まで集中して行っていました。', '今日の続き', 'タイピング: なし
盛り上がり: 途中まではとてもモヤモヤしていた様子ではありましたが、自分なりにどう結末をつけるのか？を話し合いながら決められたこと、弾幕のコードを見ながらかけたことがとても満足していたようでした'),
  ('c49ba3ba-6f98-5c33-b002-509f6c43e17b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-16', '18:40:00', null, '振替 / 自由制作DAY（青）', '製作中は黙々と作っていました。本人の中でもやりたいことがしっかりと決まっているわけではなかったようで、進行度はイマイチな状況でした。ですが、内容をしっかりと固めて作っていきたいようだったので、完成品としてはしっかりとしたものを作り上げたいようでした。次回の作成で完成まで持っていきたい様子でしたので、頑張って作っていきたいようでした。', null, '盛り上がり: 作品としての大枠は決まっていたようなので、次回はペースアップして作っていきたいようでした。'),
  ('e4f37e5d-bd38-5906-9f0f-4ad30010e89a', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '061fafe3-34fc-52d0-a03e-0a05cae3a289', '2024-02-16', '16:30:00', null, '通常 / 小技&ステージ変化 『青色Ver』', '自分で作品を作ることに関してはあまり抵抗はないものの、最初は何を作ろうか悩んでいた様子ではありました＞小技も何を使おうかは決まっていない感じ。 ただ今回の条件（スプライトのコスチュームが変化するを加えて）はきちんと自分でやろうとしていました。 作品は宇宙船がパワーがクリックで溜まって、発射するという感じでそこからの展開へと持って行こうとしていたので、宇宙船＋バトル系をイメージ＞となると弾が発射する小技を使うのか？ メッセージの部分も心配していた通り、受け取る側の部分がどうしてもごちゃごちゃになりそうだったので、メモしてねとつたえたところ素直に書いていたので、自分でも自覚があるみたい。', '今日の続き', 'タイピング: ひらがな 上級をやっていましたが、ほぼ単語のような感じだったので楽そうでした、
盛り上がり: 今まで使っていたコード、「〜までないまで待つ」のコードを思い出そうとして、惜しいところまで作っていたのですがどうしても思い出せない！と言っていた部分は、自分でわかっているコードの引き出しがキチンとストックされているなと思いました。'),
  ('5219c982-2880-57b0-b5a8-6b2444746ca4', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-16', '16:30:00', null, '通常 / 自由制作DAY（青）', '自由制作の内容としては、上から降ってくるおにぎりを避けるアクションゲームのようでした。完成度としては６割ほどでしたので、次回完成まで持っていけると思います。本人はここからさらに要素を追加していきたいようでしたので、よりボリュームのある作品に仕上がってくると思います。小技は残像を使っていて、キャラクターの犬に適用されていたので、躍動感が出ているように見えます。', null, 'タイピング: 素早く打つことができていました。
盛り上がり: やりたいことがどんどん湧いてくるようだったので作品制作を順調に出来ました。'),
  ('6e121633-660f-5ca3-a004-bc66e03086c6', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-10', null, null, '通常 / 自由製作day', '使う小技について迷っていましたが、体力ゲージの技を見ると面白く感じたようで使うことにしました。戦闘機が攻撃しあうゲームにして、まずは主人公の移動とビーム発射を作りました。ビームはクローンを活用してできていました。体力ゲージの作成にも取り掛かりましたが、どういう風にペンを使っているのかよくわからなかったようで、軽く説明しました。', '続き', '時間帯: その他
タイピング: 相変わらずクリア失敗が続いていましたが、めげずに頑張っていました。
盛り上がり: 体力ゲージは少し変わったコードですが、それ以外の普通のコードはすらすらと作れるようになってきていると思います。'),
  ('e91b1f81-84dc-51fe-a2b0-49f5666ffef7', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-16', null, null, '通常 / 自由製作day(青)', '小技を見ていくと背景スクロールに興味を持ちました。少し難しめだと伝えましたが大丈夫とのことで、使うことに決めました。スクロールのコードは写経に近い感じで写しましたが、原理をできるだけ理解してもらうべくいくつか問いかけをしました。背景のクローンを作り、右側に新しいものを置いて左側に流していくという仕組みについてイメージはつかめたようでした。ドラゴンと爆弾を登場させて、ゲームの世界観はできてきました。', '続き', '時間帯: その他
タイピング: 切り替えが遅めでしたが少しだけ頑張りました。
盛り上がり: スクロールが使えることが楽しいようでした'),
  ('440309ae-a398-58d0-a501-c2c6f6bc7c24', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-16', '17:30:00', null, '通常 / ・基本操作コース06 物語～を使った『黄色Ver』', '全体的にメッセージの送り合い自体はよく理解している感じ。 やりたい動きがきちんとメッセージの受け取りの後に出来上がっていたのでとても良かったと思う。 キャラクターが宇宙船にのるというコンセプトの部分が、「〜秒でここの座標に動く」というコードがすぐ出てくるといいなと思ったが、ヒントを出した時に多少「あぁやったかも」みたいな雰囲気になったので、本人的には満足していた感じ。 最後宇宙船から火がでるような感じにしておきたかったが、演算を使うことになる部分だったので、ひとまず宇宙船自体に火のエンジンを書いて、コスチュームが変身するほうが発車した後の動きがイマイチにならないよ〜と伝えました。', '今日の続き', 'タイピング: なし
盛り上がり: 自分がやってみたいこと＞概ね実現できることに対してとても満足していた様子でした！'),
  ('69b4a0b6-baac-5db6-b749-6589e3b50bcc', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-16', '17:30:00', null, '通常 / 基本操作コース06 物語～を使った『黄色Ver』', '最初にどのキャラクターを使うか？で多少悩む時間が長ったのでゲームの制作に時間が割けなかったが、自分なりにコスチュームを変化させたりし、スプライトのコスチュームを作成することにはとてもなれた感じがする。 また「メッセージを送り合う」という部分は覚えていたようだったので、実際につかってどう展開しようか？を悩んでいた様子だった。 全体的にはタイピングに対して苦手意識があるので、ココアをもう少し深めるといいとおもうが、短文を打つ練習をするのもいいかも。', '今日の続き', 'タイピング: なし
盛り上がり: 自分なりにコスチュームを作ること、メッセージを送ることが覚えていたこと、がとても嬉しかった様子＞１っ個でもできた！という成功体験がとても嬉しいみたいでした。'),
  ('21b2a73c-a3ca-5e14-95a1-d918404a9ae6', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-10', null, null, '通常 / 自由製作day', '宇宙服を着た犬が卵を集めるゲームを作ることにしました。場面転換のタイミングは、一定の点数を取ったときと決めました。プレイヤーの上下左右の動きは難なくできて、卵の動きについてはクローンをいくつも作り、色々な場所に移動させることができました。', '続き', '時間帯: その他
タイピング: 集中していました
盛り上がり: 全体的に順調に作れていたと思います。'),
  ('567978d2-7b46-5cce-ad2a-c7725c3fbbc0', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-10', null, null, '通常 / 自由製作day', '少し前に作った「チーズを探せ」の延長として自由製作dayに取り組みました。迷路の形はそのまま使い、戦闘機がビームを撃ちあうゲームにしたいと言っていました。自由製作の条件などを説明しましたがそのまま作り始めてしまいそうだったので、「まずは見通しを立てると作りやすいよ」などと伝えて一緒に紙を書きました。キャラクターの変身をさせる部分でアイデアが出ずに考えていましたが、ビームを10回打ち返したら敵が変身して強くなることに決めました。その後ビームを撃てるようにコードを作りましたが、ビームのクローンを生成したり、壁に当たったらクローンを削除したりと発展的な内容を使えていました。', '続き', '時間帯: その他
タイピング: 打つのが速くなってきました
盛り上がり: 思い浮かんだものを作るだけでなく、しっかり考える練習になったかと思います。'),
  ('8c2387b1-2036-5717-8823-601a6e6699a5', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-10', null, null, '通常 / 自由製作day', '話を聞くと、マリオのようなアクションゲームで床が上下に移動していくものを作りたいと言っていて、方向性を早めに決めて書けていました。地面に着地しているかの判定はほぼ初めてで自力ではきつそうだったので、「アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】」のコードを参考にやってもらいました。一番基礎となっている考え方は「足の色が地面の色に触れていたら着地している」だということを伝えると、自分の作っているゲームにそれを活用できました。作りたいものはイメージできているようですが、作り方に迷う場面が何度かありました。', '続き', '時間帯: その他'),
  ('819a673b-b22c-5a9b-a0ee-8bc48940a6d9', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '17:30:00', null, '通常 / メッセージの活用をマスターする', 'そうすけくんの癇癪を隣で聞きながらも、しっかりと自分の作業を頑張っていました。 物語を作るのがとても楽しそうで、登場人物の細かいポーズや姿勢にもこだわって、ゲームのオープニングのようなストーリーを楽しんで作成できていました。 作成していくうちにイメージが広がってきたようで、登場人物を増やして盛り上がっていました。 メッセージによって合図を送るというのは何となくわかっているようですが、基本的なメッセージ名が登場人物の動きやセリフそのままになっているので、もっとシンプルなわかりやすいメッセージにすることを促しても良いかもしれません。', 'この作品を楽しそうに作成している途中なので、一斉に自由制作に入るとしたら、この作品を宇宙テーマにするか、自由作成後にこちらに戻るのか、本人が納得するように教材を指定してやってください', '盛り上がり: 物語をふくらませるのがとにかく楽しそうで、生き生きと作成していました。'),
  ('4fa8df44-7d7d-5785-8856-9c067cd3374e', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '17:30:00', null, '通常 / メッセージを活用してストーリーを進める', '前半は、リョウ先生の指導で柚月くんと一緒に授業を受けていましたが、自分のやりたいことがうまく言語化して先生に伝えられなかったのか、普段慣れている先生が良かったのか、自分だけに向き合って話を聞いてほしかったのか、「ゆき先生に来てほしい」と癇癪をおこしかけていました。 隣に腰をおろして、話を聞く姿勢を見せただけで少し落ち着いたので、ゆき先生には後で見てもらうから、それまでに「ここまでできた」と言えるように一緒に進めてみようと声をかけました。 画面の端から鳥がとんできて魔女の肩にとまり、その後、羽を閉じた状態にしたい、ということを言いたかったようですが、順序が不明瞭でこちらが聞き返すのが気に入らなかったようで、何度か癇癪しそうになるのを落ち着かせて話を最後まで聞いてから、「一つずつ進めてみよう」と声をかけ、口頭で一緒に細分化をしていきました。 このあたりで少し気分が上向いてきたようで、まずは「画面の端に登場させる」⇒「ここに出すことができるか？」と発問し、自分で座標を指定する、「魔女の肩まで動くのはどうすればよいか」と発問して、〇秒で指定の座標に動かす、などと、手順を細かくふむことで、少しずつやりたかったことが完成していくのがわかったようでした。 この日は鳥の動きを作成するところまでしかできませんでしたが、最後は満足したようで、お母さんに得意そうに見せていました。', null, '盛り上がり: やりたいことを細分化することで、自力でできることに気が付いてからは、機嫌よく熱心に作成していました。'),
  ('13914ce1-ca10-5cd1-932e-ea1ba902a091', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '16:30:00', null, '振替 / 基本操作コース07_ピンポンゲーム（細分化されたもの）', '病み上がりできたせいか、とにかく具合が悪そうで、机の前に座っても目をつむったり机に伏せたりしていました。 いつもは興味を示すゲームや飴にもほぼ無反応だったため、開始早々にお母さんに連絡をして、お迎えに来てもらって早退しました。', null, null),
  ('0a591edf-1566-51d0-bbdc-4d4993cb5d81', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '16:30:00', null, '通常 / コードの復習をしながら、ゲームを完成させる', '未完成のところ、修正するべきところもよく覚えていて、自分で説明しながら作業を進めることができていました。 変数に演算式がまざるところなどは、式の意味がわからずに迷うこともありましたが、基本素直に作成するので動きがおかしくなることもなく、自分の今のレベルなりに納得しているようでした。', null, '盛り上がり: 次にやるべきことをしっかり自分で見つけて自己解決するというルーティンができていました。最後まで集中して楽しそうに作成できました！'),
  ('51a64d9d-8d73-515f-b2d2-23c975875202', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-15', '16:30:00', null, '通常 / 自由製作day', '基本操作コース06(物語)の内容を使うのが条件でしたが、ずいぶん前にやったため覚えていなかったので復習しました。メッセージを使ってキャラクターを順番にしゃべらせることを思い出しました。 キャラクターや変身については話し合うとアイデアが出たので、紙に書いてから製作を始めました。まずは矢印キーで動かすのをやり、少しうろ覚えではありましたが以前の記憶をたどって作れました。次に、敵が追いかけてくるようにしたいがやり方が分からなそうだったので、「～へ行く」を使って作る方法を伝えました。', '続き', 'タイピング: 強敵に苦戦していましたが倒したときは嬉しそうでした
盛り上がり: アイデアを出すときにどうしようか少し迷っていましたが、作成意欲はありそうです'),
  ('de19e671-925d-5453-93f0-d4e1821ca866', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-15', '16:30:00', null, '通常 / 計画をたてて自由制作に取り組む', '計画を立てるのは苦手と言いつつ、こちらの説明は素直に聞いて紙にも書いていました。頭の中のイメージを文章化して書くのは苦手そうですが、言葉には出ているので、少しずつ慣れていきたいところです。 テーマが絞られると発想がしづらくなって苦手と言っていましたが、その中で少しでも自分の得意な方向に持っていこうと頑張ってくれていました。 前回までのプラットフォーマーで横スクロールを作成しましたが、まだ自分で一から作るほどは理解していない、と自己申告してくれました。 昨年のコンテスト作品での場面転換は楽しかったので、今回もそういう感じでいきたい、など、イメージはわいてきているようでした。 壁にあたったら跳ね返るのを少し忘れていたようなので、チーズを探せのゲームを見せて思い出させました。', '作成続き', 'タイピング: タイピング記録用紙が補充できたので満足そうでした
盛り上がり: そうちゃんとの会話に入ってきたり、こたろうくんの作品を見に行ったりと、周りの子にもだいぶ馴染みながらがんばっていました。 口では「これが苦手」などと言いつつも、それを自分が楽しめるように工夫して作成を進めているところが良かったと思います。'),
  ('20344109-77cd-517c-9675-9ce41f13f6ee', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-15', '16:30:00', null, '通常 / 『自由制作DAY』（黄） 今自分が何を作成しているのか見失いがちなので、計画を話し合って、プリントに記述（これは先生でも構わないので）してから作成に入るとよいかも。', 'とくに何か作りたいものがなかったのですが、宇宙について連想していくうちにアイデアが出てきたようです。とうがらしのようなスプライトがロケットから逃げるプログラムになりました。背景に月を作ったり、応援隊をいれたりして工夫できていました。基本的な動きはプログラムできましたが、ダメージのプログラム、変身のプログラムがまだなので次週作っていく予定です。 自動ドアにぶつかった経験から『自動』が苦手なようです。', null, 'タイピング: うまく進めず不満そうでした。'),
  ('146bb108-1883-585c-abae-635af9d0b748', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-15', '16:30:00', null, '通常 / 『自由制作DAY』（青） ステージを変えるためのメッセージを覚えているか確認してから小技を見せて。小技を選ぶのに時間がかかりすぎないように、適宜声掛けをして先を促して。', '小技はすぐに決まりました。ゲームではなくアニメーションを作ることになりました。スペースキーを何回か押したら爆発のスプライトが表示されるようにしました。変数を使うことをアドバイスしただけで全て自力で作成できました。長押しができないようなプログラムも伝えました。 プログラムは完成しました。来週は特に希望はないようです。', null, 'タイピング: 集中して取り組めました。'),
  ('96f4aefb-864f-5767-8df4-df8b24d608e8', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-15', '17:30:00', null, '通常 / 『自由制作DAY』（青） 承太郎くんと話しながらで構わないので、自由な発想で作ってほしい。 計画的に仕上げることを目標に、今日を含めて2回での完成を目指して。', 'これから作りたいものを比較的細かく（条件など）紙に書くことができていました。小技もすぐに決まりました。 体力ゲージのプログラムは座標のコントロールが少し複雑でしたが、整理して取り組めていました。 全体のおおよそ1/4のステージができたようです。来週に完成させるのが難しそうですが、頑張って取り組むように伝えました。', null, 'タイピング: 集中して取り組めていました。'),
  ('abeeacd1-94c6-591a-9d66-b121d06fa4f0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-15', '17:30:00', null, '通常 / 『自由制作DAY』（青） 上級者ならではの発想が活かして作ってほしいところ。 少ない条件から、どれだけ発注元の希望に沿いつつ相手を満足させられるような作品に仕上げて提供できるか、ゲームクリエイターとしての立場での作成を経験することが目的ということを伝えて', 'なかなかアイデアが思い浮かばなくて紙を描くのに苦労していました。ゲームの内容が分からないとこちらがGOサインを出すのが難しいことを説明すると重要性を理解してくれたようです。弾幕のプログラムの中身を変えて自分なりのものを作ろうとしていました。プログラムの中身をしっかり把握できていてよいです！！（すこし体調も悪かったようです） 時間的に次週完成させるのは難しいようですが、頑張ってくれるそうです。', null, null),
  ('47d09221-d953-5ba6-bf5e-e74067242273', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2024-02-15', '17:30:00', null, '休み（未対象）', null, null, null),
  ('474ade8c-4c10-5804-ab2e-acbca5253196', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-15', '17:30:00', null, '通常 / 『自由制作DAY』（青） ほぼ1か月ぶりなので、小技を確認しながらコードを思いださせて、その後作成に入るようかな、と。', '作りたいものが右往左往しましたが、ロケットが動いてビームを出し、星を射抜くゲームに落ち着きました。 ロケットのプログラムは残像のプログラムを参考に作っていました。うまくいかなかったときも、あやしいプログラムの部分を自分で見つけて修正できていました。 星が落ちてくるときに使った条件分岐では、一度手を止めて不等号を確認できていたので良かったです。その後もほぼ自力で作れていました ！', null, '盛り上がり: 次週はビームの動き、得点（HP?）などをプログラムしていく予定です。'),
  ('ddc971a5-3dfd-5e81-a261-915e1672e7bf', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, null, '2024-02-13', '17:30:00', null, '休み（未対象）', null, null, null),
  ('18024e82-5e01-560c-a0f8-4040d7408401', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2024-02-13', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('f279c153-747f-57f6-b895-ff0049fb77a1', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2024-02-13', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('5d5cdd27-ba1e-53e8-a48c-50aaab6d7123', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-13', '17:30:00', null, '通常 / 『自由制作DAY』（青）', '作品のアイディアがなかなか決まっていないようで、手がイマイチ進みませんでした。キャラクターのデザインに関してはかなり凝って作っていたようで、その部分に関しては本人も納得するようなものとなっているようでした。コードについてはほとんど手をつけていない様子でしたので、次回からの制作でしっかりと作っていければ良いと感じています。集中力がイマイチ続いていない様子も見受けられたので、その部分に関しても改善していく必要があると感じました。', null, 'タイピング: 黙々と取り組んでいました。
盛り上がり: キャラクターデザインをしっかりと完成させることが出来ていたので、そこで力が抜けている様子でした。'),
  ('1d27f878-eedc-59e6-b6f1-9dadc6d54312', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-13', '16:30:00', null, '通常 / 教室に慣れる、Scratch の基本操作に慣れる', 'チュートリアルの説明は熱心に聴くことができていました。 マウスの操作に慣れなくて、気が付くと人差し指が右ボタンの位置にきていたり、クリックの際に手がぶれてしまったりすることも多かったですが、辛抱強くマウスを使おうとしている姿勢は良かったです。 デジタル水族館は楽しそうに完成させていました。課題が終わると満足するタイプのようで、アレンジを加える提案はあっさり却下して、「新しいものをやりたい」とのことでした。 デジタル水族館を作成しながら、基本操作コースの2か所にスタンプを押し、満足そうにしていました。 宇宙テーマの自由作成では、スプライトをたくさん出して、今日覚えた「旗が押されたとき」「ずっと」「〇秒でとこかの場所へ行く」をひたすら作成して喜んでいました。自機にあたるロケットは自分で動かせるように提案しましたが、矢印キーはマウスとの併用が難しそうだから嫌だとのこと、マウスの方に向ける、マウスへ行く、双方のブロックも使ってみましたが、マウスで緑の旗を押したりするときにスプライトが付いてくるのがだんだん気に障ってきたようで、ちょっと切れかけて「ついてこないで！」となっていました。勇作君の嫌な気持ちをきちんと聞いてから、プログラムはいくらでも好きなように直せるから、そういうときは怒らないで、落ち着いて作りなおそうと説明をし、納得したようでした。 スプライトを動かすのもすべて、自分が覚えた「旗が押されたとき」「ずっと」「〇秒でとこかの場所へ行く」で作りたがったので、動きを少しでも変えるために数値を変えることを教えました。 宇宙がテーマの作品がとりあえず勇作君にとって完成するところまでできたので、ほぞんを教え、残り10分間はアルスタジオでの検索と遊び方を教えました。 シューティングゲームとスイカゲームにハマっていました。', null, '盛り上がり: 基本的には楽しそうに、熱心に作成できていました。 途中、幼稚園での豆まきの話をしてから、緊張が少しとけたようで、最後のゲームのときはとても盛り上がっていました。'),
  ('a1221f73-6366-5c33-93eb-923ebe360b80', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-13', null, null, '通常 / 『自由制作DAY』（青）の完成 ・陽色くんならではの発想が活かせるとなお可 ・少ない条件から、どれだけ発注元の希望に沿いつつ相手を満足させられるような作品に仕上げて提供できるか、ゲームクリエイターとしての立場での作成を経験することが目的ということを伝えて', '紙にかくときも大事そうなところをしっかり記入できていてすばらしかったです。プログラムが変数やタイマーを使ってかなりボリュームのある仕上がりになっています。次週以降も続きをやりたいようです。 ほかのスプライトの位置情報を得るときに変数を介してプログラムしていたので、探すにあるブロックを紹介しました。', null, '時間帯: その他'),
  ('509f1d16-f4ad-59d4-b9f8-778e07f30189', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-13', '17:30:00', null, '通常 / 『自由制作DAY』（青）の完成を目標に ・小技は残像か弾幕シューティングの超基礎、背景スクロールあたりを見せて（今回は自分で小技を一から作成する必要はなしと説明） ・使用する小技とゲームのイメージが決まってきたら、プリントに書かせてから作成開始', 'ゲーム内容を考えるのに少し苦労していたようです。使う小技が決まるとなんとなく方向性を決めることができていました。手を動かす前に具体的に決めるのは苦手な様子です。スタートのスプライトやプログラムの核となる部分はおおよそできているので、来週はゲーム性を高めていく予定です（変数の追加、背景の変化など）', null, 'タイピング: 集中して取り組めていました。'),
  ('b6d6c307-2936-5ae1-b626-42e3eaf5a0ef', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-13', '16:30:00', null, '通常 / 『自由制作DAY』（青）の完成を目標に ・小技は横スクロールしかやったことがないのと、2コマ続きで時間があるので、前半は小技を検索させて、一通り体験させて、使えそうな伎をメモまたはリミックスしておく ・使用する小技とゲームのイメージが決まってきたら、プリントに書かせてから作成開始 振替もあったので2コマ分', 'ゲームの内容もスムーズに決まりました。紙に書くのは苦手なようだったので、追加でいくつかこちらから質問しました。ゲームの胆になる部分（どのように操作するのか、ステージが変わるための過程など）は、自分で明確にするのは難しかったようです。 体力ゲージのプログラムも見本を見ながらではありましたが、イチから自分で手を動かせていたのでよかったです。「キーを押しながら」などはよく使うので覚えられていましたが、「自動で～～したい」となったときによく困っていました。条件が外れるので考えやすくなるはずだということを伝えました。元からあるプログラムをそのまま持ってきたときにも、自分のプログラムとの整合性をよく確認するようにアドバイスしました。', '来週はスコアやレベルアップのスプライトの動きを作成していく予定です。', 'タイピング: 集中して取り組めていました。
盛り上がり: ブロックを消す前にひと呼吸おいていました！すごい！！'),
  ('aab49138-36d9-55fe-bb6f-d4990a98fc8a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-13', '16:30:00', null, '通常 / 『自由制作DAY』（青）', '自主制作をやっていきましたが、小技からどれを使っていくのかをしっかりと決めて作品へと取り入れることが出来ていました。本人としても、この作品ではどのような小技が必要となってくるのかをしっかりと見極めていれることができていたようなので、納得のいく作品へと仕上がってきている様子でした。作品の進行度的にも次回には完成させることが出来そうでしたので、この調子で頑張っていってほしいです。', null, 'タイピング: 丁寧に打つことが出来ていました。
盛り上がり: 作品としての軸をしっかりと決めて作ることが出来ていたため、楽しく作ることが出来ていました。'),
  ('52449efa-479b-58a2-adee-93150dc96c67', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-13', null, null, '振替 / 自主制作DAY（青）', 'プリントに書いてある条件に合わせて自主制作をしていきました。小技を作品にたくさん取り入れていきたいようで、色々なアイディアを作品に取り入れようと努力していました。コードも様々なものを取り入れようとしていることで、かなり多くなっている様子でした。本人としては、作品制作にかなり前向きなのでこのやる気を維持して作っていくことができれば、良い作品を作り上げることができると感じています。', null, '時間帯: その他
盛り上がり: やりたいことを作品へと落とし込むことが出来ているようで、満足していました。'),
  ('89f1646b-ee14-5be1-9d4d-85e2d31fce66', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-13', null, null, '通常 / 自由制作DAY（青）', '今回から、宇宙をテーマにした自由制作を開始していきました。前回まで制作していたものは、デバッグをすぐに終わらせ完成まで持っていくことができていたので、自由制作へと入っていきました。制作内容に関しては、しっかりと自分の中で固めることが出来ていたようで、順調に制作へと取り組んでいました。来週の授業で大体完成させる予定なようですので、このまま完成まで持っていきたい様子でした。', null, '時間帯: その他
タイピング: しっかりと打つことができていました。
盛り上がり: 制作を止まることなく出来ていたので嬉しそうでした。'),
  ('68f46392-b67b-579b-8b03-e671bf61a427', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-13', '16:30:00', null, '振替 / 機械学習２章', '前回実施していたジャンケンゲームでは、カメラを使って動きの機械学習をしていたので、今回は音を用いての機械学習をしていきました。外部ソフトであるTeachable Machineを用いて声の聞き分けをScratchの機械に学習させていきました。結果としてしっかりと声の聞き分けを機械学習を用いて行うことができていました。内容理解もしっかりと出来ているようでしたので、良い出来だったと感じています。', null, '盛り上がり: 機械学習を画像以外にも活用できるのだと、理解することができていました。'),
  ('b388ce2d-1d1e-5367-a030-d712a5202696', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '17:30:00', null, '通常 / オリジナル作品のアレンジ', '今回の授業の最初に柚月くんと説明しあっていた、自分の作っている作品のアレンジを行なっていました。今回やる予定であったサッカーについては次回以降に作っていければ良いと考えています。アレンジとしては、太陽系の惑星や衛星をステージ上で動き回らせるようなアレンジをしており、ゲーム全体としての難易度を向上させることが出来ていました。本人としても、このアレンジに関してはかなり満足していたようで、惑星ごとの大きさや模様などにもしっかりとこだわっている様子でした。', null, '盛り上がり: アレンジにおいて、自分の中で考えていたことをしっかりと作品に落とし込めることが出来たようで、非常に満足していました。'),
  ('6d492961-4594-5cf2-b9c1-13ecc5aceb85', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-09', '17:30:00', null, '通常 / 【Prg】51 どこまでいける？ネコのお散歩', '前回まで作成していたゲームの内容を奎歩君に説明してから作成を始めていきました。作品自体が完成していない状態でアレンジを多くしてしまっている様子で、作業の進展がイマイチな様子でした。自分自身のアイディアを取り入れていけることは良いですが、作品の進行状況に影響してきているので、次回は完成させてからアレンジへと入っていければ良いと感じています。', null, '盛り上がり: キャラクターのデザイン変更や障害物やアイテムの量を変化させたりと、様々な試行錯誤をして取り組んでいました。'),
  ('7f33e49e-226e-5788-9721-74f190605ddf', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-09', '18:40:00', null, '通常 / 基本操作コース０９', '今までに様々なゲームを作成してきましたが、今回は基本操作の内容をノーヒントで挑戦していきました。本人の中で基礎的なコードを組むことができるのかを確認する意味でも、一人の力でチャレンジしていきました。結果としては、ほとんどノーヒントで完成まで持っていくことが出来ていました。本人の年齢でのレベルとしてはかなり高いスキルを持っていると感じました。作品のアレンジの際に背景について悩んでいたようなので、次回からは背景スクロールについて学習していく予定です。', '背景スクロール', '盛り上がり: 自分一人の力で完成させることが出来ていたので、とても満足していました。'),
  ('0cc1ee80-da90-5531-a476-46a0959d1b1e', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-09', '16:30:00', null, '通常 / 機械学習序章～1章', '今回の学習で、AIと機械学習とはどのようなものか及び画像学習を用いたゲームの作成を行なっていきました。機械学習について触れることが初めてのようだったので、身近なものから派生させて教えていきました。画像学習についてはすんなりと内容を飲み込むことができていたので、作成は順調に進めていくことが出来ていました。自分の出した手を画面を通じて読み込み、学習していたことをゲームを通じて学べていたようでした。', null, 'タイピング: 素早く打つことが出来ていました。
盛り上がり: 自分自身で作成したゲームで機械学習についてしっかりと確認できている様子でした。'),
  ('38e7ddba-d67c-5d9c-8c30-21ea6ccd216b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2024-02-08', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('7477175e-9b24-57c1-9484-77a998b9ae1b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, null, '2024-02-08', '17:30:00', null, '休み（振替対象）', null, null, null),
