  ('fac605b9-ed69-56af-a456-86dbda0184de', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2024-02-08', '17:30:00', null, '休み（振替対象）', null, null, '備考: 学級閉鎖のため')
